class InstitutionalSmartMoneyEngine:
    """
    INSTITUTIONAL SMART MONEY ENGINE
    
    Advanced smart money analysis with institutional tracking:
    - Institutional Absorption
    - Institutional Distribution
    - Institutional Accumulation
    - Institutional Exit signals
    - Direction AND Strength preservation
    
    Never loses strength information.
    """
    
    @staticmethod
    def analyze_institutional_smart_money(df, lookback=50):
        """
        Comprehensive institutional smart money analysis.
        
        Returns:
            dict: Complete institutional analysis with:
                - direction: BUY/SELL/NEUTRAL
                - strength: STRONG/HEALTHY/WEAK/EXHAUSTED
                - absorption: Institutional absorption detection
                - distribution: Distribution risk
                - accumulation: Accumulation strength
                - institutional_state: EXACT institutional phase
                - entry_signal: Entry quality assessment
                - exit_warning: Early exit warnings
        """
        if df is None or df.empty or len(df) < 20:
            return InstitutionalSmartMoneyEngine._default_state()
        
        close = df["close"]
        high = df["high"]
        low = df["low"]
        volume = df["volume"]
        
        # Calculate volume metrics
        vol_ma20 = volume.rolling(20).mean()
        vol_ma50 = volume.rolling(50).mean()
        vol_current = volume.iloc[-1]
        vol_ratio = vol_current / vol_ma20.iloc[-1] if vol_ma20.iloc[-1] > 0 else 1
        
        # VWMA for institutional tracking
        vwma = (close * volume).rolling(20).sum() / volume.rolling(20).sum()
        
        # Price position relative to VWMA
        price_position = ((close - vwma) / vwma) * 100
        
        # Calculate institutional pressure
        rsi_14 = InstitutionalSmartMoneyEngine._rsi(close, 14)
        rsi_7 = InstitutionalSmartMoneyEngine._rsi(close, 7)
        volume_impulse = volume / vol_ma20.replace(0, np.nan)
        
        # Momentum calculation
        momentum = close.pct_change(5) * 100
        momentum_slow = close.pct_change(20) * 100
        
        # === INSTITUTIONAL PRESSURE CALCULATION ===
        # Banker pressure: institutions accumulate quietly
        banker_pressure = (
            rsi_14.iloc[-1] * 0.25 +
            volume_impulse.iloc[-1] * 20 +
            momentum.iloc[-1] * 3 +
            price_position.iloc[-1] * 2
        ).clip(0, 100)
        
        retailer_pressure = (100 - banker_pressure).clip(0, 100)
        
        # === ABSORPTION DETECTION ===
        # Absorption = Institutions absorbing selling pressure
        # Look for: Price stable/UP despite high selling volume
        recent_closes = close.iloc[-10:].values
        recent_volumes = volume.iloc[-10:].values
        price_change_10 = (close.iloc[-1] - close.iloc[-10]) / close.iloc[-10] * 100
        
        # High volume with minimal price movement = absorption
        avg_vol = vol_ma20.iloc[-1]
        high_volume = vol_ratio > 1.5
        stable_price = abs(price_change_10) < 2
        
        absorption_detected = high_volume and stable_price
        absorption_strength = min(100, vol_ratio * 30) if absorption_detected else 0
        
        # === DISTRIBUTION DETECTION ===
        # Distribution = Institutions selling to retail
        # Look for: Price declining with high volume, RSI divergence
        price_down = close.iloc[-1] < close.iloc[-10]
        distribution_volume = vol_ratio > 1.3
        rsi_diverging = rsi_7.iloc[-1] < rsi_14.iloc[-1] - 10
        
        distribution_risk = 0
        if distribution_volume and price_down:
            distribution_risk = min(100, vol_ratio * 25)
        if rsi_diverging and price_down:
            distribution_risk = min(100, distribution_risk + 20)
        
        # === ACCUMULATION DETECTION ===
        # Accumulation = Institutions buying quietly
        # Look for: Price rising with moderate volume, low volatility
        price_up = close.iloc[-1] > close.iloc[-10]
        accumulation_volume = vol_ratio > 0.8 and vol_ratio < 1.5
        low_volatility = df['high'].rolling(10).max().iloc[-1] - df['low'].rolling(10).min().iloc[-1]
        low_volatility = low_volatility < close.iloc[-1] * 0.03
        
        accumulation_strength = 0
        if accumulation_volume and price_up:
            accumulation_strength = min(100, 50 + vol_ratio * 20)
        if low_volatility and price_up:
            accumulation_strength = min(100, accumulation_strength + 15)
        
        # === INSTITUTIONAL STATE CLASSIFICATION ===
        # banker_pressure is now a numpy.float64 scalar after .clip(), not a Series
        # Extract scalar values for classification
        banker_val = float(banker_pressure) if hasattr(banker_pressure, '__float__') else banker_pressure
        retailer_val = float(retailer_pressure) if hasattr(retailer_pressure, '__float__') else retailer_pressure
        delta = banker_val - retailer_val
        
        # Direction
        if banker_val > 55:
            direction = "BUY"
        elif retailer_val > 60:
            direction = "SELL"
        else:
            direction = "NEUTRAL"
        
        # Strength
        if delta >= 25:
            strength = "STRONG"
        elif delta >= 10:
            strength = "HEALTHY"
        elif delta >= 0:
            strength = "WEAK"
        else:
            strength = "EXHAUSTED"
        
        # Institutional State
        if accumulation_strength > 60 and direction == "BUY":
            institutional_state = "ACCUMULATION_BUY"
        elif distribution_risk > 60 and direction == "SELL":
            institutional_state = "DISTRIBUTION_SELL"
        elif absorption_strength > 50 and direction == "BUY":
            institutional_state = "ABSORPTION_BUY"
        elif absorption_strength > 50 and direction == "SELL":
            institutional_state = "ABSORPTION_SELL"
        elif strength == "STRONG" and direction == "BUY":
            institutional_state = "INSTITUTIONAL_BUY"
        elif strength == "STRONG" and direction == "SELL":
            institutional_state = "INSTITUTIONAL_SELL"
        elif absorption_detected:
            institutional_state = "CONSOLIDATION"
        else:
            institutional_state = "DISTRIBUTION" if distribution_risk > 30 else "NEUTRAL"
        
        # === ENTRY SIGNAL ASSESSMENT ===
        # Best entry: Accumulation + Absorption + Strong Direction
        entry_signal_score = 0
        entry_signal_quality = "POOR"
        
        if accumulation_strength > 50 and direction == "BUY":
            entry_signal_score += 30
        if absorption_strength > 40:
            entry_signal_score += 20
        if strength in ("STRONG", "HEALTHY"):
            entry_signal_score += 25
        if delta > 15:
            entry_signal_score += 15
        if institutional_state in ("ACCUMULATION_BUY", "INSTITUTIONAL_BUY"):
            entry_signal_score += 10
        
        if entry_signal_score >= 80:
            entry_signal_quality = "EXCELLENT"
        elif entry_signal_score >= 60:
            entry_signal_quality = "GOOD"
        elif entry_signal_score >= 40:
            entry_signal_quality = "FAIR"
        
        # === EXIT WARNING ===
        exit_warning = None
        exit_warning_score = 0
        
        # Distribution warning
        if distribution_risk > 70:
            exit_warning = "HIGH_DISTRIBUTION_RISK"
            exit_warning_score = distribution_risk
        # Exhaustion warning
        elif strength == "EXHAUSTED":
            exit_warning = "MOMENTUM_EXHAUSTION"
            exit_warning_score = 50
        # Reversal warning
        elif delta < -20 and direction == "SELL":
            exit_warning = "POTENTIAL_REVERSAL"
            exit_warning_score = 40
        # Euphoria warning
        elif rsi_14.iloc[-1] > 80:
            exit_warning = "RSI_EXTREMES"
            exit_warning_score = 30
        
        def safe_float(v):
            if pd.isna(v) or np.isinf(v):
                return 0.0
            return float(v)
        
        return {
            # Direction and Strength
            "direction": direction,
            "strength": strength,
            "institutional_bias": direction,
            "institutional_bias_detailed": f"{strength}_{direction}",
            
            # Institutional metrics (banker_val and retailer_val are scalars now)
            "banker_pressure": safe_float(banker_val),
            "retailer_pressure": safe_float(retailer_val),
            "pressure_delta": safe_float(delta),
            
            # Institutional states
            "absorption_detected": absorption_detected,
            "absorption_strength": safe_float(absorption_strength),
            "distribution_risk": safe_float(distribution_risk),
            "accumulation_strength": safe_float(accumulation_strength),
            "institutional_state": institutional_state,
            
            # Smart money flags
            "smart_money_dominant": delta > 10,
            "smart_money_confirmed": delta > 15,
            
            # Entry assessment
            "entry_signal_score": safe_float(entry_signal_score),
            "entry_signal_quality": entry_signal_quality,
            
            # Exit warnings
            "exit_warning": exit_warning,
            "exit_warning_score": safe_float(exit_warning_score),
            
            # Additional context
            "volume_ratio": safe_float(vol_ratio),
            "price_position": safe_float(price_position.iloc[-1]),
            "momentum_short": safe_float(momentum.iloc[-1]),
            "momentum_long": safe_float(momentum_slow.iloc[-1]),
            "rsi_14": safe_float(rsi_14.iloc[-1]),
            "rsi_7": safe_float(rsi_7.iloc[-1]),
        }
    
    @staticmethod
    def _rsi(series, period=14):
        delta = series.diff()
        gain = delta.clip(lower=0)
        loss = -delta.clip(upper=0)
        avg_gain = gain.rolling(period).mean()
        avg_loss = loss.rolling(period).mean()
        rs = avg_gain / avg_loss.replace(0, np.nan)
        return 100 - (100 / (1 + rs))
    
    @staticmethod
    def _default_state():
        return {
            "direction": "NEUTRAL",
            "strength": "WEAK",
            "institutional_bias": "NEUTRAL",
            "institutional_bias_detailed": "WEAK_NEUTRAL",
            "banker_pressure": 50.0,
            "retailer_pressure": 50.0,
            "pressure_delta": 0.0,
            "absorption_detected": False,
            "absorption_strength": 0.0,
            "distribution_risk": 0.0,
            "accumulation_strength": 0.0,
            "institutional_state": "NEUTRAL",
            "smart_money_dominant": False,
            "smart_money_confirmed": False,
            "entry_signal_score": 0.0,
            "entry_signal_quality": "POOR",
            "exit_warning": None,
            "exit_warning_score": 0.0,
            "volume_ratio": 1.0,
            "price_position": 0.0,
            "momentum_short": 0.0,
            "momentum_long": 0.0,
            "rsi_14": 50.0,
            "rsi_7": 50.0,
        }


class BankerFundFlowEngine:
    """
    BANKER FUND FLOW ENGINE
    
    Implements Banker Fund Flow model concepts:
    - Fund Flow Trend
    - Bull Bear Line
    - Banker Entry signals
    - Candle color classification
    - Zone detection (Weak/Strong)
    - Overbought/Oversold
    
    Evidence contribution system - never a hard filter.
    """
    
    @staticmethod
    def analyze_banker_fund_flow(df, lookback=50):
        """
        Analyze banker fund flow patterns.
        
        Returns:
            dict: Banker fund flow analysis with:
                - banker_entry: Banker entry signal
                - fund_trend: Bull/Bear trend
                - zone: Strong/Weak zone
                - candle_state: Candle classification
                - overbought: Overbought level
                - oversold: Oversold level
                - flow_direction: Fund flow direction
                - evidence_score: Contribution to decision
        """
        if df is None or df.empty or len(df) < 20:
            return BankerFundFlowEngine._default_state()
        
        close = df["close"]
        high = df["high"]
        low = df["low"]
        volume = df["volume"]
        
        # === CANDLE CLASSIFICATION ===
        # Classify candles by institutional significance
        candles = []
        for i in range(-20, 0):
            c = close.iloc[i]
            o = df["open"].iloc[i]
            h = high.iloc[i]
            l = low.iloc[i]
            v = volume.iloc[i]
            
            body = abs(c - df["open"].iloc[i])
            upper_wick = h - max(c, df["open"].iloc[i])
            lower_wick = min(c, df["open"].iloc[i]) - l
            total_range = h - l
            
            # Candle color
            is_green = c > df["open"].iloc[i]
            is_red = c < df["open"].iloc[i]
            is_doji = body < total_range * 0.1
            
            # Institutional candle classification
            if upper_wick > body * 2 and lower_wick < body * 0.5:
                candle_type = "REJECTION_UPPER"  # Bearish rejection
            elif lower_wick > body * 2 and upper_wick < body * 0.5:
                candle_type = "REJECTION_LOWER"  # Bullish rejection
            elif body > total_range * 0.7:
                if is_green:
                    candle_type = "BULLISH_IGNITION"
                else:
                    candle_type = "BEARISH_IGNITION"
            elif is_doji:
                candle_type = "DOJI"
            elif upper_wick > body and lower_wick > body:
                candle_type = "SPINNING_TOP"
            else:
                candle_type = "NORMAL"
            
            candles.append({
                "type": candle_type,
                "green": is_green,
                "red": is_red,
                "body": body,
                "volume": v
            })
        
        # === FUND FLOW TREND ===
        # Calculate based on candle sequence and volume
        bullish_candles = sum(1 for c in candles if c["green"])
        bearish_candles = sum(1 for c in candles if c["red"])
        
        # Recent candle bias
        recent_10_green = sum(1 for c in candles[-10:] if c["green"])
        trend_ratio = recent_10_green / 10
        
        if trend_ratio > 0.7:
            fund_trend = "BULLISH"
        elif trend_ratio < 0.3:
            fund_trend = "BEARISH"
        else:
            fund_trend = "NEUTRAL"
        
        # === VOLUME WEIGHTED FLOW ===
        green_vol = sum(c["volume"] for c in candles if c["green"])
        red_vol = sum(c["volume"] for c in candles if c["red"])
        
        total_vol = green_vol + red_vol if (green_vol + red_vol) > 0 else 1
        flow_balance = (green_vol - red_vol) / total_vol * 100
        
        if flow_balance > 20:
            flow_direction = "STRONG_INFLOW"
        elif flow_balance > 5:
            flow_direction = "INFLOW"
        elif flow_balance < -20:
            flow_direction = "STRONG_OUTFLOW"
        elif flow_balance < -5:
            flow_direction = "OUTFLOW"
        else:
            flow_direction = "NEUTRAL"
        
        # === ZONE DETECTION ===
        # Identify strong vs weak zones
        current_price = close.iloc[-1]
        ema_20 = close.ewm(span=20).mean().iloc[-1]
        ema_50 = close.ewm(span=50).mean().iloc[-1]
        
        # Strong zone: Price above both EMAs
        if current_price > ema_20 and current_price > ema_50:
            if flow_direction in ("STRONG_INFLOW", "INFLOW"):
                zone = "STRONG_BULL"
            else:
                zone = "STRONG_ZONE"
        # Weak zone: Price below both EMAs
        elif current_price < ema_20 and current_price < ema_50:
            if flow_direction in ("STRONG_OUTFLOW", "OUTFLOW"):
                zone = "WEAK_BEAR"
            else:
                zone = "WEAK_ZONE"
        else:
            zone = "TRANSITION_ZONE"
        
        # === OVERBOUGHT/OVERSOLD ===
        rsi_14 = BankerFundFlowEngine._rsi(close, 14)
        rsi_val = rsi_14.iloc[-1]
        
        overbought_level = max(0, rsi_val - 70) * 3.33
        oversold_level = max(0, 30 - rsi_val) * 3.33
        
        # === BANKER ENTRY SIGNAL ===
        # Bankers typically enter at extremes and against retail
        banker_entry_score = 0
        banker_signal = None
        
        # Strong rejection at oversold = banker buying
        rejection_lower = sum(1 for c in candles[-5:] if c["type"] == "REJECTION_LOWER")
        if rejection_lower >= 2 and oversold_level > 30:
            banker_entry_score += 40
            banker_signal = "BANKER_ACCUMULATION"
        elif rejection_lower == 1 and oversold_level > 20:
            banker_entry_score += 20
            banker_signal = "POTENTIAL_ACCUMULATION"
        
        # Strong rejection at overbought = banker selling
        rejection_upper = sum(1 for c in candles[-5:] if c["type"] == "REJECTION_UPPER")
        if rejection_upper >= 2 and overbought_level > 30:
            banker_entry_score += 40
            banker_signal = "BANKER_DISTRIBUTION"
        elif rejection_upper == 1 and overbought_level > 20:
            banker_entry_score += 20
            banker_signal = "POTENTIAL_DISTRIBUTION"
        
        # Ignition candles show institutional intent
        ignition_bull = sum(1 for c in candles[-5:] if c["type"] == "BULLISH_IGNITION")
        ignition_bear = sum(1 for c in candles[-5:] if c["type"] == "BEARISH_IGNITION")
        if ignition_bull >= 2:
            banker_entry_score += 25
        if ignition_bear >= 2:
            banker_entry_score += 25
        
        # Classify banker signal
        if banker_entry_score >= 60:
            banker_entry = "STRONG"
        elif banker_entry_score >= 30:
            banker_entry = "MODERATE"
        else:
            banker_entry = "WEAK"
        
        # === EVIDENCE SCORE ===
        # How much this contributes to the decision
        evidence_score = 0
        
        if banker_entry in ("STRONG", "MODERATE"):
            evidence_score += 30
        if zone in ("STRONG_BULL", "STRONG_ZONE"):
            evidence_score += 20
            if fund_trend == "BULLISH":
                evidence_score += 10
        elif zone in ("WEAK_BEAR", "WEAK_ZONE"):
            evidence_score += 20
            if fund_trend == "BEARISH":
                evidence_score += 10
        if flow_direction in ("STRONG_INFLOW", "STRONG_OUTFLOW"):
            evidence_score += 15
        if overbought_level > 50 or oversold_level > 50:
            evidence_score += 10
        
        def safe_float(v):
            if pd.isna(v) or np.isinf(v):
                return 0.0
            return float(v)
        
        return {
            # Banker signals
            "banker_entry": banker_entry,
            "banker_signal": banker_signal,
            "banker_entry_score": safe_float(banker_entry_score),
            
            # Trend
            "fund_trend": fund_trend,
            "bullish_candles": bullish_candles,
            "bearish_candles": bearish_candles,
            
            # Flow
            "flow_direction": flow_direction,
            "flow_balance": safe_float(flow_balance),
            
            # Zone
            "zone": zone,
            "ema_20": safe_float(ema_20),
            "ema_50": safe_float(ema_50),
            
            # Extremes
            "overbought_level": safe_float(overbought_level),
            "oversold_level": safe_float(oversold_level),
            "rsi_14": safe_float(rsi_val),
            
            # Evidence
            "evidence_score": safe_float(evidence_score),
            "candle_sequence": [c["type"] for c in candles[-5:]],
        }
    
    @staticmethod
    def _rsi(series, period=14):
        delta = series.diff()
        gain = delta.clip(lower=0)
        loss = -delta.clip(upper=0)
        avg_gain = gain.rolling(period).mean()
        avg_loss = loss.rolling(period).mean()
        rs = avg_gain / avg_loss.replace(0, np.nan)
        return 100 - (100 / (1 + rs))
    
    @staticmethod
    def _default_state():
        return {
            "banker_entry": "WEAK",
            "banker_signal": None,
            "banker_entry_score": 0.0,
            "fund_trend": "NEUTRAL",
            "bullish_candles": 0,
            "bearish_candles": 0,
            "flow_direction": "NEUTRAL",
            "flow_balance": 0.0,
            "zone": "TRANSITION_ZONE",
            "ema_20": 0.0,
            "ema_50": 0.0,
            "overbought_level": 0.0,
            "oversold_level": 0.0,
            "rsi_14": 50.0,
            "evidence_score": 0.0,
            "candle_sequence": [],
        }


class HotMoneyEngine:
    """
    HOT MONEY ENGINE
    
    Tracks hot money and retail activity:
    - Retail FOMO detection
    - Panic selling detection
    - Late buying/selling
    - Blow off top patterns
    - Capitulation detection
    
    Evidence contribution - never a hard filter.
    """
    
    @staticmethod
    def analyze_hot_money(df, lookback=30):
        """
        Analyze hot money and retail activity.
        
        Returns:
            dict: Hot money analysis with:
                - retail_state: Current retail activity
                - fomo_detected: FOMO buying detected
                - panic_detected: Panic selling detected
                - late_entry: Late entry warning
                - blow_off_top: Blow off top pattern
                - capitulation: Capitulation detected
                - acceleration: Hot money acceleration
                - evidence_score: Contribution to decision
        """
        if df is None or df.empty or len(df) < 20:
            return HotMoneyEngine._default_state()
        
        close = df["close"]
        high = df["high"]
        low = df["low"]
        volume = df["volume"]
        
        # === VOLUME ANALYSIS ===
        vol_ma20 = volume.rolling(20).mean()
        vol_ma5 = volume.rolling(5).mean()
        vol_ratio = volume.iloc[-1] / vol_ma20.iloc[-1] if vol_ma20.iloc[-1] > 0 else 1
        vol_spike = vol_ratio > 2.0
        
        # === MOMENTUM ANALYSIS ===
        momentum_3 = close.pct_change(3) * 100
        momentum_10 = close.pct_change(10) * 100
        momentum_30 = close.pct_change(30) * 100
        
        # === RETAIL ACTIVITY ===
        # High volume + high momentum = retail FOMO
        fomo_detected = vol_ratio > 1.8 and momentum_3.iloc[-1] > 2
        
        # Panic = High volume + negative momentum + high volatility
        volatility = (high.rolling(10).max() - low.rolling(10).min()) / close
        high_volatility = volatility.iloc[-1] > 0.05
        panic_detected = vol_ratio > 1.5 and momentum_3.iloc[-1] < -2 and high_volatility
        
        # === LATE ENTRY DETECTION ===
        # Late buying: Price already moved significantly, retail entering at top
        price_rally_10 = (close.iloc[-1] - close.iloc[-10]) / close.iloc[-10] * 100
        late_buying = price_rally_10 > 8 and momentum_3.iloc[-1] > 1.5 and vol_ratio > 1.3
        
        late_selling = price_rally_10 < -8 and momentum_3.iloc[-1] < -1.5 and vol_ratio > 1.3
        late_entry = late_buying or late_selling
        
        # === BLOW OFF TOP ===
        # Extreme move with extreme volume = blow off
        blow_off_top = (
            momentum_10.iloc[-1] > 15 and
            vol_ratio > 2.5 and
            volatility.iloc[-1] > 0.08
        )
        
        # === CAPITULATION ===
        # Sudden crash with volume spike = potential capitulation
        capitulation = (
            momentum_10.iloc[-1] < -15 and
            vol_ratio > 2.5 and
            volatility.iloc[-1] > 0.08
        )
        
        # === ACCELERATION / DECELERATION ===
        # Hot money acceleration: Momentum increasing rapidly
        mom_change = momentum_3.iloc[-1] - momentum_3.iloc[-5]
        acceleration = mom_change > 3
        deceleration = mom_change < -3
        
        # === RETAIL STATE ===
        if fomo_detected or late_buying:
            retail_state = "FOMO_BUYING"
        elif panic_detected or late_selling:
            retail_state = "PANIC_SELLING"
        elif blow_off_top:
            retail_state = "BLOW_OFF_TOP"
        elif capitulation:
            retail_state = "CAPITULATION"
        elif acceleration:
            retail_state = "ACCELERATION"
        elif deceleration:
            retail_state = "DECELERATION"
        elif vol_ratio > 1.5:
            retail_state = "HIGH_VOLUME"
        else:
            retail_state = "NORMAL"
        
        # === EVIDENCE SCORE ===
        evidence_score = 0
        
        # Late entry is a warning
        if late_entry:
            evidence_score -= 20
        
        # Blow off top = reversal likely
        if blow_off_top:
            evidence_score += 30
        
        # Capitulation = potential bottom
        if capitulation:
            evidence_score += 25
        
        # FOMO = continuation possible but risky
        if fomo_detected:
            evidence_score += 15
        
        # Panic = potential reversal
        if panic_detected:
            evidence_score += 20
        
        # Acceleration = strong momentum
        if acceleration and momentum_3.iloc[-1] > 0:
            evidence_score += 15
        
        def safe_float(v):
            if pd.isna(v) or np.isinf(v):
                return 0.0
            return float(v)
        
        return {
            # Retail state
            "retail_state": retail_state,
            
            # Detection flags
            "fomo_detected": fomo_detected,
            "panic_detected": panic_detected,
            "late_entry": late_entry,
            "late_buying": late_buying,
            "late_selling": late_selling,
            "blow_off_top": blow_off_top,
            "capitulation": capitulation,
            
            # Momentum
            "acceleration": acceleration,
            "deceleration": deceleration,
            "momentum_change": safe_float(mom_change),
            "momentum_3": safe_float(momentum_3.iloc[-1]),
            "momentum_10": safe_float(momentum_10.iloc[-1]),
            "momentum_30": safe_float(momentum_30.iloc[-1]),
            
            # Volume
            "volume_ratio": safe_float(vol_ratio),
            "volume_spike": vol_spike,
            
            # Evidence
            "evidence_score": safe_float(evidence_score),
            "hot_money_pressure": safe_float(min(100, vol_ratio * 40)),
        }
    
    @staticmethod
    def _default_state():
        return {
            "retail_state": "NORMAL",
            "fomo_detected": False,
            "panic_detected": False,
            "late_entry": False,
            "late_buying": False,
            "late_selling": False,
            "blow_off_top": False,
            "capitulation": False,
            "acceleration": False,
            "deceleration": False,
            "momentum_change": 0.0,
            "momentum_3": 0.0,
            "momentum_10": 0.0,
            "momentum_30": 0.0,
            "volume_ratio": 1.0,
            "volume_spike": False,
            "evidence_score": 0.0,
            "hot_money_pressure": 50.0,
        }


class SmartMCDXEngine:
    """
    SMART MCDX ENGINE
    
    Institutional Flow Analysis Engine inspired by SmartMCDX concepts.
    Estimates institutional vs retail activity through price action analysis.
    
    EVIDENCE PROVIDER ONLY - Never makes decisions.
    
    Metrics Generated:
    - Institutional Buying/Selling pressure
    - Retail Buying/Selling pressure  
    - Market Control (Institutional vs Retail)
    - Flow Phase (Accumulation, Distribution, etc.)
    - Hot Money State
    - Money Rotation
    - Flow Acceleration/Deceleration
    """
    
    @staticmethod
    def analyze_mcdx(df, lookback=50):
        """
        Comprehensive SmartMCDX institutional flow analysis.
        
        Args:
            df: Price dataframe with OHLCV
            lookback: Period for analysis
            
        Returns:
            dict: Institutional flow evidence
        """
        if df is None or df.empty or len(df) < 20:
            return SmartMCDXEngine._default_state()
        
        close = df["close"]
        high = df["high"]
        low = df["low"]
        volume = df["volume"]
        open_price = df["open"]
        
        # === VOLUME ANALYSIS ===
        vol_ma20 = volume.rolling(20).mean()
        vol_ma50 = volume.rolling(50).mean()
        vol_ratio = volume / vol_ma20.replace(0, 1)
        
        # === PRICE ACTION ANALYSIS ===
        # Calculate true range for normalization
        tr = np.maximum(
            high - low,
            np.maximum(
                abs(high - close.shift(1)),
                abs(low - close.shift(1))
            )
        )
        
        # === INSTITUTIONAL vs RETAIL FLOW ESTIMATION ===
        # Institutional typically trades with larger size, sustained pressure
        # Retail typically shows quick reactions, FOMO patterns
        
        # Price momentum components
        up_momentum = close.diff().clip(lower=0).rolling(14).mean()
        down_momentum = (-close.diff()).clip(lower=0).rolling(14).mean()
        
        # Volume-weighted price change
        vwap = (close * volume).rolling(20).sum() / volume.rolling(20).sum()
        price_distance = ((close - vwap) / vwap.replace(0, 1)) * 100
        
        # === INSTITUTIONAL PRESSURE CALCULATION ===
        # Higher volume + price stability = institutional
        # Higher volume + price volatility = retail/speculative
        
        # Institutional buying: Rising price with controlled volume
        inst_buy_pressure = (
            (up_momentum / (up_momentum + down_momentum + 0.001)) * 100 * 0.4 +
            (1 - vol_ratio.clip(0, 2) / 2) * 30 +
            (price_distance.clip(-5, 5) + 5) * 3
        ).clip(0, 100)
        
        # Institutional selling: Declining price with institutional volume
        inst_sell_pressure = (
            (down_momentum / (up_momentum + down_momentum + 0.001)) * 100 * 0.4 +
            (1 - vol_ratio.clip(0, 2) / 2) * 30 +
            (-price_distance.clip(-5, 5) + 5) * 3
        ).clip(0, 100)
        
        # === RETAIL PRESSURE ESTIMATION ===
        # High volume + momentum divergence = retail
        rsi_14 = SmartMCDXEngine._rsi(close, 14)
        rsi_slope = rsi_14.diff().rolling(5).mean()
        
        # Retail buying: High volume + overbought RSI + price spike
        retail_buy_pressure = (
            vol_ratio.clip(0, 3) / 3 * 100 * 0.5 +
            rsi_14.clip(50, 100) - 50 +
            abs(rsi_slope.clip(-5, 5)) * 10
        ).clip(0, 100)
        
        # Retail selling: High volume + oversold + panic
        retail_sell_pressure = (
            vol_ratio.clip(0, 3) / 3 * 100 * 0.5 +
            (50 - rsi_14.clip(0, 50)) +
            abs(rsi_slope.clip(-5, 5)) * 10
        ).clip(0, 100)
        
        # === MARKET CONTROL ===
        inst_total = inst_buy_pressure.iloc[-1] + inst_sell_pressure.iloc[-1]
        retail_total = retail_buy_pressure.iloc[-1] + retail_sell_pressure.iloc[-1]
        
        if inst_total > retail_total * 1.2:
            market_control = "INSTITUTIONAL"
        elif retail_total > inst_total * 1.2:
            market_control = "RETAIL"
        else:
            market_control = "BALANCED"
        
        # === INSTITUTIONAL DOMINANCE ===
        dominance = inst_total - retail_total
        if dominance > 30:
            dominance_level = "STRONG_INSTITUTIONAL"
        elif dominance > 10:
            dominance_level = "MODERATE_INSTITUTIONAL"
        elif dominance < -30:
            dominance_level = "STRONG_RETAIL"
        elif dominance < -10:
            dominance_level = "MODERATE_RETAIL"
        else:
            dominance_level = "BALANCED"
        
        # === HOT MONEY STATE ===
        mom_5 = close.pct_change(5) * 100
        mom_20 = close.pct_change(20) * 100
        
        if rsi_14.iloc[-1] > 75 and vol_ratio.iloc[-1] > 1.5:
            hot_money_state = "FOMO_BUYING"
        elif rsi_14.iloc[-1] < 25 and vol_ratio.iloc[-1] > 1.5:
            hot_money_state = "PANIC_SELLING"
        elif abs(mom_5.iloc[-1]) > 3 and vol_ratio.iloc[-1] > 1.8:
            hot_money_state = "SPECULATIVE"
        elif abs(mom_5.iloc[-1]) > abs(mom_20.iloc[-1]) * 2:
            hot_money_state = "MOMENTUM"
        else:
            hot_money_state = "NORMAL"
        
        # === FLOW PHASE ===
        # Detect accumulation, distribution, markup, markdown phases
        price_change_20 = (close.iloc[-1] - close.iloc[-20]) / close.iloc[-20] * 100
        
        if price_change_20 > 5 and inst_buy_pressure.iloc[-1] > 60:
            flow_phase = "INSTITUTIONAL_ACCUMULATION"
        elif price_change_20 < -5 and inst_sell_pressure.iloc[-1] > 60:
            flow_phase = "INSTITUTIONAL_DISTRIBUTION"
        elif price_change_20 > 10 and retail_buy_pressure.iloc[-1] > 50:
            flow_phase = "RETAIL_FOMO"
        elif price_change_20 < -10 and retail_sell_pressure.iloc[-1] > 50:
            flow_phase = "RETAIL_PANIC"
        elif abs(price_change_20) < 3 and vol_ratio.iloc[-1] > 1.2:
            flow_phase = "CONSOLIDATION"
        elif price_change_20 > 5:
            flow_phase = "MARKUP"
        elif price_change_20 < -5:
            flow_phase = "MARKDOWN"
        else:
            flow_phase = "RANGE"
        
        # === MONEY ROTATION ===
        # Track rotation between sectors/strong-weak
        # Simplified: Rotation = changing leadership
        mom_short = close.pct_change(5)
        mom_long = close.pct_change(20)
        rotation_score = (mom_short - mom_long).abs().clip(0, 10) * 10
        
        # === FLOW ACCELERATION/DECELERATION ===
        mom_change = mom_short.diff().rolling(3).mean()
        if mom_change.iloc[-1] > 0.5:
            flow_state = "ACCELERATING"
        elif mom_change.iloc[-1] < -0.5:
            flow_state = "DECELERATING"
        else:
            flow_state = "STABLE"
        
        # === HOT MONEY EXHAUSTION ===
        hot_exhaustion = 0
        if rsi_14.iloc[-1] > 85:
            hot_exhaustion = 80
        elif rsi_14.iloc[-1] > 75:
            hot_exhaustion = 50
        elif rsi_14.iloc[-1] < 15:
            hot_exhaustion = 80
        elif rsi_14.iloc[-1] < 25:
            hot_exhaustion = 50
        
        # === INSTITUTIONAL ABSORPTION/EXHAUSTION ===
        # Absorption = Price stable despite high volume
        price_stability = 100 - (vol_ratio.clip(0, 3) * 20)
        absorption = (vol_ratio.iloc[-1] > 1.5) and (abs(price_change_20) < 3)
        exhaustion = hot_exhaustion > 60
        
        # === COMPOSITE SCORES ===
        institutional_pressure = (inst_buy_pressure.iloc[-1] + inst_sell_pressure.iloc[-1]) / 2
        retail_pressure = (retail_buy_pressure.iloc[-1] + retail_sell_pressure.iloc[-1]) / 2
        
        # Flow confidence
        total_pressure = institutional_pressure + retail_pressure
        if total_pressure > 80:
            confidence = "HIGH"
        elif total_pressure > 50:
            confidence = "MEDIUM"
        else:
            confidence = "LOW"
        
        def safe_float(v):
            if pd.isna(v) or np.isinf(v):
                return 0.0
            return float(v)
        
        return {
            # Pressure metrics
            "institutional_buy_pressure": safe_float(inst_buy_pressure.iloc[-1]),
            "institutional_sell_pressure": safe_float(inst_sell_pressure.iloc[-1]),
            "retail_buy_pressure": safe_float(retail_buy_pressure.iloc[-1]),
            "retail_sell_pressure": safe_float(retail_sell_pressure.iloc[-1]),
            "institutional_pressure": safe_float(institutional_pressure),
            "retail_pressure": safe_float(retail_pressure),
            
            # Direction
            "institutional_direction": "BUY" if inst_buy_pressure.iloc[-1] > inst_sell_pressure.iloc[-1] else "SELL",
            "institutional_strength": dominance_level.replace("_INSTITUTIONAL", "").replace("_RETAIL", ""),
            
            # Control
            "market_control": market_control,
            "dominance_level": dominance_level,
            "dominance_score": safe_float(dominance),
            
            # States
            "hot_money_state": hot_money_state,
            "flow_phase": flow_phase,
            "flow_state": flow_state,
            
            # Additional
            "hot_money_exhaustion": safe_float(hot_exhaustion),
            "absorption_detected": absorption,
            "exhaustion_detected": exhaustion,
            
            # Rotation
            "money_rotation": safe_float(rotation_score.iloc[-1]),
            
            # Confidence
            "confidence": confidence,
            
            # RSI for reference
            "rsi_14": safe_float(rsi_14.iloc[-1]),
            "price_change_20": safe_float(price_change_20),
            "volume_ratio": safe_float(vol_ratio.iloc[-1]),
        }
    
    @staticmethod
    def _rsi(series, period=14):
        delta = series.diff()
        gain = delta.clip(lower=0)
        loss = -delta.clip(upper=0)
        avg_gain = gain.rolling(period).mean()
        avg_loss = loss.rolling(period).mean()
        rs = avg_gain / avg_loss.replace(0, np.nan)
        return 100 - (100 / (1 + rs))
    
    @staticmethod
    def _default_state():
        return {
            "institutional_buy_pressure": 50.0,
            "institutional_sell_pressure": 50.0,
            "retail_buy_pressure": 50.0,
            "retail_sell_pressure": 50.0,
            "institutional_pressure": 50.0,
            "retail_pressure": 50.0,
            "institutional_direction": "NEUTRAL",
            "institutional_strength": "BALANCED",
            "market_control": "BALANCED",
            "dominance_level": "BALANCED",
            "dominance_score": 0.0,
            "hot_money_state": "NORMAL",
            "flow_phase": "RANGE",
            "flow_state": "STABLE",
            "hot_money_exhaustion": 0.0,
            "absorption_detected": False,
            "exhaustion_detected": False,
            "money_rotation": 0.0,
            "confidence": "LOW",
            "rsi_14": 50.0,
            "price_change_20": 0.0,
            "volume_ratio": 1.0,
        }


class L3BankerFundFlowEngine:
    """
    L3 BANKER FUND FLOW OSCILLATOR
    
    Advanced Banker Fund Flow tracking inspired by TradingView concepts.
    Tracks institutional entry/exit patterns without relying on visual indicators.
    
    EVIDENCE PROVIDER ONLY - Never makes decisions.
    
    Signals Generated:
    - Fund Flow Trend
    - Bull Bear Line
    - Institutional Entry/Exit Zones
    - Banker Accumulation/Distribution
    - Weak Rebound Detection
    - Institutional Continuation
    """
    
    @staticmethod
    def analyze_l3_banker_flow(df, lookback=50):
        """
        L3 Banker Fund Flow analysis.
        
        Args:
            df: Price dataframe with OHLCV
            lookback: Period for analysis
            
        Returns:
            dict: Banker fund flow evidence
        """
        if df is None or df.empty or len(df) < 20:
            return L3BankerFundFlowEngine._default_state()
        
        close = df["close"]
        high = df["high"]
        low = df["low"]
        volume = df["volume"]
        open_price = df["open"]
        
        # === CANDLE CLASSIFICATION ===
        # Classify candles by institutional significance
        candles = []
        for i in range(-20, 0):
            o = open_price.iloc[i]
            c = close.iloc[i]
            h = high.iloc[i]
            l = low.iloc[i]
            v = volume.iloc[i]
            
            body = abs(c - o)
            upper_wick = h - max(c, o)
            lower_wick = min(c, o) - l
            total_range = h - l
            
            is_green = c > o
            is_red = c < o
            is_doji = body < total_range * 0.1
            
            # Institutional candle types
            if upper_wick > body * 2 and lower_wick < body * 0.5:
                candle_type = "REJECTION_UPPER"  # Bearish rejection = potential buy
            elif lower_wick > body * 2 and upper_wick < body * 0.5:
                candle_type = "REJECTION_LOWER"  # Bullish rejection = potential sell
            elif body > total_range * 0.7:
                candle_type = "IGNITION" if is_green else "DISTRIBUTION"
            elif is_doji:
                candle_type = "DOJI"
            elif upper_wick > body and lower_wick > body:
                candle_type = "SPINNING_TOP"
            else:
                candle_type = "NORMAL"
            
            candles.append({
                "type": candle_type,
                "green": is_green,
                "red": is_red,
                "body": body,
                "volume": v,
                "close": c,
                "high": h,
                "low": l
            })
        
        # === GREEN EXPANSION (Yellow Entry Equivalent) ===
        # Strong bullish candle with high volume
        recent_candles = candles[-5:]
        green_expansion = any(
            c["type"] == "IGNITION" and c["green"] and c["volume"] > np.mean([x["volume"] for x in candles]) * 1.3
            for c in recent_candles
        )
        
        # === RED EXIT ===
        # Strong bearish candle showing institutional exit
        red_exit = any(
            c["type"] == "DISTRIBUTION" and c["red"] and c["volume"] > np.mean([x["volume"] for x in candles]) * 1.3
            for c in recent_candles
        )
        
        # === BLUE WEAK REBOUND (Equivalent) ===
        # Small bullish candle after decline = weak recovery
        weak_rebound = False
        if len(candles) >= 3:
            recent_3 = candles[-3:]
            if all(c["green"] for c in recent_3):
                # Check if it's a weak rebound (small gains, declining volume)
                vol_trend = sum(1 for c in recent_3 if c["volume"] < np.mean([x["volume"] for x in candles]))
                if vol_trend >= 2:
                    weak_rebound = True
        
        # === WHITE POSITION REDUCTION (Equivalent) ===
        # Declining volume in sideways market = institutional reducing
        vol_ma20 = volume.rolling(20).mean()
        vol_ma5 = volume.rolling(5).mean()
        position_reduction = vol_ma5.iloc[-1] < vol_ma20.iloc[-1] * 0.7
        
        # === FUND FLOW CALCULATION ===
        # Calculate based on candle sequence and volume
        bullish_candles = sum(1 for c in candles if c["green"])
        bearish_candles = sum(1 for c in candles if c["red"])
        
        # Recent trend
        recent_10_green = sum(1 for c in candles[-10:] if c["green"])
        trend_ratio = recent_10_green / 10
        
        if trend_ratio > 0.7:
            fund_trend = "BULLISH"
        elif trend_ratio < 0.3:
            fund_trend = "BEARISH"
        else:
            fund_trend = "NEUTRAL"
        
        # === BULL BEAR LINE ===
        # Compare current price to VWAP
        vwap = (close * volume).rolling(20).sum() / volume.rolling(20).sum()
        bull_bear_line = close.iloc[-1] - vwap.iloc[-1]
        
        if bull_bear_line > 0:
            bull_bear_relation = "ABOVE"  # Bullish
        elif bull_bear_line < 0:
            bull_bear_relation = "BELOW"  # Bearish
        else:
            bull_bear_relation = "AT"
        
        # === INSTITUTIONAL ENTRY ZONE ===
        # Identify where institutions are likely entering
        recent_lows = [c["low"] for c in candles[-10:]]
        recent_highs = [c["high"] for c in candles[-10:]]
        
        # Support = recent lows
        support_zone = min(recent_lows)
        resistance_zone = max(recent_highs)
        
        # Check if price is near support (potential entry)
        dist_to_support = abs(close.iloc[-1] - support_zone) / close.iloc[-1] * 100
        dist_to_resistance = abs(close.iloc[-1] - resistance_zone) / close.iloc[-1] * 100
        
        # === INSTITUTIONAL ENTRY/EXIT ===
        # Strong rejection at support = entry
        rejection_lower_count = sum(1 for c in candles[-5:] if c["type"] == "REJECTION_LOWER")
        rejection_upper_count = sum(1 for c in candles[-5:] if c["type"] == "REJECTION_UPPER")
        
        institutional_entry = rejection_lower_count >= 1 and dist_to_support < 2
        institutional_exit = rejection_upper_count >= 1 and dist_to_resistance < 2
        
        # === BANKER ACCUMULATION/DISTRIBUTION ===
        # Accumulation: Price rising with moderate volume
        price_5_change = (close.iloc[-1] - close.iloc[-5]) / close.iloc[-5] * 100
        avg_vol_ratio = volume.iloc[-5:].mean() / vol_ma20.iloc[-1]
        
        if price_5_change > 3 and avg_vol_ratio > 0.8 and avg_vol_ratio < 1.5:
            banker_state = "ACCUMULATION"
        elif price_5_change < -3 and avg_vol_ratio > 0.8 and avg_vol_ratio < 1.5:
            banker_state = "DISTRIBUTION"
        elif green_expansion:
            banker_state = "EXPANSION"
        elif red_exit:
            banker_state = "EXIT"
        elif weak_rebound:
            banker_state = "WEAK_REBOUND"
        elif position_reduction:
            banker_state = "REDUCING"
        else:
            banker_state = "NEUTRAL"
        
        # === INSTITUTIONAL CONTINUATION ===
        # Multiple bullish candles with stable volume = continuation
        continuation_score = 0
        if recent_10_green >= 7:
            continuation_score += 30
        if avg_vol_ratio > 0.8:
            continuation_score += 20
        if bull_bear_relation == "ABOVE":
            continuation_score += 25
        if institutional_entry:
            continuation_score += 25
        
        # === COMPOSITE SCORES ===
        fund_flow_score = (bullish_candles - bearish_candles + 10) * 5  # 0-100
        
        # Banker confidence
        banker_confidence = 0
        if institutional_entry:
            banker_confidence += 30
        if banker_state == "ACCUMULATION":
            banker_confidence += 25
        if bull_bear_relation == "ABOVE":
            banker_confidence += 20
        if continuation_score > 50:
            banker_confidence += 15
        if not position_reduction:
            banker_confidence += 10
        
        # Signal classification
        if banker_confidence >= 70:
            banker_signal = "STRONG_BANKER_BUY"
        elif banker_confidence >= 50:
            banker_signal = "BANKER_ACCUMULATION"
        elif banker_confidence >= 30:
            banker_signal = "MODERATE_BUY"
        elif banker_confidence <= 10 and red_exit:
            banker_signal = "BANKER_DISTRIBUTION"
        elif banker_confidence <= 10:
            banker_signal = "NO_SIGNAL"
        else:
            banker_signal = "NEUTRAL"
        
        # === EMA CROSS FOR TREND ===
        ema_9 = close.ewm(span=9).mean()
        ema_21 = close.ewm(span=21).mean()
        ema_cross = 1 if ema_9.iloc[-1] > ema_21.iloc[-1] else -1
        
        # === VOLUME PROFILE ===
        vol_profile = "NORMAL"
        if avg_vol_ratio > 2:
            vol_profile = "EXPLOSIVE"
        elif avg_vol_ratio > 1.5:
            vol_profile = "HIGH"
        elif avg_vol_ratio < 0.5:
            vol_profile = "DRY"
        
        def safe_float(v):
            if pd.isna(v) or np.isinf(v):
                return 0.0
            return float(v)
        
        return {
            # Fund flow
            "fund_flow": safe_float(fund_flow_score),
            "fund_trend": fund_trend,
            "bull_bear_line": safe_float(bull_bear_line),
            "bull_bear_relation": bull_bear_relation,
            
            # Signals
            "banker_signal": banker_signal,
            "banker_confidence": safe_float(banker_confidence),
            "banker_state": banker_state,
            
            # Entry/Exit
            "institutional_entry": institutional_entry,
            "institutional_exit": institutional_exit,
            "green_expansion": green_expansion,
            "red_exit": red_exit,
            "weak_rebound": weak_rebound,
            "position_reduction": position_reduction,
            
            # Continuation
            "continuation_score": safe_float(continuation_score),
            "institutional_continuation": continuation_score > 50,
            
            # Zones
            "support_zone": safe_float(support_zone),
            "resistance_zone": safe_float(resistance_zone),
            "dist_to_support": safe_float(dist_to_support),
            "dist_to_resistance": safe_float(dist_to_resistance),
            
            # Trend
            "ema_cross": ema_cross,
            "volume_profile": vol_profile,
            
            # Candle counts
            "bullish_candles": bullish_candles,
            "bearish_candles": bearish_candles,
        }
    
    @staticmethod
    def _default_state():
        return {
            "fund_flow": 50.0,
            "fund_trend": "NEUTRAL",
            "bull_bear_line": 0.0,
            "bull_bear_relation": "AT",
            "banker_signal": "NO_SIGNAL",
            "banker_confidence": 0.0,
            "banker_state": "NEUTRAL",
            "institutional_entry": False,
            "institutional_exit": False,
            "green_expansion": False,
            "red_exit": False,
            "weak_rebound": False,
            "position_reduction": False,
            "continuation_score": 0.0,
            "institutional_continuation": False,
            "support_zone": 0.0,
            "resistance_zone": 0.0,
            "dist_to_support": 0.0,
            "dist_to_resistance": 0.0,
            "ema_cross": 0,
            "volume_profile": "NORMAL",
            "bullish_candles": 0,
            "bearish_candles": 0,
        }


class MarketStoryEngine:
    """
    MARKET STORY ENGINE
    
    Creates unified market narrative from all evidence:
    - Complete market story
    - Institutional alignment
    - Entry quality assessment
    - Risk narrative
    - Trade thesis generation
    
    The story is the truth, not individual indicators.
    """
    
    @staticmethod
    def generate_market_story(
        smart_money: dict,
        momentum: dict,
        banker_flow: dict,
        hot_money: dict,
        liquidity: dict,
        structure: dict,
        volume: dict,
        df,
        side: str,
        smart_mcdx: dict = None,
        l3_banker_flow: dict = None
    ) -> dict:
        """
        Generate complete market story from all evidence.
        
        Args:
            smart_money: InstitutionalSmartMoneyEngine output
            momentum: MomentumFlowEngine output
            banker_flow: BankerFundFlowEngine output
            hot_money: HotMoneyEngine output
            liquidity: Liquidity analysis
            structure: Structure analysis
            volume: Volume analysis
            df: Price dataframe
            side: Trade direction
            smart_mcdx: SmartMCDX Engine output (NEW)
            l3_banker_flow: L3 Banker Fund Flow output (NEW)
            
        Returns:
            dict: Complete market story with thesis
        """
        if df is None or df.empty:
            return MarketStoryEngine._default_story()
        
        # Default values for new engines
        if smart_mcdx is None:
            smart_mcdx = {}
        if l3_banker_flow is None:
            l3_banker_flow = {}
        
        close = df["close"]
        story_elements = []
        warnings = []
        confirms = []
        
        # === BUILD STORY ===
        
        # Smart Money Story
        sm_state = smart_money.get("institutional_state", "NEUTRAL")
        sm_direction = smart_money.get("direction", "NEUTRAL")
        sm_strength = smart_money.get("strength", "WEAK")
        
        if "ACCUMULATION" in sm_state:
            story_elements.append(f"📊 SmartMoney: INSTITUTIONAL ACCUMULATION detected")
            confirms.append("institutional_accumulation")
        elif "DISTRIBUTION" in sm_state:
            story_elements.append(f"📊 SmartMoney: INSTITUTIONAL DISTRIBUTION detected")
            warnings.append("institutional_distribution")
        elif sm_direction == side and sm_strength in ("STRONG", "HEALTHY"):
            story_elements.append(f"📊 SmartMoney: {sm_strength} {sm_direction} aligned with trade")
            confirms.append("smart_money_aligned")
        else:
            story_elements.append(f"📊 SmartMoney: {sm_state}")
        
        # Banker Flow Story
        banker_entry = banker_flow.get("banker_entry", "WEAK")
        banker_signal = banker_flow.get("banker_signal", None)
        banker_zone = banker_flow.get("zone", "TRANSITION_ZONE")
        
        if banker_signal:
            story_elements.append(f"🏦 BankerFlow: {banker_signal}")
            if "ACCUMULATION" in banker_signal:
                confirms.append("banker_accumulation")
            elif "DISTRIBUTION" in banker_signal:
                warnings.append("banker_distribution")
        
        if banker_zone in ("STRONG_BULL", "STRONG_ZONE") and side == "BUY":
            story_elements.append(f"🏦 BankerZone: STRONG BULL zone - institutional support")
            confirms.append("strong_zone")
        elif banker_zone in ("WEAK_BEAR", "WEAK_ZONE") and side == "SELL":
            story_elements.append(f"🏦 BankerZone: WEAK BEAR zone - institutional resistance")
            confirms.append("weak_zone")
        
        # Hot Money Story
        retail_state = hot_money.get("retail_state", "NORMAL")
        
        if hot_money.get("fomo_detected"):
            story_elements.append(f"🔥 HotMoney: FOMO DETECTED - retail chasing")
            warnings.append("retail_fomo")
        elif hot_money.get("panic_detected"):
            story_elements.append(f"🔥 HotMoney: PANIC DETECTED - potential reversal")
            confirms.append("panic_reversal")
        elif hot_money.get("blow_off_top"):
            story_elements.append(f"🔥 HotMoney: BLOW OFF TOP - reversal imminent")
            warnings.append("blow_off")
        elif hot_money.get("capitulation"):
            story_elements.append(f"🔥 HotMoney: CAPITULATION - potential bottom")
            confirms.append("capitulation_bottom")
        elif hot_money.get("acceleration"):
            story_elements.append(f"🔥 HotMoney: MOMENTUM ACCELERATION")
            confirms.append("momentum_acceleration")
        
        # Liquidity Story
        if liquidity.get("sweep"):
            sweep_type = "BUY" if side == "BUY" else "SELL"
            story_elements.append(f"💧 Liquidity: {sweep_type} side sweep detected")
            confirms.append("liquidity_sweep")
        if liquidity.get("retest"):
            story_elements.append(f"💧 Liquidity: Order block retest confirmed")
            confirms.append("ob_retest")
        
        # Structure Story
        if structure.get("bos"):
            story_elements.append(f"📐 Structure: BOS confirmed - trend intact")
            confirms.append("bos_confirmed")
        if structure.get("mss"):
            story_elements.append(f"📐 Structure: MSS detected - momentum shift")
            confirms.append("mss_confirmed")
        if structure.get("choch"):
            story_elements.append(f"📐 Structure: CHoCH - structure shift")
            warnings.append("structure_shift")
        
        # SmartMCDX Story (NEW)
        mcdx_flow_phase = smart_mcdx.get("flow_phase", "RANGE")
        mcdx_control = smart_mcdx.get("market_control", "BALANCED")
        mcdx_state = smart_mcdx.get("hot_money_state", "NORMAL")
        
        if mcdx_flow_phase in ("INSTITUTIONAL_ACCUMULATION", "ACCUMULATION"):
            story_elements.append(f"📈 MCDX: INSTITUTIONAL ACCUMULATION")
            confirms.append("mcdx_accumulation")
        elif mcdx_flow_phase in ("INSTITUTIONAL_DISTRIBUTION", "DISTRIBUTION"):
            story_elements.append(f"📉 MCDX: INSTITUTIONAL DISTRIBUTION")
            warnings.append("mcdx_distribution")
        elif mcdx_flow_phase == "RETAIL_FOMO":
            story_elements.append(f"🔥 MCDX: RETAIL FOMO detected")
            warnings.append("mcdx_fomo")
        elif mcdx_flow_phase == "MARKUP":
            story_elements.append(f"📈 MCDX: MARKUP phase")
        
        if mcdx_control == "INSTITUTIONAL" and side == "BUY":
            story_elements.append(f"📈 MCDX: INSTITUTIONAL CONTROL confirmed")
            confirms.append("mcdx_institutional")
        elif mcdx_control == "RETAIL" and side == "BUY":
            story_elements.append(f"⚠️ MCDX: RETAIL CONTROL - risky entry")
            warnings.append("mcdx_retail")
        
        # L3 Banker Fund Flow Story (NEW)
        l3_signal = l3_banker_flow.get("banker_signal", "NEUTRAL")
        l3_state = l3_banker_flow.get("banker_state", "NEUTRAL")
        l3_entry = l3_banker_flow.get("institutional_entry", False)
        l3_exit = l3_banker_flow.get("institutional_exit", False)
        l3_continuation = l3_banker_flow.get("institutional_continuation", False)
        
        if l3_signal in ("STRONG_BANKER_BUY", "BANKER_ACCUMULATION"):
            story_elements.append(f"🏦 L3: BANKER ACCUMULATION confirmed")
            confirms.append("l3_accumulation")
        elif l3_signal == "BANKER_DISTRIBUTION":
            story_elements.append(f"🏦 L3: BANKER DISTRIBUTION detected")
            warnings.append("l3_distribution")
        
        if l3_entry:
            story_elements.append(f"🎯 L3: INSTITUTIONAL ENTRY zone")
            confirms.append("l3_entry")
        if l3_exit:
            story_elements.append(f"⚠️ L3: INSTITUTIONAL EXIT zone")
            warnings.append("l3_exit")
        if l3_continuation:
            story_elements.append(f"📈 L3: INSTITUTIONAL CONTINUATION")
            confirms.append("l3_continuation")
        
        # Pattern Detection
        patterns = []
        if mcdx_flow_phase == "CONSOLIDATION" and structure.get("bos"):
            patterns.append("BREAKOUT_SETUP")
        if l3_banker_flow.get("green_expansion", False):
            patterns.append("GREEN_EXPANSION")
        if l3_banker_flow.get("red_exit", False):
            patterns.append("RED_EXIT")
        if l3_banker_flow.get("weak_rebound", False):
            patterns.append("WEAK_REBOUND")
        
        for pattern in patterns:
            if pattern in ("BREAKOUT_SETUP", "GREEN_EXPANSION"):
                confirms.append(pattern.lower())
            else:
                warnings.append(pattern.lower())
        
        # === TRADE THESIS ===
        thesis_parts = []
        
        # Entry reason
        thesis_parts.append(f"Entry: {side} on {smart_money.get('institutional_state', 'neutral')} market")
        
        # Confirmation story
        if len(confirms) >= 3:
            thesis_parts.append(f"Thesis: STRONG setup with {len(confirms)} confirmations")
        elif len(confirms) >= 1:
            thesis_parts.append(f"Thesis: MODERATE setup with {len(confirms)} confirmation(s)")
        else:
            thesis_parts.append("Thesis: WEAK setup - limited confirmation")
        
        # Warning narrative
        if warnings:
            warning_narrative = f"⚠️ Warnings: {', '.join(w.replace('_', ' ') for w in warnings[:3])}"
            thesis_parts.append(warning_narrative)
        
        # === ENTRY QUALITY ===
        quality_score = 0
        quality_score += len(confirms) * 15
        quality_score -= len(warnings) * 10
        quality_score += smart_money.get("entry_signal_score", 0) * 0.3
        quality_score += banker_flow.get("evidence_score", 0) * 0.2
        quality_score += max(0, hot_money.get("evidence_score", 0))
        
        if quality_score >= 70:
            entry_quality = "EXCELLENT"
        elif quality_score >= 50:
            entry_quality = "GOOD"
        elif quality_score >= 30:
            entry_quality = "FAIR"
        else:
            entry_quality = "POOR"
        
        # === EXIT THESIS ===
        exit_parts = []
        
        if smart_money.get("exit_warning"):
            exit_parts.append(f"Exit Signal: {smart_money['exit_warning']}")
        if hot_money.get("blow_off_top") and side == "BUY":
            exit_parts.append("Exit: Take profit on blow off")
        if hot_money.get("capitulation") and side == "SELL":
            exit_parts.append("Exit: Cover on capitulation")
        
        return {
            # Story elements
            "story": story_elements,
            "confirms": confirms,
            "warnings": warnings,
            
            # Thesis
            "thesis": thesis_parts,
            "entry_quality": entry_quality,
            "quality_score": quality_score,
            
            # Exit
            "exit_thesis": exit_parts,
            "early_exit_warning": len(warnings) > 2,
            
            # Alignment check
            "institutional_aligned": sm_direction == side,
            "banker_aligned": banker_signal and side == "BUY" and "ACCUMULATION" in banker_signal,
            "structure_aligned": structure.get("bos") or structure.get("mss"),
            "volume_aligned": volume.get("expansion", False),
            
            # Final recommendation
            "market_story": " ".join(story_elements),
            "trade_recommended": len(confirms) >= 2 and len(warnings) < 2,
        }
    
    @staticmethod
    def _default_story():
        return {
            "story": [],
            "confirms": [],
            "warnings": [],
            "thesis": ["Thesis: No data available"],
            "entry_quality": "UNKNOWN",
            "quality_score": 0.0,
            "exit_thesis": [],
            "early_exit_warning": False,
            "institutional_aligned": False,
            "banker_aligned": False,
            "structure_aligned": False,
            "volume_aligned": False,
            "market_story": "No story - insufficient data",
            "trade_recommended": False,
        }


# ========== ENTRY EVIDENCE PROVIDERS ==========
# Refactored from old bot's entry engines (v28)
# These are Evidence Providers ONLY - they never call execute_entry()
# UnifiedDecisionEngine is the ONLY Decision Authority

class EntryEvidence:
    """
    Standard evidence object returned by all entry evidence providers.
    
    Attributes:
        provider_name: Which evidence provider generated this
        score_contribution: 0-10 score from this provider
        confidence: HIGH/MEDIUM/LOW/NONE
        detected_setup: Type of setup detected (if any)
        institutional_confirmed: Whether institutional confirmation exists
        rf_confirmed: Whether RF alignment exists
        liquidity_confirmed: Whether liquidity confirmation exists
        timing_quality: EXCELLENT/GOOD/FAIR/POOR
        reasons: List of supporting reasons
        warnings: List of concerns
        explanation: Human-readable summary
    """
    
    CONFIDENCE_LEVELS = ["HIGH", "MEDIUM", "LOW", "NONE"]
    
    def __init__(
        self,
        provider_name: str,
        score_contribution: float = 0.0,
        confidence: str = "NONE",
        detected_setup: str = None,
        institutional_confirmed: bool = False,
        rf_confirmed: bool = False,
        liquidity_confirmed: bool = False,
        timing_quality: str = "POOR",
        reasons: List[str] = None,
        warnings: List[str] = None,
        explanation: str = ""
    ):
        self.provider_name = provider_name
        self.score_contribution = max(0, min(10, score_contribution))
        self.confidence = confidence if confidence in self.CONFIDENCE_LEVELS else "NONE"
        self.detected_setup = detected_setup
        self.institutional_confirmed = institutional_confirmed
        self.rf_confirmed = rf_confirmed
        self.liquidity_confirmed = liquidity_confirmed
        self.timing_quality = timing_quality
        self.reasons = reasons or []
        self.warnings = warnings or []
        self.explanation = explanation
    
    def to_dict(self) -> dict:
        return {
            "provider": self.provider_name,
            "score": self.score_contribution,
            "confidence": self.confidence,
            "setup": self.detected_setup,
            "institutional": self.institutional_confirmed,
            "rf": self.rf_confirmed,
            "liquidity": self.liquidity_confirmed,
            "timing": self.timing_quality,
            "reasons": self.reasons,
            "warnings": self.warnings,
            "explanation": self.explanation
        }
    
    def __repr__(self):
        return f"EntryEvidence({self.provider_name}, score={self.score_contribution:.1f}, conf={self.confidence})"


class EntryEvidenceAggregator:
    """
    Aggregates evidence from multiple providers for UnifiedDecisionEngine.
    """
    
    @staticmethod
    def aggregate(evidences: List[EntryEvidence]) -> dict:
        """Aggregate multiple evidences into a single decision-ready summary."""
        if not evidences:
            return {
                "total_score": 0,
                "max_confidence": "NONE",
                "all_setups": [],
                "institutional_count": 0,
                "rf_count": 0,
                "liquidity_count": 0,
                "timing_scores": [],
                "all_reasons": [],
                "all_warnings": [],
                "explanations": []
            }
        
        timing_map = {"EXCELLENT": 4, "GOOD": 3, "FAIR": 2, "POOR": 1}
        
        return {
            "total_score": sum(e.score_contribution for e in evidences),
            "max_confidence": max(e.confidence for e in evidences if e.confidence in EntryEvidence.CONFIDENCE_LEVELS),
            "all_setups": [e.detected_setup for e in evidences if e.detected_setup],
            "institutional_count": sum(1 for e in evidences if e.institutional_confirmed),
            "rf_count": sum(1 for e in evidences if e.rf_confirmed),
            "liquidity_count": sum(1 for e in evidences if e.liquidity_confirmed),
            "timing_scores": [timing_map.get(e.timing_quality, 1) for e in evidences],
            "all_reasons": [r for e in evidences for r in e.reasons],
            "all_warnings": [w for e in evidences for w in e.warnings],
            "explanations": [e.explanation for e in evidences if e.explanation]
        }


# ========== EVIDENCE PROVIDER FUNCTIONS ==========
# Each function provides evidence - NEVER calls execute_entry()

def provides_institutional_evidence(df, ob, atr, price, side) -> EntryEvidence:
    """
    Institutional Entry Evidence Provider.
    
    Refactored from check_institutional_entry() in old bot (v28).
    Provides evidence for institutional-grade entries with:
    - Liquidity sweep detection
    - Smart zones/OB/FVG validation
    - Structure shift confirmation
    - Candle rejection/displacement
    - Volume expansion
    - ADX with slope protection
    - RF alignment
    
    Args:
        df: DataFrame with OHLCV data
        ob: Orderbook data
        atr: ATR value
        price: Current price
        side: "BUY" or "SELL"
    
    Returns:
        EntryEvidence object with institutional confirmation details
    """
    reasons = []
    warnings = []
    score = 0
    institutional_confirmed = False
    rf_confirmed = False
    liquidity_confirmed = False
    timing_quality = "POOR"
    detected_setup = None
    
    # 1. Liquidity Sweep Detection
    pools = build_liquidity_pools(df)
    swept_high, swept_low = detect_sweep(df, pools)
    sweep_ok = (side == "BUY" and swept_low) or (side == "SELL" and swept_high)
    
    if sweep_ok:
        score += 2
        reasons.append("Liquidity sweep detected")
        liquidity_confirmed = True
    else:
        warnings.append("No liquidity sweep")
    
    # 2. Smart Zones / OB / FVG Validation
    zones = get_smart_zones(df.symbol if hasattr(df, 'symbol') else "unknown", df, ob)
    zone_ok = False
    zone_price = None
    
    if side == "BUY" and zones["buy_zones"]:
        if zones["buy_zones"][0]["strength"] >= 5:
            zone_price = zones["buy_zones"][0]["price"]
            if abs(price - zone_price) / price < 0.003:
                zone_ok = True
                reasons.append(f"Buy zone {zone_price:.4f} (strength {zones['buy_zones'][0]['strength']})")
    elif side == "SELL" and zones["sell_zones"]:
        if zones["sell_zones"][0]["strength"] >= 5:
            zone_price = zones["sell_zones"][0]["price"]
            if abs(price - zone_price) / price < 0.003:
                zone_ok = True
                reasons.append(f"Sell zone {zone_price:.4f} (strength {zones['sell_zones'][0]['strength']})")
    
    # Fallback to FVG
    if not zone_ok:
        fvg = detect_fvg(df)
        if fvg:
            if side == "BUY" and fvg[0] == "bullish" and price >= fvg[1] and price <= fvg[2]:
                zone_ok = True
                reasons.append("Bullish FVG")
            elif side == "SELL" and fvg[0] == "bearish" and price >= fvg[1] and price <= fvg[2]:
                zone_ok = True
                reasons.append("Bearish FVG")
    
    # Fallback to Order Block
    if not zone_ok:
        ob_level = detect_order_block(df, side)
        if ob_level:
            if side == "BUY" and abs(price - ob_level["low"]) / price < 0.003:
                zone_ok = True
                reasons.append("Bullish OB")
            elif side == "SELL" and abs(price - ob_level["high"]) / price < 0.003:
                zone_ok = True
                reasons.append("Bearish OB")
    
    if not zone_ok:
        warnings.append("No strong zone tap")
    
    # 3. Structure Shift (MSS/CHoCH)
    struct_shift = detect_structure_shift(df)
    bos_up, bos_down = detect_bos(df)
    choch_ok = False
    
    if side == "BUY" and (struct_shift == "bullish_shift" or bos_up):
        choch_ok = True
        reasons.append("Bullish MSS/CHoCH")
        score += 1.5
    elif side == "SELL" and (struct_shift == "bearish_shift" or bos_down):
        choch_ok = True
        reasons.append("Bearish MSS/CHoCH")
        score += 1.5
    
    # MSS required only if sweep detected (reversal trade)
    if sweep_ok and not choch_ok:
        warnings.append("Reversal requires MSS/CHoCH confirmation")
    
    # 4. Candle Rejection / Displacement
    rejection_ok = candle_rejection(df, side)
    vol_state = classify_volume(df)
    displacement_ok = detect_displacement(df, side, atr, vol_state, body_atr_threshold=0.8, volume_expansion_required=False)
    
    if rejection_ok or displacement_ok:
        score += 1.5
        if rejection_ok:
            reasons.append("Rejection candle")
        if displacement_ok:
            reasons.append("Displacement confirmed")
    else:
        warnings.append("No rejection/displacement candle")
    
    # 5. Volume Expansion
    if vol_state in ("expansion", "spike"):
        score += 1
        reasons.append(f"Volume {vol_state}")
    else:
        warnings.append("No volume expansion")
    
    # 6. ADX with Slope Protection
    adx_series = compute_adx(df)
    if len(adx_series) >= 3:
        adx_now = adx_series.iloc[-1]
        adx_prev = adx_series.iloc[-2]
        adx_slope = adx_now - adx_prev
        plus_di, minus_di, _, _ = get_di_components(df)
        di_spread = (plus_di - minus_di) if side == "BUY" else (minus_di - plus_di)
        
        if adx_now < 18:
            warnings.append(f"ADX too low ({adx_now:.1f})")
        elif adx_now > 50:
            if adx_slope > 0 and di_spread > 8:
                score += 1
                reasons.append(f"Strong trend ADX={adx_now:.1f} slope={adx_slope:.1f} DI_spread={di_spread:.1f}")
            else:
                warnings.append(f"Exhaustion risk: ADX>50 but slope={adx_slope:.1f} DI_spread={di_spread:.1f}")
        elif adx_now > 35:
            if adx_slope > 0:
                score += 0.5
                reasons.append(f"Strong trend ADX={adx_now:.1f} slope={adx_slope:.1f}")
            else:
                warnings.append(f"ADX high but falling slope ({adx_now:.1f} slope={adx_slope:.1f})")
        else:
            if adx_slope > 0:
                reasons.append(f"Healthy ADX={adx_now:.1f} rising")
            else:
                warnings.append(f"ADX not rising ({adx_now:.1f} slope={adx_slope:.1f})")
    
    # 7. RF Alignment
    rf = RFEngine(20, 3.5).compute(df)
    rf_match = rf["signal"] == side if rf["signal"] else False
    rf_close = abs(rf["distance"]) < 0.003 if rf["distance"] else False
    
    if rf_match and rf_close:
        score += 2
        reasons.append("RF aligned")
        rf_confirmed = True
    elif rf_match:
        warnings.append(f"RF distance {rf.get('distance', 0):.4f} too far")
    else:
        warnings.append(f"RF signal {rf.get('signal', 'None')} does not match {side}")
    
    # 8. Timing Quality
    if zone_price:
        move_from_zone = abs(price - zone_price) / zone_price * 100
        if move_from_zone <= 0.2:
            timing_quality = "EXCELLENT"
            score += 1
        elif move_from_zone <= 0.5:
            timing_quality = "GOOD"
        else:
            timing_quality = "FAIR"
            warnings.append(f"Price moved {move_from_zone:.2f}% from zone")
    
    # Late candle check
    last_candle = df.iloc[-1]
    candle_range_pct = (last_candle['high'] - last_candle['low']) / last_candle['close'] * 100
    atr_pct = atr / price * 100
    if candle_range_pct > 1.5 * atr_pct:
        warnings.append("Large displacement candle already occurred, too late")
        timing_quality = "POOR"
    
    # Determine confidence
    if sweep_ok and zone_ok and choch_ok and (rejection_ok or displacement_ok) and vol_state in ("expansion", "spike"):
        confidence = "HIGH"
        detected_setup = "INSTITUTIONAL_SNIPER"
        institutional_confirmed = True
    elif sweep_ok and zone_ok and (rejection_ok or displacement_ok):
        confidence = "MEDIUM"
        detected_setup = "INSTITUTIONAL_EARLY"
    elif zone_ok and (rejection_ok or displacement_ok):
        confidence = "LOW"
        detected_setup = "ZONE_ENTRY"
    else:
        confidence = "NONE"
        detected_setup = None
    
    explanation = f"Institutional entry evidence: {', '.join(reasons) if reasons else 'No confirmation'}"
    
    return EntryEvidence(
        provider_name="check_institutional_entry",
        score_contribution=score,
        confidence=confidence,
        detected_setup=detected_setup,
        institutional_confirmed=institutional_confirmed,
        rf_confirmed=rf_confirmed,
        liquidity_confirmed=liquidity_confirmed,
        timing_quality=timing_quality,
        reasons=reasons,
        warnings=warnings,
        explanation=explanation
    )


def provides_smart_evidence(df, ob, symbol) -> EntryEvidence:
    """
    Smart Decision Evidence Provider.
    
    Refactored from smart_decision() in old bot (v28).
    Provides evidence for smart money entries with:
    - Stop hunt detection
    - Exhaustion zone detection
    - Reset confirmation
    
    Args:
        df: DataFrame with OHLCV data
        ob: Orderbook data
        symbol: Trading symbol
    
    Returns:
        EntryEvidence object with smart money confirmation details
    """
    reasons = []
    warnings = []
    score = 0
    institutional_confirmed = False
    liquidity_confirmed = False
    timing_quality = "POOR"
    detected_setup = None
    
    mode = choose_mode(df)
    is_hunt, hunt_side = detect_stop_hunt(df)
    
    if is_hunt and hunt_side:
        score += 3
        reasons.append(f"Stop hunt detected ({hunt_side})")
        reasons.append(f"Mode: {mode}")
        detected_setup = "STOP_HUNT"
        institutional_confirmed = True
        timing_quality = "GOOD"
    
    is_zone, zone_price, zone_type = detect_exhaustion_zone(df)
    
    if is_zone and zone_price is not None:
        STATE["zone"][symbol] = (zone_price, zone_type)
    
    if symbol in STATE["zone"]:
        zone_price, zone_type = STATE["zone"][symbol]
        if detect_reset(df, zone_price, zone_type) and confirm_reversal(df, ob, zone_type):
            side = "SELL" if zone_type == "TOP" else "BUY"
            score += 3
            reasons.append(f"Exhaustion zone reset confirmed")
            reasons.append(f"Zone: {zone_type} at {zone_price:.4f}")
            detected_setup = "EXHAUSTION_ENTRY"
            institutional_confirmed = True
            timing_quality = "GOOD"
    
    if not detected_setup:
        confidence = "NONE"
        warnings.append("No smart money setup detected")
    elif score >= 5:
        confidence = "HIGH"
    elif score >= 3:
        confidence = "MEDIUM"
    else:
        confidence = "LOW"
    
    explanation = f"Smart money evidence: {', '.join(reasons) if reasons else 'No smart setup'}"
    
    return EntryEvidence(
        provider_name="smart_decision",
        score_contribution=score,
        confidence=confidence,
        detected_setup=detected_setup,
        institutional_confirmed=institutional_confirmed,
        liquidity_confirmed=liquidity_confirmed,
        timing_quality=timing_quality,
        reasons=reasons,
        warnings=warnings,
        explanation=explanation
    )


def provides_early_evidence(df, ob, atr, side) -> EntryEvidence:
    """
    Early Entry Evidence Provider.
    
    Refactored from early_score() in old bot (v28).
    Provides early entry evidence with:
    - MACD flip detection
    - Volume pressure analysis
    - Flow detection
    - Orderbook imbalance
    - Wall detection
    - Late move penalty
    
    Args:
        df: DataFrame with OHLCV data
        ob: Orderbook data
        atr: ATR value
        side: "BUY" or "SELL"
    
    Returns:
        EntryEvidence object with early entry details
    """
    reasons = []
    warnings = []
    score = 0
    institutional_confirmed = False
    timing_quality = "POOR"
    detected_setup = None
    
    # 1. MACD Flip
    macd, signal, hist = compute_macd(df)
    if macd_first_flip(hist):
        score += 2
        reasons.append("MACD flip")
    
    # 2. Volume Pressure
    if volume_pressure_real(df):
        score += 2
        reasons.append("Volume pressure")
        institutional_confirmed = True
    
    # 3. Flow Detection
    flow = flow_engine(df)
    if side == "BUY" and flow == "aggressive_buy":
        score += 2
        reasons.append("Aggressive buy flow")
        institutional_confirmed = True
    elif side == "SELL" and flow == "aggressive_sell":
        score += 2
        reasons.append("Aggressive sell flow")
        institutional_confirmed = True
    elif flow == "absorption":
        reasons.append("Absorption detected")
        institutional_confirmed = True
    
    # 4. Orderbook Imbalance
    obi = orderbook_imbalance(ob, depth=10)
    if side == "BUY" and obi > 0.2:
        score += 2
        reasons.append(f"OBI bullish ({obi:.2f})")
    elif side == "SELL" and obi < -0.2:
        score += 2
        reasons.append(f"OBI bearish ({obi:.2f})")
    
    # 5. Wall Detection
    bid_wall, ask_wall = detect_walls(ob, depth=10, threshold=3.0)
    if side == "BUY" and bid_wall:
        score += 1
        reasons.append("Bid wall")
    elif side == "SELL" and ask_wall:
        score += 1
        reasons.append("Ask wall")
    
    # 6. Late Move Penalty
    if is_late_move(df, atr, multiplier=1.5):
        score -= 3
        warnings.append("Late move penalty")
        timing_quality = "POOR"
    elif score >= 4:
        timing_quality = "EXCELLENT"
    elif score >= 2:
        timing_quality = "GOOD"
    
    # Determine confidence and setup
    if score >= 6:
        confidence = "HIGH"
        detected_setup = "EARLY_SNIPER"
    elif score >= 4:
        confidence = "MEDIUM"
        detected_setup = "EARLY_ENTRY"
    elif score >= 2:
        confidence = "LOW"
        detected_setup = "EARLY_SIGNAL"
    else:
        confidence = "NONE"
    
    explanation = f"Early entry evidence: {', '.join(reasons) if reasons else 'No early setup'}"
    
    return EntryEvidence(
        provider_name="early_score",
        score_contribution=max(0, score),
        confidence=confidence,
        detected_setup=detected_setup,
        institutional_confirmed=institutional_confirmed,
        timing_quality=timing_quality,
        reasons=reasons,
        warnings=warnings,
        explanation=explanation
    )


def provides_decision_evidence(df, ob, atr, side) -> Tuple[EntryEvidence, EntryEvidence]:
    """
    Decision Score Evidence Provider (Dual return).
    
    Refactored from decision_score() and decision_score_v1() in old bot (v28).
    Provides unified decision evidence combining:
    - early_score components
    - scenario detection
    - RF signal integration
    
    Returns tuple of (decision_v1_evidence, decision_evidence):
    - v1: Higher threshold (>= 5)
    - standard: Lower threshold (>= 7 OR >= 5)
    
    Args:
        df: DataFrame with OHLCV data
        ob: Orderbook data
        atr: ATR value
        side: "BUY" or "SELL"
    
    Returns:
        Tuple of EntryEvidence objects
    """
    reasons = []
    warnings = []
    score = 0
    institutional_confirmed = False
    rf_confirmed = False
    timing_quality = "POOR"
    
    # Get early score components
    es, early_reasons = early_score(df, ob, atr, side)
    score += es
    reasons.extend(early_reasons)
    
    # Get scenario
    vol_state = classify_volume(df)
    scenario = advanced_detect_scenario(df, side, atr, vol_state)
    
    # Scenario bonuses
    if scenario == "TRAP_REVERSAL":
        score += 3
        reasons.append(f"Trap Reversal scenario")
        institutional_confirmed = True
    elif scenario == "TREND_CONTINUATION":
        score += 2
        reasons.append(f"Trend Continuation scenario")
    
    # RF confirmation
    rf = RFEngine(20, 3.5).compute(df)
    if rf["signal"] == side and abs(rf["distance"]) < 0.003:
        rf_confirmed = True
        reasons.append("RF aligned")
    
    # Timing
    if score >= 7:
        timing_quality = "EXCELLENT"
    elif score >= 5:
        timing_quality = "GOOD"
    elif score >= 3:
        timing_quality = "FAIR"
    
    # Determine confidence and setup
    if score >= 7:
        confidence = "HIGH"
        detected_setup = "UNIFIED_SNIPER"
    elif score >= 5:
        confidence = "MEDIUM"
        detected_setup = "UNIFIED_EARLY"
    else:
        confidence = "LOW"
        detected_setup = None
    
    # Create evidence for decision_score_v1 (threshold 5)
    evidence_v1 = EntryEvidence(
        provider_name="decision_score_v1",
        score_contribution=min(score, 10),
        confidence=confidence,
        detected_setup=detected_setup if score >= 5 else None,
        institutional_confirmed=institutional_confirmed,
        rf_confirmed=rf_confirmed,
        timing_quality=timing_quality,
        reasons=reasons.copy(),
        warnings=warnings.copy(),
        explanation=f"Decision v1 evidence: score={min(score, 10)}, scenario={scenario}"
    )
    
    # Create evidence for decision_score (threshold 7)
    evidence_standard = EntryEvidence(
        provider_name="decision_score",
        score_contribution=min(score, 10),
        confidence=confidence,
        detected_setup=detected_setup if score >= 7 else None,
        institutional_confirmed=institutional_confirmed,
        rf_confirmed=rf_confirmed,
        timing_quality=timing_quality,
        reasons=reasons.copy(),
        warnings=warnings.copy(),
        explanation=f"Decision evidence: score={min(score, 10)}, scenario={scenario}"
    )
    
    return evidence_v1, evidence_standard


def provides_advanced_evidence(df, side, atr, adx, volume_state, location) -> EntryEvidence:
    """
    Advanced Decision Evidence Provider.
    
    Refactored from advanced_decision_engine() in old bot (v28).
    Provides advanced evidence with:
    - Scenario detection
    - ADX validation
    - Volume state check
    - Location awareness
    
    Args:
        df: DataFrame with OHLCV data
        side: "BUY" or "SELL"
        atr: ATR value
        adx: ADX value
        volume_state: Current volume state
        location: "LOW", "HIGH", or "MIDDLE"
    
    Returns:
        EntryEvidence object with advanced decision details
    """
    reasons = []
    warnings = []
    score = 0
    institutional_confirmed = False
    timing_quality = "POOR"
    detected_setup = None
    
    # Get scenario
    scenario = advanced_detect_scenario(df, side, atr, volume_state)
    
    if scenario == "NONE":
        warnings.append("No scenario detected")
        confidence = "NONE"
        return EntryEvidence(
            provider_name="advanced_decision_engine",
            score_contribution=0,
            confidence="NONE",
            detected_setup=None,
            institutional_confirmed=False,
            timing_quality="POOR",
            reasons=[],
            warnings=["No advanced scenario"],
            explanation="No advanced scenario detected"
        )
    
    # Volume exhaustion check
    if volume_state == "exhaustion":
        warnings.append("Volume exhaustion - SKIP")
        confidence = "NONE"
        return EntryEvidence(
            provider_name="advanced_decision_engine",
            score_contribution=0,
            confidence="NONE",
            detected_setup=None,
            institutional_confirmed=False,
            timing_quality="POOR",
            reasons=[],
            warnings=["Volume exhaustion"],
            explanation="Volume exhaustion scenario"
        )
    
    # ADX validation
    adx = float(adx) if adx is not None else 20.0
    
    if adx < 18:
        warnings.append(f"ADX too low ({adx:.1f})")
        confidence = "NONE"
        return EntryEvidence(
            provider_name="advanced_decision_engine",
            score_contribution=0,
            confidence="NONE",
            detected_setup=None,
            institutional_confirmed=False,
            timing_quality="POOR",
            reasons=[],
            warnings=[f"ADX too low ({adx:.1f})"],
            explanation=f"ADX too low: {adx:.1f}"
        )
    
    # Scenario-specific logic
    if scenario == "TRAP_REVERSAL":
        if adx < 35:
            score += 3
            reasons.append(f"Trap Reversal with healthy ADX ({adx:.1f})")
            confidence = "HIGH"
            detected_setup = "SMC_ADV_TRAP"
            institutional_confirmed = True
            timing_quality = "GOOD"
        else:
            warnings.append(f"Trap Reversal but ADX >= 35 ({adx:.1f})")
            confidence = "NONE"
    
    elif scenario == "TREND_CONTINUATION":
        if 20 < adx < 45:
            score += 2
            reasons.append(f"Trend Continuation with ADX {adx:.1f}")
            confidence = "MEDIUM"
            detected_setup = "SMC_ADV_TREND"
            timing_quality = "GOOD"
        else:
            warnings.append(f"Trend Continuation but ADX out of range (20-45): {adx:.1f}")
            confidence = "NONE"
    
    else:
        warnings.append(f"Unknown scenario: {scenario}")
        confidence = "NONE"
    
    explanation = f"Advanced evidence: scenario={scenario}, score={score}, ADX={adx:.1f}"
    
    return EntryEvidence(
        provider_name="advanced_decision_engine",
        score_contribution=max(0, score),
        confidence=confidence,
        detected_setup=detected_setup,
        institutional_confirmed=institutional_confirmed,
        timing_quality=timing_quality,
        reasons=reasons,
        warnings=warnings,
        explanation=explanation
    )


def collect_all_evidence(df, ob, atr, price, side, symbol=None, location="MIDDLE") -> List[EntryEvidence]:
    """
    Collect evidence from all entry providers.
    
    This is the main entry point for evidence collection.
    Call this function to get comprehensive evidence from all providers.
    
    Args:
        df: DataFrame with OHLCV data
        ob: Orderbook data
        atr: ATR value
        price: Current price
        side: "BUY" or "SELL"
        symbol: Optional trading symbol
        location: "LOW", "HIGH", or "MIDDLE"
    
    Returns:
        List of EntryEvidence objects from all providers
    """
    evidences = []
    
    # 1. Institutional Evidence
    try:
        inst_evidence = provides_institutional_evidence(df, ob, atr, price, side)
        evidences.append(inst_evidence)
    except Exception as e:
        log_execution(f"[EVIDENCE] check_institutional_entry failed: {e}", "WARN")
    
    # 2. Smart Decision Evidence
    try:
        smart_evidence = provides_smart_evidence(df, ob, symbol or "unknown")
        evidences.append(smart_evidence)
    except Exception as e:
        log_execution(f"[EVIDENCE] smart_decision failed: {e}", "WARN")
    
    # 3. Early Evidence
    try:
        early_evidence = provides_early_evidence(df, ob, atr, side)
        evidences.append(early_evidence)
    except Exception as e:
        log_execution(f"[EVIDENCE] early_score failed: {e}", "WARN")
    
    # 4. Decision Evidence
    try:
        vol_state = classify_volume(df)
        dec_v1, dec_std = provides_decision_evidence(df, ob, atr, side)
        evidences.append(dec_v1)
        evidences.append(dec_std)
    except Exception as e:
        log_execution(f"[EVIDENCE] decision_score failed: {e}", "WARN")
    
    # 5. Advanced Evidence
    try:
        adx_series = compute_adx(df)
        adx_val = adx_series.iloc[-1] if adx_series is not None else 20.0
        adv_evidence = provides_advanced_evidence(df, side, atr, adx_val, vol_state, location)
        evidences.append(adv_evidence)
    except Exception as e:
        log_execution(f"[EVIDENCE] advanced_decision_engine failed: {e}", "WARN")
    
    return evidences


# ========== TRADE STATE MACHINE ==========
class TradeStateMachine:
    STATES = {
        "ACCUMULATION": 0,
        "EXPANSION": 1,
        "TREND_RIDE": 2,
        "DISTRIBUTION": 3,
        "EXHAUSTION": 4,
        "FAKE_BREAKOUT": 5,
        "MOMENTUM_COLLAPSE": 6,
        "PANIC_EXIT": 7,
        "RANGE_CHOP": 8,
        "HEALTHY_PULLBACK": 9,
        "PROFIT_DEFENSE": 10,
        "LIQUIDITY_EXHAUSTION": 11
    }

    def __init__(self):
        self.current_state = "RANGE_CHOP"
        self.last_state_change = 0
        self.state_confidence = 0.0

    def update(self, smart: dict, momentum: dict, adx: float, regime: str) -> str:
        banker = smart.get("banker_pressure", 50)
        retail = smart.get("retailer_pressure", 50)
        dist_risk = smart.get("distribution_risk", 0)
        accum = smart.get("accumulation_strength", 0)
        mom_health = momentum.get("momentum_health", 50)
        cont_strength = momentum.get("continuation_strength", 50)
        exh_risk = momentum.get("exhaustion_risk", 0)
        climax = momentum.get("climax_risk", 0)
        expansion = momentum.get("trend_expansion", False)
        decay = momentum.get("momentum_decay", False)
        bias_detailed = smart.get("institutional_bias_detailed", "NEUTRAL")

        # PANIC_EXIT
        if (bias_detailed in ("STRONG_SELL", "STRONG_BUY") and
            dist_risk > 75 and mom_health < 15 and cont_strength < 20):
            new_state = "PANIC_EXIT"
        # MOMENTUM_COLLAPSE
        elif mom_health < 15 and cont_strength < 25 and decay:
            new_state = "MOMENTUM_COLLAPSE"
        # LIQUIDITY_EXHAUSTION
        elif exh_risk > 70 or climax > 75:
            new_state = "LIQUIDITY_EXHAUSTION"
        # PROFIT_DEFENSE
        elif dist_risk > 50 and banker < 45 and mom_health < 30:
            new_state = "PROFIT_DEFENSE"
        # DISTRIBUTION
        elif dist_risk > 60 and banker < 45:
            new_state = "DISTRIBUTION"
        # ACCUMULATION
        elif banker > 65 and dist_risk < 25 and mom_health > 40:
            new_state = "ACCUMULATION"
        # EXPANSION
        elif adx > 30 and expansion and cont_strength > 60 and mom_health > 50:
            new_state = "EXPANSION"
        # TREND_RIDE
        elif cont_strength > 75 and mom_health > 60 and dist_risk < 30:
            new_state = "TREND_RIDE"
        # HEALTHY_PULLBACK
        elif 20 <= adx <= 35 and mom_health > 45 and not expansion and not decay and dist_risk < 40:
            new_state = "HEALTHY_PULLBACK"
        # FAKE_BREAKOUT
        elif retail > 70 and banker < 45 and climax > 60:
            new_state = "FAKE_BREAKOUT"
        # RANGE_CHOP
        elif adx < 22 or regime in ("CHOPPY", "COMPRESSION"):
            new_state = "RANGE_CHOP"
        else:
            new_state = self.current_state

        if new_state != self.current_state:
            self.last_state_change = time.time()
            self.state_confidence = 0.5
            log_execution(f"[STATE] {self.current_state} -> {new_state}", "INFO")
        else:
            self.state_confidence = min(1.0, self.state_confidence + 0.05)

        self.current_state = new_state
        return new_state

    def get_trail_multiplier(self) -> float:
        mult_map = {
            "ACCUMULATION": 3.0,
            "EXPANSION": 3.5,
            "TREND_RIDE": 4.0,
            "HEALTHY_PULLBACK": 2.8,
            "PROFIT_DEFENSE": 1.2,
            "DISTRIBUTION": 1.2,
            "EXHAUSTION": 1.0,
            "LIQUIDITY_EXHAUSTION": 0.8,
            "FAKE_BREAKOUT": 0.8,
            "MOMENTUM_COLLAPSE": 0.6,
            "PANIC_EXIT": 0.5,
            "RANGE_CHOP": 1.5
        }
        return mult_map.get(self.current_state, 1.5)

    def should_delay_tp1(self) -> bool:
        return self.current_state in ("ACCUMULATION", "EXPANSION", "TREND_RIDE", "HEALTHY_PULLBACK")

    def should_aggressive_profit_lock(self) -> bool:
        return self.current_state in ("EXHAUSTION", "DISTRIBUTION", "MOMENTUM_COLLAPSE", "PROFIT_DEFENSE", "LIQUIDITY_EXHAUSTION")

    def should_hard_exit(self) -> bool:
        return self.current_state in ("PANIC_EXIT", "MOMENTUM_COLLAPSE", "LIQUIDITY_EXHAUSTION")

    def get_patience_level(self) -> str:
        if self.current_state in ("ACCUMULATION", "EXPANSION", "TREND_RIDE", "HEALTHY_PULLBACK"):
            return "HIGH"
        elif self.current_state in ("DISTRIBUTION", "EXHAUSTION", "PROFIT_DEFENSE"):
            return "LOW"
        else:
            return "MEDIUM"


# ========== ENHANCED TRADE MEMORY ENGINE ==========
class TradeMemory:
    """
    EnhancedTradeMemory - Single Source of Truth لإدارة ذاكرة الصفقات.
    
    جميع البيانات المطلوبة:
    - Entry Reason, Trade Type, Trend/Reversal, Entry Thesis
    - Current Phase, Management Mode, Highest/Lowest Price
    - Highest ROE, Highest PnL (Unrealized/Realized)
    - Entry Time, Last/Previous Decision, Decision History
    - Recommendation History, Trade Story
    - Pullback/Retest/BOS/CHoCH/Rejection History
    - Smart Money/Banker/Hot Money/Momentum/ATR/ADX History
    - Verified Leverage, Verification Time
    """
    _instance = None

    def __new__(cls):
        if cls._instance is None:
            cls._instance = super().__new__(cls)
            cls._instance._initialized = False
        return cls._instance

    def __init__(self):
        if self._initialized:
            return
        self._initialized = True
        self._lock = threading.Lock()
        self.open_trades: Dict[str, dict] = {}
        self.closed_trades: List[dict] = []
        self.performance_history: List[dict] = []
        self._max_closed_history = 500
        self._init_from_global_state()

    def _create_empty_trade_state(self) -> dict:
        """إنشاء هيكل فارغ للصفقة."""
        return {
            # الأساسية
            "symbol": None, "side": None, "entry": 0.0, "qty": 0.0, "entry_time": 0.0,
            "mark_price": 0.0, "roe_pct": 0.0, "unrealized_pnl": 0.0, "margin": 0.0,
            # نوع الصفقة
            "trade_type": None,  # TREND, REVERSAL
            "trade_subtype": None,  # BREAKOUT, PULLBACK, etc.
            "entry_reason": None,  # سبب الدخول
            "entry_thesis": {},  # Thesis الدخول
            "narrative_classification": None,
            # Phase & Mode
            "trade_state": "ACCUMULATION",  # ACCUMULATION, EXPANSION, TREND_RIDE, etc.
            "current_phase": None,  # Phase الحالية
            "management_mode": None,  # NORMAL, AGGRESSIVE, CONSERVATIVE
            # الأسعار
            "highest_price": 0.0, "lowest_price": float('inf'),
            "highest_roe": 0.0, "highest_unrealized_pnl": 0.0, "highest_realized_pnl": 0.0,
            "sl": 0.0, "tp1": 0.0, "tp2": 0.0,
            "synthetic_sl": 0.0, "synthetic_tp1": 0.0, "synthetic_tp2": 0.0,
            # التنفيذ
            "tp1_hit": False, "tp2_hit": False, "trail_active": False, "trail_stop": 0.0,
            "trail_mult": 1.5, "runner_mode": False, "profit_lock_activated": False,
            "be_done": False, "partial_closed": False,
            # القرارات
            "last_decision": None, "previous_decision": None,
            "decision_history": [],  # [{"time": ts, "decision": str, "reason": str}]
            "recommendation_history": [],  # [{"time": ts, "rec": str, "score": float}]
            "current_recommendation": None, "recommendation_score": 0.0,
            # القصة
            "trade_story": [],  # [{"time": ts, "event": str, "data": dict}]
            #counters
            "pullback_count": 0, "retest_count": 0, "failed_retest_count": 0,
            "bos_history": [],  # [{"time": ts, "type": "bullish/bearish", "price": float}]
            "choch_history": [],  # [{"time": ts, "type": "bullish_shift/bearish_shift", "price": float}]
            "rejection_history": [],  # [{"time": ts, "type": "strong/weak", "price": float}]
            # المؤشرات
            "smart_money_history": [],  # [{"time": ts, "data": dict}]
            "banker_history": [],  # [{"time": ts, "pressure": float}]
            "hot_money_history": [],  # [{"time": ts, "pressure": float}]
            "momentum_history": [],  # [{"time": ts, "data": dict}]
            "atr_history": [],  # [{"time": ts, "value": float}]
            "adx_history": [],  # [{"time": ts, "value": float, "slope": float}]
            # الرافعة
            "verified_leverage": None, "leverage_verified_at": None,
            # الحالة الحالية
            "smart_money": {}, "momentum_flow": {},
            "continuation_probability": 50.0, "hold_quality": 5,
            "counter_pressure": 0, "reclaim_risk": 0.0,
            "trend_strength": 50.0, "exhaustion_probability": 0.0,
            "adx": 20.0, "adx_slope": 0.0, "plus_di": 20.0, "minus_di": 20.0,
            "volume_ratio": 1.0, "market_regime": "UNKNOWN",
            "current_confidence": 50.0, "thesis_failure_score": 0.0,
            # Institutional Context Fields
            "zone_type": None,          # "demand" | "supply"
            "zone_state": None,         # ZoneLifecycleState enum value
            "zone_score": 0.0,         # Dynamic zone score
            "zone_price": 0.0,         # Zone level at entry
            "structure_state": None,    # StructureState enum value
            "structure_key": None,     # "HH" | "HL" | "LH" | "LL" | "BOS" | "CHoCH"
            "institutional_bias": None, # "LONG" | "SHORT" | "NEUTRAL"
            "adx_override_used": False,# ADX override flag
            "adx_value_at_entry": 0.0, # ADX value when entering
            "context_history": [],      # List of context snapshots
        }

    def _init_from_global_state(self):
        """تهيئة من الحالة العالمية STATE."""
        # تأكد أن STATE موجود في globals قبل استخدامه
        _globals = globals()
        if 'STATE' not in _globals:
            return
        
        _state = _globals.get('STATE', {})
        if _state.get("open") and _state.get("current_symbol"):
            symbol = _state["current_symbol"]
            trade = self._create_empty_trade_state()
            trade.update({
                "symbol": symbol,
                "side": _state.get("side"),
                "entry": _state.get("entry", 0.0),
                "qty": _state.get("qty", 0.0),
                "entry_time": _state.get("entry_time", time.time()),
                "mark_price": _state.get("mark_price", 0.0),
                "roe_pct": _state.get("roe_pct", 0.0),
                "unrealized_pnl": _state.get("unrealized_pnl_usdt", 0.0),
                "margin": _state.get("margin", 0.0),
                "trade_type": _state.get("trade_type"),
                "entry_reason": _state.get("entry_reason", _state.get("reason")),
                "entry_thesis": _state.get("trade_thesis", {}),
                "narrative_classification": _state.get("narrative_classification"),
                "trade_state": _state.get("trade_state", "ACCUMULATION"),
                "sl": _state.get("sl", 0.0),
                "tp1": _state.get("tp1_price", 0.0),
                "tp2": _state.get("tp2_price", 0.0),
                "synthetic_sl": _state.get("synthetic_sl", 0.0),
                "synthetic_tp1": _state.get("synthetic_tp1", 0.0),
                "trail_active": _state.get("trail_activated", False),
                "trail_stop": _state.get("trail_stop", 0.0),
                "trail_mult": _state.get("smart_trail_mult", 1.5),
                "tp1_hit": _state.get("tp1_hit", False),
                "tp2_hit": _state.get("tp2_hit", False),
                "runner_mode": _state.get("runner_mode", False),
                "profit_lock_activated": _state.get("profit_lock_activated", False),
                "be_done": _state.get("be_done", False),
                "partial_closed": _state.get("partial_closed", False),
                "smart_money": _state.get("smart_money", {}),
                "momentum_flow": _state.get("momentum_flow", {}),
                "continuation_probability": _state.get("continuation_probability", 50.0),
                "hold_quality": _state.get("hold_quality", 5),
                "counter_pressure": _state.get("counter_pressure", 0),
                "reclaim_risk": _state.get("reclaim_risk", 0.0),
                "trend_strength": _state.get("trend_strength", 50.0),
                "adx": _state.get("adx_live", 20.0),
                "plus_di": _state.get("di_plus_live", 20.0),
                "minus_di": _state.get("di_minus_live", 20.0),
                "volume_ratio": _state.get("volume_ratio", 1.0),
                "market_regime": _state.get("market_regime", "UNKNOWN"),
                "current_confidence": _state.get("current_confidence", 50.0),
                "thesis_failure_score": _state.get("thesis_failure_score", 0.0),
                "verified_leverage": _state.get("verified_leverage", {}).get(symbol, {}).get("leverage"),
                "leverage_verified_at": _state.get("verified_leverage", {}).get(symbol, {}).get("timestamp"),
            })
            self.open_trades[symbol] = trade

    def add_open_trade(self, symbol: str, side: str, entry: float, qty: float, **kwargs):
        """إضافة صفقة مفتوحة جديدة."""
        with self._lock:
            trade = self._create_empty_trade_state()
            trade.update({
                "symbol": symbol, "side": side, "entry": entry, "qty": qty,
                "entry_time": kwargs.get("entry_time", time.time()),
                "mark_price": entry,
                "trade_type": kwargs.get("trade_type"),  # TREND, REVERSAL
                "trade_subtype": kwargs.get("trade_subtype"),
                "entry_reason": kwargs.get("entry_reason"),
                "entry_thesis": kwargs.get("entry_thesis", {}),
                "narrative_classification": kwargs.get("narrative_classification"),
                "highest_price": entry, "lowest_price": entry,
                "verified_leverage": kwargs.get("leverage", 10),
                "leverage_verified_at": time.time(),
                "sl": kwargs.get("sl", 0.0),
                "tp1": kwargs.get("tp1", 0.0),
                "tp2": kwargs.get("tp2", 0.0),
            })
            self.open_trades[symbol] = trade

    def update_open_trade(self, symbol: str, **updates):
        """تحديث بيانات صفقة مفتوحة."""
        with self._lock:
            if symbol in self.open_trades:
                trade = self.open_trades[symbol]
                # تحديث القيم الأساسية
                for key, value in updates.items():
                    trade[key] = value
                # تحديث الأسعار القصوى
                price = updates.get("mark_price", trade.get("mark_price"))
                if price:
                    trade["highest_price"] = max(trade["highest_price"], price)
                    trade["lowest_price"] = min(trade["lowest_price"], price)
                # تحديث ROE القصوى
                roe = updates.get("roe_pct", trade.get("roe_pct", 0))
                if roe:
                    trade["highest_roe"] = max(trade["highest_roe"], roe)
                pnl = updates.get("unrealized_pnl", trade.get("unrealized_pnl", 0))
                if pnl:
                    trade["highest_unrealized_pnl"] = max(trade["highest_unrealized_pnl"], pnl)
            elif STATE.get("open") and STATE.get("current_symbol") == symbol:
                self._init_from_global_state()

    def record_decision(self, symbol: str, decision: str, reason: str = ""):
        """تسجيل قرار."""
        with self._lock:
            if symbol in self.open_trades:
                trade = self.open_trades[symbol]
                trade["previous_decision"] = trade["last_decision"]
                trade["last_decision"] = decision
                trade["decision_history"].append({
                    "time": time.time(),
                    "decision": decision,
                    "reason": reason,
                    "roe_pct": trade.get("roe_pct", 0),
                    "price": trade.get("mark_price", 0)
                })
                # Limit history
                if len(trade["decision_history"]) > 100:
                    trade["decision_history"] = trade["decision_history"][-100:]

    def record_recommendation(self, symbol: str, recommendation: str, score: float):
        """تسجيل توصية."""
        with self._lock:
            if symbol in self.open_trades:
                trade = self.open_trades[symbol]
                trade["current_recommendation"] = recommendation
                trade["recommendation_score"] = score
                trade["recommendation_history"].append({
                    "time": time.time(),
                    "recommendation": recommendation,
                    "score": score,
                    "roe_pct": trade.get("roe_pct", 0)
                })
                if len(trade["recommendation_history"]) > 100:
                    trade["recommendation_history"] = trade["recommendation_history"][-100:]

    def record_event(self, symbol: str, event: str, data: dict = None):
        """تسجيل حدث في القصة."""
        with self._lock:
            if symbol in self.open_trades:
                trade = self.open_trades[symbol]
                trade["trade_story"].append({
                    "time": time.time(),
                    "event": event,
                    "data": data or {},
                    "roe_pct": trade.get("roe_pct", 0),
                    "price": trade.get("mark_price", 0)
                })
                if len(trade["trade_story"]) > 200:
                    trade["trade_story"] = trade["trade_story"][-200:]

    def record_indicator(self, symbol: str, indicator_type: str, data: dict):
        """تسجيل مؤشر في التاريخ."""
        with self._lock:
            if symbol not in self.open_trades:
                return
            trade = self.open_trades[symbol]
            entry = {"time": time.time(), "data": data}
            if indicator_type == "smart_money":
                trade["smart_money_history"].append(entry)
                trade["smart_money"] = data
                if "banker_pressure" in data:
                    trade["banker_history"].append({"time": time.time(), "pressure": data["banker_pressure"]})
                if "hot_money_pressure" in data:
                    trade["hot_money_history"].append({"time": time.time(), "pressure": data["hot_money_pressure"]})
            elif indicator_type == "momentum":
                trade["momentum_history"].append(entry)
                trade["momentum_flow"] = data
            elif indicator_type == "atr":
                trade["atr_history"].append(entry)
            elif indicator_type == "adx":
                trade["adx_history"].append(entry)
                trade["adx"] = data.get("value", 20.0)
                trade["adx_slope"] = data.get("slope", 0.0)
            # Limit history
            for key in ["smart_money_history", "momentum_history", "atr_history", "adx_history", "banker_history", "hot_money_history"]:
                if len(trade.get(key, [])) > 100:
                    trade[key] = trade[key][-100:]

    def record_structure_event(self, symbol: str, event_type: str, price: float, event_data: dict = None):
        """تسجيل حدث هيكل (BOS, CHoCH, Rejection)."""
        with self._lock:
            if symbol not in self.open_trades:
                return
            trade = self.open_trades[symbol]
            entry = {"time": time.time(), "price": price, "data": event_data or {}}
            if event_type in ("bullish_bos", "bearish_bos"):
                trade["bos_history"].append(entry)
            elif event_type in ("bullish_shift", "bearish_shift"):
                trade["choch_history"].append(entry)
            elif event_type in ("strong_rejection", "weak_rejection"):
                trade["rejection_history"].append(entry)
            elif event_type == "pullback":
                trade["pullback_count"] = trade.get("pullback_count", 0) + 1
            elif event_type == "retest":
                trade["retest_count"] = trade.get("retest_count", 0) + 1
            elif event_type == "failed_retest":
                trade["failed_retest_count"] = trade.get("failed_retest_count", 0) + 1

    def close_trade(self, symbol: str, pnl_pct: float, pnl_usdt: float, result: str, close_reason: str = "MANUAL"):
        """إغلاق صفقة ونقلها إلى السجل."""
        with self._lock:
            if symbol in self.open_trades:
                trade = self.open_trades.pop(symbol)
                close_time = time.time()
                trade.update({
                    "close_time": close_time,
                    "duration_minutes": (close_time - trade["entry_time"]) / 60,
                    "pnl_pct": pnl_pct,
                    "pnl_usdt": pnl_usdt,
                    "result": result,
                    "close_reason": close_reason,
                    "final_mark": STATE.get("mark_price", 0.0),
                    "final_roe": trade.get("roe_pct", 0),
                    "highest_roe_achieved": trade.get("highest_roe", 0),
                })
                self.closed_trades.append(trade)
                self.performance_history.append({
                    "timestamp": close_time,
                    "symbol": symbol,
                    "result": result,
                    "pnl_pct": pnl_pct,
                    "pnl_usdt": pnl_usdt,
                    "duration_minutes": trade["duration_minutes"],
                    "trade_type": trade.get("trade_type"),
                    "entry_reason": trade.get("entry_reason"),
                })
                if len(self.closed_trades) > self._max_closed_history:
                    self.closed_trades = self.closed_trades[-self._max_closed_history:]
                if len(self.performance_history) > self._max_closed_history:
                    self.performance_history = self.performance_history[-self._max_closed_history:]
                return trade
            return None

    def get_open_trade(self, symbol: str = None) -> Optional[dict]:
        """الحصول على صفقة مفتوحة."""
        with self._lock:
            if symbol:
                return self.open_trades.get(symbol)
            elif len(self.open_trades) == 1:
                return list(self.open_trades.values())[0]
            return None

    def get_trade_story(self, symbol: str) -> List[dict]:
        """الحصول على قصة الصفقة."""
        with self._lock:
            trade = self.open_trades.get(symbol)
            if trade:
                return trade.get("trade_story", [])
            return []

    def get_stats(self) -> dict:
        """الحصول على إحصائيات الصفقات."""
        with self._lock:
            total = len(self.closed_trades)
            wins = sum(1 for t in self.closed_trades if t.get("result") == "WIN")
            losses = sum(1 for t in self.closed_trades if t.get("result") == "LOSS")
            total_pnl = sum(t.get("pnl_pct", 0) for t in self.closed_trades)
            total_pnl_usdt = sum(t.get("pnl_usdt", 0) for t in self.closed_trades)
            avg_win = sum(t.get("pnl_pct", 0) for t in self.closed_trades if t.get("result") == "WIN") / wins if wins > 0 else 0
            avg_loss = sum(t.get("pnl_pct", 0) for t in self.closed_trades if t.get("result") == "LOSS") / losses if losses > 0 else 0
            best_trade = max((t.get("pnl_pct", 0) for t in self.closed_trades), default=0)
            worst_trade = min((t.get("pnl_pct", 0) for t in self.closed_trades), default=0)
            return {
                "total_trades": total, "wins": wins, "losses": losses,
                "winrate": (wins / total * 100) if total > 0 else 0,
                "total_pnl_pct": total_pnl, "total_pnl_usdt": total_pnl_usdt,
                "avg_win_pct": avg_win, "avg_loss_pct": avg_loss,
                "profit_factor": abs(avg_win / avg_loss) if avg_loss != 0 else 0,
                "best_trade": best_trade, "worst_trade": worst_trade,
                "open_trades_count": len(self.open_trades),
                "open_trades": list(self.open_trades.keys()),
            }

    def sync_from_global_state(self):
        """مزامنة TradeMemory من STATE العالمي."""
        with self._lock:
            if STATE.get("open") and STATE.get("current_symbol"):
                symbol = STATE["current_symbol"]
                if symbol not in self.open_trades:
                    self._init_from_global_state()
                else:
                    trade = self.open_trades[symbol]
                    trade.update({
                        "mark_price": STATE.get("mark_price", trade.get("mark_price")),
                        "roe_pct": STATE.get("roe_pct", 0.0),
                        "unrealized_pnl": STATE.get("unrealized_pnl_usdt", 0.0),
                        "trade_state": STATE.get("trade_state", trade.get("trade_state")),
                        "smart_money": STATE.get("smart_money", trade.get("smart_money", {})),
                        "momentum_flow": STATE.get("momentum_flow", trade.get("momentum_flow", {})),
                        "continuation_probability": STATE.get("continuation_probability", 50.0),
                        "hold_quality": STATE.get("hold_quality", 5),
                        "counter_pressure": STATE.get("counter_pressure", 0),
                    })
                    # Update max values
                    trade["highest_price"] = max(trade["highest_price"], trade.get("mark_price", 0))
                    trade["highest_roe"] = max(trade["highest_roe"], trade.get("roe_pct", 0))
                    trade["highest_unrealized_pnl"] = max(trade["highest_unrealized_pnl"], trade.get("unrealized_pnl", 0))
            else:
                if self.open_trades:
                    self.open_trades.clear()


# ========== ENHANCED CANDLE MEMORY ENGINE ==========
class CandleMemory:
    """
    EnhancedCandleMemory - Single Source of Truth لإدارة ذاكرة الشموع.
    
    الأحداث المكتشفة:
    - Healthy Pullback, Deep Pullback
    - Retest, Failed Retest
    - BOS, CHoCH
    - Strong Rejection, Weak Rejection
    - Liquidity Sweep, Failed Breakout
    - Compression, Expansion
    - Distribution, Trend Exhaustion
    """
    _instance = None
    _max_candles_since_entry = 30  # آخر 30 شمعة منذ فتح الصفقة

    def __new__(cls):
        if cls._instance is None:
            cls._instance = super().__new__(cls)
            cls._instance._initialized = False
        return cls._instance

    def __init__(self):
        if self._initialized:
            return
        self._initialized = True
        self._lock = threading.Lock()
        self._candle_history: Dict[str, pd.DataFrame] = {}
        self._entry_candles: Dict[str, pd.DataFrame] = {}  # الشموع منذ فتح الصفقة
        self._indicators_cache: Dict[str, dict] = {}
        self._events_cache: Dict[str, List[dict]] = {}  # الأحداث المكتشفة
        self._last_update: Dict[str, float] = {}

    def store_candles(self, symbol: str, df: pd.DataFrame, since_entry: bool = False):
        """تخزين الشموع."""
        with self._lock:
            if symbol in self._candle_history:
                existing = self._candle_history[symbol]
                if len(existing) > 0 and len(df) > 0:
                    last_ts = existing['timestamp'].iloc[-1] if 'timestamp' in existing.columns else 0
                    new_candles = df[df['timestamp'] > last_ts] if 'timestamp' in df.columns else df
                    if len(new_candles) > 0:
                        combined = pd.concat([existing, new_candles], ignore_index=True)
                        self._candle_history[symbol] = combined.tail(200)
                    else:
                        self._candle_history[symbol] = df.tail(200)
                else:
                    self._candle_history[symbol] = df.tail(200)
            else:
                self._candle_history[symbol] = df.tail(200)
            self._last_update[symbol] = time.time()

    def store_entry_candles(self, symbol: str, df: pd.DataFrame):
        """تخزين الشموع منذ فتح الصفقة (آخر 30 شمعة فقط)."""
        with self._lock:
            self._entry_candles[symbol] = df.tail(self._max_candles_since_entry)

    def get_candles(self, symbol: str) -> Optional[pd.DataFrame]:
        """الحصول على الشموع المخزنة."""
        with self._lock:
            return self._candle_history.get(symbol)

    def get_entry_candles(self, symbol: str) -> Optional[pd.DataFrame]:
        """الحصول على الشموع منذ فتح الصفقة."""
        with self._lock:
            return self._entry_candles.get(symbol)

    def detect_events(self, symbol: str) -> List[dict]:
        """اكتشاف الأحداث من الشموع."""
        with self._lock:
            df = self._entry_candles.get(symbol)
            if df is None or len(df) < 5:
                return []
            
            events = []
            for i in range(1, len(df)):
                candle = df.iloc[i]
                prev = df.iloc[i-1]
                event = self._detect_candle_event(candle, prev, df.iloc[:i], symbol)
                if event:
                    events.append(event)
            
            self._events_cache[symbol] = events
            return events

    def _detect_candle_event(self, candle, prev_candle, history, symbol) -> Optional[dict]:
        """اكتشاف حدث واحد من شمعة."""
        event_time = candle.get('timestamp', time.time())
        high, low, close, open_price = candle.get('high', 0), candle.get('low', 0), candle.get('close', 0), candle.get('open', 0)
        prev_high, prev_low = prev_candle.get('high', 0), prev_candle.get('low', 0)
        
        body = abs(close - open_price)
        upper_wick = high - max(close, open_price)
        lower_wick = min(close, open_price) - low
        is_bullish = close > open_price
        
        # ATR للـ timeframe
        atr = 0.002 * close  # تقدير
        
        event = None
        
        # 1. Pullback Detection
        if len(history) >= 5:
            recent_highs = [h.get('high', 0) for h in history.tail(5)]
            recent_lows = [l.get('low', 0) for l in history.tail(5)]
            
            if is_bullish and lower_wick > body * 1.5:
                depth = lower_wick / close
                if depth > 0.01:  # Deep pullback > 1%
                    event = {"time": event_time, "type": "deep_pullback", "data": {"depth": depth, "price": close}}
                elif depth > 0.003:  # Healthy pullback
                    event = {"time": event_time, "type": "healthy_pullback", "data": {"depth": depth, "price": close}}
        
        # 2. Rejection Detection
        if upper_wick > body * 2 and not is_bullish:
            strength = upper_wick / close
            event = {"time": event_time, "type": "strong_rejection", "data": {"strength": strength, "price": close}}
        elif upper_wick > body and not is_bullish:
            event = {"time": event_time, "type": "weak_rejection", "data": {"price": close}}
        
        if lower_wick > body * 2 and is_bullish:
            strength = lower_wick / close
            event = {"time": event_time, "type": "strong_rejection", "data": {"strength": strength, "price": close}}
        
        # 3. BOS Detection
        if len(history) >= 3:
            prev_highs = [h.get('high', 0) for h in history.tail(3)]
            prev_lows = [l.get('low', 0) for l in history.tail(3)]
            
            if close > max(prev_highs) and not is_bullish:
                event = {"time": event_time, "type": "bullish_bos", "data": {"price": close, "break_level": max(prev_highs)}}
            elif close < min(prev_lows) and is_bullish:
                event = {"time": event_time, "type": "bearish_bos", "data": {"price": close, "break_level": min(prev_lows)}}
        
        # 4. CHoCH Detection
        if len(history) >= 2:
            highs = [h.get('high', 0) for h in history.tail(2)]
            lows = [l.get('low', 0) for l in history.tail(2)]
            
            if max(highs[:-1]) > max(highs) and is_bullish:
                event = {"time": event_time, "type": "bullish_shift", "data": {"price": close}}
            elif min(lows[:-1]) < min(lows) and not is_bullish:
                event = {"time": event_time, "type": "bearish_shift", "data": {"price": close}}
        
        # 5. Liquidity Sweep
        if len(history) >= 3:
            swing_high = max(h.get('high', 0) for h in history.tail(3))
            swing_low = min(l.get('low', 0) for l in history.tail(3))
            
            if high > swing_high * 1.001 and close < swing_high:
                event = {"time": event_time, "type": "liquidity_sweep", "data": {"sweep_price": high, "return_price": close}}
            elif low < swing_low * 0.999 and close > swing_low:
                event = {"time": event_time, "type": "liquidity_sweep", "data": {"sweep_price": low, "return_price": close}}
        
        # 6. Compression/Expansion
        if len(history) >= 10:
            recent_high = max(h.get('high', 0) for h in history.tail(5))
            recent_low = min(l.get('low', 0) for l in history.tail(5))
            recent_range = recent_high - recent_low
            older_high = max(h.get('high', 0) for h in history.tail(10))
            older_low = min(l.get('low', 0) for l in history.tail(10))
            older_range = older_high - older_low
            
            if older_range > 0 and recent_range < older_range * 0.5:
                event = {"time": event_time, "type": "compression", "data": {"range_ratio": recent_range/older_range}}
            elif older_range > 0 and recent_range > older_range * 1.5:
                event = {"time": event_time, "type": "expansion", "data": {"range_ratio": recent_range/older_range}}
        
        return event

    def get_events(self, symbol: str) -> List[dict]:
        """الحصول على الأحداث."""
        with self._lock:
            if symbol in self._events_cache:
                return self._events_cache[symbol]
            return self.detect_events(symbol)

    def get_event_summary(self, symbol: str) -> dict:
        """ملخص الأحداث."""
        events = self.get_events(symbol)
        summary = {
            "total_events": len(events),
            "healthy_pullback": sum(1 for e in events if e["type"] == "healthy_pullback"),
            "deep_pullback": sum(1 for e in events if e["type"] == "deep_pullback"),
            "strong_rejection": sum(1 for e in events if e["type"] == "strong_rejection"),
            "weak_rejection": sum(1 for e in events if e["type"] == "weak_rejection"),
            "bullish_bos": sum(1 for e in events if e["type"] == "bullish_bos"),
            "bearish_bos": sum(1 for e in events if e["type"] == "bearish_bos"),
            "bullish_shift": sum(1 for e in events if e["type"] == "bullish_shift"),
            "bearish_shift": sum(1 for e in events if e["type"] == "bearish_shift"),
            "liquidity_sweep": sum(1 for e in events if e["type"] == "liquidity_sweep"),
            "compression": sum(1 for e in events if e["type"] == "compression"),
            "expansion": sum(1 for e in events if e["type"] == "expansion"),
        }
        return summary

    def clear_symbol(self, symbol: str):
        """مسح جميع البيانات لsymbol معين."""
        with self._lock:
            self._candle_history.pop(symbol, None)
            self._entry_candles.pop(symbol, None)
            self._indicators_cache.pop(symbol, None)
            self._events_cache.pop(symbol, None)
            self._last_update.pop(symbol, None)

    def get_all_symbols(self) -> List[str]:
        """الحصول على قائمةالرموز المحدثة."""
        with self._lock:
            return list(set(list(self._candle_history.keys()) + list(self._entry_candles.keys())))


# ========== TRADE EVALUATION ENGINE ==========
class TradeEvaluationEngine:
    """
    TradeEvaluationEngine - محرك تقييم الصفقات.
    يدير:
    - تقييمcontinuation الاحتمالية
    - تقييم صحة الصفقة
    - تقييم thesis
    """
    def __init__(self):
        self._continuation_engine = None
        self._confidence_engine = None
        self._thesis_engine = None

    def evaluate_entry(self, symbol: str, df: pd.DataFrame, indicators: dict, side: str) -> dict:
        """
        ⚠️ DEPRECATED - DO NOT USE ⚠️
        
        This method is deprecated and should NEVER be used for entry decisions.
        
        ARCHITECTURAL CONSTRAINT:
        Entry decisions are made EXACTLY ONCE by Watchlist via UnifiedDecisionEngine.
        Trade Management must NEVER rebuild entry confidence or change BUY/SELL/SKIP.
        
        This method exists only for backwards compatibility and will be removed.
        """
        import warnings
        warnings.warn(
            "TradeEvaluationEngine.evaluate_entry() is deprecated. "
            "Entry decisions must be made by Watchlist via UnifiedDecisionEngine.",
            DeprecationWarning,
            stacklevel=2
        )
        result = {
            "symbol": symbol,
            "side": side,
            "timestamp": time.time(),
            "score": 0.0,
            "continuation_probability": 50.0,
            "confidence": 5,
            "thesis_valid": True,
            "reasons": [],
            "warnings": [],
            "decision": "HOLD",
            "deprecated": True,
        }
        try:
            smart_money = SmartMoneyEngine.analyze_smart_money(df)
            momentum = MomentumFlowEngine.analyze_momentum_flow(df)
            adx = indicators.get("adx", 20.0)
            regime = indicators.get("regime", "UNKNOWN")
            continuation_pressure = indicators.get("continuation_pressure", 50.0)
            hold_quality = indicators.get("hold_quality", 5)
            counter_pressure = indicators.get("counter_pressure", 0)
            thesis = indicators.get("thesis", {})

            if side == "BUY":
                if smart_money.get("institutional_bias") in ("SELL", "STRONG_SELL"):
                    result["warnings"].append("Bearish institutional bias")
                    result["score"] -= 15
                if momentum.get("greed_state", False):
                    result["warnings"].append("Momentum greed state - exhaustion risk")
                    result["score"] -= 10
            else:
                if smart_money.get("institutional_bias") in ("BUY", "STRONG_BUY"):
                    result["warnings"].append("Bullish institutional bias")
                    result["score"] -= 15
                if momentum.get("greed_state", False):
                    result["warnings"].append("Momentum greed state - exhaustion risk")
                    result["score"] -= 10

            if adx < 20:
                result["warnings"].append("Weak trend (ADX < 20)")
                result["score"] -= 10
            elif 25 <= adx <= 35:
                result["score"] += 15
                result["reasons"].append(f"Optimal ADX range: {adx:.1f}")
            elif adx > 40:
                result["warnings"].append("Strong trend - exhaustion risk")
                result["score"] += 5

            if continuation_pressure > 60:
                result["score"] += 10
                result["reasons"].append(f"Strong continuation pressure: {continuation_pressure:.1f}")
            elif continuation_pressure < 40:
                result["score"] -= 10
                result["warnings"].append(f"Weak continuation pressure: {continuation_pressure:.1f}")

            if hold_quality >= 7:
                result["score"] += 10
                result["reasons"].append(f"High hold quality: {hold_quality}")
            elif hold_quality <= 3:
                result["score"] -= 15
                result["warnings"].append(f"Low hold quality: {hold_quality}")

            if counter_pressure > 60:
                result["score"] -= 20
                result["warnings"].append(f"High counter pressure: {counter_pressure:.1f}")

            result["continuation_probability"] = continuation_pressure
            result["confidence"] = hold_quality
            result["smart_money"] = smart_money
            result["momentum"] = momentum
            result["regime"] = regime

            if result["score"] >= 70:
                result["decision"] = "STRONG_ENTRY"
                result["reasons"].append("Strong entry signal")
            elif result["score"] >= 50:
                result["decision"] = "ENTRY"
                result["reasons"].append("Entry signal")
            elif result["score"] >= 30:
                result["decision"] = "WEAK_ENTRY"
                result["reasons"].append("Weak entry signal")
            else:
                result["decision"] = "SKIP"
                result["warnings"].append("Entry rejected due to low score")

        except Exception as e:
            result["warnings"].append(f"Evaluation error: {str(e)}")
            result["decision"] = "ERROR"

        return result

    def evaluate_hold(self, symbol: str, df: pd.DataFrame, state: dict) -> dict:
        """تقييم استمرارية الصفقة المفتوحة."""
        result = {
            "symbol": symbol,
            "timestamp": time.time(),
            "should_hold": True,
            "should_close": False,
            "close_reason": None,
            "score": 100.0,
            "reasons": [],
            "warnings": [],
        }
        try:
            side = state.get("side")
            entry = state.get("entry", 0.0)
            roe = state.get("roe_pct", 0.0)
            atr = state.get("atr", 0.0)
            smart_money = state.get("smart_money", {})
            momentum = state.get("momentum_flow", {})
            trade_state = state.get("trade_state", "RANGE_CHOP")
            continuation_prob = state.get("continuation_probability", 50.0)
            counter_pressure = state.get("counter_pressure", 0)

            dist_risk = smart_money.get("distribution_risk", 0)
            climax_risk = momentum.get("climax_risk", 0)
            exhaustion_risk = momentum.get("exhaustion_risk", 0)

            if dist_risk > 50:
                result["score"] -= 25
                result["warnings"].append(f"High distribution risk: {dist_risk:.1f}")

            if climax_risk > 50:
                result["score"] -= 20
                result["warnings"].append(f"High climax risk: {climax_risk:.1f}")

            if exhaustion_risk > 40:
                result["score"] -= 15
                result["warnings"].append(f"Exhaustion risk: {exhaustion_risk:.1f}")

            if continuation_prob < 30:
                result["score"] -= 25
                result["warnings"].append(f"Weak continuation: {continuation_prob:.1f}")

            if counter_pressure > 70:
                result["score"] -= 30
                result["warnings"].append(f"High counter pressure: {counter_pressure:.1f}")

            if trade_state in ("PANIC_EXIT", "MOMENTUM_COLLAPSE", "LIQUIDITY_EXHAUSTION"):
                result["should_close"] = True
                result["close_reason"] = f"Trade state: {trade_state}"
                result["should_hold"] = False

            if result["score"] < 40:
                result["should_close"] = True
                result["close_reason"] = "Low hold score"
                result["should_hold"] = False

            if result["score"] >= 70:
                result["reasons"].append("Strong hold signal")
            elif result["score"] >= 50:
                result["reasons"].append("Hold signal")

            result["score"] = max(0, min(100, result["score"]))

        except Exception as e:
            result["warnings"].append(f"Hold evaluation error: {str(e)}")

        return result


# ========== TRADE DECISION ENGINE ==========
class TradeDecisionEngine:
    """
    TradeDecisionEngine - محرك اتخاذ القرارات.
    يدير:
    - قرارات الدخول
    - قرارات الخروج
    - قرارات إدارة الصفقة
    """
    def __init__(self):
        self._evaluation_engine = TradeEvaluationEngine()
        self._decision_history: List[dict] = []
        self._max_history = 100

    def decide_entry(self, symbol: str, df: pd.DataFrame, indicators: dict, side: str) -> dict:
        """
        ⚠️ DEPRECATED - DO NOT USE ⚠️
        
        This method is deprecated and should NEVER be used for entry decisions.
        
        ARCHITECTURAL CONSTRAINT:
        Entry decisions are made EXACTLY ONCE by Watchlist via UnifiedDecisionEngine.
        Trade Management must NEVER rebuild entry confidence or change BUY/SELL/SKIP.
        
        This method exists only for backwards compatibility and will be removed.
        """
        import warnings
        warnings.warn(
            "TradeDecisionEngine.decide_entry() is deprecated. "
            "Entry decisions must be made by Watchlist via UnifiedDecisionEngine.",
            DeprecationWarning,
            stacklevel=2
        )
        evaluation = self._evaluation_engine.evaluate_entry(symbol, df, indicators, side)
        decision = {
            "symbol": symbol,
            "side": side,
            "timestamp": time.time(),
            "evaluation": evaluation,
            "action": "WAIT",
            "confidence": 0,
            "reasons": evaluation.get("reasons", []),
            "warnings": evaluation.get("warnings", []),
            "deprecated": True,
        }

        if evaluation["decision"] in ("STRONG_ENTRY", "ENTRY"):
            decision["action"] = "ENTER"
            decision["confidence"] = evaluation["score"]
            decision["reasons"].append(f"Entry decision: {evaluation['decision']}")
        elif evaluation["decision"] == "WEAK_ENTRY":
            if evaluation["score"] >= 35:
                decision["action"] = "CONDITIONAL_ENTER"
                decision["confidence"] = evaluation["score"]
                decision["reasons"].append("Conditional entry - proceed with caution")
            else:
                decision["action"] = "WAIT"
                decision["reasons"].append("Entry too weak")
        else:
            decision["action"] = "SKIP"
            decision["reasons"].append("Entry rejected")
            decision["warnings"].extend(evaluation.get("warnings", []))

        self._log_decision(decision)
        return decision

    def decide_exit(self, symbol: str, df: pd.DataFrame, state: dict) -> dict:
        """اتخاذ قرار الخروج."""
        evaluation = self._evaluation_engine.evaluate_hold(symbol, df, state)
        decision = {
            "symbol": symbol,
            "timestamp": time.time(),
            "evaluation": evaluation,
            "action": "HOLD",
            "confidence": evaluation["score"],
            "reasons": evaluation.get("reasons", []),
            "warnings": evaluation.get("warnings", []),
        }

        if evaluation["should_close"]:
            decision["action"] = "EXIT"
            decision["close_reason"] = evaluation.get("close_reason", "Evaluation")
            decision["reasons"].append(f"Exit decision: {evaluation['close_reason']}")
        elif evaluation["should_hold"]:
            decision["action"] = "HOLD"
        else:
            decision["action"] = "CONDITIONAL_EXIT"
            decision["reasons"].append("Conditional exit - monitor closely")

        self._log_decision(decision)
        return decision

    def decide_management(self, symbol: str, state: dict) -> dict:
        """
        Trade management (SL, TP, Trail).
        
        Uses:
        - TradeState from InstitutionalTradeBrain
        - SmartMoney, Momentum from existing engines
        - Candle events from CandleMemory
        
        Differentiates:
        - TREND: Allows natural corrections, no exit on healthy pullback
        - REVERSAL: More sensitive, tightens protection early
        """
        management = {
            "symbol": symbol,
            "timestamp": time.time(),
            "action": "HOLD",
            "sl_adjustment": None,
            "tp_adjustment": None,
            "trail_adjustment": None,
            "partial_close": None,
            "reasons": [],
            "source": "TradeDecisionEngine",
            "confidence": 50.0,  # Base confidence
        }
        try:
            trade_state = state.get("trade_state", "RANGE_CHOP")
            trade_type = state.get("trade_type", "TREND")
            roe = state.get("roe_pct", 0.0)
            trail_active = state.get("trail_active", False)
            tp1_hit = state.get("tp1_hit", False)
            profit_lock = state.get("profit_lock_activated", False)
            smart_money = state.get("smart_money", {})
            momentum = state.get("momentum_flow", {})
            candle_events = state.get("candle_events", [])
            candle_summary = state.get("candle_event_summary", {})
            structure_aligned = state.get("structure_aligned", False)
            weak_pullback = state.get("weak_pullback", False)

            dist_risk = smart_money.get("distribution_risk", 0)
            climax_risk = momentum.get("climax_risk", 0)
            exhaustion_risk = momentum.get("exhaustion_risk", 0)
            continuation_strength = momentum.get("continuation_strength", 50)
            
            # Analyze candle events
            strong_rejections = candle_summary.get("strong_rejection", 0)
            weak_rejections = candle_summary.get("weak_rejection", 0)
            bos_events = candle_summary.get("bullish_bos", 0) + candle_summary.get("bearish_bos", 0)
            liquidity_sweeps = candle_summary.get("liquidity_sweep", 0)
            deep_pullbacks = candle_summary.get("deep_pullback", 0)
            healthy_pullbacks = candle_summary.get("healthy_pullback", 0)
            choch_events = candle_summary.get("bullish_shift", 0) + candle_summary.get("bearish_shift", 0)
            compression_events = candle_summary.get("compression", 0)
            
            is_trend_trade = trade_type == "TREND"
            is_reversal_trade = trade_type == "REVERSAL"
            

            # ========== ZONE-BASED MANAGEMENT ==========
            ctx = state.get("institutional_context")
            if ctx:
                zone_state = ctx.zone_state
                zone_score = ctx.zone_score

                # Strong zone - more patient
                if zone_score >= 80:
                    if management["action"] == "HOLD":
                        management["reasons"].append(f"Strong zone (score: {zone_score:.0f})")
                        management["confidence"] = min(management["confidence"] + 10, 99)
                # Weak zone - tighten protection
                elif zone_score < 50:
                    if management["action"] == "HOLD":
                        management["action"] = "TIGHTEN"
                        management["reasons"].append(f"Weak zone (score: {zone_score:.0f})")
                        management["confidence"] = max(management["confidence"] - 15, 5)

                # Zone state transitions
                if zone_state:
                    zone_val = zone_state.value if hasattr(zone_state, 'value') else str(zone_state)
                    if zone_val == "FRESH" and management["action"] in ("EXIT", "SECURE_PROFIT"):
                        management["action"] = "HOLD"
                        management["reasons"].append("Fresh zone - allow correction")
                    if zone_val in ("BROKEN", "FLIP") and management["action"] == "HOLD":
                        management["action"] = "EXIT"
                        management["reasons"].append("Zone broken/flip - exit")
                        management["confidence"] = 95

            # ========== INSTITUTIONAL READINESS MANAGEMENT ==========
            # Adjust management based on readiness VALUE + TREND
            # Readiness is NOT exit trigger - TradeDecisionEngine decides
            ctx = state.get("institutional_context")
            if ctx:
                readiness = ctx.confidence
                read_class = getattr(ctx, 'readiness_class', 'NORMAL')
                read_trend = getattr(ctx, 'readiness_trend', 'STABLE')

                # STRONG (>=85): Patient management
                if read_class == "STRONG" and readiness >= 85:
                    if management["action"] == "HOLD":
                        management["reasons"].append(f"Strong ({read_class})")
                        management["confidence"] = min(management["confidence"] + 5, 99)
                    if management["action"] == "TIGHTEN":
                        management["action"] = "HOLD"
                        management["reasons"].append("Strong - pause tightening")

                # STRONG but FALLING: Monitor, don't exit
                elif read_class == "STRONG" and read_trend == "FALLING":
                    management["reasons"].append(f"Strong but FALLING ({read_trend})")
                    management["confidence"] = max(management["confidence"] - 5, 30)

                # WEAK (50-69): Tighten protection
                elif read_class == "WEAK":
                    if management["action"] == "HOLD":
                        management["action"] = "TIGHTEN"
                        management["reasons"].append(f"Weak ({read_class})")
                        management["confidence"] = max(management["confidence"] - 10, 5)
                    # WEAK but RISING: Don't lock profits yet
                    if read_trend == "RISING" and "PROFIT" in management["action"]:
                        management["action"] = "HOLD"
                        management["reasons"].append("Weak but RISING - allow growth")
                    # WEAK and FALLING: Lock profits
                    elif read_trend == "FALLING" and "PROFIT" not in management["action"]:
                        management["action"] = "SECURE_PROFIT"
                        management["reasons"].append("Weak+FALLING - secure gains")

                # AVOID (<50): Allow TradeDecisionEngine to decide
                elif read_class == "AVOID":
                    if management["action"] == "HOLD":
                        management["confidence"] = max(management["confidence"] - 20, 1)
                        management["reasons"].append(f"AVOID ({readiness:.0f})")

            # ========== TREND TRADE MANAGEMENT ==========
            if is_trend_trade:
                # Healthy Pullback: expected in trend, ignore
                if healthy_pullbacks >= 1 and structure_aligned:
                    management["reasons"].append("Healthy Pullback in Trend (ignored)")
                
                # Deep Pullback: monitor only if trade_state is positive
                if deep_pullbacks >= 1:
                    if trade_state in ("EXHAUSTION", "DISTRIBUTION"):
                        management["reasons"].append(f"Deep Pullback in {trade_state}")
                        if roe >= 2.0:
                            management["action"] = "EARLY_TP1"
                            management["partial_close"] = 0.5
                    elif roe > 5.0 and climax_risk > 60:
                        management["action"] = "TIGHTEN_TRAIL"
                        management["trail_adjustment"] = "TIGHTEN"
                        management["reasons"].append("Deep Pullback with high profits")
                
                # CHoCH: dangerous in trend
                if choch_events >= 1:
                    management["reasons"].append("CHoCH detected in Trend")
                    if climax_risk > 50:
                        management["action"] = "PROFIT_LOCK"
                        management["partial_close"] = 0.5
                
                # BOS: positive in trend
                if bos_events >= 1 and structure_aligned:
                    management["reasons"].append("BOS confirms Trend")
                    management["trail_adjustment"] = "LOOSEN"
                
                # Compression
                if compression_events >= 3:
                    management["reasons"].append("Compression in Trend")
                    if continuation_strength < 40 and roe > 3.0:
                        management["action"] = "SECURE_PROFIT"
                        management["partial_close"] = 0.5
            
            # ========== REVERSAL TRADE MANAGEMENT ==========
            if is_reversal_trade:
                # Failed Retest: thesis collapse
                for event in candle_events:
                    if event.get("type") == "failed_retest":
                        management["reasons"].append("Failed Retest - Thesis Collapse")
                        if roe > 0:
                            management["action"] = "SECURE_PROFIT"
                            management["partial_close"] = 0.5
                        else:
                            management["action"] = "EXIT"
                
                # Strong Rejection
                if strong_rejections >= 1:
                    management["reasons"].append("Strong Rejection - Reversal failed")
                    if climax_risk > 30:
                        management["action"] = "EXIT"
                
                # Weak Rejection in negative state
                if weak_rejections >= 1 and trade_state in ("EXHAUSTION", "DISTRIBUTION"):
                    management["reasons"].append("Weak Rejection in negative state")
                    if roe > 0:
                        management["action"] = "SECURE_PROFIT"
                        management["partial_close"] = 0.5
                    elif climax_risk > 40:
                        management["action"] = "TIGHTEN_TRAIL"
                        management["trail_adjustment"] = "TIGHTEN"
                
                # Liquidity Sweep
                if liquidity_sweeps >= 1:
                    management["reasons"].append("Liquidity Sweep - Thesis at risk")
                    if climax_risk > 40:
                        management["action"] = "PROFIT_LOCK"
                        management["partial_close"] = 0.5
                
                # BOS against direction
                if bos_events >= 1 and not structure_aligned:
                    management["reasons"].append("BOS against Reversal thesis")
                    if climax_risk > 30:
                        management["action"] = "EXIT"
                
                # CHoCH
                if choch_events >= 1:
                    management["reasons"].append("CHoCH - Reversal failed")
                    management["action"] = "EXIT"
                
                # Healthy Pullback in Reversal
                if healthy_pullbacks >= 1:
                    management["reasons"].append("Retest in Reversal")
                    if continuation_strength < 30:
                        management["action"] = "TIGHTEN_TRAIL"
                        management["trail_adjustment"] = "TIGHTEN"
            
            # ========== COMMON DECISIONS ==========
            # Failed Retest affects both types
            for event in candle_events:
                if event.get("type") == "failed_retest":
                    if roe > 0 and dist_risk > 40 and management["action"] == "HOLD":
                        management["action"] = "SECURE_PROFIT"
                        management["partial_close"] = 0.5
            
            # Distribution Risk
            if dist_risk > 50 and not profit_lock and management["action"] == "HOLD":
                management["action"] = "PROFIT_LOCK"
                management["reasons"].append(f"Distribution risk: {dist_risk:.1f}")
                management["partial_close"] = 0.5
            
            # Climax Risk
            if climax_risk > 60 and trail_active and management["action"] == "HOLD":
                management["action"] = "TIGHTEN_TRAIL"
                management["trail_adjustment"] = "TIGHTEN"
                management["reasons"].append(f"Climax risk: {climax_risk:.1f}")
            
            # Trade State negative
            if trade_state in ("EXHAUSTION", "DISTRIBUTION", "LIQUIDITY_EXHAUSTION"):
                if not tp1_hit and roe >= 2.0 and management["action"] == "HOLD":
                    management["action"] = "EARLY_TP1"
                    management["reasons"].append(f"Trade state: {trade_state}")
                    management["partial_close"] = 0.5
            
            # Weak continuation
            if continuation_strength < 10 and roe > 3.0 and management["action"] == "HOLD":
                management["action"] = "SECURE_PROFIT"
                management["partial_close"] = 0.5
                management["reasons"].append("Weak continuation strength")
            
            management["trade_type"] = trade_type
            
            # Calculate confidence based on evidence strength
            evidence_count = len(management["reasons"])
            if evidence_count == 0:
                management["confidence"] = 30.0  # Low confidence - no strong signals
            elif evidence_count == 1:
                management["confidence"] = 60.0  # Medium confidence
            elif evidence_count == 2:
                management["confidence"] = 80.0  # Higher confidence
            else:
                management["confidence"] = 95.0  # Strong consensus
                
            # Adjust confidence based on action severity
            if management["action"] in ("EXIT", "PROFIT_LOCK"):
                management["confidence"] = min(management["confidence"] + 10, 99.0)
            elif management["action"] == "HOLD":
                management["confidence"] = max(management["confidence"] - 20, 10.0)

        except Exception as e:
            management["reasons"].append(f"Management error: {str(e)}")

        return management

    def _log_decision(self, decision: dict):
        """تسجيل القرار في السجل."""
        self._decision_history.append(decision)
        if len(self._decision_history) > self._max_history:
            self._decision_history = self._decision_history[-self._max_history:]

    def get_decision_history(self, symbol: str = None, limit: int = 20) -> List[dict]:
        """الحصول على سجل القرارات."""
        if symbol:
            return [d for d in self._decision_history if d.get("symbol") == symbol][-limit:]
        return self._decision_history[-limit:]


# ========== CLOSE VERIFICATION PIPELINE ==========
class CloseVerificationPipeline:
    """
    CloseVerificationPipeline - Pipeline احترافي لإغلاق الصفقات.
    
    ترتيب التنفيذ:
    1. request_close()
    2. close_position_full()
    3. verify_exchange()
    4. retry_if_needed()
    5. reconcile_state()
    6. update_statistics()
    7. telegram_report()
    8. cleanup_trade()
    9. EventBus.publish()
    
    ⚠️ ممنوع أي Engine من استدعاء close_position_full() مباشرة
    ⚠️ يجب استخدام request_close() فقط
    """
    _instance = None

    def __new__(cls):
        if cls._instance is None:
            cls._instance = super().__new__(cls)
            cls._instance._initialized = False
        return cls._instance

    def __init__(self):
        if self._initialized:
            return
        self._initialized = True
        self._lock = threading.Lock()
        self._verification_history: List[dict] = []
        self._max_history = 100
        self._max_retries = 3
        self._retry_delay = 2  # seconds

    def request_close(self, symbol: str, reason: str = "MANUAL", partial_ratio: float = 1.0) -> dict:
        """
        طلب إغلاق الصفقة - الطريقة الوحيدة المسموحة لإغلاق الصفقات.
        
        Pipeline:
        1. close_position_full()
        2. verify_exchange()
        3. retry_if_needed()
        4. reconcile_state()
        5. update_statistics()
        6. telegram_report()
        7. cleanup_trade()
        8. EventBus.publish()
        """
        with self._lock:
            result = {
                "symbol": symbol,
                "timestamp": time.time(),
                "reason": reason,
                "success": False,
                "verified": False,
                "retries": 0,
                "final_pnl_pct": 0.0,
                "final_pnl_usdt": 0.0,
                "result": "UNKNOWN",
                "trade_data": None,
                "errors": [],
            }
            
            # STEP 1: close_position_full()
            try:
                log_execution(f"[CLOSE_PIPELINE] Step 1: Closing position for {symbol}", "INFO")
                close_result = close_position_full()
                if not close_result:
                    result["errors"].append("close_position_full() returned False")
                    self._log_pipeline_result(result)
                    return result
            except Exception as e:
                result["errors"].append(f"Step 1 error: {str(e)}")
                self._log_pipeline_result(result)
                return result
            
            # STEP 2: verify_exchange()
            try:
                log_execution(f"[CLOSE_PIPELINE] Step 2: Verifying exchange for {symbol}", "INFO")
                verification = self._verify_exchange(symbol)
                if not verification["success"]:
                    result["errors"].extend(verification.get("errors", []))
                    result["retries"] = verification.get("retries", 0)
                else:
                    result["verified"] = True
                    result["final_pnl_pct"] = verification.get("pnl_pct", 0.0)
                    result["final_pnl_usdt"] = verification.get("pnl_usdt", 0.0)
            except Exception as e:
                result["errors"].append(f"Step 2 error: {str(e)}")
            
            # STEP 3: retry_if_needed()
            if not result["verified"]:
                for retry in range(self._max_retries):
                    result["retries"] = retry + 1
                    log_execution(f"[CLOSE_PIPELINE] Retry {retry+1}/{self._max_retries} for {symbol}", "WARN")
                    time.sleep(self._retry_delay)
                    verification = self._verify_exchange(symbol)
                    if verification["success"]:
                        result["verified"] = True
                        result["final_pnl_pct"] = verification.get("pnl_pct", 0.0)
                        result["final_pnl_usdt"] = verification.get("pnl_usdt", 0.0)
                        break
                    result["errors"].extend(verification.get("errors", []))
            
            # STEP 4: reconcile_state()
            try:
                log_execution(f"[CLOSE_PIPELINE] Step 4: Reconciling state for {symbol}", "INFO")
                self._reconcile_state(symbol)
            except Exception as e:
                result["errors"].append(f"Step 4 error: {str(e)}")
            
            # STEP 5: update_statistics()
            try:
                log_execution(f"[CLOSE_PIPELINE] Step 5: Updating statistics", "INFO")
                self._update_statistics(result)
            except Exception as e:
                result["errors"].append(f"Step 5 error: {str(e)}")
            
            # STEP 6: telegram_report()
            try:
                log_execution(f"[CLOSE_PIPELINE] Step 6: Sending Telegram report", "INFO")
                self._send_telegram_report(result)
            except Exception as e:
                result["errors"].append(f"Step 6 error: {str(e)}")
            
            # STEP 7: cleanup_trade()
            try:
                log_execution(f"[CLOSE_PIPELINE] Step 7: Cleaning up trade", "INFO")
                self._cleanup_trade(symbol)
            except Exception as e:
                result["errors"].append(f"Step 7 error: {str(e)}")
            
            # STEP 8: EventBus.publish()
            try:
                log_execution(f"[CLOSE_PIPELINE] Step 8: Publishing event", "INFO")
                self._publish_event(symbol, result)
            except Exception as e:
                result["errors"].append(f"Step 8 error: {str(e)}")
            
            result["success"] = result["verified"]
            self._log_pipeline_result(result)
            return result

    def _verify_exchange(self, symbol: str) -> dict:
        """التحقق من إغلاق الصفقة على المنصة."""
        result = {"success": False, "pnl_pct": 0.0, "pnl_usdt": 0.0, "errors": [], "retries": 0}
        
        try:
            if PAPER_MODE:
                result["success"] = True
                result["pnl_pct"] = STATE.get("roe_pct", 0.0)
                result["pnl_usdt"] = STATE.get("unrealized_pnl_usdt", 0.0)
                return result
            
            real_pos = sync_position_with_exchange(symbol)
            if real_pos is None:
                # تم التأكد من إغلاق المركز
                realized_pnl, realized_pct = get_realized_pnl_for_symbol(symbol, lookback_seconds=120)
                if realized_pnl != 0:
                    result["pnl_usdt"] = realized_pnl
                    result["pnl_pct"] = realized_pct
                result["success"] = True
            else:
                result["errors"].append("Position still open on exchange")
        except Exception as e:
            result["errors"].append(f"Verify error: {str(e)}")
        
        return result

    def _reconcile_state(self, symbol: str):
        """مزامنة الحالة بعد الإغلاق."""
        try:
            with _TRADE_LOCK:
                STATE["open"] = False
                STATE["side"] = None
                STATE["current_symbol"] = None
                STATE["qty"] = 0.0
                STATE["remaining_qty"] = 0.0
                STATE["entry"] = 0.0
                STATE["roe_pct"] = 0.0
                STATE["unrealized_pnl_usdt"] = 0.0
                STATE["mark_price"] = 0.0
                STATE["tp1_hit"] = False
                STATE["tp2_hit"] = False
                STATE["trail_activated"] = False
                
                TRADE_STATE["in_position"] = False
                TRADE_STATE["symbol"] = None
                TRADE_STATE["side"] = None
                TRADE_STATE["entry"] = 0.0
                TRADE_STATE["qty"] = 0.0
                TRADE_STATE["tp1_hit"] = False
                TRADE_STATE["tp2_hit"] = False
                TRADE_STATE["trail_on"] = False
                
                DASHBOARD_STATE["live_trade_mode"] = False
        except Exception as e:
            log_execution(f"[CLOSE_PIPELINE] State reconciliation error: {e}", "ERROR")

    def _update_statistics(self, result: dict):
        """تحديث الإحصائيات."""
        try:
            pnl_pct = result.get("final_pnl_pct", 0.0)
            pnl_usdt = result.get("final_pnl_usdt", 0.0)
            
            PERF["total_pnl_pct"] += pnl_pct
            PERF["total_pnl_usdt"] += pnl_usdt
            PERF["trades"] += 1
            
            if pnl_pct >= 0:
                PERF["wins"] += 1
                result["result"] = "WIN"
            else:
                PERF["losses"] += 1
                result["result"] = "LOSS"
            
            PERF["last_trade"] = {
                "result": result["result"],
                "pnl_pct": pnl_pct,
                "symbol": result.get("symbol"),
            }
            
            update_stats(pnl_pct)
            log_execution(f"[CLOSE_PIPELINE] Statistics updated: {result['result']} {pnl_pct:.2f}%", "SUCCESS" if pnl_pct >= 0 else "ERROR")
        except Exception as e:
            log_execution(f"[CLOSE_PIPELINE] Statistics update error: {e}", "ERROR")

    def _send_telegram_report(self, result: dict):
        """إرسال تقرير Telegram احترافي لإغلاق الصفقة."""
        try:
            if PAPER_MODE or not TELEGRAM_BOT_TOKEN or not TELEGRAM_CHAT_ID:
                return
            
            symbol = result.get("symbol", "UNKNOWN")
            
            # بيانات الصفقة من STATE
            side = STATE.get("side", "UNKNOWN")
            entry = STATE.get("entry", 0.0)
            mark_price = STATE.get("mark_price", 0.0)
            pnl_pct = result.get("final_pnl_pct", 0.0)
            pnl_usdt = result.get("final_pnl_usdt", 0.0)
            trade_type = STATE.get("trade_type", "TREND")
            entry_reason = STATE.get("entry_reason", "UNKNOWN")
            entry_time = STATE.get("entry_time", 0)
            highest_roe = STATE.get("highest_roe", 0.0)
            highest_unrealized = STATE.get("highest_unrealized_pnl", 0.0)
            tp1_hit = STATE.get("tp1_hit", False)
            tp2_hit = STATE.get("tp2_hit", False)
            trail_active = STATE.get("trail_activated", False)
            profit_lock = STATE.get("profit_lock_activated", False)
            be_done = STATE.get("be_done", False)
            trade_state = STATE.get("trade_state", "UNKNOWN")
            close_reason = result.get("reason", "UNKNOWN")
            final_roe = STATE.get("roe_pct", 0.0)
            
            # TradeMemory data
            trade = None
            if '_trade_memory' in dir():
                trade = _trade_memory.get_open_trade(symbol)

            # Readiness data for analytics
            entry_readiness = STATE.get("entry_readiness", 0)
            entry_readiness_class = STATE.get("entry_readiness_class", "N/A")
            current_readiness = 0
            readiness_trend = "N/A"
            if trade and 'context_history' in trade:
                history = trade.get('context_history', [])
                if history:
                    current_readiness = history[-1].get('conf', 0)
                    readiness_trend = history[-1].get('trend', 'N/A')
            highest_readiness = entry_readiness
            
            # حساب المدة
            duration_min = 0
            if entry_time > 0:
                duration_min = (time.time() - entry_time) / 60
            
            # عدد الشموع منذ الدخول
            candles_since_entry = 0
            if trade and 'entry_time' in trade:
                entry_ts = trade.get('entry_time', 0)
                if entry_ts > 0 and '_candle_memory' in dir():
                    df_entry = _candle_memory.get_entry_candles(symbol)
                    if df_entry is not None:
                        candles_since_entry = len(df_entry)
            
            # أهم الأحداث
            important_events = []
            if trade:
                recent_decisions = trade.get('decision_history', [])[-5:]
                for d in recent_decisions:
                    if d.get('decision') != 'HOLD':
                        important_events.append(d.get('decision'))
            
            # أيقونات
            result_icon = "✅" if pnl_pct >= 0 else "❌"
            direction_icon = "🟢" if side == "BUY" else "🔴"
            management_type = "TREND" if trade_type == "TREND" else "REVERSAL"
            
            # بناء الرسالة
            msg_parts = []
            msg_parts.append(f"{result_icon} <b>TRADE CLOSED</b>")
            msg_parts.append("━━━━━━━━━━━━━━━━━━━━")
            msg_parts.append(f"{direction_icon} <b>{side}</b> | {management_type} | 10x")
            msg_parts.append(f"📊 <code>{symbol}</code>")

            # Zone and Structure info from TradeMemory
            zone_type = None
            zone_state = None
            zone_score = 0
            structure_state = None
            adx_override = False
            adx_value = 0
            if trade:
                zone_type = trade.get("zone_type")
                zone_state = trade.get("zone_state")
                zone_score = trade.get("zone_score", 0)
                structure_state = trade.get("structure_state")
                adx_override = trade.get("adx_override_used", False)
                adx_value = trade.get("adx_value_at_entry", 0)

            # Zone section
            if zone_type:
                zone_icon = "🟢" if zone_type == "demand" else "🔴"
                entry_zone_str = f"{zone_icon} Entry: {zone_type.capitalize()} ({zone_state or '?'})"
                if zone_score > 0:
                    entry_zone_str += f" Score: {zone_score:.0f}"
                msg_parts.append(entry_zone_str)
                if structure_state:
                    msg_parts.append(f"📐 Structure: {structure_state}")
            if adx_override:
                msg_parts.append(f"🟡 Mode: ADX Override ({adx_value:.0f})")
            msg_parts.append(f"━━━━━━━━━━━━━━━━━━━━")
            
            # التوقيت
            entry_time_str = time.strftime("%H:%M", time.localtime(entry_time)) if entry_time > 0 else "N/A"
            close_time_str = time.strftime("%H:%M", time.localtime())
            msg_parts.append(f"⏱ {entry_time_str} → {close_time_str} | {duration_min:.0f}m")
            
            # السعر
            msg_parts.append(f"💰 Entry: <code>{entry:.4f}</code>")
            msg_parts.append(f"💰 Exit: <code>{mark_price:.4f}</code>")
            
            # النتائج
            msg_parts.append("━━━━━━━━━━━━━━━━━━━━")
            pnl_icon = "💚" if pnl_pct >= 0 else "❤️"
            msg_parts.append(f"{pnl_icon} PnL: <b>{pnl_pct:+.2f}%</b>")
            msg_parts.append(f"💵 {pnl_usdt:+.2f} USDT")
            msg_parts.append(f"📈 ROE: <code>{final_roe:+.2f}%</code>")
            msg_parts.append(f"📈 Peak ROE: <code>{highest_roe:+.2f}%</code>")
            msg_parts.append(f"📈 Peak PnL: <code>{highest_unrealized:+.2f}</code>")
            
            # القرار
            msg_parts.append("━━━━━━━━━━━━━━━━━━━━")
            
            # Readiness Analytics Section
            if entry_readiness > 0:
                readiness_icon = "🟢" if entry_readiness >= 85 else "🟡" if entry_readiness >= 70 else "🔴"
                trend_icon = "📈" if readiness_trend == "RISING" else "📉" if readiness_trend == "FALLING" else "➡️"
                msg_parts.append(f"{readiness_icon} <b>Readiness</b>")
                msg_parts.append(f"Entry: {entry_readiness:.0f} ({entry_readiness_class})")
                msg_parts.append(f"Current: {current_readiness:.0f} {trend_icon} {readiness_trend}")
                msg_parts.append(f"Close: <code>{close_reason}</code>")
                msg_parts.append(f"🧠 Decision: <code>TradeDecisionEngine</code>")
            else:
                msg_parts.append(f"🎯 Close: <code>{close_reason}</code>")
                msg_parts.append(f"🧠 Decision: <code>TradeDecisionEngine</code>")
            # Get confidence from latest decision
            decision_confidence = 50.0
            if trade:
                recent = trade.get('decision_history', [])
                if recent:
                    last = recent[-1]
                    decision_confidence = last.get('confidence', 50.0)
            msg_parts.append(f"📊 Exit Confidence: <code>{decision_confidence:.0f}%</code>")
            tp_str = "✅" if tp1_hit else "❌"
            tp2_str = "✅" if tp2_hit else "❌"
            trail_str = "✅" if trail_active else "❌"
            lock_str = "✅" if profit_lock else "❌"
            be_str = "✅" if be_done else "❌"
            msg_parts.append(f"TP1: {tp_str} | TP2: {tp2_str} | Trail: {trail_str}")
            msg_parts.append(f"Lock: {lock_str} | BE: {be_str}")
            
            # الأحداث المؤثرة
            if important_events:
                events_str = ", ".join(important_events[:3])
                msg_parts.append(f"⚡ Events: <code>{events_str}</code>")
            
            msg_parts.append(f"🕯 Candles: <code>{candles_since_entry}</code>")
            
            # إحصائيات الحساب من المنصة
            msg_parts.append("━━━━━━━━━━━━━━━━━━━━")
            msg_parts.append("<b>Account Stats</b>")
            
            # الحصول على بيانات المنصة
            balance = 0.0
            available = 0.0
            try:
                if not PAPER_MODE:
                    account = safe_api_call(ex.fetch_account)
                    if account:
                        for b in account.get('info', {}).get('data', [{}]):
                            if b.get('asset') == 'USDT':
                                balance = float(b.get('balance', 0))
                                available = float(b.get('availableBalance', 0))
                                break
                        if balance == 0:
                            balance = account.get('total', {}).get('USDT', 0)
                            available = account.get('free', {}).get('USDT', 0)
            except:
                balance = get_balance_safe()
                available = get_free_balance_safe()
            
            # PERF stats
            wins = PERF.get("wins", 0)
            losses = PERF.get("losses", 0)
            total_trades = wins + losses
            winrate = (wins / total_trades * 100) if total_trades > 0 else 0
            realized_pnl = PERF.get("total_pnl_usdt", 0.0)
            
            msg_parts.append(f"Balance: <code>{balance:.2f}</code> USDT")
            msg_parts.append(f"Available: <code>{available:.2f}</code> USDT")
            msg_parts.append(f"━━━━━━━━━━━━━━━━━━━━")
            msg_parts.append(f"🏆 Trades: <code>{total_trades}</code> | W: <code>{wins}</code> | L: <code>{losses}</code>")
            msg_parts.append(f"📊 Win Rate: <code>{winrate:.1f}%</code>")
            msg_parts.append(f"💰 Realized: <code>{realized_pnl:+.2f}</code> USDT")
            msg = "\n".join(msg_parts)
            _tg_send(msg)
        except Exception as e:
            log_execution(f"[CLOSE_PIPELINE] Telegram error: {e}", "ERROR")

    def _cleanup_trade(self, symbol: str):
        """تنظيف الصفقة."""
        try:
            # حذف من TradeMemory
            if '_trade_memory' in dir():
                _trade_memory.close_trade(
                    symbol,
                    STATE.get("roe_pct", 0.0),
                    STATE.get("unrealized_pnl_usdt", 0.0),
                    "WIN" if STATE.get("roe_pct", 0) >= 0 else "LOSS",
                    "CLOSE_PIPELINE"
                )
            
            # حذف من CandleMemory
            if '_candle_memory' in dir():
                _candle_memory.clear_symbol(symbol)
            
            # تنظيف STATE
            keys_to_clear = [
                "trade_state", "smart_money", "momentum_flow",
                "continuation_probability", "hold_quality", "counter_pressure",
                "trade_thesis", "management"
            ]
            for key in keys_to_clear:
                if key in STATE:
                    STATE[key] = None if key != "trade_state" else "RANGE_CHOP"
        except Exception as e:
            log_execution(f"[CLOSE_PIPELINE] Cleanup error: {e}", "ERROR")

    def _publish_event(self, symbol: str, result: dict):
        """نشر حدث EventBus."""
        try:
            if '_event_bus' in dir():
                _event_bus.emit("trade_closed", {
                    "symbol": symbol,
                    "result": result["result"],
                    "pnl_pct": result.get("final_pnl_pct", 0.0),
                    "pnl_usdt": result.get("final_pnl_usdt", 0.0),
                    "reason": result.get("reason", "UNKNOWN"),
                    "verified": result.get("verified", False),
                    "timestamp": time.time()
                })
                _event_bus.emit("lifecycle_change", TradeLifecycleState.CLOSED)
        except Exception as e:
            log_execution(f"[CLOSE_PIPELINE] Event publish error: {e}", "ERROR")

    def _log_pipeline_result(self, result: dict):
        """تسجيل نتيجة الـ Pipeline."""
        self._verification_history.append(result.copy())
        if len(self._verification_history) > self._max_history:
            self._verification_history = self._verification_history[-self._max_history:]
        
        if result["success"]:
            log_execution(f"[CLOSE_PIPELINE] SUCCESS: {result['symbol']} closed with {result['final_pnl_pct']:+.2f}%", "SUCCESS")
        else:
            log_execution(f"[CLOSE_PIPELINE] FAILED: {result['symbol']} - {result['errors']}", "ERROR")

    def get_verification_history(self, limit: int = 20) -> List[dict]:
        """الحصول على سجل التحقق."""
        return self._verification_history[-limit:]

    def get_last_verification(self) -> Optional[dict]:
        """الحصول على آخر تحقق."""
        return self._verification_history[-1] if self._verification_history else None


# ========== TRADE MANAGER CENTRAL ==========
class TradeManagerCentral:
    """
    TradeManagerCentral - Single Source of Truth لإدارة الصفقات.
    يدير:
    - TradeMemory: ذاكرة الصفقات
    - CandleMemory: ذاكرة الشموع
    - TradeEvaluationEngine: محرك التقييم
    - TradeDecisionEngine: محرك القرارات
    - CloseVerificationPipeline: التحقق من الإغلاق
    - إدارة Dashboard
    - إرسال Telegram
    """
    _instance = None

    def __new__(cls):
        if cls._instance is None:
            cls._instance = super().__new__(cls)
            cls._instance._initialized = False
        return cls._instance

    def __init__(self):
        if self._initialized:
            return
        self._initialized = True
        self._lock = threading.Lock()
        self.trade_memory = TradeMemory()
        self.candle_memory = CandleMemory()
        self.evaluation_engine = TradeEvaluationEngine()
        self.decision_engine = TradeDecisionEngine()
        self.close_pipeline = CloseVerificationPipeline()
        self._last_dashboard_update = 0
        self._dashboard_update_interval = 5

    def open_trade(self, symbol: str, side: str, entry: float, qty: float, **kwargs) -> dict:
        """فتح صفقة جديدة."""
        with self._lock:
            log_execution(f"[CENTRAL] Opening trade: {symbol} {side} @ {entry}", "INFO")
            self.trade_memory.add_open_trade(symbol, side, entry, qty, **kwargs)
            trade = self.trade_memory.get_open_trade(symbol)
            self._update_performance_on_open(trade)
            self._update_dashboard_on_open(trade)
            self._send_telegram_on_open(trade)
            return trade

    def update_trade(self, symbol: str, **updates):
        """تحديث صفقة مفتوحة."""
        with self._lock:
            self.trade_memory.update_open_trade(symbol, **updates)
            if time.time() - self._last_dashboard_update > self._dashboard_update_interval:
                self._update_dashboard_on_update(symbol)
            if STATE.get("current_symbol") == symbol:
                for key, value in updates.items():
                    STATE[key] = value

    def evaluate_and_decide(self, symbol: str, df: pd.DataFrame, indicators: dict) -> dict:
        """
        Evaluate and decide on an open trade.
        
        ⚠️ ARCHITECTURAL CONSTRAINT:
        This method ONLY handles open positions.
        Entry decisions are made by Watchlist via UnifiedDecisionEngine.
        Trade Management must NEVER:
        - Rebuild entry confidence
        - Change BUY/SELL/SKIP decision
        - Recalculate strategy_score
        
        Returns decisions for managing an already-open position.
        """
        with self._lock:
            self.candle_memory.store_candles(symbol, df)
            self.candle_memory.store_indicators(symbol, indicators)
            trade = self.trade_memory.get_open_trade(symbol)
            
            if not trade:
                # Architectural violation fix: No entry decisions in Trade Management
                # Entry decisions must come from Watchlist via UnifiedDecisionEngine
                return {
                    "error": "NO_OPEN_TRADE",
                    "message": "No open trade for evaluation. Entry decisions are made by Watchlist only.",
                    "decision": None,
                    "management": None,
                }
            
            trade.update({
                "atr": indicators.get("atr", 0.0),
                "adx": indicators.get("adx", 20.0),
                "smart_money": indicators.get("smart_money", {}),
                "momentum_flow": indicators.get("momentum_flow", {}),
                "continuation_probability": indicators.get("continuation_probability", 50.0),
                "hold_quality": indicators.get("hold_quality", 5),
                "counter_pressure": indicators.get("counter_pressure", 0),
                "trade_state": indicators.get("trade_state", "RANGE_CHOP"),
                "regime": indicators.get("regime", "UNKNOWN"),
            })
            decision = self.decision_engine.decide_exit(symbol, df, trade)
            management = self.decision_engine.decide_management(symbol, trade)
            return {
                "decision": decision,
                "management": management,
            }

    def close_trade(self, symbol: str, close_reason: str = "MANUAL", force_verify: bool = True) -> dict:
        """
        إغلاق صفقة مع التحقق - يستخدم Pipeline احترافي.
        
        ⚠️ لا يستدعي close_position_full() مباشرة
        ⚠️ يستخدم CloseVerificationPipeline.request_close()
        """
        with self._lock:
            log_execution(f"[CENTRAL] Closing trade: {symbol} (reason: {close_reason})", "INFO")
            
            if force_verify:
                # استخدام Pipeline - الطريقة الوحيدة المسموحة
                pipeline_result = self.close_pipeline.request_close(symbol, close_reason)
                
                verification = {
                    "verified": pipeline_result.get("verified", False),
                    "pnl_pct": pipeline_result.get("final_pnl_pct", 0.0),
                    "pnl_usdt": pipeline_result.get("final_pnl_usdt", 0.0),
                    "result": pipeline_result.get("result", "UNKNOWN"),
                    "close_reason": close_reason,
                    "success": pipeline_result.get("success", False),
                    "retries": pipeline_result.get("retries", 0),
                    "errors": pipeline_result.get("errors", []),
                }
            else:
                verification = {
                    "verified": True,
                    "pnl_pct": STATE.get("roe_pct", 0.0),
                    "pnl_usdt": STATE.get("unrealized_pnl_usdt", 0.0),
                    "result": "WIN" if STATE.get("roe_pct", 0) >= 0 else "LOSS",
                    "close_reason": close_reason,
                }
            
            closed_trade = self.trade_memory.close_trade(
                symbol,
                verification.get("pnl_pct", 0.0),
                verification.get("pnl_usdt", 0.0),
                verification.get("result", "UNKNOWN"),
                close_reason
            )
            self._update_performance_on_close(verification, closed_trade)
            self._update_dashboard_on_close(symbol)
            # Telegram يُرسل من Pipeline مباشرة بعد verify_exchange()
            
            # POST-TRADE CLEANUP - Phase 7 of Trade Lifecycle
            cleanup_report = post_trade_cleanup(symbol)
            
            return {
                "closed_trade": closed_trade,
                "verification": verification,
                "cleanup_report": cleanup_report,
            }

    def sync_state(self):
        """مزامنة الحالة المركزية مع STATE العالمي."""
        with self._lock:
            self.trade_memory.sync_from_global_state()

    def get_status(self) -> dict:
        """الحصول على الحالة المركزية."""
        with self._lock:
            return {
                "trade_memory": {
                    "open_trades": list(self.trade_memory.open_trades.keys()),
                    "stats": self.trade_memory.get_stats(),
                },
                "candle_memory": {
                    "symbols": self.candle_memory.get_all_symbols(),
                },
                "last_decisions": self.decision_engine.get_decision_history(limit=5),
                "verification_history": self.close_pipeline.get_verification_history(limit=5),
            }

    def _update_performance_on_open(self, trade: dict):
        """تحديث الأداء عند فتح صفقة."""
        try:
            if trade:
                symbol = trade.get("symbol")
                side = trade.get("side")
                log_execution(f"[CENTRAL] Performance updated - Open: {symbol} {side}", "SUCCESS")
        except Exception as e:
            log_execution(f"[CENTRAL] Performance update error: {e}", "ERROR")

    def _update_performance_on_close(self, verification: dict, closed_trade: dict):
        """تحديث الأداء عند إغلاق صفقة."""
        try:
            pnl_pct = verification.get("pnl_pct", 0.0)
            pnl_usdt = verification.get("pnl_usdt", 0.0)
            result = verification.get("result", "UNKNOWN")
            PERF["total_pnl_pct"] += pnl_pct
            PERF["total_pnl_usdt"] += pnl_usdt
            PERF["trades"] += 1
            if result == "WIN":
                PERF["wins"] += 1
            else:
                PERF["losses"] += 1
            PERF["last_trade"] = {
                "result": result,
                "pnl_pct": pnl_pct,
                "symbol": closed_trade.get("symbol") if closed_trade else None,
            }
            log_execution(f"[CENTRAL] Performance updated - Close: {result} {pnl_pct:.2f}%", "SUCCESS" if result == "WIN" else "ERROR")
        except Exception as e:
            log_execution(f"[CENTRAL] Performance close update error: {e}", "ERROR")

    def _update_dashboard_on_open(self, trade: dict):
        """تحديث Dashboard عند فتح صفقة."""
        try:
            self._last_dashboard_update = time.time()
            DASHBOARD_STATE["live_trade_mode"] = True
            DASHBOARD_STATE["current_symbol"] = trade.get("symbol")
            DASHBOARD_STATE["position_side"] = trade.get("side")
            DASHBOARD_STATE["entry_price"] = trade.get("entry")
            DASHBOARD_STATE["position_size"] = trade.get("qty")
            DASHBOARD_STATE["entry_time"] = trade.get("entry_time")
            log_execution(f"[CENTRAL] Dashboard updated - Open", "INFO")
        except Exception as e:
            log_execution(f"[CENTRAL] Dashboard update error: {e}", "ERROR")

    def _update_dashboard_on_update(self, symbol: str):
        """تحديث Dashboard عند تحديث الصفقة."""
        try:
            self._last_dashboard_update = time.time()
            trade = self.trade_memory.get_open_trade(symbol)
            if trade:
                DASHBOARD_STATE["current_pnl"] = trade.get("roe_pct", 0.0)
                DASHBOARD_STATE["mark_price"] = trade.get("mark_price", 0.0)
                DASHBOARD_STATE["trade_state"] = trade.get("trade_state", "RANGE_CHOP")
                DASHBOARD_STATE["continuation_prob"] = trade.get("continuation_probability", 50.0)
                DASHBOARD_STATE["hold_quality"] = trade.get("hold_quality", 5)
        except Exception as e:
            log_execution(f"[CENTRAL] Dashboard update error: {e}", "ERROR")

    def _update_dashboard_on_close(self, symbol: str):
        """تحديث Dashboard عند إغلاق صفقة."""
        try:
            self._last_dashboard_update = time.time()
            DASHBOARD_STATE["live_trade_mode"] = False
            DASHBOARD_STATE["current_symbol"] = None
            DASHBOARD_STATE["position_side"] = None
            DASHBOARD_STATE["entry_price"] = 0.0
            DASHBOARD_STATE["position_size"] = 0.0
            DASHBOARD_STATE["current_pnl"] = 0.0
            DASHBOARD_STATE["last_closed_trade"] = PERF.get("last_trade", {})
            log_execution(f"[CENTRAL] Dashboard updated - Close", "INFO")
        except Exception as e:
            log_execution(f"[CENTRAL] Dashboard close update error: {e}", "ERROR")

    def _send_telegram_on_open(self, trade: dict):
        """إرسال إشعار Telegram عند فتح صفقة."""
        try:
            balance = get_balance_safe()
            mode = "LIVE" if MODE_LIVE else "PAPER"
            symbol = trade.get("symbol", "UNKNOWN")
            side = trade.get("side", "UNKNOWN")
            entry = trade.get("entry", 0.0)
            qty = trade.get("qty", 0.0)
            if not PAPER_MODE and TELEGRAM_BOT_TOKEN and TELEGRAM_CHAT_ID:
                message = f"🔔 <b>Trade Opened</b>\n\n📊 Symbol: <code>{symbol}</code>\n📈 Side: <b>{side}</b>\n💰 Entry: <code>{entry}</code>\n📦 Qty: <code>{qty}</code>\n💵 Balance: <code>{balance:.2f}</code>\n🎯 Mode: <code>{mode}</code>"
                _tg_send(message)
        except Exception as e:
            log_execution(f"[CENTRAL] Telegram open error: {e}", "ERROR")

    def _send_telegram_on_close(self, closed_trade: dict, verification: dict):
        """إرسال إشعار Telegram عند إغلاق صفقة."""
        try:
            symbol = closed_trade.get("symbol", "UNKNOWN") if closed_trade else STATE.get("current_symbol", "UNKNOWN")
            side = closed_trade.get("side", STATE.get("side", "UNKNOWN")) if closed_trade else STATE.get("side", "UNKNOWN")
            pnl_pct = verification.get("pnl_pct", 0.0)
            duration_min = closed_trade.get("duration_minutes", 0) if closed_trade else 0
            result = verification.get("result", "UNKNOWN")
            if not PAPER_MODE and TELEGRAM_BOT_TOKEN and TELEGRAM_CHAT_ID:
                emoji = "✅" if result == "WIN" else "❌"
                message = f"{emoji} <b>Trade Closed</b>\n\n📊 Symbol: <code>{symbol}</code>\n📈 Side: <b>{side}</b>\n💰 Result: <b>{result}</b>\n📈 PnL: <code>{pnl_pct:+.2f}%</code>\n⏱️ Duration: <code>{duration_min:.1f} min</code>"
                _tg_send(message)
        except Exception as e:
            log_execution(f"[CENTRAL] Telegram close error: {e}", "ERROR")


