def _get_cached_symbol_data(symbol, cache_type="light"):
    """Get cached data for a symbol if not expired"""
    ttl = _SCANNER_CACHE_TTL.get(cache_type, 60)
    cached = _SCANNER_DATA_CACHE["symbols_metadata"].get(symbol)
    if cached and (time.time() - cached.get("ts", 0)) < ttl:
        return cached
    return None

def _set_cached_symbol_data(symbol, data, cache_type="light"):
    """Cache symbol data with timestamp"""
    if symbol not in _SCANNER_DATA_CACHE["symbols_metadata"]:
        _SCANNER_DATA_CACHE["symbols_metadata"][symbol] = {}
    _SCANNER_DATA_CACHE["symbols_metadata"][symbol].update({
        **data,
        "ts": time.time(),
        "cache_type": cache_type
    })

def _is_symbol_fresh(symbol, cache_type="light"):
    """Check if symbol data is fresh enough"""
    ttl = _SCANNER_CACHE_TTL.get(cache_type, 60)
    cached = _SCANNER_DATA_CACHE["symbols_metadata"].get(symbol)
    if cached and (time.time() - cached.get("ts", 0)) < ttl:
        return True
    return False

def _get_heavy_analysis(symbol):
    """Get heavy analysis data (engines) if fresh"""
    cached = _SCANNER_DATA_CACHE["analyzed_cache"].get(symbol)
    if cached and (time.time() - cached.get("ts", 0)) < _SCANNER_CACHE_TTL["heavy"]:
        return cached.get("data")
    return None

def _set_heavy_analysis(symbol, data):
    """Cache heavy analysis data (engines results)"""
    _SCANNER_DATA_CACHE["analyzed_cache"][symbol] = {
        "data": data,
        "ts": time.time()
    }

def _add_to_discovery_queue(symbols):
    """Add symbols to discovery queue for ranking"""
    _SCANNER_DATA_CACHE["discovery_ranked"] = symbols
    _SCANNER_DATA_CACHE["discovery_timestamp"] = time.time()

def _get_discovery_candidates():
    """Get discovery candidates if fresh"""
    if time.time() - _SCANNER_DATA_CACHE["discovery_timestamp"] < _SCANNER_CACHE_TTL["discovery"]:
        return _SCANNER_DATA_CACHE["discovery_ranked"]
    return []

def _build_analysis_queue(candidates, batch_size=6):
    """Build analysis queue from candidates with priority"""
    queue = []
    for c in candidates:
        sym = c.get("symbol") or c.get("symbol")
        priority = c.get("score", 50)
        # Add to queue with priority
        queue.append({"symbol": sym, "priority": priority, "score": c.get("score", 0)})
    # Sort by priority (highest first)
    queue.sort(key=lambda x: x["priority"], reverse=True)
    _SCANNER_DATA_CACHE["analysis_queue"] = queue
    _SCANNER_DATA_CACHE["analysis_index"] = 0
    return queue


