def get_cached_ticker(symbol):
    """
    Get cached ticker data if fresh (within TTL).
    This is the PRIMARY way to fetch ticker data.
    
    Includes per-symbol rate limit cooldown:
    - If symbol returned 109415 (Paused) or 109429 (Rate Limited)
    - Skip API call for that symbol until cooldown expires
    - Return stale cache if available
    """
    global _TICKER_CACHE, _API_CALL_COUNTER, _SYMBOL_RATE_LIMIT_COOLDOWN

    sym = normalize_symbol(symbol)
    now = time.time()

    # Check per-symbol rate limit cooldown FIRST
    if sym in _SYMBOL_RATE_LIMIT_COOLDOWN:
        cooldown_until = _SYMBOL_RATE_LIMIT_COOLDOWN[sym]
        if now < cooldown_until:
            # Symbol is in cooldown - return stale cache if available
            if sym in _TICKER_CACHE:
                _API_CALL_COUNTER["ticker"]["cooldown_hits"] += 1
                return _TICKER_CACHE[sym]["data"]
            return None
        else:
            # Cooldown expired - remove from cooldown dict
            del _SYMBOL_RATE_LIMIT_COOLDOWN[sym]

    # Check cache first
    if sym in _TICKER_CACHE:
        cached = _TICKER_CACHE[sym]
        if now - cached["timestamp"] < _TICKER_CACHE_TTL:
            _API_CALL_COUNTER["ticker"]["cache_hits"] += 1
            return cached["data"]

    # Cache miss - fetch from exchange
    _API_CALL_COUNTER["ticker"]["cache_misses"] += 1
    _API_CALL_COUNTER["ticker"]["requests"] += 1
    _API_CALL_COUNTER["ticker"]["symbols"].add(sym)

    try:
        rate_limit()
        data = ex.fetch_ticker(sym)
        if data:
            _TICKER_CACHE[sym] = {"data": data, "timestamp": now}
            return data
    except Exception as e:
        error_str = str(e)
        # Check for rate limit errors (109415 = Paused, 109429 = Rate Limited)
        if "109415" in error_str or "109429" in error_str or "rate limit" in error_str.lower():
            # Put symbol in cooldown
            _SYMBOL_RATE_LIMIT_COOLDOWN[sym] = now + _SYMBOL_RATE_LIMIT_COOLDOWN_SEC
            _API_CALL_COUNTER["ticker"]["rate_limit_cooldowns"] += 1
            log_execution(f"[CACHE_TICKER] ⏳ {sym} in cooldown ({_SYMBOL_RATE_LIMIT_COOLDOWN_SEC}s) - {error_str[:50]}", "WARN")
        
        log_execution(f"[CACHE_TICKER] Fetch failed for {sym}: {e}", "WARN")

    # Return stale cache if available
    if sym in _TICKER_CACHE:
        _API_CALL_COUNTER["ticker"]["cache_hits"] += 1
        return _TICKER_CACHE[sym]["data"]

    return None


def get_cached_balance(force_refresh=False):
    """
    Get cached balance if fresh (within TTL).
    This is the PRIMARY way to fetch balance.
    """
    global _BALANCE_CACHE, _API_CALL_COUNTER
    
    now = time.time()
    
    # Check cache first
    if not force_refresh and _BALANCE_CACHE["data"] and (now - _BALANCE_CACHE["timestamp"]) < _BALANCE_CACHE_TTL:
        _API_CALL_COUNTER["balance"]["cache_hits"] += 1
        return _BALANCE_CACHE["data"]
    
    # Cache miss - fetch from exchange
    _API_CALL_COUNTER["balance"]["cache_misses"] += 1
    _API_CALL_COUNTER["balance"]["requests"] += 1
    
    try:
        rate_limit()
        data = ex.fetch_balance()
        if data:
            _BALANCE_CACHE = {"data": data, "timestamp": now}
            _API_CALL_COUNTER["balance"]["last_fetch"] = now
            return data
    except Exception as e:
        log_execution(f"[CACHE_BALANCE] Fetch failed: {e}", "WARN")
    
    # Return stale cache if available
    if _BALANCE_CACHE["data"]:
        _API_CALL_COUNTER["balance"]["cache_hits"] += 1
        return _BALANCE_CACHE["data"]
    
    return None

