def _merge_discovery_with_watchlist():
    """
    DYNAMIC ROTATION: Merge fresh Discovery candidates with Watchlist.
    
    This ensures the Watchlist is NEVER frozen - it continuously updates
    with better candidates from Discovery even between 20-min cycles.
    
    Logic:
    1. Get fresh Discovery candidates (if available)
    2. Get current Watchlist entries
    3. For each Discovery candidate not in Watchlist:
       - If Watchlist has low-scoring entries, replace them
       - If Watchlist has stale entries, replace them
    4. Add new Discovery candidates to Watchlist
    5. Update queue to include new candidates
    
    Returns: Number of replacements made
    """
    discovery_candidates = _get_discovery_candidates()
    if not discovery_candidates:
        return 0
    
    watchlist = MEMORY.get("watchlist", {})
    if not watchlist:
        return 0
    
    replacements = 0
    new_candidates = []
    now = time.time()
    
    # Track symbols already in watchlist
    watchlist_symbols = set(watchlist.keys())
    
    # Find Discovery candidates NOT in Watchlist
    for cand in discovery_candidates:
        sym = cand.get("symbol")
        if sym and sym not in watchlist_symbols:
            new_candidates.append(cand)
    
    if not new_candidates:
        return 0
    
    log_execution(f"[DYNAMIC ROTATION] Found {len(new_candidates)} new Discovery candidates", "INFO")
    
    # Sort current Watchlist by score (lowest first - candidates for replacement)
    watchlist_by_score = sorted(
        watchlist.items(),
        key=lambda x: (x[1].get("score", 0), x[1].get("last_update", 0)),
        reverse=False  # Lowest score first
    )
    
    # Replace low-scoring or stale entries with better Discovery candidates
    for cand in new_candidates:
        sym = cand.get("symbol")
        disc_score = cand.get("score", 50)
        
        if not sym:
            continue
        
        # Find lowest scoring entry in Watchlist
        for wl_sym, wl_entry in watchlist_by_score:
            wl_score = wl_entry.get("score", 0)
            
            # Replace if Discovery candidate has significantly higher score
            # OR if Watchlist entry is very stale
            wl_last_update = wl_entry.get("last_update", 0)
            stale_minutes = (now - wl_last_update) / 60 if wl_last_update > 0 else 999
            
            # Replacement conditions:
            # 1. Discovery score is at least 20 points higher
            # 2. OR Watchlist entry is stale (>15 min without update) AND Discovery has decent score
            should_replace = (disc_score > wl_score + 20) or (stale_minutes > 15 and disc_score > 50)
            
            if should_replace:
                # Mark old entry for removal (will be replaced by Discovery entry)
                old_entry = watchlist.pop(wl_sym, None)
                old_state = old_entry.get("watchlist_state", "UNKNOWN") if old_entry else "UNKNOWN"
                log_execution(
                    f"[DYNAMIC ROTATION] REPLACE {wl_sym} ({wl_score:.0f}, {old_state}) → {sym} ({disc_score:.0f})",
                    "INFO"
                )
                replacements += 1
                break
    
    # Add new Discovery candidates that didn't replace anything
    # (if Watchlist is not full)
    if len(watchlist) < 40:  # Max Watchlist size
        for cand in new_candidates[:5]:  # Add up to 5 new entries
            sym = cand.get("symbol")
            if sym and sym not in watchlist:
                # Create placeholder entry - will be analyzed in next batch
                # NOTE: Do NOT pre-set action/entry_readiness here!
                # Let aggregate_decision() determine them after analysis
                watchlist[sym] = {
                    "symbol": sym,
                    "score": cand.get("score", 50),
                    "discovery_score": cand.get("score", 50),
                    "last_update": now,
                    "last_analyzed_at": 0,  # Never analyzed
                    "watchlist_state": "WAITING",  # Needs analysis
                    # action and entry_readiness will be set by Pipeline after analysis
                    "strategy_valid": False,  # Placeholder - will be validated by StrategyEntryFilter
                }
                log_execution(f"[DYNAMIC ROTATION] ADD {sym} (Discovery, score={cand.get('score', 50):.0f}) | Awaiting analysis...", "INFO")
                replacements += 1
    
    if replacements > 0:
        log_execution(f"[DYNAMIC ROTATION] ✅ Made {replacements} replacements/additions", "INFO")
        # Rebuild analysis queue with new Watchlist entries
        # Convert tuples to dict format expected by _build_analysis_queue
        queue_items = []
        for wl_sym, wl_entry in watchlist_by_score:
            queue_items.append({
                "symbol": wl_sym,
                "score": wl_entry.get("score", 0),
                "priority": wl_entry.get("score", 50)
            })
        for cand in new_candidates:
            queue_items.append({
                "symbol": cand.get("symbol"),
                "score": cand.get("score", 50),
                "priority": cand.get("score", 50)
            })
        _build_analysis_queue(queue_items)
    
    return replacements


def _get_next_analysis_batch(batch_size=6):
    """Get next batch of symbols to analyze"""
    queue = _SCANNER_DATA_CACHE["analysis_queue"]
    idx = _SCANNER_DATA_CACHE["analysis_index"]
    if idx >= len(queue):
        return []
    batch = queue[idx:idx + batch_size]
    _SCANNER_DATA_CACHE["analysis_index"] = idx + batch_size
    return batch

def _reset_analysis_cycle():
    """Reset analysis cycle for next 20-minute round"""
    _SCANNER_DATA_CACHE["analysis_index"] = 0

def _is_discovery_fresh():
    """Check if discovery data is fresh"""
    return time.time() - _SCANNER_DATA_CACHE["discovery_timestamp"] < _SCANNER_CACHE_TTL["discovery"]

def _clear_scanner_cache():
    """Clear scanner cache on startup"""
    _SCANNER_DATA_CACHE["symbols_metadata"].clear()
    _SCANNER_DATA_CACHE["analyzed_cache"].clear()
    _SCANNER_DATA_CACHE["analysis_queue"].clear()
    _SCANNER_DATA_CACHE["analysis_index"] = 0
    log_execution("[CACHE] Scanner data cache cleared", "INFO")


def _build_watchlist_rotation_queue():
    """
    Build rotation queue from MEMORY["watchlist"] for continuous analysis.
    
    PRIORITY SYSTEM:
    1. READY entries: Highest priority (接近入场条件)
    2. WATCHING entries: Medium priority (继续监控)
    3. Other entries: Lower priority (距离入场较远)
    
    This ensures:
    - Watchlist NEVER becomes empty between Discovery cycles
    - Strong entries get analyzed more frequently
    - Weak entries still get rotation but less often
    """
    import time as time_module
    
    watchlist = MEMORY.get("watchlist", {})
    log_execution(f"[WATCHLIST ROTATION] Building from MEMORY['watchlist'] | Size={len(watchlist)}", "INFO")
    
    if not watchlist:
        log_execution("[WATCHLIST ROTATION] ❌ Watchlist is EMPTY - cannot build rotation queue", "WARN")
        return []
    
    candidates = []
    now = time_module.time()
    
    for sym, entry in watchlist.items():
        # Calculate dynamic priority based on entry state and freshness
        base_priority = 50
        
        # Action-based priority
        action = entry.get("action", "SKIP")
        if action == "READY":
            base_priority = 100  # Highest - ready for entry
        elif action == "WATCH":
            base_priority = 70  # High - watching for opportunity
        
        # Freshness bonus - entries not analyzed recently get higher priority
        last_analyzed = entry.get("last_analyzed_at", 0)
        if last_analyzed > 0:
            minutes_since = (now - last_analyzed) / 60
            if minutes_since > 10:
                base_priority += 20  # Needs re-analysis
            elif minutes_since > 5:
                base_priority += 10
        
        # Strategy validity bonus
        if entry.get("strategy_valid"):
            base_priority += 15
        
        # Confidence bonus
        confidence = entry.get("confidence", 0)
        if confidence >= 70:
            base_priority += 10
        elif confidence >= 50:
            base_priority += 5
        
        # Readiness level bonus
        readiness = entry.get("entry_readiness", "NORMAL")
        if readiness == "STRONG":
            base_priority += 15
        elif readiness == "ELEVATED":
            base_priority += 10
        
        candidates.append({
            "symbol": sym,
            "priority": base_priority,
            "score": entry.get("score", 0),
            "action": action,
            "last_analyzed_at": last_analyzed
        })
    
    # Sort by priority (highest first)
    candidates.sort(key=lambda x: x["priority"], reverse=True)
    
    log_execution(
        f"[WATCHLIST ROTATION] Queue built: {len(candidates)} symbols | "
        f"READY={sum(1 for c in candidates if c['action']=='READY')} | "
        f"WATCH={sum(1 for c in candidates if c['action']=='WATCH')}",
        "INFO"
    )
    
    return candidates


def rate_limit():
    global _last_api_call
    now = time.time()
    elapsed = now - _last_api_call
    if elapsed < MIN_API_INTERVAL:
        time.sleep(MIN_API_INTERVAL - elapsed)
    _last_api_call = time.time()

def cache_get(key, ttl):
    item = CACHE.get(key)
    if item and time.time() - item["ts"] < ttl:
        return item["value"]
    return None

def cache_set(key, value):
    CACHE[key] = {"value": value, "ts": time.time()}

# ========== COMPREHENSIVE API CALL TRACING ==========
_API_TRACE = {
    "enabled": False,
    "start_time": 0,
    "stages": {},  # Stage-based calls
    "all_calls": [],  # All calls with timestamps
    "sources": {},  # API calls by source (entry/scanner/dashboard/background)
    "current_stage": None,
}

def _enable_api_trace():
    """Enable comprehensive API call tracing"""
    global _API_TRACE
    _API_TRACE = {
        "enabled": True,
        "start_time": time.time(),
        "stages": {},
        "all_calls": [],
        "sources": {},
        "current_stage": "INIT",
    }

def _disable_api_trace():
    """Disable API call tracing"""
    global _API_TRACE
    _API_TRACE["enabled"] = False

def _set_api_stage(stage_name):
    """Set the current pipeline stage for API tracing"""
    global _API_TRACE
    if _API_TRACE["enabled"]:
        _API_TRACE["current_stage"] = stage_name
        if stage_name not in _API_TRACE["stages"]:
            _API_TRACE["stages"][stage_name] = []

def _track_api_call(func_name, source="unknown"):
    """Track an API call with stage and source info"""
    global _API_TRACE
    if not _API_TRACE["enabled"]:
        return
    
    call_info = {
        "func": func_name,
        "stage": _API_TRACE["current_stage"],
        "source": source,
        "timestamp": time.time() - _API_TRACE["start_time"],
    }
    
    # Track in stage
    if _API_TRACE["current_stage"] and _API_TRACE["current_stage"] in _API_TRACE["stages"]:
        _API_TRACE["stages"][_API_TRACE["current_stage"]].append(func_name)
    
    # Track in source
    if source not in _API_TRACE["sources"]:
        _API_TRACE["sources"][source] = {}
    _API_TRACE["sources"][source][func_name] = _API_TRACE["sources"][source].get(func_name, 0) + 1
    
    # Track all calls
    _API_TRACE["all_calls"].append(call_info)

def _get_api_trace_report():
    """Get comprehensive formatted API trace report"""
    global _API_TRACE
    
    if not _API_TRACE.get("all_calls"):
        return "No API calls recorded"
    
    elapsed_ms = (time.time() - _API_TRACE["start_time"]) * 1000
    lines = []
    
    lines.append("\n" + "═" * 60)
    lines.append("📊 API AUDIT REPORT")
    lines.append("═" * 60)
    lines.append(f"⏱️  Time in execute_entry: {elapsed_ms:.0f}ms")
    lines.append(f"📞 Total API Calls: {len(_API_TRACE['all_calls'])}")
    lines.append("─" * 60)
    
    # Stage-based breakdown
    lines.append("\n📍 API CALLS BY STAGE:")
    lines.append("─" * 40)
    
    stage_order = [
        "INIT", "BALANCE_CHECK", "POSITION_CHECK", "LEVERAGE_CHECK",
        "DATA_FETCH", "ORDER_PLACEMENT", "ORDER_VERIFICATION"
    ]
    
    for stage in stage_order:
        if stage in _API_TRACE["stages"]:
            calls = _API_TRACE["stages"][stage]
            stage_dots = "." * max(2, 20 - len(stage))
            lines.append(f"  [{stage}]{stage_dots}{len(calls)}")
            # Show unique calls in this stage
            unique_calls = list(dict.fromkeys(calls))
            for call in unique_calls:
                count = calls.count(call)
                call_dots = "." * max(2, 20 - len(call))
                lines.append(f"      └─ {call}{call_dots}{count}")
    
    # Source-based breakdown
    lines.append("\n📂 API CALLS BY SOURCE:")
    lines.append("─" * 40)
    for source, calls in sorted(_API_TRACE["sources"].items(), key=lambda x: -sum(x[1].values())):
        total = sum(calls.values())
        lines.append(f"  {source}: {total} calls")
        for func, count in sorted(calls.items(), key=lambda x: -x[1]):
            func_dots = "." * max(2, 20 - len(func))
            lines.append(f"      └─ {func}{func_dots}{count}")
    
    # Summary
    lines.append("\n" + "─" * 40)
    lines.append("📈 SUMMARY:")
    lines.append("─" * 40)
    
    all_funcs = {}
    for call in _API_TRACE["all_calls"]:
        func = call["func"]
        all_funcs[func] = all_funcs.get(func, 0) + 1
    
    for func, count in sorted(all_funcs.items(), key=lambda x: -x[1]):
        dots = "." * max(2, 25 - len(func))
        lines.append(f"  {func}{dots}{count}")
    
    total = len(_API_TRACE["all_calls"])
    lines.append(f"\n  {'TOTAL':25s}{total}")
    lines.append("═" * 60)
    
    return "\n".join(lines)


# Wrapper for exchange API calls to track ALL calls
class TrackedExchange:
    """Wrapper around exchange to track ALL API calls"""
    def __init__(self, exchange):
        self._ex = exchange
    
    def __getattr__(self, name):
        attr = getattr(self._ex, name)
        if callable(attr):
            return self._tracked_call(attr, name)
        return attr
    
    def _tracked_call(self, func, func_name):
        """Wrap function to track all calls"""
        def tracked(*args, **kwargs):
            # Determine source
            source = _API_TRACE.get("current_source", "unknown")
            _track_api_call(func_name, source)
            return func(*args, **kwargs)
        return tracked

# Apply tracking wrapper to exchange
_exchange_tracker = None

def _init_exchange_tracker():
    """Initialize exchange tracker"""
    global _exchange_tracker, ex
    if 'ex' in globals() and ex is not None:
        _exchange_tracker = TrackedExchange(ex)

def safe_api_call(func, *args, **kwargs):
    """Safe API call wrapper with comprehensive tracing"""
    # Extract function name for tracing
    func_name = getattr(func, '__name__', str(func))
    
    # Track the call if enabled
    if _API_TRACE["enabled"]:
        source = _API_TRACE.get("current_source", "unknown")
        _track_api_call(func_name, source)
    
    for attempt in range(3):
        try:
            rate_limit()
            result = func(*args, **kwargs)
            return result
        except Exception as e:
            error_str = str(e)
            if "rate limit" in error_str.lower() or "100410" in error_str or "109429" in error_str:
                wait = 2 ** attempt
                print(color_text(f"Rate limit hit (API: {func_name}), waiting {wait}s...", YELLOW))
                time.sleep(wait)
                continue
            if attempt == 2:
                raise
            time.sleep(1)
    return None

