def normalize_symbol(symbol):
    if not symbol.endswith(":USDT"):
        return f"{symbol}:USDT"
    return symbol


# ========== LEVERAGE MANAGER (10x FIXED) ==========
class LeverageManager:
    """
    LeverageManager - يضمن أن جميع الصفقات تعمل برافعة مالية 10x الفعلية على المنصة.
    
    Multi-Symbol Support: ✅ YES
    - كل رمز له ذاكرة مستقلة
    - _leverage_cache[symbol]: ذاكرة الرافعة لكل رمز
    - _verification_cache[symbol]: التحقق لكل رمز
    - _last_set_time[symbol]: وقت آخر محاولة لكل رمز
    
    Thread Safety: ✅ YES
    - threading.Lock() على جميع العمليات الحساسة
    
    Cooldown Bypass: ✅ YES
    - force=True يتخطى الـ cooldown
    - يُستخدم عند: تغيير الرمز، Restart، Exchange Restart
    
    API Verification: BingX Futures
    - fetch_positions() أولاً
    - fetch_account() كـ fallback
    - إذا فشل = None = فشل
    
    STATE Integration: ✅ YES
    - STATE["verified_leverage"][symbol] = {leverage, verified, timestamp}
    """
    _instance = None

    def __new__(cls):
        if cls._instance is None:
            cls._instance = super().__new__(cls)
            cls._instance._initialized = False
        return cls._instance

    def __init__(self):
        if self._initialized:
            return
        self._initialized = True
        self._lock = threading.Lock()
        self._target_leverage = 10
        self._current_symbol: Optional[str] = None
        # Multi-Symbol caches
        self._last_set_time: Dict[str, float] = {}
        self._leverage_cache: Dict[str, int] = {}
        self._verification_cache: Dict[str, dict] = {}
        self._cooldown_seconds = 300
        self._verification_ttl = 60

    def get_target_leverage(self) -> int:
        """الحصول على الرافعة المستهدفة (10x)."""
        return self._target_leverage

    def _try_set_leverage(self, sym: str, leverage: int, side: str = None) -> bool:
        """
        محاولة تعيين الرافعة على المنصة.
        
        BingX API requires 'side' parameter for set_leverage in ALL cases:
        - HEDGE mode: BUY -> LONG, SELL -> SHORT
        - ONE-WAY mode: BOTH (always)
        
        If side is provided and mode is HEDGE:
        - BUY -> side=LONG
        - SELL -> side=SHORT
        
        If side is not provided or mode is ONE-WAY:
        - Use side=BOTH
        """
        try:
            if not hasattr(ex, 'set_leverage'):
                log_execution(f"[LEVERAGE] Exchange does not support set_leverage", "WARN")
                return True
            
            # Determine position mode (Hedge or One-way)
            position_mode = self._get_position_mode(sym)
            
            if position_mode == "HEDGE" and side:
                # HEDGE mode with specific side
                if side == "BUY":
                    pos_side = "LONG"
                else:  # SELL
                    pos_side = "SHORT"
                params = {"side": pos_side}
                ex.set_leverage(leverage, sym, params)
                log_execution(f"[LEVERAGE] Set {sym} {pos_side} to {leverage}x", "SUCCESS")
                return True
            else:
                # ONE-WAY mode OR HEDGE without specific side -> use BOTH
                # This covers: default case, ONE-WAY mode, or when side is not specified
                params = {"side": "BOTH"}
                ex.set_leverage(leverage, sym, params)
                log_execution(f"[LEVERAGE] Set {sym} to {leverage}x (side=BOTH)", "SUCCESS")
                return True
                
        except Exception as e:
            log_execution(f"[LEVERAGE] Failed to set leverage for {sym}: {e}", "ERROR")
            self._send_leverage_error(sym, leverage, str(e), "SET_FAILED")
            return False
    
    def _get_position_mode(self, sym: str) -> str:
        """
        تحديد وضع المركز (Hedge أو One-way).
        
        Returns:
            "HEDGE" for hedge mode, "ONE_WAY" for one-way mode
        """
        try:
            # Try to get position mode from exchange
            if hasattr(ex, 'get_position_mode'):
                mode = ex.get_position_mode(sym)
                # BingX returns: True for hedge mode, False for one-way
                if mode is True or mode == "HEDGE":
                    return "HEDGE"
                else:
                    return "ONE_WAY"
            elif hasattr(ex, 'fetch_position_mode'):
                result = ex.fetch_position_mode(sym)
                if result and result.get("hedger"):
                    return "HEDGE"
                return "ONE_WAY"
        except Exception as e:
            log_execution(f"[LEVERAGE] Could not determine position mode for {sym}: {e}", "WARN")
        
        # Default to ONE_WAY if we can't determine
        return "ONE_WAY"
    
    def set_leverage(self, symbol: str, leverage: int = None, force: bool = False, side: str = None) -> bool:
        """
        تعيين الرافعة المالية على المنصة.
        
        Args:
            symbol: رمز السوق
            leverage: الرافعة المطلوبة (default: 10x)
            force: إذا True، يتخطى الـ cooldown
            side: جانب الصفقة (BUY/SELL) - اختياري
        """
        if leverage is None:
            leverage = self._target_leverage
        sym = normalize_symbol(symbol)
        
        with self._lock:
            now = time.time()
            
            # التحقق من الذاكرة أولاً (يتخطى set_leverage إذا كانت صحيحة)
            if not force and sym in self._verification_cache:
                cached = self._verification_cache[sym]
                if now - cached.get("timestamp", 0) < self._verification_ttl:
                    if cached.get("leverage") == leverage and cached.get("verified"):
                        return True
            
            # التحقق من وقت آخر محاولة (يتخطى إذا force=True)
            if not force:
                last_time = self._last_set_time.get(sym, 0)
                if now - last_time < self._cooldown_seconds:
                    if sym in self._leverage_cache and self._leverage_cache[sym] == leverage:
                        return True
            
            # محاولة التغيير
            success = self._try_set_leverage(sym, leverage, side)
            
            if success:
                self._last_set_time[sym] = now
                self._leverage_cache[sym] = leverage
                self._verification_cache[sym] = {"leverage": leverage, "timestamp": now, "verified": True}
                self._update_state_verified_leverage(sym, leverage, True)
                return True
            else:
                self._verification_cache[sym] = {"leverage": leverage, "timestamp": now, "verified": False}
                self._update_state_verified_leverage(sym, leverage, False)
                return False

    def _update_state_verified_leverage(self, sym: str, leverage: int, verified: bool):
        """تحديث STATE["verified_leverage"][symbol]."""
        try:
            if "verified_leverage" not in STATE:
                STATE["verified_leverage"] = {}
            STATE["verified_leverage"][sym] = {
                "leverage": leverage,
                "verified": verified,
                "timestamp": time.time(),
                "confirmed": verified
            }
        except Exception:
            pass

    def verify_leverage(self, symbol: str, force: bool = False) -> Optional[int]:
        """
        التحقق من الرافعة الفعلية على المنصة.
        
        Test 2: إذا Network Error → يُرجع None → Entry يتوقف
        
        API Priority:
        1. fetch_positions() - معلومات المركز
        2. fetch_account() - معلومات الحساب
        """
        sym = normalize_symbol(symbol)
        
        with self._lock:
            # التحقق من الذاكرة أولاً
            if not force and sym in self._verification_cache:
                cached = self._verification_cache[sym]
                if time.time() - cached.get("timestamp", 0) < self._verification_ttl:
                    if cached.get("verified"):
                        return cached.get("leverage")
            
            if PAPER_MODE:
                return self._target_leverage
            
            try:
                # الطريقة 1: fetch_positions()
                if hasattr(ex, 'fetch_positions'):
                    positions = safe_api_call(ex.fetch_positions, [sym])
                    if positions:
                        for pos in positions:
                            pos_sym = pos.get('symbol', '')
                            info_sym = pos.get('info', {}).get('symbol', '')
                            if sym in pos_sym or sym in info_sym:
                                lev = int(float(pos.get('leverage', 0)))
                                if lev == 0:
                                    lev = int(float(pos.get('info', {}).get('leverage', self._target_leverage)))
                                self._verification_cache[sym] = {"leverage": lev, "timestamp": time.time(), "verified": True}
                                self._update_state_verified_leverage(sym, lev, True)
                                return lev
                
                # الطريقة 2: fetch_account()
                if hasattr(ex, 'fetch_account'):
                    account = safe_api_call(ex.fetch_account)
                    if account and 'positions' in account:
                        for pos in account['positions']:
                            pos_sym = pos.get('symbol', '')
                            if sym in pos_sym or sym in normalize_symbol(pos_sym):
                                lev = int(float(pos.get('leverage', self._target_leverage)))
                                self._verification_cache[sym] = {"leverage": lev, "timestamp": time.time(), "verified": True}
                                self._update_state_verified_leverage(sym, lev, True)
                                return lev
                
                # فشل - لم نتمكن من التحقق (لا يوجد مركز أو API لا يُرجع بيانات)
                log_execution(f"[LEVERAGE] Could not verify leverage for {sym} - API returned no position data (this is normal for empty positions)", "WARN")
                return None
                
            except Exception as e:
                # خطأ شبكة أو API
                log_execution(f"[LEVERAGE] Verification error for {sym}: {e}", "ERROR")
                self._send_leverage_error(sym, self._target_leverage, str(e), "VERIFICATION_ERROR")
                return None

    def ensure_leverage(self, symbol: str, force: bool = False) -> bool:
        """
        ضمان أن الرافعة 10x مطبقة على المنصة.
        
        Args:
            symbol: رمز السوق
            force: إذا True، يتخطى الـ cooldown ويُعيد التحقق
        """
        sym = normalize_symbol(symbol)
        
        # التحقق أولاً (يتخطى set_leverage إذا كانت صحيحة)
        current = self.verify_leverage(sym, force=force)
        
        if current == self._target_leverage:
            # الرافعة صحيحة
            return True
        
        if current is None:
            # API لم يُرجع بيانات - هذا طبيعي إذا لم يكن هناك صفقة مفتوحة
            # لا نحاول تعيين الرافعة لأن setLeverage يتطلب وجود مركز
            # التحقق الفعلي من الرافعة يحدث قبل فتح الصفقة مباشرة
            log_execution(f"[LEVERAGE] No position data for {sym} (normal if no open trade) - leverage will be verified before entry", "INFO")
            return True

        # الرافعة مختلفة، محاولة التغيير
        log_execution(f"[LEVERAGE] Current leverage {current}x != target {self._target_leverage}x, changing...", "WARN")
        
        if self.set_leverage(sym, self._target_leverage, force=force):
            new_leverage = self.verify_leverage(sym, force=True)
            if new_leverage == self._target_leverage:
                log_execution(f"[LEVERAGE] Leverage verified at {self._target_leverage}x for {sym}", "SUCCESS")
                return True
            elif new_leverage is None:
                # API لا يُرجع بيانات، لكن set نجح - افترض النجاح
                log_execution(f"[LEVERAGE] Leverage set to {self._target_leverage}x for {sym} (set verified, API read returned None)", "SUCCESS")
                return True
            else:
                log_execution(f"[LEVERAGE] Leverage change verification failed for {sym}: {new_leverage}x", "ERROR")
                self._send_leverage_error(sym, self._target_leverage, f"Verification shows {new_leverage}x", "VERIFICATION_MISMATCH")
                return False
        
        return False

    def check_before_entry(self, symbol: str) -> Tuple[bool, str]:
        """
        فحص شامل قبل فتح الصفقة.
        
        Test 1: إذا الرافعة 10x → set_leverage لا يُستدعى
        Test 2: إذا Network Error → Entry يتوقف
        
        Returns:
            (نجاح, رسالة)
        """
        sym = normalize_symbol(symbol)
        
        success = self.ensure_leverage(sym, force=False)
        
        if success:
            return True, f"🔒 Leverage {self._target_leverage}x CONFIRMED for {sym}"
        else:
            return False, f"🔴 LEVERAGE FAILED for {sym} | Expected: {self._target_leverage}x | Entry BLOCKED"

    def on_symbol_change(self, new_symbol: str):
        """يُستدعى عند تغيير الرمز المتداول."""
        sym = normalize_symbol(new_symbol)
        if self._current_symbol != sym:
            self._current_symbol = sym
            self.set_leverage(sym, self._target_leverage, force=True)
            log_execution(f"[LEVERAGE] Symbol changed to {sym}, leverage reset (force)", "INFO")

    def on_startup(self):
        """يُستدعى عند بدء التشغيل."""
        with self._lock:
            self._leverage_cache.clear()
            self._verification_cache.clear()
            self._last_set_time.clear()
        log_execution(f"[LEVERAGE] Startup: target leverage is {self._target_leverage}x for all trades", "INFO")

    def on_exchange_restart(self):
        """يُستدعى عند إعادة تشغيل Exchange."""
        with self._lock:
            self._leverage_cache.clear()
            self._verification_cache.clear()
            self._last_set_time.clear()
        log_execution(f"[LEVERAGE] Exchange restart detected, clearing all leverage caches", "INFO")

    def _send_leverage_error(self, symbol: str, leverage: int, error: str, error_type: str):
        """إرسال تنبيه Telegram عند فشل الرافعة."""
        try:
            msg = (
                f"🔴 <b>LEVERAGE ERROR</b>\n\n"
                f"Symbol: <code>{symbol}</code>\n"
                f"Expected: <b>{leverage}x</b>\n"
                f"Error: <code>{error[:80]}</code>\n"
                f"Type: <b>{error_type}</b>\n\n"
                f"⚠️ Trade BLOCKED until resolved!"
            )
            _tg_send(msg)
        except:
            pass

    def get_status(self) -> dict:
        """الحصول على حالة الرافعة."""
        with self._lock:
            return {
                "target_leverage": self._target_leverage,
                "current_symbol": self._current_symbol,
                "leverage_cache": self._leverage_cache.copy(),
                "verification_cache": {
                    k: {"leverage": v.get("leverage"), "age": time.time() - v.get("timestamp", 0), "verified": v.get("verified")}
                    for k, v in self._verification_cache.items()
                },
                "cooldown_seconds": self._cooldown_seconds,
                "verification_ttl": self._verification_ttl,
            }

    def get_verified_leverage(self, symbol: str) -> Optional[dict]:
        """الحصول على تفاصيل الرافعة المحققة."""
        sym = normalize_symbol(symbol)
        with self._lock:
            return self._verification_cache.get(sym)


