def get_spread_bps(symbol):
    try:
        ob = get_orderbook_cached(symbol, 5)
        if ob and ob['asks'] and ob['bids']:
            ask = ob['asks'][0][0]
            bid = ob['bids'][0][0]
            return (ask - bid) / bid * 100
    except:
        pass
    return 100.0

def validate_dataframe(df, min_length=100):
    if df is None or not isinstance(df, pd.DataFrame) or df.empty:
        return False
    required = ["open", "high", "low", "close", "volume"]
    if not all(c in df.columns for c in required):
        return False
    if df[required].iloc[-min_length:].isna().any().any():
        return False
    if (df['close'].iloc[-min_length:] == 0).any():
        return False
    if df['close'].iloc[-min_length:].std() < 1e-8:
        return False
    return True

def get_ohlcv_safe(symbol, limit=120, htf=False):
    # Increase TTL during open trade to reduce API calls
    ttl = 10 if (STATE.get("open") or TRADE_STATE["in_position"]) else 30
    if htf:
        ttl = max(ttl, 30)
    cache_key = f"ohlcv_{symbol}_{INTERVAL}_{limit}_htf" if htf else f"ohlcv_{symbol}_{INTERVAL}_{limit}"
    cached = cache_get(cache_key, ttl)
    if cached is not None:
        if len(cached) >= 100:
            return cached
    if htf:
        df = fetch_ohlcv_htf(symbol, '1h', limit)
    else:
        df = fetch_ohlcv(symbol, limit)
    if df is not None and validate_dataframe(df, min(limit, 100)):
        cache_set(cache_key, df)
        return df
    return None

def get_ticker_safe(symbol):
    # Use short TTL for live price
    cached = cache_get(f"ticker_{symbol}", 1)
    if cached is not None:
        return cached
    ticker = fetch_ticker(symbol)
    if ticker:
        price = ticker["last"]
        if price and price > 0:
            cache_set(f"ticker_{symbol}", price)
            return price
    return None

def get_balance_safe():
    """Get total balance using centralized cache (prevents rate limit)."""
    bal = get_cached_balance(force_refresh=False)
    if bal:
        return bal.get("total", {}).get("USDT", 0.0)
    return 0.0

def get_free_balance_safe():
    """Get free balance using centralized cache (prevents rate limit)."""
    bal = get_cached_balance(force_refresh=False)
    if bal:
        return bal.get("free", {}).get("USDT", 0.0)
    return 0.0

def get_orderbook_cached(symbol, limit=20):
    # During live trade, avoid fetching orderbook to save API calls
    if STATE.get("open") or TRADE_STATE["in_position"]:
        cached = cache_get(f"ob_{symbol}_{limit}", 60)  # long TTL
        if cached is not None:
            return cached
        return None  # don't fetch during trade
    cached = cache_get(f"ob_{symbol}_{limit}", 1)
    if cached is not None:
        return cached
    ob = fetch_orderbook(symbol, limit)
    if ob:
        cache_set(f"ob_{symbol}_{limit}", ob)
    return ob

# ========== EXCHANGE POSITION SYNC ==========
def fetch_position(symbol):
    if PAPER_MODE:
        return None
    try:
        sym = normalize_symbol(symbol)
        if hasattr(ex, 'fetch_positions'):
            positions = safe_api_call(ex.fetch_positions, [sym])
        elif hasattr(ex, 'fetch_open_positions'):
            positions = safe_api_call(ex.fetch_open_positions, [sym])
        else:
            return None
        if not positions:
            return None
        for pos in positions:
            pos_sym = pos.get('symbol', '')
            if normalize_symbol(symbol) in pos_sym and float(pos.get('contracts', 0)) > 0:
                return pos
        return None
    except Exception as e:
        log_execution(f"[POS_SYNC] fetch_position error: {e}", "ERROR")
        return None

def get_mark_price(symbol):
    if PAPER_MODE:
        return get_ticker_safe(symbol)
    pos = fetch_position(symbol)
    if pos and 'markPrice' in pos and pos['markPrice']:
        return float(pos['markPrice'])
    return get_ticker_safe(symbol)

# ========== TRADE THESIS ENGINE ==========
from dataclasses import dataclass, field

@dataclass
class TradeThesis:
    thesis_id: str
    symbol: str
    side: str
    trade_type: str
    created_at: float
    entry_reason: List[str] = field(default_factory=list)
    continuation_factors: List[str] = field(default_factory=list)
    invalidation_factors: List[str] = field(default_factory=list)
    risk_factors: List[str] = field(default_factory=list)
    market_context: Dict = field(default_factory=dict)
    confidence: float = 0.0
    continuation_probability: float = 0.5
    exhaustion_probability: float = 0.0
    thesis_strength: float = 0.0
    current_status: str = "ACTIVE"
    last_update: float = field(default_factory=time.time)

class TradeThesisEngine:
    def build_thesis(self, symbol: str, side: str, trade_type: str, market_state: Dict,
                     narrative: Dict, entry_context: Dict) -> TradeThesis:
        reasons = []
        continuation = []
        invalidation = []
        risks = []
        adx = market_state.get("adx", 0)
        regime = market_state.get("regime", "UNKNOWN")
        continuation_probability = 0.5
        if adx > 25:
            reasons.append("strong_trend_environment")
            continuation.append("adx_expansion")
            continuation_probability += 0.1
        if market_state.get("di_dominance", False):
            reasons.append("di_dominance")
            continuation.append("persistent_pressure")
            continuation_probability += 0.1
        if market_state.get("weak_pullback", False):
            reasons.append("weak_pullback")
            continuation.append("counter_move_weakness")
            continuation_probability += 0.1
        if market_state.get("structure_aligned", False):
            reasons.append("market_structure_alignment")
            continuation_probability += 0.1
        narrative_class = narrative.get("classification", "NEUTRAL")
        if narrative_class in ("TREND_CONTINUATION", "INSTITUTIONAL_CONTINUATION"):
            reasons.append("institutional_narrative_alignment")
            continuation_probability += 0.1
        if adx > 45:
            risks.append("trend_exhaustion_risk")
        if market_state.get("counter_displacement", 0) > 1.0:
            risks.append("counter_displacement_risk")
        if regime == "CHOP":
            risks.append("choppy_environment")
        invalidation.extend(["ema_loss", "di_flip", "failed_continuation", "vwap_reclaim", "strong_counter_displacement"])
        confidence = min(continuation_probability, 0.95)
        thesis_strength = (len(reasons) * 1.2 + len(continuation) * 1.5 - len(risks) * 0.8)
        thesis = TradeThesis(
            thesis_id=f"{symbol}_{int(time.time())}",
            symbol=symbol,
            side=side,
            trade_type=trade_type,
            created_at=time.time(),
            entry_reason=reasons,
            continuation_factors=continuation,
            invalidation_factors=invalidation,
            risk_factors=risks,
            market_context=market_state,
            confidence=round(confidence, 2),
            continuation_probability=round(continuation_probability, 2),
            exhaustion_probability=0.0,
            thesis_strength=round(thesis_strength, 2)
        )
        return thesis

    def update_thesis(self, thesis: TradeThesis, market_state: Dict) -> TradeThesis:
        continuation_prob = thesis.continuation_probability
        exhaustion_prob = thesis.exhaustion_probability
        trend_health = market_state.get("trend_health", 5)
        if trend_health >= 7:
            continuation_prob += 0.05
        elif trend_health <= 3:
            continuation_prob -= 0.1
        adx_slope = market_state.get("adx_slope", 0)
        if adx_slope > 0:
            continuation_prob += 0.05
        else:
            continuation_prob -= 0.03
        counter_displacement = market_state.get("counter_displacement", 0)
        if counter_displacement > 1.2:
            continuation_prob -= 0.15
            exhaustion_prob += 0.2
        if market_state.get("weak_pullback", False):
            continuation_prob += 0.08
        continuation_prob = max(0.0, min(1.0, continuation_prob))
        exhaustion_prob = max(0.0, min(1.0, exhaustion_prob))
        thesis.continuation_probability = round(continuation_prob, 2)
        thesis.exhaustion_probability = round(exhaustion_prob, 2)
        thesis.last_update = time.time()
        return thesis

_thesis_engine = TradeThesisEngine()

# ========== REJECTION INTELLIGENCE ENGINE ==========
class RejectionIntelligence:
    @staticmethod
    def is_bearish_rejection(df, atr, zone_price=None):
        if len(df) < 1:
            return False, []
        last = df.iloc[-1]
        body = abs(last['close'] - last['open'])
        range_ = last['high'] - last['low']
        if range_ == 0:
            return False, []
        upper_wick = last['high'] - max(last['open'], last['close'])
        wick_condition = upper_wick >= 1.5 * body
        close_near_low = (last['close'] - last['low']) / range_ <= 0.3
        zone_failure = False
        if zone_price is not None:
            zone_failure = last['close'] < zone_price
        if len(df) >= 3:
            prev2 = df.iloc[-2]
            prev3 = df.iloc[-3]
            weak_continuation = (prev2['close'] < prev2['open'] or prev3['close'] < prev3['open'])
        else:
            weak_continuation = False
        vol_state = classify_volume(df)
        volume_ok = vol_state in ("expansion", "spike") and df['volume'].iloc[-1] < df['volume'].rolling(20).mean().iloc[-1] * 1.2
        di_plus, di_minus, _, _ = get_di_components(df)
        di_ok = (di_minus is not None and di_plus is not None and di_minus > di_plus and (di_minus - di_plus) > 2)
        is_shooting_star = (body / range_ <= 0.3 and upper_wick >= 2 * body and last['close'] < last['open'])
        is_bearish_engulfing = False
        if len(df) >= 2:
            prev = df.iloc[-2]
            is_bearish_engulfing = (prev['close'] > prev['open'] and last['close'] < last['open'] and
                                     last['high'] > prev['high'] and last['low'] < prev['low'])
        reasons = []
        score = 0
        if wick_condition:
            score += 2
            reasons.append("long_upper_wick")
        if close_near_low:
            score += 1
            reasons.append("close_near_low")
        if zone_failure:
            score += 2
            reasons.append("zone_failure")
        if weak_continuation:
            score += 1
            reasons.append("weak_continuation")
        if volume_ok:
            score += 1
            reasons.append("volume_absorption")
        if di_ok:
            score += 2
            reasons.append("di_dominance_sell")
        if is_shooting_star:
            score += 1.5
            reasons.append("shooting_star")
        if is_bearish_engulfing:
            score += 2
            reasons.append("bearish_engulfing")
        is_valid = score >= 5
        return is_valid, reasons

    @staticmethod
    def is_bullish_rejection(df, atr, zone_price=None):
        if len(df) < 1:
            return False, []
        last = df.iloc[-1]
        body = abs(last['close'] - last['open'])
        range_ = last['high'] - last['low']
        if range_ == 0:
            return False, []
        lower_wick = min(last['open'], last['close']) - last['low']
        wick_condition = lower_wick >= 1.5 * body
        close_near_high = (last['high'] - last['close']) / range_ <= 0.3
        zone_failure = False
        if zone_price is not None:
            zone_failure = last['close'] > zone_price
        if len(df) >= 3:
            prev2 = df.iloc[-2]
            prev3 = df.iloc[-3]
            weak_continuation = (prev2['close'] > prev2['open'] or prev3['close'] > prev3['open'])
        else:
            weak_continuation = False
        vol_state = classify_volume(df)
        volume_ok = vol_state in ("expansion", "spike") and df['volume'].iloc[-1] < df['volume'].rolling(20).mean().iloc[-1] * 1.2
        di_plus, di_minus, _, _ = get_di_components(df)
        di_ok = (di_plus is not None and di_minus is not None and di_plus > di_minus and (di_plus - di_minus) > 2)
        is_hammer = (body / range_ <= 0.3 and lower_wick >= 2 * body and last['close'] > last['open'])
        is_bullish_engulfing = False
        if len(df) >= 2:
            prev = df.iloc[-2]
            is_bullish_engulfing = (prev['close'] < prev['open'] and last['close'] > last['open'] and
                                     last['high'] > prev['high'] and last['low'] < prev['low'])
        reasons = []
        score = 0
        if wick_condition:
            score += 2
            reasons.append("long_lower_wick")
        if close_near_high:
            score += 1
            reasons.append("close_near_high")
        if zone_failure:
            score += 2
            reasons.append("zone_failure")
        if weak_continuation:
            score += 1
            reasons.append("weak_continuation")
        if volume_ok:
            score += 1
            reasons.append("volume_absorption")
        if di_ok:
            score += 2
            reasons.append("di_dominance_buy")
        if is_hammer:
            score += 1.5
            reasons.append("hammer")
        if is_bullish_engulfing:
            score += 2
            reasons.append("bullish_engulfing")
        is_valid = score >= 5
        return is_valid, reasons

# ========== MSS / CHOCH VALIDATION ==========
class MSSValidator:
    @staticmethod
    def validate_structure_shift(df, side, atr):
        if len(df) < 10:
            return False, [], 0
        last = df.iloc[-1]
        prev = df.iloc[-2]
        body = abs(last['close'] - last['open'])
        prev_body = abs(prev['close'] - prev['open'])
        displacement_strength = body / (prev_body + 1e-9) if prev_body > 0 else 1.0
        body_expansion = displacement_strength >= 1.5
        follow_through = False
        if len(df) >= 3:
            next_candle = df.iloc[-1]
            if side == "BUY":
                follow_through = next_candle['close'] > next_candle['open'] and body > prev_body
            else:
                follow_through = next_candle['close'] < next_candle['open'] and body > prev_body
        else:
            follow_through = True
        di_plus, di_minus, adx, adx_slope = get_di_components(df)
        di_spread = abs(di_plus - di_minus) if di_plus is not None and di_minus is not None else 0
        vol_state = classify_volume(df)
        volume_ok = vol_state in ("expansion", "spike")
        adx_acc = adx_slope > 0 and adx > 25
        score = 0
        reasons = []
        if body_expansion:
            score += 2
            reasons.append("body_expansion")
        if follow_through:
            score += 2
            reasons.append("follow_through")
        if di_spread > 8:
            score += 2
            reasons.append("di_spread_strong")
        if volume_ok:
            score += 1
            reasons.append("volume_confirm")
        if adx_acc:
            score += 2
            reasons.append("adx_accelerating")
        is_valid = score >= 5
        if adx < 20:
            is_valid = False
            reasons.append("adx_too_low")
        if not body_expansion and not follow_through:
            is_valid = False
            reasons.append("weak_displacement")
        return is_valid, reasons, score

# ========== ADX + DI INTELLIGENCE ==========
class ADXDIIntelligence:
    @staticmethod
    def get_adx_state(df):
        adx_series = compute_adx(df)
        if adx_series is None or len(adx_series) < 3:
            return {"state": "UNKNOWN", "value": 20, "slope": 0, "acceleration": 0}
        adx_val = adx_series.iloc[-1]
        adx_prev = adx_series.iloc[-2]
        adx_prev2 = adx_series.iloc[-3] if len(adx_series) >= 3 else adx_prev
        slope = adx_val - adx_prev
        accel = slope - (adx_prev - adx_prev2)
        if adx_val < 18:
            state = "CHOP"
        elif 18 <= adx_val < 22:
            state = "EMERGING"
        elif 22 <= adx_val < 35:
            state = "STRONG_TREND"
        elif 35 <= adx_val < 45:
            state = "VERY_STRONG"
        else:
            state = "EXHAUSTION"
        return {"state": state, "value": adx_val, "slope": slope, "acceleration": accel}

    @staticmethod
    def get_di_state(df):
        plus_di, minus_di, _, _ = get_di_components(df)
        if plus_di is None or minus_di is None:
            return {"dominant": "NEUTRAL", "spread": 0, "trend": "NEUTRAL"}
        spread = plus_di - minus_di
        if spread > 5:
            dominant = "BUY"
            trend = "BULLISH"
        elif spread < -5:
            dominant = "SELL"
            trend = "BEARISH"
        else:
            dominant = "NEUTRAL"
            trend = "CHOP"
        return {"dominant": dominant, "spread": spread, "trend": trend}

    @staticmethod
    def is_healthy_trend(df, side):
        adx_state = ADXDIIntelligence.get_adx_state(df)
        di_state = ADXDIIntelligence.get_di_state(df)
        if side == "BUY":
            return adx_state["state"] in ("STRONG_TREND", "VERY_STRONG") and di_state["dominant"] == "BUY" and adx_state["slope"] > 0
        else:
            return adx_state["state"] in ("STRONG_TREND", "VERY_STRONG") and di_state["dominant"] == "SELL" and adx_state["slope"] > 0

# ========== CONTINUATION PRESSURE ENGINE ==========
class ContinuationPressureEngine:
    @staticmethod
    def calculate_pressure(df, side, entry_price, atr, entry_time):
        if len(df) < 3:
            return 50, []
        score = 50
        reasons = []
        bodies = [abs(df['close'].iloc[-i] - df['open'].iloc[-i]) for i in range(1, 4)]
        if len(bodies) >= 2:
            growth = bodies[0] / (bodies[1] + 1e-9)
            if growth > 1.2:
                score += 10
                reasons.append("body_expansion")
            elif growth < 0.8:
                score -= 10
                reasons.append("body_contraction")
        adx_state = ADXDIIntelligence.get_adx_state(df)
        di_state = ADXDIIntelligence.get_di_state(df)
        if side == "BUY" and adx_state["slope"] > 0 and di_state["dominant"] == "BUY":
            score += 15
            reasons.append("adx_rising_di_bullish")
        elif side == "SELL" and adx_state["slope"] > 0 and di_state["dominant"] == "SELL":
            score += 15
            reasons.append("adx_rising_di_bearish")
        elif adx_state["slope"] <= 0:
            score -= 10
            reasons.append("adx_falling")
        if di_state["spread"] > 10:
            score += 10
            reasons.append("di_spread_wide")
        elif abs(di_state["spread"]) < 4:
            score -= 10
            reasons.append("di_tangled")
        vol_state = classify_volume(df)
        if vol_state == "expansion":
            score += 15
            reasons.append("volume_expansion")
        elif vol_state == "exhaustion":
            score -= 15
            reasons.append("volume_exhaustion")
        last_close = df['close'].iloc[-1]
        if side == "BUY" and last_close < entry_price:
            score -= 10
            reasons.append("price_below_entry")
        elif side == "SELL" and last_close > entry_price:
            score -= 10
            reasons.append("price_above_entry")
        consecutive = 0
        for i in range(1, min(5, len(df))):
            if side == "BUY" and df['close'].iloc[-i] > df['open'].iloc[-i]:
                consecutive += 1
            elif side == "SELL" and df['close'].iloc[-i] < df['open'].iloc[-i]:
                consecutive += 1
            else:
                break
        if consecutive >= 3:
            score += 10
            reasons.append(f"consecutive_{consecutive}")
        elif consecutive == 0:
            score -= 5
            reasons.append("no_follow_through")
        score = max(0, min(100, score))
        return score, reasons

# ========== THESIS FAILURE ENGINE ==========
class ThesisFailureEngine:
    @staticmethod
    def evaluate_failure(thesis: Dict, market_state: Dict, current_price, entry_price, side):
        if not thesis:
            return False, [], 0
        failure_score = 0
        reasons = []
        if market_state.get("strong_reclaim", False):
            failure_score += 30
            reasons.append("strong_reclaim")
        di_state = ADXDIIntelligence.get_di_state(market_state.get("df", None))
        if side == "BUY" and di_state.get("dominant") == "SELL":
            failure_score += 25
            reasons.append("di_flip_bearish")
        elif side == "SELL" and di_state.get("dominant") == "BUY":
            failure_score += 25
            reasons.append("di_flip_bullish")
        adx_state = ADXDIIntelligence.get_adx_state(market_state.get("df", None))
        if adx_state.get("state") == "CHOP" and adx_state.get("value") < 18:
            failure_score += 20
            reasons.append("adx_collapse")
        last_candle = market_state.get("last_candle", {})
        if side == "SELL" and last_candle.get("close", 0) > last_candle.get("open", 0):
            body = abs(last_candle.get("close",0)-last_candle.get("open",0))
            if body > market_state.get("atr", 0) * 0.6:
                failure_score += 20
                reasons.append("strong_bullish_candle")
        elif side == "BUY" and last_candle.get("close", 0) < last_candle.get("open", 0):
            body = abs(last_candle.get("close",0)-last_candle.get("open",0))
            if body > market_state.get("atr", 0) * 0.6:
                failure_score += 20
                reasons.append("strong_bearish_candle")
        continuation_pressure = market_state.get("continuation_pressure", 50)
        if continuation_pressure < 30:
            failure_score += 25
            reasons.append("low_continuation_pressure")
        sl_distance = abs(current_price - thesis.get("sl", entry_price)) / entry_price
        if sl_distance < 0.005:
            failure_score += 15
            reasons.append("sl_too_close")
        failed = failure_score >= 50
        return failed, reasons, failure_score

# ========== DYNAMIC STRATEGY ENGINE ==========
# Based on TradingView Ultimate Sniper Pro + L&L Trend System
# Extracts professional logic and applies dynamically

class DynamicStrategyEngine:
    """
    Dynamic Strategy Engine - Based on TradingView Analysis
    
    Strategy Types:
    - TREND_CONTINUATION: Follow the trend with structure confirmation
    - LIQUIDITY_REVERSAL: Catch reversals at liquidity zones
    - BREAKOUT: Trade breakouts with momentum confirmation
    - RANGE_MEAN_REVERSION: Trade range boundaries with exhaustion
    
    Scoring System:
    - Each element contributes to final score based on trade type
    - No single filter blocks trade - everything is weighted
    - Final score determines entry readiness
    """
    
    # Scoring weights for each strategy type
    WEIGHTS = {
        "TREND_CONTINUATION": {
            "adx": 3,        # ADX > 20 = strong trend
            "dmi": 3,        # DMI in trend direction
            "ema_cloud": 3,  # EMA alignment (8>13>21>34)
            "volume": 2,     # Volume confirmation
            "structure": 3,  # BOS/CHoCH confirmation
            "sweep": 1,      # Sweep less important for trends
            "mss": 2,       # MSS as confirmation
            "exhaustion": 1, # Exhaustion not needed
            "overextended": 2, # Overextension confirmation
            "vwap": 1,      # VWAP context
            "candle": 2     # Candle quality
        },
        "LIQUIDITY_REVERSAL": {
            "adx": 1,        # ADX less important for reversals
            "dmi": 1,        # DMI less important
            "ema_cloud": 1,  # EMA less important
            "volume": 3,     # Volume critical for reversals
            "structure": 2,  # Structure (CHoCH, MSS) important
            "sweep": 3,      # Sweep IS the setup!
            "mss": 2,       # MSS confirmation
            "exhaustion": 3, # Exhaustion confirms reversal
            "overextended": 2, # Overextension context
            "vwap": 2,      # VWAP as reference
            "candle": 2     # Candle rejection quality
        },
        "BREAKOUT": {
            "adx": 2,        # ADX for momentum
            "dmi": 2,        # DMI confirmation
            "ema_cloud": 2,  # EMA trend alignment
            "volume": 3,     # Volume expansion critical
            "structure": 3,  # Structure break is the setup
            "sweep": 1,      # Sweep less important
            "mss": 3,       # MSS IS the setup!
            "exhaustion": 1, # Exhaustion less important
            "overextended": 1, # Overextended less important
            "vwap": 1,      # VWAP context
            "candle": 2     # Candle quality
        },
        "RANGE_MEAN_REVERSION": {
            "adx": 1,        # ADX low = range
            "dmi": 1,        # DMI weak = range
            "ema_cloud": 1,  # EMA in middle = range
            "volume": 1,     # Volume less critical
            "structure": 1,  # Range boundaries
            "sweep": 2,      # Sweep at boundaries
            "mss": 1,       # MSS less important
            "exhaustion": 2, # Exhaustion at edges
            "overextended": 2, # Overextended from mean
            "vwap": 3,      # VWAP is the mean!
            "candle": 2     # Candle rejection at boundaries
        }
    }
    
    # Score thresholds
    ENTRY_THRESHOLD = 14  # 70% of max (20)
    STRONG_THRESHOLD = 16  # 80% for STRONG signals
    
    @classmethod
    def analyze(cls, df, smart_money=None, momentum=None, market_phase=None, 
                narrative=None, structure_data=None, volume_data=None):
        """
        Analyze symbol and return dynamic strategy scores.
        
        Diagnostics:
        - Element sources logging
        - Element scores logging
        - Confidence tracing
        - Duration measurement
        """
        # Start diagnostic session
        session = DiagnosticSession("DYNAMIC_STRATEGY")
        
        with session:
            if df is None or len(df) < 30:
                session.record_failure("Insufficient data")
                return cls._null_result(reason="Insufficient data")
            
            # Extract element scores
            elements, sources = cls._extract_elements(df, smart_money, momentum, market_phase, narrative, structure_data, volume_data)
            
            if not elements:
                session.record_failure("Element extraction failed")
                return cls._null_result(reason="Element extraction failed")
            
            # If all elements are zero, log warning but continue
            if all(v == 0 for v in elements.values()):
                session.record_failure("All element scores are zero")
                if DEBUG_CONFIDENCE_TRACE:
                    log_execution(f"{diag_prefix()} WARNING: All element scores are zero", "DEBUG")
            
            # Calculate scores for each strategy
            scores = {}
            for strategy, weights in cls.WEIGHTS.items():
                score = cls._calculate_strategy_score(strategy, elements, weights)
                scores[strategy] = score
            
            # Determine best strategy
            best_strategy = max(scores, key=scores.get)
            best_score = scores[best_strategy]
            
            # Calculate confidence
            confidence = cls._calculate_confidence(elements, best_strategy)
            
            # Determine entry readiness
            if best_score >= cls.STRONG_THRESHOLD:
                entry_readiness = "READY"
            elif best_score >= cls.ENTRY_THRESHOLD:
                entry_readiness = "ANALYZING"
            else:
                entry_readiness = "NOT_READY"
            
            # FORENSIC: Log readiness decision with detailed breakdown
            # NEVER let forensic errors stop the pipeline!
            try:
                lifecycle_id = DIAG_CTX.get_lifecycle_id()
                if lifecycle_id:
                    # Calculate contribution breakdown
                    contribution_breakdown = {}
                    total_contribution = 0
                    for elem_name, score in elements.items():
                        weight = 1.0 / len(elements) if len(elements) > 0 else 0
                        contrib = score * weight
                        total_contribution += contrib
                        passed = score >= 50 if entry_readiness == "READY" else score < 30
                        contribution_breakdown[elem_name] = {
                            "weight": f"{weight*100:.1f}%",
                            "raw": f"{score:.1f}",
                            "contribution": f"{contrib:.1f}",
                            "passed": passed,
                        }
                    
                    # Get symbol/side from narrative if available
                    sym = narrative.get("symbol", "UNKNOWN") if narrative else "UNKNOWN"
                    sde = narrative.get("side", "UNKNOWN") if narrative else "UNKNOWN"
                    
                    if entry_readiness != "READY":
                        # Log rejection
                        log_pipeline_stage(
                            lifecycle_id, "READINESS", False,
                            expected=f">={cls.STRONG_THRESHOLD}",
                            actual=f"{best_score:.1f}",
                            reason=f"Confidence={confidence:.1f}%, Entry below threshold",
                            contribution=total_contribution,
                        )
                        
                        # Create rejection report
                        evidence_breakdown = {}
                        for elem_name, data in contribution_breakdown.items():
                            evidence_breakdown[elem_name] = data
                        
                        create_rejection_report(
                            lifecycle_id=lifecycle_id,
                            symbol=sym,
                            side=sde,
                            current_stage="READINESS",
                            rejection_reasons=[
                                {"stage": "READINESS", "reason": f"Score {best_score:.1f} < {cls.STRONG_THRESHOLD}", 
                                 "expected": f">={cls.STRONG_THRESHOLD}", "actual": f"{best_score:.1f}"},
                                {"stage": "CONFIDENCE", "reason": f"Confidence {confidence:.1f}%", "actual": f"{confidence:.1f}%"},
                            ],
                            evidence_breakdown=evidence_breakdown,
                            composite_score=best_score,
                            composite_confidence=confidence,
                        )
                    else:
                        # Log pass
                        log_pipeline_stage(
                            lifecycle_id, "READINESS", True,
                            expected=f">={cls.STRONG_THRESHOLD}",
                            actual=f"{best_score:.1f}",
                            contribution=total_contribution,
                        )
            except Exception as forensic_err:
                # FORENSIC MUST NEVER STOP TRADING PIPELINE
                log_execution(f"[FORENSIC ERROR] Pipeline safety catch: {forensic_err}", "WARN")
            
            # Determine trade quality
            if best_score >= cls.STRONG_THRESHOLD and confidence >= 70:
                trade_quality = "HIGH"
            elif best_score >= cls.ENTRY_THRESHOLD and confidence >= 50:
                trade_quality = "MEDIUM"
            else:
                trade_quality = "LOW"
            
            # Diagnostic: Record element sources and scores
            if DEBUG_CONFIDENCE_TRACE:
                prefix = diag_prefix()
                log_execution(f"{prefix} DynamicStrategyEngine analyze: confidence={confidence}, best_score={best_score}, type={best_strategy}", "DEBUG")
                log_execution(f"{prefix} element_scores: {elements}", "DEBUG")
                log_execution(f"{prefix} element_sources: {sources}", "DEBUG")
                log_execution(f"{prefix} strategy_scores: {scores}", "DEBUG")
                
                # Trace confidence calculation
                diag_trace_confidence(
                    confidence,
                    threshold=cls.ENTRY_THRESHOLD,
                    reason=f"best_strategy={best_strategy}, best_score={best_score}"
                )
            
            # Record element diagnostics in session
            for elem_name, score in elements.items():
                source = sources.get(elem_name, "unknown")
                session.record_element(elem_name, score, source)
            
            # Set session result
            session.set_result(
                strategy_type=best_strategy,
                best_score=best_score,
                confidence=confidence,
                entry_readiness=entry_readiness,
                trade_quality=trade_quality,
                element_count=len(elements)
            )
            
            return {
                "strategy_type": best_strategy,
                "scores": scores,
                "element_scores": elements,
                "element_sources": sources,
                "confidence": confidence,
                "entry_readiness": entry_readiness,
                "trade_quality": trade_quality,
                "best_score": best_score,
                "failure_reason": None
            }
    
    @classmethod
    def _null_result(cls, reason="Insufficient data"):
        return {
            "strategy_type": "UNKNOWN",
            "scores": {
                "TREND_CONTINUATION": 0,
                "LIQUIDITY_REVERSAL": 0,
                "BREAKOUT": 0,
                "RANGE_MEAN_REVERSION": 0
            },
            "element_scores": {},
            "element_sources": {},
            "confidence": 0,
            "entry_readiness": "NOT_READY",
            "trade_quality": "LOW",
            "best_score": 0,
            "failure_reason": reason
        }
    
    @classmethod
    def _extract_elements(cls, df, smart_money, momentum, market_phase, narrative, structure_data, volume_data):
        """Extract individual element scores from available data.
        
        Returns:
            tuple: (elements dict, sources dict)
        """
        elements = {}
        sources = {}
        
        # === ADX Element ===
        # From TradingView: ADX < 18 = weak, 18-25 = moderate, > 25 = strong
        adx_val = cls._get_adx(df)
        if adx_val >= 25:
            elements["adx"] = 3  # Strong trend
            sources["adx"] = "df (ADX)"
        elif adx_val >= 20:
            elements["adx"] = 2  # Moderate trend
            sources["adx"] = "df (ADX)"
        elif adx_val >= 18:
            elements["adx"] = 1  # Weak trend
            sources["adx"] = "df (ADX)"
        else:
            elements["adx"] = 0  # No trend / chop
            sources["adx"] = "df (ADX)"
        
        # === DMI Element ===
        # From TradingView: DMI colored candles
        plus_di, minus_di = cls._get_di(df)
        di_spread = abs(plus_di - minus_di)
        if di_spread >= 15:
            elements["dmi"] = 3  # Strong directional
            sources["dmi"] = "df (DI)"
        elif di_spread >= 8:
            elements["dmi"] = 2  # Moderate directional
            sources["dmi"] = "df (DI)"
        elif di_spread >= 3:
            elements["dmi"] = 1  # Weak directional
            sources["dmi"] = "df (DI)"
        else:
            elements["dmi"] = 0  # No directional
            sources["dmi"] = "df (DI)"
        
        # === EMA Cloud Element ===
        # From TradingView: EMA 8, 13, 21, 34 alignment
        ema_cloud = cls._get_ema_cloud(df)
        elements["ema_cloud"] = ema_cloud
        sources["ema_cloud"] = "df (EMA)"
        
        # === Volume Element ===
        # From TradingView: Volume > MA * 1.5 = expansion
        vol_ratio = cls._get_volume_ratio(df)
        if vol_ratio >= 1.5:
            elements["volume"] = 3  # Strong expansion
            sources["volume"] = "df (Volume)"
        elif vol_ratio >= 1.2:
            elements["volume"] = 2  # Moderate expansion
            sources["volume"] = "df (Volume)"
        elif vol_ratio >= 1.0:
            elements["volume"] = 1  # Normal
            sources["volume"] = "df (Volume)"
        else:
            elements["volume"] = 0  # Low
            sources["volume"] = "df (Volume)"
        
        # === Structure Element ===
        # From TradingView: BOS/CHoCH detection
        structure_score = 0
        if structure_data:
            if structure_data.get("bos"):
                structure_score += 2
                sources["structure"] = "structure_data (BOS)"
            if structure_data.get("choch"):
                structure_score += 2
                sources["structure"] = "structure_data (CHoCH)"
            if structure_data.get("mss"):
                structure_score += 1
                sources["structure"] = "structure_data (MSS)"
            if "structure" not in sources:
                sources["structure"] = "structure_data (no signals)"
        else:
            sources["structure"] = "structure_data (missing)"
        elements["structure"] = min(3, structure_score)
        
        # === Sweep Element ===
        # From TradingView: X pattern (Sweep)
        sweep_score = 0
        if narrative:
            if narrative and narrative.get("sweep"):
                sweep_score = 3
                sources["sweep"] = "narrative (sweep)"
            elif narrative.get("retest"):
                sweep_score = 2
                sources["sweep"] = "narrative (retest)"
            else:
                sources["sweep"] = "narrative (none)"
        else:
            sources["sweep"] = "narrative (missing)"
        elements["sweep"] = sweep_score
        
        # === MSS Element ===
        # From TradingView: MSS pattern
        mss_score = 0
        if structure_data:
            if structure_data.get("mss"):
                mss_score = 3
                sources["mss"] = "structure_data (MSS)"
        if narrative and narrative.get("displacement"):
            mss_score = max(mss_score, 2)
            sources["mss"] = "narrative (displacement)"
        if "mss" not in sources:
            sources["mss"] = "none"
        elements["mss"] = min(3, mss_score)
        
        # === Exhaustion Element ===
        # From TradingView: Sniper Exhaustion Detection
        exhaustion = cls._detect_exhaustion(df)
        elements["exhaustion"] = exhaustion
        sources["exhaustion"] = "df (exhaustion)"
        
        # === Overextended Element ===
        # From TradingView: Distance from EMA > ATR * 2.0
        overextended = cls._detect_overextended(df)
        elements["overextended"] = overextended
        sources["overextended"] = "df (overextended)"
        
        # === VWAP Element ===
        # From TradingView: VWAP proximity
        vwap_score = cls._get_vwap_proximity(df)
        elements["vwap"] = vwap_score
        sources["vwap"] = "df (VWAP)"
        
        # === Candle Element ===
        # From TradingView: Strong candle detection
        candle_score = cls._get_candle_quality(df)
        elements["candle"] = candle_score
        sources["candle"] = "df (candle)"
        
        # Diagnostic logging of element sources
        if DEBUG_CONFIDENCE_TRACE:
            prefix = diag_prefix()
            log_execution(f"{prefix} ElementSources: {sources}", "DEBUG")
            log_execution(f"{prefix} ElementScores: {elements}", "DEBUG")
        
        return elements, sources
    
    @classmethod
    def _calculate_strategy_score(cls, strategy, elements, weights):
        """Calculate weighted score for a strategy."""
        total_weight = sum(weights.values())  # 22 total
        weighted_score = 0
        
        for element, score in elements.items():
            if element in weights:
                weight = weights[element]
                # Score contribution = (score/3) * weight
                contribution = (score / 3.0) * weight
                weighted_score += contribution
        
        # Normalize to 0-20 scale
        max_possible = total_weight
        normalized_score = (weighted_score / max_possible) * 20
        return round(normalized_score, 1)
    
    @classmethod
    def _calculate_confidence(cls, elements, strategy):
        """Calculate confidence based on element consistency."""
        # Count elements with score >= 2
        strong_elements = sum(1 for s in elements.values() if s >= 2)
        total_elements = len(elements)
        
        # Consistency ratio
        consistency = (strong_elements / total_elements) * 100 if total_elements > 0 else 0
        
        # Strategy-specific adjustments
        if strategy == "TREND_CONTINUATION":
            # Need trend elements
            trend_score = (elements.get("adx", 0) + elements.get("dmi", 0) + elements.get("ema_cloud", 0)) / 9 * 100
            confidence = (consistency * 0.4 + trend_score * 0.6)
        elif strategy == "LIQUIDITY_REVERSAL":
            # Need reversal elements
            reversal_score = (elements.get("sweep", 0) + elements.get("exhaustion", 0) + elements.get("candle", 0)) / 9 * 100
            confidence = (consistency * 0.4 + reversal_score * 0.6)
        elif strategy == "BREAKOUT":
            # Need breakout elements
            breakout_score = (elements.get("volume", 0) + elements.get("structure", 0) + elements.get("mss", 0)) / 9 * 100
            confidence = (consistency * 0.4 + breakout_score * 0.6)
        else:  # RANGE_MEAN_REVERSION
            confidence = consistency
        
        return round(min(100, max(0, confidence)), 1)
    
    @classmethod
    def _get_adx(cls, df):
        """Get ADX value."""
        try:
            adx_val, _ = compute_adx(df)
            if adx_val is not None and len(adx_val) > 0:
                return adx_val.iloc[-1]
        except:
            pass
        return 20  # Default
    
    @classmethod
    def _get_di(cls, df):
        """Get DMI values."""
        try:
            plus_di, minus_di, _ = compute_adx(df)
            if plus_di is not None and len(plus_di) > 0:
                return plus_di.iloc[-1], minus_di.iloc[-1]
        except:
            pass
        return 20, 20  # Default
    
    @classmethod
    def _get_ema_cloud(cls, df):
        """Get EMA cloud alignment score (from L&L Trend System)."""
        try:
            closes = df['close']
            ema8 = ema(closes, 8).iloc[-1]
            ema13 = ema(closes, 13).iloc[-1]
            ema21 = ema(closes, 21).iloc[-1]
            ema34 = ema(closes, 34).iloc[-1]
            
            # Bullish alignment
            if ema8 > ema13 > ema21 > ema34:
                return 3
            # Moderate bullish
            elif ema8 > ema13 and ema13 > ema34:
                return 2
            # Bearish alignment
            elif ema8 < ema13 < ema21 < ema34:
                return 3
            # Moderate bearish
            elif ema8 < ema13 and ema13 < ema34:
                return 2
            else:
                return 1  # Mixed
        except:
            return 1
    
    @classmethod
    def _get_volume_ratio(cls, df):
        """Get volume ratio vs moving average."""
        try:
            vol = df['volume']
            vol_ma = vol.rolling(20).mean()
            if len(vol) > 0 and len(vol_ma) > 0 and vol_ma.iloc[-1] > 0:
                return vol.iloc[-1] / vol_ma.iloc[-1]
        except:
            pass
        return 1.0
    
    @classmethod
    def _detect_exhaustion(cls, df):
        """
        Detect exhaustion (from TradingView Sniper Exhaustion).
        is_strong_candle = body > ATR * 1.5
        is_expansion = volume > MA * 1.5
        overextended = distance from EMA > ATR * 2.0
        """
        try:
            closes = df['close']
            highs = df['high']
            lows = df['low']
            opens = df['open']
            
            # Body size
            body = abs(closes.iloc[-1] - opens.iloc[-1])
            
            # ATR
            atr = compute_atr(df).iloc[-1] if len(df) > 14 else closes.iloc[-1] * 0.01
            
            # Strong candle?
            is_strong = body > atr * 1.5
            
            # Volume expansion?
            vol_ratio = cls._get_volume_ratio(df)
            is_expansion = vol_ratio > 1.5
            
            # Overextended?
            ema50 = ema(closes, 50).iloc[-1]
            distance = abs(closes.iloc[-1] - ema50)
            is_overextended = distance > atr * 2.0
            
            if is_strong and is_expansion and is_overextended:
                return 3
            elif is_strong and (is_expansion or is_overextended):
                return 2
            elif is_strong:
                return 1
            else:
                return 0
        except:
            return 0
    
    @classmethod
    def _detect_overextended(cls, df):
        """Detect if price is overextended from EMA."""
        try:
            closes = df['close']
            atr = compute_atr(df).iloc[-1] if len(df) > 14 else closes.iloc[-1] * 0.01
            ema50 = ema(closes, 50).iloc[-1]
            distance = abs(closes.iloc[-1] - ema50)
            
            # Overextended if distance > ATR * 2.0
            if distance > atr * 2.0:
                return 3
            elif distance > atr * 1.5:
                return 2
            elif distance > atr:
                return 1
            else:
                return 0
        except:
            return 0
    
    @classmethod
    def _get_vwap_proximity(cls, df):
        """
        Get VWAP proximity score.
        From TradingView: VWAP = HLC3 average
        """
        try:
            hlc3 = (df['high'] + df['low'] + df['close']) / 3
            vwap = hlc3.rolling(20).mean().iloc[-1]  # Simplified VWAP
            price = df['close'].iloc[-1]
            atr = compute_atr(df).iloc[-1] if len(df) > 14 else price * 0.01
            
            distance_pct = abs(price - vwap) / price * 100
            
            # Near VWAP = good for mean reversion
            if distance_pct < 0.2:
                return 3
            elif distance_pct < 0.5:
                return 2
            elif distance_pct < 1.0:
                return 1
            else:
                return 0
        except:
            return 0
    
    @classmethod
    def _get_candle_quality(cls, df):
        """Get candle quality score (from TradingView strong candle detection)."""
        try:
            closes = df['close']
            opens = df['open']
            highs = df['high']
            lows = df['low']
            
            current = closes.iloc[-1]
            open_price = opens.iloc[-1]
            high = highs.iloc[-1]
            low = lows.iloc[-1]
            
            # Body size
            body = abs(current - open_price)
            
            # Total range
            total_range = high - low
            
            if total_range == 0:
                return 0
            
            # Body to range ratio
            body_ratio = body / total_range
            
            # Upper/lower wick
            if current > open_price:  # Bullish
                upper_wick = high - current
                lower_wick = open_price - low
            else:  # Bearish
                upper_wick = high - open_price
                lower_wick = current - low
            
            # Strong candle: body > 60% of range
            if body_ratio > 0.7:
                return 3
            elif body_ratio > 0.5:
                return 2
            elif body_ratio > 0.3:
                return 1
            else:
                return 0
        except:
            return 0


# ========== MARKET REGIME CLASSIFIER ==========
class MarketRegimeClassifier:
    @staticmethod
    def classify(df, ob=None):
        if df is None or len(df) < 50:
            return "UNKNOWN"
        adx_state = ADXDIIntelligence.get_adx_state(df)
        di_state = ADXDIIntelligence.get_di_state(df)
        atr = compute_atr(df).iloc[-1]
        price = df['close'].iloc[-1]
        atr_pct = (atr / price) * 100
        vol_state = classify_volume(df)
        range_20 = (df['high'].rolling(20).max() - df['low'].rolling(20).min()).iloc[-1]
        range_pct = (range_20 / price) * 100
        ema20 = ema(df['close'], 20).iloc[-1]
        ema50 = ema(df['close'], 50).iloc[-1]
        price_above_ema = price > ema20 and ema20 > ema50
        price_below_ema = price < ema20 and ema20 < ema50
        bos_up, bos_down = detect_bos(df, lookback=5)
        struct_shift = detect_structure_shift(df)
        if adx_state["state"] in ("STRONG_TREND", "VERY_STRONG") and di_state["dominant"] != "NEUTRAL":
            if (price_above_ema and di_state["dominant"] == "BUY") or (price_below_ema and di_state["dominant"] == "SELL"):
                if atr_pct > 2.0:
                    return "EXPANSION"
                else:
                    return "STRONG_TREND"
        if adx_state["state"] == "EMERGING" and adx_state["slope"] > 0:
            return "WEAK_TREND"
        if adx_state["value"] < 18 or di_state["dominant"] == "NEUTRAL":
            if range_pct < 1.5:
                return "COMPRESSION"
            else:
                return "CHOPPY"
        if vol_state == "expansion" and adx_state["value"] > 25:
            return "EXPANSION"
        if vol_state == "exhaustion" and adx_state["value"] > 30:
            return "DISTRIBUTION"
        if (struct_shift == "bullish_shift" and bos_up) or (struct_shift == "bearish_shift" and bos_down):
            return "TRANSITION"
        if vol_state == "absorption":
            return "ACCUMULATION"
        return "RANGE"


# ========== MARKET PHASE CLASSIFIER ==========
class MarketPhaseClassifier:
    """
    Market Phase Classification - SINGLE SOURCE OF TRUTH for market phase detection.
    
    This classifies the market into one of 7 phases:
    - TREND: Strong directional market with ADX > 25
    - TREND_PULLBACK: Pullback within a trend
    - EXHAUSTION: End of move / exhaustion signals
    - LIQUIDITY_GRAB: Liquidity sweep / SFP patterns
    - STRUCTURE_BREAK: MSS / BOS confirmed
    - RANGE: No trend, ADX < 20
    - NO_TRADE: No clear setup
    
    IMPORTANT: ADX is used as CONTEXT, not as a hard filter.
    The classification is based on the combination of:
    - DMI direction
    - Volume patterns
    - Price structure
    - Liquidity events
    """
    
    @staticmethod
    def classify(df, momentum_data=None, smart_money=None, liquidity_data=None):
        """
        Classify market phase based on multiple indicators.
        
        Args:
            df: DataFrame with OHLCV data
            momentum_data: Optional pre-calculated momentum data
            smart_money: Optional pre-calculated smart money data
            liquidity_data: Optional pre-calculated liquidity data
        
        Returns:
            str: Market phase
        """
        if df is None or len(df) < 30:
            log_execution(f"[FORENSIC][MPC] classify() called with df=None or len<30 → NO_TRADE", "INFO")
            return "NO_TRADE"
        
        # ========== FORENSIC: Log ALL INPUT VALUES ==========
        log_execution(f"[FORENSIC][MPC] classify() ENTRY:", "INFO")
        log_execution(f"  df length: {len(df)}", "INFO")
        log_execution(f"  momentum_data is None: {momentum_data is None}", "INFO")
        if momentum_data:
            log_execution(f"  momentum_data keys: {list(momentum_data.keys())}", "INFO")
            log_execution(f"  momentum_data['adx_value']: {momentum_data.get('adx_value', 'NOT_FOUND')}", "INFO")
            log_execution(f"  momentum_data['di_plus']: {momentum_data.get('di_plus', 'NOT_FOUND')}", "INFO")
            log_execution(f"  momentum_data['di_minus']: {momentum_data.get('di_minus', 'NOT_FOUND')}", "INFO")
            log_execution(f"  momentum_data['flow_bias']: {momentum_data.get('flow_bias', 'NOT_FOUND')}", "INFO")
            log_execution(f"  momentum_data['trend_expansion']: {momentum_data.get('trend_expansion', 'NOT_FOUND')}", "INFO")
        
        # Get ADX context (NOT filter)
        if momentum_data is None:
            plus_di, minus_di, adx_val, _ = get_di_components(df)
            log_execution(f"  ADX Source: get_di_components() (momentum_data was None)", "INFO")
        else:
            adx_val = momentum_data.get("adx_value", 20)
            plus_di = momentum_data.get("di_plus", 20)
            minus_di = momentum_data.get("di_minus", 20)
            log_execution(f"  ADX Source: momentum_data (adx_value, di_plus, di_minus)", "INFO")
        
        # ========== FORENSIC: Log extracted values ==========
        log_execution(f"  EXTRACTED VALUES:", "INFO")
        log_execution(f"    adx_val: {adx_val} (type: {type(adx_val).__name__})", "INFO")
        log_execution(f"    plus_di: {plus_di} (type: {type(plus_di).__name__})", "INFO")
        log_execution(f"    minus_di: {minus_di} (type: {type(minus_di).__name__})", "INFO")
        
        # Determine direction
        if plus_di is None:
            plus_di = 20
            log_execution(f"    plus_di was None → set to 20", "INFO")
        if minus_di is None:
            minus_di = 20
            log_execution(f"    minus_di was None → set to 20", "INFO")
        
        di_spread = plus_di - minus_di
        direction = "BULLISH" if plus_di > minus_di else "BEARISH" if minus_di > plus_di else "NEUTRAL"
        
        log_execution(f"    di_spread: {di_spread} (plus_di - minus_di)", "INFO")
        log_execution(f"    direction: {direction}", "INFO")
        
        # Check for exhaustion signals
        exhaustion_score = MarketPhaseClassifier._calculate_exhaustion_score(df, adx_val, direction)
        log_execution(f"    exhaustion_score: {exhaustion_score:.4f} (threshold: > 0.7)", "INFO")
        
        # Check for liquidity sweep
        liquidity_score = MarketPhaseClassifier._calculate_liquidity_score(df, liquidity_data)
        log_execution(f"    liquidity_score: {liquidity_score:.4f} (threshold: > 0.6)", "INFO")
        
        # Check for structure break
        structure_score = MarketPhaseClassifier._calculate_structure_score(df, direction)
        log_execution(f"    structure_score: {structure_score:.4f} (threshold: > 0.6)", "INFO")
        
        # ========== FORENSIC: Log each decision condition ==========
        log_execution(f"[FORENSIC][MPC] DECISION TREE:", "INFO")
        
        # Phase classification logic
        condition_1 = exhaustion_score > 0.7
        log_execution(f"  Condition 1: exhaustion_score={exhaustion_score:.4f} > 0.7 → {condition_1} {'✅ EXHAUSTION' if condition_1 else '❌ Continue'}", "INFO")
        if condition_1:
            result = "EXHAUSTION"
            log_execution(f"  RESULT: {result}", "INFO")
            return result
        
        condition_2 = liquidity_score > 0.6
        log_execution(f"  Condition 2: liquidity_score={liquidity_score:.4f} > 0.6 → {condition_2} {'✅ LIQUIDITY_GRAB' if condition_2 else '❌ Continue'}", "INFO")
        if condition_2:
            result = "LIQUIDITY_GRAB"
            log_execution(f"  RESULT: {result}", "INFO")
            return result
        
        condition_3 = structure_score > 0.6
        log_execution(f"  Condition 3: structure_score={structure_score:.4f} > 0.6 → {condition_3} {'✅ STRUCTURE_BREAK' if condition_3 else '❌ Continue'}", "INFO")
        if condition_3:
            result = "STRUCTURE_BREAK"
            log_execution(f"  RESULT: {result}", "INFO")
            return result
        
        condition_4 = adx_val < 20 and abs(di_spread) < 10
        log_execution(f"  Condition 4: adx_val={adx_val} < 20 AND abs(di_spread)={abs(di_spread):.2f} < 10 → {condition_4} {'✅ RANGE' if condition_4 else '❌ Continue'}", "INFO")
        if condition_4:
            result = "RANGE"
            log_execution(f"  RESULT: {result}", "INFO")
            return result
        
        condition_5 = adx_val > 25 and direction != "NEUTRAL"
        log_execution(f"  Condition 5: adx_val={adx_val} > 25 AND direction={direction} != 'NEUTRAL' → {condition_5} {'✅ TREND' if condition_5 else '❌ Continue'}", "INFO")
        if condition_5:
            # Check if in pullback
            is_pullback = MarketPhaseClassifier._is_pullback(df, direction)
            log_execution(f"    Pullback check: _is_pullback() → {is_pullback}", "INFO")
            result = "TREND_PULLBACK" if is_pullback else "TREND"
            log_execution(f"  RESULT: {result}", "INFO")
            return result
        
        condition_6 = adx_val >= 20 and adx_val <= 25 and direction != "NEUTRAL"
        log_execution(f"  Condition 6: adx_val={adx_val} >= 20 AND <= 25 AND direction={direction} != 'NEUTRAL' → {condition_6} {'✅ TREND_PULLBACK' if condition_6 else '❌ Continue'}", "INFO")
        if condition_6:
            result = "TREND_PULLBACK"
            log_execution(f"  RESULT: {result}", "INFO")
            return result
        
        # Default case
        log_execution(f"[FORENSIC][MPC] NO CONDITIONS MET → NO_TRADE", "INFO")
        log_execution(f"  WHY NO_TRADE: All conditions failed", "INFO")
        log_execution(f"  adx_val={adx_val} → must be <20 or >25 for valid phases", "INFO")
        log_execution(f"  direction={direction} → must not be NEUTRAL for valid phases", "INFO")
        log_execution(f"  di_spread={di_spread:.2f} → must be small (<10) for RANGE", "INFO")
        
        return "NO_TRADE"
    
    @staticmethod
    def _calculate_exhaustion_score(df, adx_val, direction):
        """Calculate exhaustion score 0-1"""
        if len(df) < 20:
            return 0.0
        
        score = 0.0
        
        # Strong candle at extremes
        last = df.iloc[-1]
        body = abs(last['close'] - last['open'])
        upper_wick = last['high'] - max(last['open'], last['close'])
        lower_wick = min(last['open'], last['close']) - last['low']
        
        # Exhaustion candle: large wicks, small body
        if body > 0:
            try:
                wick_ratio = max(upper_wick, lower_wick) / body
                if wick_ratio > 2.0:
                    score += 0.4
            except (ZeroDivisionError, FloatingPointError):
                pass
        
        # High volume at extreme
        try:
            vol_ma = df['volume'].rolling(20).mean().iloc[-1]
            if pd.notna(vol_ma) and vol_ma > 0:
                vol_ratio = df['volume'].iloc[-1] / vol_ma
                if vol_ratio > 1.5:
                    score += 0.3
        except (ZeroDivisionError, FloatingPointError):
            pass
        
        # ADX near peak then declining - safe calculation
        try:
            if len(df) >= 5:
                # Calculate average close over last 5 candles as proxy for ADX trend
                adx_avg = df['close'].rolling(5).mean().iloc[-1]
                if pd.notna(adx_avg) and adx_val > 30 and adx_val > adx_avg * 1.05:
                    score += 0.3
        except (ZeroDivisionError, FloatingPointError, KeyError):
            pass
        
        return min(1.0, score)
    
    @staticmethod
    def _calculate_liquidity_score(df, liquidity_data):
        """Calculate liquidity grab score 0-1"""
        if liquidity_data is not None:
            sweep = liquidity_data.get("sweep", False)
            sfp = liquidity_data.get("sfp", False)
            if sweep or sfp:
                return 0.8
        
        # Manual detection
        if len(df) < 10:
            return 0.0
        
        score = 0.0
        
        # Detect SFP pattern
        if len(df) >= 3:
            c1, c2, c3 = df.iloc[-3], df.iloc[-2], df.iloc[-1]
            
            # Bullish SFP: high sweep then close below
            if c2['high'] > c1['high'] and c3['close'] < c1['high'] and c3['close'] < c3['open']:
                score += 0.5
            
            # Bearish SFP: low sweep then close above
            if c2['low'] < c1['low'] and c3['close'] > c1['low'] and c3['close'] > c3['open']:
                score += 0.5
        
        # Detect sweep of session levels
        high_20 = df['high'].rolling(20).max().iloc[-1]
        low_20 = df['low'].rolling(20).min().iloc[-1]
        
        if df.iloc[-1]['high'] >= high_20 * 0.999 and df.iloc[-1]['close'] < high_20:
            score += 0.3
        
        if df.iloc[-1]['low'] <= low_20 * 1.001 and df.iloc[-1]['close'] > low_20:
            score += 0.3
        
        return min(1.0, score)
    
    @staticmethod
    def _calculate_structure_score(df, direction):
        """Calculate structure break score 0-1"""
        if len(df) < 10:
            return 0.0
        
        score = 0.0
        
        # BOS detection
        bos_up, bos_down = detect_bos(df, lookback=5)
        
        # MSS detection (close beyond swing high/low)
        if len(df) >= 3:
            swing_high = df['high'].rolling(5).max().iloc[-2]
            swing_low = df['low'].rolling(5).min().iloc[-2]
            
            if direction == "BULLISH":
                if df.iloc[-1]['close'] > swing_high:
                    score += 0.6
            else:
                if df.iloc[-1]['close'] < swing_low:
                    score += 0.6
        
        # Displacement candle
        atr = compute_atr(df).iloc[-1] if len(df) > 14 else df['close'].iloc[-1] * 0.01
        last_body = abs(df.iloc[-1]['close'] - df.iloc[-1]['open'])
        if last_body > atr * 1.5:
            vol_ma = df['volume'].rolling(20).mean().iloc[-1]
            if df.iloc[-1]['volume'] > vol_ma * 1.3:
                score += 0.4
        
        return min(1.0, score)
    
    @staticmethod
    def _is_pullback(df, direction):
        """Check if price is in pullback"""
        if len(df) < 20:
            return False
        
        # Pullback: price moved away from trend then returning
        ema20 = ema(df['close'], 20).iloc[-1]
        price = df['close'].iloc[-1]
        
        if direction == "BULLISH":
            # Check if price is below EMA after being above
            recent_high = df['high'].rolling(10).max().iloc[-1]
            if price < ema20 and recent_high > ema20 * 1.01:
                return True
        
        return False
    
    @staticmethod
    def get_phase_description(phase):
        """Get human-readable description of phase"""
        descriptions = {
            "TREND": "Strong directional market",
            "TREND_PULLBACK": "Pullback within trend",
            "EXHAUSTION": "End of move / reversal likely",
            "LIQUIDITY_GRAB": "Liquidity sweep occurred",
            "STRUCTURE_BREAK": "Market structure shift",
            "RANGE": "No clear direction",
            "NO_TRADE": "No clear setup"
        }
        return descriptions.get(phase, "Unknown")


# ========== CONFIDENCE ENGINE ==========
class ConfidenceEngine:
    @staticmethod
    def calculate_initial_confidence(entry_score, narrative_score, regime, adx, di_spread, location_quality):
        base = (entry_score / 10) * 30 + (narrative_score / 10) * 30
        regime_map = {"STRONG_TREND": 20, "WEAK_TREND": 10, "EXPANSION": 25, "COMPRESSION": 5, "CHOPPY": 0, "ACCUMULATION": 15, "DISTRIBUTION": 10, "TRANSITION": 10}
        regime_bonus = regime_map.get(regime, 5)
        adx_bonus = min(20, max(0, (adx - 20) * 2))
        di_bonus = min(15, abs(di_spread))
        location_bonus = {"discount": 10, "premium": 10, "mid": 0}.get(location_quality, 0)
        total = base + regime_bonus + adx_bonus + di_bonus + location_bonus
        return min(100, total)

    @staticmethod
    def update_live_confidence(current_confidence, continuation_pressure, thesis_failure_score, adx_slope, di_spread_change):
        new_conf = current_confidence
        new_conf += (continuation_pressure - 50) * 0.3
        new_conf -= thesis_failure_score * 0.5
        new_conf += adx_slope * 2
        new_conf += di_spread_change * 1.5
        return max(0, min(100, new_conf))

    @staticmethod
    def apply_institutional_modifiers(base_confidence, smart_money, momentum, continuation_strength):
        conf = base_confidence
        if smart_money.get("smart_money_dominant", False):
            conf += 10
            log_execution("[CONF] Smart money dominant: +10", "INFO", debounce_key="conf_smart", debounce_sec=30)
        else:
            conf -= 8
        cont = min(100, max(0, continuation_strength))
        if cont > 20:
            conf += 8
        elif cont < 5:
            conf -= 10
        mom_health = momentum.get("momentum_health", 50)
        if mom_health > 15:
            conf += 6
        elif mom_health < 0:
            conf -= 8
        banker = smart_money.get("banker_pressure", 50)
        retail = smart_money.get("retailer_pressure", 50)
        if banker > retail:
            conf += 5
        else:
            conf -= 6
        dist = smart_money.get("distribution_risk", 0)
        if dist > 45:
            conf -= 12
        climax = momentum.get("climax_risk", 0)
        if climax > 50:
            conf -= 10
        conf = max(0, min(100, conf))
        return conf

# ========== PRECISION SAFETY ==========
class PrecisionSafety:
    @staticmethod
    def normalize_price(symbol, price):
        try:
            market = ex.market(normalize_symbol(symbol))
            prec = market['precision']['price']
            return round(price, prec)
        except:
            return price

    @staticmethod
    def normalize_amount(symbol, amount):
        try:
            market = ex.market(normalize_symbol(symbol))
            prec = market['precision']['amount']
            return math.floor(amount / (10 ** -prec)) * (10 ** -prec)
        except:
            return amount

    @staticmethod
    def adjust_sl_tp(symbol, entry, sl, tp, side, atr):
        min_dist = max(atr * 0.5, entry * 0.002)
        if side == "BUY":
            if entry - sl < min_dist:
                sl = entry - min_dist
            if tp - entry < min_dist:
                tp = entry + min_dist
        else:
            if sl - entry < min_dist:
                sl = entry + min_dist
            if entry - tp < min_dist:
                tp = entry - min_dist
        sl = PrecisionSafety.normalize_price(symbol, sl)
        tp = PrecisionSafety.normalize_price(symbol, tp)
        return sl, tp

# ========== CONTINUATION PROBABILITY ENGINE ==========
from dataclasses import dataclass

@dataclass
class ContinuationEvaluation:
    continuation_probability: float
    trend_strength: float
    exhaustion_probability: float
    reclaim_risk: float
    counter_pressure: float
    confidence: float
    reasons: List[str]
    should_hold: bool
    hold_quality: str

class ContinuationProbabilityEngine:
    HOLD_THRESHOLD = 0.62

    def evaluate(self, side: str, df, market_state: Dict, thesis: Dict) -> ContinuationEvaluation:
        score = 0.0
        reasons = []
        close = df["close"].iloc[-1]
        atr = market_state.get("atr", 0)
        adx = market_state.get("adx", 0)
        adx_slope = market_state.get("adx_slope", 0)
        di_plus = market_state.get("di_plus", 0)
        di_minus = market_state.get("di_minus", 0)
        trend_health = market_state.get("trend_health", 5)
        weak_pullback = market_state.get("weak_pullback", False)
        counter_displacement = market_state.get("counter_displacement", 0)
        volume_ratio = market_state.get("volume_ratio", 1.0)
        ema20 = df["close"].ewm(span=20).mean().iloc[-1]
        ema50 = df["close"].ewm(span=50).mean().iloc[-1]
        exhaustion_probability = 0.0
        reclaim_risk = 0.0
        counter_pressure = 0.0

        if side == "BUY":
            di_spread = di_plus - di_minus
        else:
            di_spread = di_minus - di_plus
        if di_spread > 8:
            score += 2.5
            reasons.append("strong_di_pressure")
        elif di_spread > 4:
            score += 1.5
            reasons.append("moderate_di_pressure")
        else:
            score -= 2.0
            reasons.append("weak_di_pressure")

        if adx > 25:
            score += 2.5
            reasons.append("healthy_adx")
        elif adx > 18:
            score += 1.0
            reasons.append("developing_adx")
        else:
            score -= 2.5
            reasons.append("dead_adx")
        if adx_slope > 0:
            score += 1.5
            reasons.append("adx_expanding")
        else:
            score -= 1.0
            reasons.append("adx_fading")

        if trend_health >= 8:
            score += 3.0
            reasons.append("excellent_trend_health")
        elif trend_health >= 6:
            score += 2.0
            reasons.append("healthy_trend")
        elif trend_health <= 3:
            score -= 3.0
            reasons.append("trend_breakdown")

        if weak_pullback:
            score += 2.0
            reasons.append("weak_pullback_detected")

        if counter_displacement > 1.5:
            counter_pressure += 0.5
            score -= 3.0
            reasons.append("strong_counter_pressure")
        elif counter_displacement > 0.8:
            counter_pressure += 0.25
            score -= 1.5
            reasons.append("moderate_counter_pressure")

        if side == "BUY":
            if close > ema20:
                score += 1.5
                reasons.append("holding_ema20")
            if close > ema50:
                score += 2.0
                reasons.append("holding_ema50")
            if close < ema20:
                reclaim_risk += 0.2
            if close < ema50:
                reclaim_risk += 0.4
        else:
            if close < ema20:
                score += 1.5
                reasons.append("holding_ema20")
            if close < ema50:
                score += 2.0
                reasons.append("holding_ema50")
            if close > ema20:
                reclaim_risk += 0.2
            if close > ema50:
                reclaim_risk += 0.4

        if atr > 0:
            extension = abs(close - ema20) / atr
            if extension > 3:
                exhaustion_probability += 0.5
                score -= 1.5
                reasons.append("overextended")
            elif extension > 2:
                exhaustion_probability += 0.25
                reasons.append("extended_move")

        if volume_ratio > 1.2:
            score += 1.5
            reasons.append("volume_confirmation")
        elif volume_ratio < 0.7:
            score -= 1.5
            reasons.append("weak_volume")

        thesis_strength = thesis.get("thesis_strength", 5)
        score += thesis_strength * 0.3

        smart_money = SmartMoneyEngine.analyze_smart_money(df)
        momentum = MomentumFlowEngine.analyze_momentum_flow(df)

        adx_strength = (adx - 18) / 22 * 100 if adx > 18 else 0
        structure_aligned = 1 if market_state.get("structure_aligned", False) else 0
        continuation_strength = (
            momentum.get("momentum_health", 50) * 0.35 +
            smart_money.get("banker_pressure", 50) * 0.25 +
            adx_strength * 0.25 +
            structure_aligned * 15
        )
        continuation_strength = max(0, min(100, continuation_strength))
        market_state["continuation_strength_scaled"] = continuation_strength
        score += (continuation_strength - 50) / 10

        dominance_weight = 0.7 if smart_money["smart_money_dominant"] else 0.3
        score += (dominance_weight - 0.5) * 6

        if momentum["trend_expansion"]:
            score += 2.0
            reasons.append("momentum_expansion")
        if momentum["momentum_decay"]:
            score -= 2.5
            reasons.append("momentum_decay")
        dist_risk = smart_money["distribution_risk"] / 100.0
        score -= dist_risk * 3.0
        if dist_risk > 0.7:
            reasons.append("high_distribution_risk")
        if smart_money["retail_euphoria"]:
            score -= 1.5
            reasons.append("retail_euphoria")

        probability = (score + 15) / 30
        probability = max(0.0, min(1.0, probability))
        confidence = min(abs(score) / 15, 1.0)
        should_hold = probability >= self.HOLD_THRESHOLD
        if probability >= 0.8:
            hold_quality = "STRONG"
        elif probability >= 0.65:
            hold_quality = "HEALTHY"
        elif probability >= 0.5:
            hold_quality = "NEUTRAL"
        else:
            hold_quality = "WEAK"

        return ContinuationEvaluation(
            continuation_probability=round(probability, 2),
            trend_strength=round(trend_health / 10, 2),
            exhaustion_probability=round(exhaustion_probability, 2),
            reclaim_risk=round(reclaim_risk, 2),
            counter_pressure=round(counter_pressure, 2),
            confidence=round(confidence, 2),
            reasons=reasons,
            should_hold=should_hold,
            hold_quality=hold_quality
        )

_continuation_engine = ContinuationProbabilityEngine()

