class TradeLifecycleState(Enum):
    IDLE = "IDLE"
    OPEN_REQUESTED = "OPEN_REQUESTED"
    OPEN_PENDING_CONFIRMATION = "OPEN_PENDING_CONFIRMATION"
    LIVE = "LIVE"
    PARTIALLY_CLOSED = "PARTIALLY_CLOSED"
    CLOSING = "CLOSING"
    CLOSED = "CLOSED"
    RECOVERING = "RECOVERING"
    ERROR_DEGRADED = "ERROR_DEGRADED"


class TradePhaseLifecycleState(Enum):
    """
    Extended Trade Lifecycle - tracks every phase of a trade from discovery to exit.
    
    Pipeline:
    DISCOVERED → ANALYZED → RANKED → READY → ENTRY_SENT → EXECUTED → TP1_HIT → BREAKEVEN → TRAILING → EXIT
    
    Each transition records:
    - timestamp
    - reason
    - engine that decided
    - data used
    """
    # Pre-Entry States
    DISCOVERED = "DISCOVERED"      # Found by Discovery Scanner
    ANALYZED = "ANALYZED"          # Analyzed by Continuous Analysis
    RANKED = "RANKED"             # Ranked by Opportunity Selection
    READY = "READY"               # Ready for entry (passes all filters)
    ENTRY_SENT = "ENTRY_SENT"      # Entry order sent to exchange
    EXECUTED = "EXECUTED"         # Entry order filled
    
    # Post-Entry States
    TP1_HIT = "TP1_HIT"           # First take profit hit
    BREAKEVEN = "BREAKEVEN"        # Stop loss moved to breakeven
    TRAILING = "TRAILING"          # Trailing stop activated
    
    # Exit States
    EXIT = "EXIT"                  # Trade closed


class TradePlaybookType(Enum):
    """
    Trade Playbook Types - defines management style based on entry type.
    
    Each type has different:
    - Entry conditions
    - Profit management
    - Stop loss approach
    - Exit criteria
    """
    TREND_CONTINUATION = "TREND_CONTINUATION"      # Trend following with wide management
    LIQUIDITY_REVERSAL = "LIQUIDITY_REVERSAL"    # Reversal at liquidity with tight management
    BREAKOUT = "BREAKOUT"                          # Breakout with momentum management
    RANGE_MEAN_REVERSION = "RANGE_MEAN_REVERSION"  # Range trading with quick targets


