# ========== LIVE TRADE MANAGER WITH SYNTHETIC PROTECTION (OPTIMIZED) ==========


def post_trade_cleanup(closed_symbol: str) -> dict:
    """
    Post-Trade Cleanup - Phase 7 of Trade Lifecycle
    
    Executes ONLY after:
    1. Position confirmed closed on BingX
    2. Balance updated
    3. Trade state synchronized
    4. Trade Manager and Exit Manager finished
    
    Cleans ONLY runtime state, preserves permanent data.
    
    Returns:
        dict: Cleanup report showing what was cleaned and what was preserved
    """
    log_execution(f"[CLEANUP] ════════════════════════════════════════════════════", "INFO")
    log_execution(f"[CLEANUP] POST-TRADE CLEANUP STARTED for {closed_symbol}", "INFO")
    log_execution(f"[CLEANUP] ════════════════════════════════════════════════════", "INFO")
    
    cleanup_report = {
        "timestamp": time.time(),
        "symbol": closed_symbol,
        "cleaned": [],
        "preserved": [],
        "errors": []
    }
    
    try:
        # ========== 1. RESET TRADE STATE ==========
        log_execution(f"[CLEANUP] Stage 1/10: Resetting TRADE_STATE...", "INFO")
        TRADE_STATE.update({
            "in_position": False,
            "symbol": None,
            "side": None,
            "entry": 0.0,
            "qty": 0.0,
            "tp1_hit": False,
            "tp2_hit": False,
            "trail_on": False,
            "zone": None,
            "location": None,
            "reason": [],
            "last_update_ts": 0
        })
        cleanup_report["cleaned"].append("TRADE_STATE")
        
        # ========== 2. RESET MAIN STATE ==========
        log_execution(f"[CLEANUP] Stage 2/10: Resetting STATE...", "INFO")
        STATE.update({
            "open": False,
            "side": None,
            "entry": 0.0,
            "qty": 0.0,
            "remaining_qty": 0.0,
            "bot_opened": False,
            "sl": 0.0,
            "tp1_done": False,
            "trail_activated": False,
            "trail_stop": 0.0,
            "peak": 0.0,
            "current_symbol": None,
            "balance": 0.0,
            "atr": 0.0,
            "entry_time": None,
            "entry_reasons": [],
            "trade_score": 0,
            "partial_closed": False,
            "tp1_price": 0.0,
            "tp2_price": 0.0,
            "trade_type": None,
            "entry_type": None,
            "be_done": False,
            "classification": None,
            "location": None,
            "zone_info": None,
            "scale_ins": 0,
            "decision_log": [],
            "tp1_hit": False,
            "tp2_hit": False,
            "zone": {},
            "initial_margin": 0.0,
            "real_unrealized_pnl": 0.0,
            "roe_pct": 0.0,
            "leverage": LEVERAGE,
            "smart_tightened": False,
            "smart_partial_done": False,
            "smart_exit_triggered": False,
            "mark_price": 0.0,
            "unrealized_pnl_usdt": 0.0,
            "margin": 0.0,
            "liquidation_price": 0.0,
            "narrative_classification": None,
            "narrative_confidence": 0.0,
            "confidence_level": None,
            "continuation_probability": 0.5,
            "hold_quality": "UNKNOWN",
            "counter_pressure": 0.0,
            "reclaim_risk": 0.0,
            "trend_strength": 0.0,
            "continuation_reasons": [],
            "trade_thesis": None,
            "current_confidence": 50.0,
            "market_regime": "UNKNOWN",
            "continuation_pressure": 50,
            "thesis_failure_score": 0,
            "prev_di_spread": 0.0,
            "adx_live": 0.0,
            "di_plus_live": 0.0,
            "di_minus_live": 0.0,
            "trade_personality": "NEUTRAL",
            "institutional_flow": "NEUTRAL",
            "profit_lock_activated": False,
            "trail_tightened": False,
            "smart_money": {},
            "momentum_flow": {},
            "trade_state": "RANGE_CHOP",
            "delay_tp1": False,
            "smart_trail_mult": 1.5,
            "synthetic_sl": 0.0,
            "synthetic_tp1": 0.0,
            "max_price": 0.0,
            "min_price": 0.0
        })
        cleanup_report["cleaned"].append("STATE")
        
        # ========== 3. RESET DASHBOARD STATE ==========
        log_execution(f"[CLEANUP] Stage 3/10: Resetting DASHBOARD_STATE...", "INFO")
        DASHBOARD_STATE.update({
            "position": None,
            "live_trade_mode": False,
            "current_symbol": None,
            "position_side": None,
            "entry_price": 0.0,
            "position_size": 0.0,
            "entry_time": None,
            "current_pnl": 0.0,
            "mark_price": 0.0,
            "trade_state": "RANGE_CHOP",
            "lifecycle_state": "IDLE",
            "live_supervisor": {},
            "institutional_flow": {},
            "decision_cache": []
        })
        cleanup_report["cleaned"].append("DASHBOARD_STATE (runtime only)")
        
        # ========== 4. CLEAN EXECUTION QUEUE ==========
        log_execution(f"[CLEANUP] Stage 4/10: Cleaning EXECUTION QUEUE...", "INFO")
        global _EXECUTION_QUEUE
        original_queue_len = len(_EXECUTION_QUEUE)
        _EXECUTION_QUEUE = [eq for eq in _EXECUTION_QUEUE if eq.get("symbol") != closed_symbol]
        removed_count = original_queue_len - len(_EXECUTION_QUEUE)
        if removed_count > 0:
            log_execution(f"[CLEANUP] Removed {removed_count} entries from execution queue", "INFO")
        cleanup_report["cleaned"].append(f"EXECUTION_QUEUE (removed {removed_count} entries)")
        
        # ========== 5. CLEAN WATCHLIST ENTRY ==========
        log_execution(f"[CLEANUP] Stage 5/10: Cleaning WATCHLIST entry...", "INFO")
        if closed_symbol in MEMORY.get("watchlist", {}):
            del MEMORY["watchlist"][closed_symbol]
            cleanup_report["cleaned"].append(f"WATCHLIST entry for {closed_symbol}")
        # Clean no_entry_feed
        if closed_symbol in MEMORY.get("no_entry_feed", []):
            MEMORY["no_entry_feed"] = [s for s in MEMORY.get("no_entry_feed", []) if s != closed_symbol]
            cleanup_report["cleaned"].append("no_entry_feed entry")
        
        # ========== 6. CLEAN ENTRY CACHE ==========
        log_execution(f"[CLEANUP] Stage 6/10: Cleaning ENTRY CACHE...", "INFO")
        if "entry_cache" in MEMORY:
            before_cache = len(MEMORY.get("entry_cache", {}))
            MEMORY["entry_cache"] = {}
            cleanup_report["cleaned"].append(f"ENTRY_CACHE ({before_cache} entries cleared)")
        
        # ========== 7. CLEAN DECISION CACHE ==========
        log_execution(f"[CLEANUP] Stage 7/10: Cleaning DECISION CACHE...", "INFO")
        if "decision_cache" in MEMORY:
            MEMORY["decision_cache"] = []
            cleanup_report["cleaned"].append("DECISION_CACHE")
        DASHBOARD_STATE["decision_cache"] = []
        
        # ========== 8. CLEAN API CACHES FOR SYMBOL ==========
        log_execution(f"[CLEANUP] Stage 8/10: Cleaning API CACHES for {closed_symbol}...", "INFO")
        
        # Clean ticker cache
        if closed_symbol in _TICKER_CACHE:
            del _TICKER_CACHE[closed_symbol]
            cleanup_report["cleaned"].append("TICKER_CACHE")
        
        # Clean forensic snapshots for this symbol
        before_forensic = len(MEMORY.get("forensic_snapshots", []))
        MEMORY["forensic_snapshots"] = [
            fs for fs in MEMORY.get("forensic_snapshots", []) 
            if fs.get("symbol") != closed_symbol
        ]
        if before_forensic > len(MEMORY["forensic_snapshots"]):
            cleanup_report["cleaned"].append(f"FORENSIC_SNAPSHOTS (removed {before_forensic - len(MEMORY['forensic_snapshots'])} snapshots)")
        
        # Clean price action cache if exists
        if "price_action_cache" in MEMORY and closed_symbol in MEMORY["price_action_cache"]:
            del MEMORY["price_action_cache"][closed_symbol]
            cleanup_report["cleaned"].append("PRICE_ACTION_CACHE")
        
        # ========== 9. CLEAN FLAGS AND TIMERS ==========
        log_execution(f"[CLEANUP] Stage 9/10: Cleaning FLAGS and TIMERS...", "INFO")
        global _ACTIVE_TRADE, INSUFFICIENT_MARGIN_COOLDOWN_UNTIL
        _ACTIVE_TRADE = False
        
        # Reset any symbol-specific cooldowns
        if "trade_cooldowns" in MEMORY and closed_symbol in MEMORY["trade_cooldowns"]:
            del MEMORY["trade_cooldowns"][closed_symbol]
            cleanup_report["cleaned"].append("trade_cooldowns")
        
        cleanup_report["cleaned"].append("FLAGS (_ACTIVE_TRADE)")
        
        # ========== 10. VERIFY CLEANUP ==========
        log_execution(f"[CLEANUP] Stage 10/10: Verifying cleanup...", "INFO")
        
        # Verify STATE is clean
        if STATE["open"]:
            cleanup_report["errors"].append("WARNING: STATE['open'] still True")
        
        if STATE["current_symbol"]:
            cleanup_report["errors"].append("WARNING: STATE['current_symbol'] not cleared")
        
        # ========== PRESERVED DATA ==========
        cleanup_report["preserved"].append("PERF (wins, losses, total_pnl)")
        cleanup_report["preserved"].append("MEMORY candidates, watchlist structure")
        cleanup_report["preserved"].append("Scanner data and intervals")
        cleanup_report["preserved"].append("Strategy settings")
        cleanup_report["preserved"].append("Risk management settings")
        cleanup_report["preserved"].append("Trade history")
        cleanup_report["preserved"].append("Daily statistics")
        cleanup_report["preserved"].append("Equity curve data")
        cleanup_report["preserved"].append("Logs")
        cleanup_report["preserved"].append("API rate limit counters")
        
        # ========== FINAL LOG ==========
        log_execution(f"[CLEANUP] ════════════════════════════════════════════════════", "INFO")
        log_execution(f"[CLEANUP] CLEANUP COMPLETED for {closed_symbol}", "SUCCESS")
        log_execution(f"[CLEANUP] Cleaned: {len(cleanup_report['cleaned'])} items", "INFO")
        for item in cleanup_report["cleaned"]:
            log_execution(f"  ✅ {item}", "INFO")
        log_execution(f"[CLEANUP] Preserved: {len(cleanup_report['preserved'])} items", "INFO")
        for item in cleanup_report["preserved"]:
            log_execution(f"  🔒 {item}", "INFO")
        if cleanup_report["errors"]:
            log_execution(f"[CLEANUP] Warnings: {len(cleanup_report['errors'])}", "WARN")
            for err in cleanup_report["errors"]:
                log_execution(f"  ⚠️ {err}", "WARN")
        log_execution(f"[CLEANUP] ════════════════════════════════════════════════════", "INFO")
        
        return cleanup_report
        
    except Exception as e:
        error_msg = f"CLEANUP ERROR: {e}"
        log_execution(error_msg, "ERROR")
        import traceback
        for line in traceback.format_exc().split('\n'):
            if line.strip():
                log_execution(f"  {line}", "ERROR")
        cleanup_report["errors"].append(error_msg)
        return cleanup_report



class LiveTradeManager:
    """
    LiveTradeManager - إدارة الصفقات المفتوحة.
    
    ⚠️ يعتمد على TradeMemory و CandleMemory كمصادر للبيانات
    ⚠️ يستخدم TradeDecisionEngine لاتخاذ القرارات
    ⚠️ يستخدم CloseVerificationPipeline لإغلاق الصفقات
    """
    def __init__(self, event_bus, exchange_sync, recovery_guard):
        self.event_bus = event_bus
        self.exchange_sync = exchange_sync
        self.recovery = recovery_guard
        self.lifecycle_state = TradeLifecycleState.IDLE
        self.current_snapshot = None
        self.last_management_ts = 0
        self.last_log_ts = 0
        self.last_live_debug_ts = 0
        self.last_heavy_calc_ts = 0
        self.last_position_sync_ts = 0
        self.continuation_pressure_engine = ContinuationPressureEngine()
        self.thesis_failure_engine = ThesisFailureEngine()
        self.confidence_engine = ConfidenceEngine()
        self.regime_classifier = MarketRegimeClassifier()
        self.brain = InstitutionalTradeBrain()
        # Institutional Context Engine - single source of truth
        self._context_engine = InstitutionalContextEngine()
        # TradeMemory و CandleMemory كـ Single Source of Truth
        self._trade_memory = TradeMemory()
        self._candle_memory = CandleMemory()
        self._decision_engine = TradeDecisionEngine()
        self._evaluation_engine = TradeEvaluationEngine()
        self._close_pipeline = CloseVerificationPipeline()
        event_bus.subscribe("reconciled", self._on_reconciled)
        event_bus.subscribe("force_close_local", self._force_close)
        event_bus.subscribe("lifecycle_change", self._set_lifecycle)

    def _set_lifecycle(self, state):
        self.lifecycle_state = state
        log_execution(f"[LIFECYCLE] New state: {state.value}", "INFO")
        DASHBOARD_STATE["lifecycle_state"] = state.value

    def _on_reconciled(self, snapshot):
        self.current_snapshot = snapshot
        DASHBOARD_STATE["live_trade_mode"] = True
        if self.lifecycle_state == TradeLifecycleState.RECOVERING:
            self.lifecycle_state = TradeLifecycleState.LIVE

    def _force_close(self, _):
        """إغلاق إجباري - يستخدم Pipeline."""
        if STATE["open"]:
            symbol = STATE["current_symbol"]
            # استخدام Pipeline لإغلاق الصفقة
            result = self._close_pipeline.request_close(symbol, "EMERGENCY_CLOSE")
            if result.get("success"):
                self.lifecycle_state = TradeLifecycleState.CLOSED
                DASHBOARD_STATE["live_trade_mode"] = False
            else:
                log_execution(f"[LIFECYCLE] Emergency close failed: {result.get('errors')}", "ERROR")

    def start_trade(self, symbol, side, entry_price, qty, sl, tp1, tp2):
        self.lifecycle_state = TradeLifecycleState.OPEN_PENDING_CONFIRMATION
        self.event_bus.emit("lifecycle_change", TradeLifecycleState.OPEN_PENDING_CONFIRMATION)
        log_execution(f"[LIFECYCLE] Trade open requested for {symbol} {side}", "INFO")
        
        # تسجيل الصفقة في TradeMemory
        self._trade_memory.add_open_trade(
            symbol, side, entry_price, qty,
            sl=sl, tp1=tp1, tp2=tp2,
            entry_time=time.time()
        )

    def manage_live_trade(self):
        """إدارة الصفقة المفتوحة - يستخدم TradeMemory و CandleMemory."""
        if not (STATE.get("open") and STATE.get("current_symbol")):
            if self.lifecycle_state not in (TradeLifecycleState.IDLE, TradeLifecycleState.CLOSED):
                self.lifecycle_state = TradeLifecycleState.IDLE
                DASHBOARD_STATE["live_trade_mode"] = False
            return
        now = time.time()
        roe = STATE.get("roe_pct", 0.0)
        adx = STATE.get("adx_live", 20.0)
        # Adaptive interval: calm trade -> 5 seconds, volatile -> 2 seconds
        calm_conditions = abs(roe) < 1.5 and 18 < adx < 30
        target_interval = 5 if calm_conditions else 2
        if now - self.last_management_ts < target_interval:
            return
        self.last_management_ts = now
        symbol = STATE["current_symbol"]
        with _TRADE_LOCK:
            # Position reconciliation only every 10 seconds
            if now - self.last_position_sync_ts >= 10:
                self.exchange_sync.reconcile(symbol, STATE)
                self.last_position_sync_ts = now
            self._apply_management(symbol, now)
        self._log_live_status()

    def _log_live_status(self):
        now = time.time()
        if now - self.last_log_ts < 5:
            return
        self.last_log_ts = now
        if not STATE.get("open"):
            return
        roe = STATE.get("roe_pct", 0.0)
        side = STATE.get("side", "?")
        entry = STATE.get("entry", 0.0)
        mark = STATE.get("mark_price", 0.0)
        pnl_usdt = STATE.get("unrealized_pnl_usdt", 0.0)
        margin = STATE.get("margin", 0.0)
        sl = STATE.get("synthetic_sl", 0.0)
        tp1 = STATE.get("synthetic_tp1", 0.0)
        trail = STATE.get("trail_activated", False)
        tp1_hit = STATE.get("tp1_hit", False)
        direction_icon = "🟢" if side == "BUY" else "🔴"
        roe_color = color_pnl(roe)
        pnl_color = GREEN if pnl_usdt >= 0 else RED
        state_str = self.brain.current_trade_state
        log_msg = (f"{BLUE}[LIVE_MGMT]{RESET} {direction_icon} {STATE['current_symbol']} {side} | "
                   f"Entry: {entry:.2f} | Mark: {mark:.2f} | ROE: {roe_color} | "
                   f"PnL: {pnl_color}{pnl_usdt:.2f} USDT{RESET} | Margin: {margin:.2f} | "
                   f"SL: {sl:.2f} | TP1: {tp1:.2f} | Trail: {'✅' if trail else '❌'} | TP1 Hit: {'✅' if tp1_hit else '❌'} | "
                   f"State: {state_str}")
        log_execution(log_msg, "INFO")

    def _apply_management(self, symbol, now):
        if not STATE.get("open"):
            return
        if self.lifecycle_state != TradeLifecycleState.LIVE:
            return

        # Fetch closed candles (cached with longer TTL)
        df_closed = get_ohlcv_safe(symbol, 50)
        if df_closed is None:
            return
        mark_price = STATE.get("mark_price", get_ticker_safe(symbol))
        if not mark_price:
            return

        # Build live hybrid dataframe
        df_live = get_live_hybrid_df(symbol, df_closed, mark_price)
        atr = compute_atr(df_live).iloc[-1] if len(df_live) > 14 else mark_price * 0.01
        side = STATE["side"]
        entry = STATE["entry"]
        roe = STATE.get("roe_pct", 0.0)

        # No orderbook fetching during live trade
        ob = None

        # Heavy calculations every 5 seconds (ADX, DI, SmartMoney, Momentum, StateMachine)
        if now - self.last_heavy_calc_ts >= 5:
            plus_di, minus_di, adx_now, adx_slope = get_di_components(df_live)
            if plus_di is None: plus_di = 20.0
            if minus_di is None: minus_di = 20.0
            if adx_now is None: adx_now = 20.0
            if adx_slope is None: adx_slope = 0.0

            # Pullback intelligence
            pullback_type = trend_engine.analyze_pullback(df_live, side, atr)
            weak_pullback = (pullback_type == "WEAK_PULLBACK")
            counter_displacement = 0.0
            last_candle = df_live.iloc[-1]
            if side == "SELL" and last_candle['close'] > last_candle['open']:
                body = abs(last_candle['close'] - last_candle['open'])
                if body > atr * 0.6:
                    counter_displacement = body / atr
            elif side == "BUY" and last_candle['close'] < last_candle['open']:
                body = abs(last_candle['close'] - last_candle['open'])
                if body > atr * 0.6:
                    counter_displacement = body / atr
            volume_ratio = df_live['volume'].iloc[-1] / df_live['volume'].iloc[-10:-1].mean() if len(df_live) >= 10 else 1.0
            trend_health = trend_engine.get_trend_health(df_live, side)
            struct_shift = detect_structure_shift(df_live)
            structure_aligned = (side == "BUY" and struct_shift == "bullish_shift") or (side == "SELL" and struct_shift == "bearish_shift")
            market_state = {
                "atr": atr,
                "adx": adx_now,
                "adx_slope": adx_slope,
                "di_plus": plus_di,
                "di_minus": minus_di,
                "trend_health": trend_health,
                "weak_pullback": weak_pullback,
                "counter_displacement": counter_displacement,
                "volume_ratio": volume_ratio,
                "df": df_live,
                "last_candle": last_candle,
                "structure_aligned": structure_aligned,
                "continuation_pressure": 50
            }

            smart_money = SmartMoneyEngine.analyze_smart_money(df_live)
            momentum = MomentumFlowEngine.analyze_momentum_flow(df_live)

            regime = self.regime_classifier.classify(df_live, ob)
            trade_state = self.brain.update(smart_money, momentum, adx_now, regime)
            STATE["trade_state"] = trade_state
            STATE["smart_trail_mult"] = self.brain.get_trail_multiplier()
            STATE["delay_tp1"] = self.brain.should_delay_tp1()
            STATE["adx_live"] = adx_now
            STATE["di_plus_live"] = plus_di
            STATE["di_minus_live"] = minus_di
            STATE["smart_money"] = smart_money
            STATE["momentum_flow"] = momentum
            STATE["market_regime"] = regime

            # ========== CandleMemory Integration ==========
            # تخزين الشموع منذ فتح الصفقة
            entry_time = STATE.get("entry_time", time.time())
            entry_idx = None
            for i in range(len(df_live) - 1, -1, -1):
                if df_live['timestamp'].iloc[i] <= entry_time:
                    entry_idx = i
                    break
            if entry_idx is not None and entry_idx < len(df_live) - 1:
                entry_candles = df_live.iloc[entry_idx:].copy()
            else:
                entry_candles = df_live.tail(30).copy()
            
            # تخزين في CandleMemory
            self._candle_memory.store_candles(symbol, df_live)
            self._candle_memory.store_entry_candles(symbol, entry_candles)
            
            # اكتشاف أحداث الشموع
            candle_events = self._candle_memory.detect_events(symbol)
            candle_event_summary = self._candle_memory.get_event_summary(symbol)
            
            # تسجيل الأحداث في TradeMemory
            for event in candle_events[-3:]:  # آخر 3 أحداث فقط
                event_type = event.get("type", "")
                event_price = event.get("data", {}).get("price", mark_price)
                self._trade_memory.record_structure_event(symbol, event_type, event_price, event.get("data", {}))
            
            # تحديث STATE بأحداث الشموع للاستخدام في القرارات
            STATE["candle_events"] = candle_events[-5:]  # آخر 5 أحداث
            STATE["candle_event_summary"] = candle_event_summary
            
            # تسجيل المؤشرات في TradeMemory
            self._trade_memory.update_indicator(symbol, "smart_money", smart_money)
            self._trade_memory.update_indicator(symbol, "momentum", momentum)
            self._trade_memory.update_indicator(symbol, "atr", {"value": atr})
            self._trade_memory.update_indicator(symbol, "adx", {"value": adx_now, "slope": adx_slope})
            
            # مزامنة TradeMemory مع STATE
            self._trade_memory.sync_from_global_state()
            # ========== End CandleMemory Integration ==========

            # Thesis and continuation (using df_live)
            thesis_dict = STATE.get("trade_thesis", {})
            cont_pressure_score, cont_pressure_reasons = self.continuation_pressure_engine.calculate_pressure(df_live, side, entry, atr, STATE.get("entry_time", time.time()))
            market_state["continuation_pressure"] = cont_pressure_score
            continuation_eval = _continuation_engine.evaluate(side, df_live, market_state, thesis_dict)
            STATE["continuation_probability"] = continuation_eval.continuation_probability
            STATE["hold_quality"] = continuation_eval.hold_quality
            STATE["counter_pressure"] = continuation_eval.counter_pressure
            STATE["reclaim_risk"] = continuation_eval.reclaim_risk
            STATE["trend_strength"] = continuation_eval.trend_strength
            STATE["continuation_reasons"] = continuation_eval.reasons
            STATE["continuation_pressure"] = cont_pressure_score

            # Thesis failure check
            failed, failure_reasons, failure_score = self.thesis_failure_engine.evaluate_failure(thesis_dict, market_state, mark_price, entry, side)
            STATE["thesis_failure_score"] = failure_score
            if failed:
                log_execution(f"[THESIS_FAILURE] Thesis failed for {symbol}: {failure_reasons}", "WARN")
                if roe > 0:
                    close_partial(0.5)
                    STATE["synthetic_sl"] = entry
                    log_execution(f"[THESIS_FAILURE] Partial exit and SL moved to breakeven", "WARN")
                else:
                    # استخدام Pipeline لإغلاق الصفقة
                    result = self._close_pipeline.request_close(symbol, "THESIS_FAILURE")
                    self.event_bus.emit("lifecycle_change", TradeLifecycleState.CLOSED)
                    DASHBOARD_STATE["live_trade_mode"] = False
                    return

            # ========== MARKET PHASE EXIT ==========
            # Check if market phase changed against the trade direction
            current_phase = MarketPhaseClassifier.classify(df_live, momentum, smart_money)
            STATE["market_phase"] = current_phase
            
            # Get trade direction
            trade_direction = STATE.get("side", "BUY")
            phase_exit_triggered = False
            phase_exit_reason = ""
            
            # Get entry phase from trade_type
            trade_type = STATE.get("trade_type", "TREND")
            
            # Market Phase Exit Logic by Trade Type
            if trade_type == "TREND":
                # Trend trade: exit when phase changes to AGAINST trend
                if current_phase == "RANGE" and trade_direction == "BUY":
                    phase_exit_triggered = True
                    phase_exit_reason = "TREND→RANGE (Bullish → No Trend)"
                elif current_phase == "RANGE" and trade_direction == "SELL":
                    phase_exit_triggered = True
                    phase_exit_reason = "TREND→RANGE (Bearish → No Trend)"
                elif current_phase == "EXHAUSTION" and trade_direction == "BUY":
                    phase_exit_triggered = True
                    phase_exit_reason = "TREND→EXHAUSTION (Bullish → Reversal Risk)"
                elif current_phase == "EXHAUSTION" and trade_direction == "SELL":
                    phase_exit_triggered = True
                    phase_exit_reason = "TREND→EXHAUSTION (Bearish → Reversal Risk)"
            
            elif trade_type == "REVERSAL":
                # Reversal trade: exit when phase confirms TREND
                if current_phase == "TREND" and trade_direction == "BUY":
                    phase_exit_triggered = True
                    phase_exit_reason = "REVERSAL→TREND (Reversal → Trend Confirmed)"
                elif current_phase == "TREND" and trade_direction == "SELL":
                    phase_exit_triggered = True
                    phase_exit_reason = "REVERSAL→TREND (Reversal → Trend Confirmed)"
                elif current_phase == "STRUCTURE_BREAK" and STATE.get("tp1_hit"):
                    # Take profit when structure breaks
                    phase_exit_triggered = True
                    phase_exit_reason = "REVERSAL→STRUCTURE_BREAK (Target Achieved)"
            
            elif trade_type == "BREAKOUT":
                # Breakout trade: exit when phase changes to RANGE
                if current_phase == "RANGE":
                    phase_exit_triggered = True
                    phase_exit_reason = "BREAKOUT→RANGE (Breakout → Consolidation)"
                elif current_phase == "EXHAUSTION":
                    phase_exit_triggered = True
                    phase_exit_reason = "BREAKOUT→EXHAUSTION (Momentum Fading)"
            
            # Execute Market Phase Exit
            if phase_exit_triggered:
                log_execution(f"[PHASE_EXIT] {symbol}: {phase_exit_reason} | Phase: {current_phase}", "WARN")
                if roe > 0 and STATE.get("tp1_hit"):
                    # Profitable with TP1 hit - close remaining
                    close_result = close_partial(0.5)
                    log_execution(f"[PHASE_EXIT] Closed remaining 50% due to phase change", "WARN")
                    # Check if position is fully closed
                    if not STATE.get("open"):
                        self.event_bus.emit("lifecycle_change", TradeLifecycleState.CLOSED)
                        DASHBOARD_STATE["live_trade_mode"] = False
                        return
                elif roe > 0:
                    # Profitable but no TP1 - partial close and tighten
                    close_result = close_partial(0.3)
                    STATE["synthetic_sl"] = entry  # Move to BE
                    log_execution(f"[PHASE_EXIT] Partial close 30% and SL to BE", "WARN")
                    # Continue management for remaining position
                else:
                    # Not profitable - full exit
                    result = self._close_pipeline.request_close(symbol, "MARKET_PHASE_EXIT")
                    if result.get("success"):
                        self.event_bus.emit("lifecycle_change", TradeLifecycleState.CLOSED)
                        DASHBOARD_STATE["live_trade_mode"] = False
                    return
            # ========== END MARKET PHASE EXIT ==========
            
            # Confidence update
            old_conf = STATE.get("current_confidence", 50.0)
            di_spread_change = (plus_di - minus_di) - STATE.get("prev_di_spread", 0)
            new_conf = self.confidence_engine.update_live_confidence(old_conf, cont_pressure_score, failure_score, adx_slope, di_spread_change)
            new_conf = ConfidenceEngine.apply_institutional_modifiers(new_conf, smart_money, momentum, continuation_eval.continuation_probability * 100)
            STATE["current_confidence"] = new_conf
            STATE["prev_di_spread"] = plus_di - minus_di
            
            # استخدام InstitutionalContextEngine للحصول على سياق واحد
            # هذا يُستدعى مرة واحدة فقط في كل دورة إدارة
            institutional_context = self._context_engine.analyze(
                df_live, smart_money, momentum, candle_events, side, STATE
            )
            
            # تحديث TradeMemory بالسياق
            trade = self._trade_memory.get_open_trade(symbol)
            if trade:
                # Smart rolling context history - only save on CHANGE
                history = trade.get("context_history", [])
                if self._context_engine._has_changed(institutional_context):
                    snapshot = self._context_engine._create_snapshot(institutional_context)
                    history.append(snapshot)
                    # Rolling: keep last 10 only
                    if len(history) > 10:
                        history = history[-10:]
                    self._context_engine._prev_snapshot = snapshot

                self._trade_memory.update_open_trade(symbol,
                    zone_type=institutional_context.zone_type,
                    zone_state=institutional_context.zone_state.value if institutional_context.zone_state else None,
                    zone_score=institutional_context.zone_score,
                    zone_price=institutional_context.zone_price,
                    structure_state=institutional_context.structure_state.value if institutional_context.structure_state else None,
                    structure_key=institutional_context.structure_key,
                    institutional_bias=institutional_context.institutional_bias,
                    current_confidence=institutional_context.confidence,
                    context_history=history
                )
            
            # استخدام TradeDecisionEngine لإدارة الصفقة
            trade_type = STATE.get("trade_type", "TREND")
            management_state = {
                "symbol": symbol,
                "trade_state": trade_state,
                "trade_type": trade_type,
                "roe_pct": roe,
                "trail_active": STATE.get("trail_activated", False),
                "tp1_hit": STATE.get("tp1_hit", False),
                "profit_lock_activated": STATE.get("profit_lock_activated", False),
                "smart_money": smart_money,
                "momentum_flow": momentum,
                "candle_events": candle_events[-5:],
                "candle_event_summary": candle_event_summary,
                "structure_aligned": structure_aligned,
                "weak_pullback": weak_pullback,
                "counter_displacement": counter_displacement,
                "entry": entry,
                "mark_price": mark_price,
                "atr": atr,
                # Institutional Context
                "institutional_context": institutional_context,
            }
            management_decision = self._decision_engine.decide_management(symbol, management_state)
            
            # تسجيل القرار في TradeMemory
            self._trade_memory.record_decision(
                symbol, 
                management_decision.get("action", "HOLD"),
                ", ".join(management_decision.get("reasons", []))
            )
            self._trade_memory.record_recommendation(
                symbol,
                management_decision.get("action", "HOLD"),
                management_decision.get("score", 100)
            )
            
            # تسجيل حدث في Trade Story
            self._trade_memory.record_event(symbol, "management_cycle", {
                "action": management_decision.get("action"),
                "trade_type": trade_type,
                "roe": roe,
                "trade_state": trade_state,
                "events": [e.get("type") for e in candle_events[-3:]],
            })
            
            # تنفيذ قرار إدارة الصفقة
            if management_decision.get("action") == "PROFIT_LOCK":
                if not STATE.get("tp1_hit", False):
                    close_partial(0.5)
                STATE["profit_lock_activated"] = True
                log_execution(f"[MGMT] Profit Lock activated: {management_decision.get('reasons')}", "INFO")
            
            elif management_decision.get("action") == "TIGHTEN_TRAIL":
                STATE["trail_tightened"] = True
                log_execution(f"[MGMT] Trail tightened: {management_decision.get('reasons')}", "INFO")
            
            elif management_decision.get("action") == "EARLY_TP1":
                if not STATE.get("tp1_hit", False) and roe >= 2.0:
                    close_partial(0.5)
                    STATE["tp1_hit"] = True
                    STATE["synthetic_sl"] = entry
                    tg_tp_hit(symbol, 1, roe)
                    log_execution(f"[MGMT] Early TP1: {management_decision.get('reasons')}", "INFO")
            
            elif management_decision.get("action") == "SECURE_PROFIT":
                close_partial(0.5)
                log_execution(f"[MGMT] Secure profit: {management_decision.get('reasons')}", "INFO")

            self.last_heavy_calc_ts = now
        else:
            # Use cached values from STATE
            adx_now = STATE.get("adx_live", 20.0)
            plus_di = STATE.get("di_plus_live", 20.0)
            minus_di = STATE.get("di_minus_live", 20.0)
            smart_money = STATE.get("smart_money", {})
            momentum = STATE.get("momentum_flow", {})
            trade_state = STATE.get("trade_state", "RANGE_CHOP")
            continuation_eval = ContinuationEvaluation(
                continuation_probability=STATE.get("continuation_probability", 0.5),
                trend_strength=STATE.get("trend_strength", 0.5),
                exhaustion_probability=0.0,
                reclaim_risk=STATE.get("reclaim_risk", 0.0),
                counter_pressure=STATE.get("counter_pressure", 0.0),
                confidence=0.5,
                reasons=STATE.get("continuation_reasons", []),
                should_hold=STATE.get("continuation_probability", 0.5) >= 0.62,
                hold_quality=STATE.get("hold_quality", "UNKNOWN")
            )

        # LIVE DEBUG LOG every 5 seconds
        if now - self.last_live_debug_ts >= 5:
            self.last_live_debug_ts = now
            log_execution(
                f"[LIVE_DEBUG] {symbol} | ADX={adx_now:.1f} | DI+={plus_di:.1f} | DI-={minus_di:.1f} | "
                f"ContProb={continuation_eval.continuation_probability:.2f} | MomHealth={momentum.get('momentum_health', 50):.1f} | "
                f"DistRisk={smart_money.get('distribution_risk', 0):.1f} | TradeState={trade_state} | "
                f"TrailMult={self.brain.get_trail_multiplier():.2f} | TP1Delay={self.brain.should_delay_tp1()} | "
                f"TrailActive={STATE.get('trail_activated', False)} | SyntheticSL={STATE.get('synthetic_sl', 0):.4f} | ROE={roe:.2f}%",
                "INFO"
            )

        # Aggressive profit lock / hard exit (fast checks using cached values)
        if self.brain.should_aggressive_profit_lock() and not STATE.get("profit_lock_activated", False):
            log_execution(f"[PROFIT_LOCK] Aggressive profit lock triggered (state={trade_state})", "WARN")
            if not STATE.get("tp1_hit", False):
                close_partial(0.5)
            STATE["profit_lock_activated"] = True

        if self.brain.should_hard_exit():
            log_execution(f"[HARD_EXIT] Hard exit triggered (state={trade_state})", "ERROR")
            # استخدام Pipeline لإغلاق الصفقة
            result = self._close_pipeline.request_close(symbol, "HARD_EXIT")
            self.event_bus.emit("lifecycle_change", TradeLifecycleState.CLOSED)
            DASHBOARD_STATE["live_trade_mode"] = False
            return

        # ========== SYNTHETIC PROTECTION ENGINE (fast checks) ==========
        base_sl_mult = 1.6
        if smart_money.get("distribution_risk", 0) > 45:
            base_sl_mult = 1.2
        elif smart_money.get("distribution_risk", 0) > 65:
            base_sl_mult = 0.8
        if side == "BUY":
            synthetic_sl = entry - atr * base_sl_mult
            if STATE.get("tp1_hit", False):
                synthetic_sl = max(synthetic_sl, entry)
        else:
            synthetic_sl = entry + atr * base_sl_mult
            if STATE.get("tp1_hit", False):
                synthetic_sl = min(synthetic_sl, entry)
        STATE["synthetic_sl"] = synthetic_sl

        # Check stop loss hit (every cycle)
        if (side == "BUY" and mark_price <= synthetic_sl) or (side == "SELL" and mark_price >= synthetic_sl):
            log_execution(f"[SYNTHETIC_SL] Hit at {mark_price:.4f} (SL={synthetic_sl:.4f})", "WARN")
            # استخدام Pipeline لإغلاق الصفقة
            result = self._close_pipeline.request_close(symbol, "STOP_LOSS")
            self.event_bus.emit("lifecycle_change", TradeLifecycleState.CLOSED)
            DASHBOARD_STATE["live_trade_mode"] = False
            return

        # TP1 logic with dynamic threshold
        base_tp1_pct = 0.025
        if self.brain.should_delay_tp1():
            base_tp1_pct = 0.04
        if continuation_eval.continuation_probability > 0.75:
            base_tp1_pct = 0.05
        elif continuation_eval.continuation_probability < 0.4:
            base_tp1_pct = 0.015
        if momentum.get("momentum_health", 50) < 20:
            base_tp1_pct = min(base_tp1_pct, 0.02)
        if smart_money.get("distribution_risk", 0) > 50:
            base_tp1_pct = min(base_tp1_pct, 0.015)
        tp1_price = entry * (1 + base_tp1_pct) if side == "BUY" else entry * (1 - base_tp1_pct)
        STATE["synthetic_tp1"] = tp1_price

        if not STATE.get("tp1_hit", False):
            if (side == "BUY" and mark_price >= tp1_price) or (side == "SELL" and mark_price <= tp1_price):
                log_execution(f"[SYNTHETIC_TP1] Hit at {mark_price:.4f} (target={tp1_price:.4f})", "SUCCESS")
                close_partial(0.5)
                STATE["tp1_hit"] = True
                STATE["synthetic_sl"] = entry
                tg_tp_hit(symbol, 1, roe)
        else:
            tp2_pct = 0.05
            if continuation_eval.continuation_probability > 0.8:
                tp2_pct = 0.08
            tp2_price = entry * (1 + tp2_pct) if side == "BUY" else entry * (1 - tp2_pct)
            STATE["tp2_price"] = tp2_price
            if not STATE.get("tp2_hit", False):
                if (side == "BUY" and mark_price >= tp2_price) or (side == "SELL" and mark_price <= tp2_price):
                    log_execution(f"[SYNTHETIC_TP2] Hit at {mark_price:.4f}", "SUCCESS")
                    STATE["tp2_hit"] = True
                    # استخدام Pipeline لإغلاق الصفقة
                    result = self._close_pipeline.request_close(symbol, "TAKE_PROFIT_2")
                    self.event_bus.emit("lifecycle_change", TradeLifecycleState.CLOSED)
                    DASHBOARD_STATE["live_trade_mode"] = False
                    return

        # Adaptive Trailing Stop
        trail_mult = self.brain.get_trail_multiplier()
        if smart_money.get("distribution_risk", 0) > 45:
            trail_mult *= 0.7
        if momentum.get("momentum_health", 50) < 30:
            trail_mult *= 0.8
        if continuation_eval.continuation_probability > 0.8:
            trail_mult *= 1.2
        trail_mult = max(0.5, min(4.5, trail_mult))

        if roe > 1.5:
            if not STATE.get("trail_activated", False):
                STATE["trail_activated"] = True
                STATE["trail_stop"] = synthetic_sl
                log_execution(f"[TRAIL] Activated with multiplier {trail_mult}", "INFO")
            if side == "BUY":
                new_trail = mark_price - trail_mult * atr
                if new_trail > STATE.get("trail_stop", 0):
                    STATE["trail_stop"] = new_trail
            else:
                new_trail = mark_price + trail_mult * atr
                if new_trail < STATE.get("trail_stop", float('inf')):
                    STATE["trail_stop"] = new_trail
            if (side == "BUY" and mark_price <= STATE.get("trail_stop", 0)) or (side == "SELL" and mark_price >= STATE.get("trail_stop", float('inf'))):
                log_execution(f"[TRAIL] Stop hit at {mark_price:.4f} (trail={STATE['trail_stop']:.4f})", "WARN")
                # استخدام Pipeline لإغلاق الصفقة
                result = self._close_pipeline.request_close(symbol, "TRAILING_STOP")
                self.event_bus.emit("lifecycle_change", TradeLifecycleState.CLOSED)
                DASHBOARD_STATE["live_trade_mode"] = False
                return
        else:
            STATE["trail_activated"] = False
            STATE["trail_stop"] = 0.0

        # PPE layer (using cached values, df_live only if needed)
        if USE_PPE:
            state_ppe = {
                "symbol": symbol,
                "trail_active": STATE.get("trail_activated", False),
                "tp1_done": STATE.get("tp1_hit", False),
                "runner_mode": STATE.get("runner_mode", False),
                "max_price": STATE.get("max_price", entry),
                "min_price": STATE.get("min_price", entry),
                "sl": STATE.get("synthetic_sl", 0.0),
                "trail_stop": STATE.get("trail_stop", 0.0),
                "remaining_qty": STATE.get("remaining_qty", STATE["qty"]),
                "tp1_hit": STATE.get("tp1_hit", False),
                "smart_trail_mult": trail_mult,
                "smart_money": smart_money,
                "momentum_flow": momentum,
                "profit_lock_activated": STATE.get("profit_lock_activated", False),
                "trail_tightened": STATE.get("trail_tightened", False)
            }
            idx = len(df_live) - 1
            action, new_sl, new_trail = apply_50_50_profit_engine(
                df_live, idx, mark_price, atr, side, entry, state_ppe, roe, trade_state=trade_state
            )
            STATE["synthetic_sl"] = new_sl
            STATE["trail_stop"] = new_trail
            STATE["trail_activated"] = state_ppe["trail_active"]
            STATE["tp1_hit"] = state_ppe["tp1_hit"]
            STATE["runner_mode"] = state_ppe["runner_mode"]
            STATE["max_price"] = state_ppe["max_price"]
            STATE["min_price"] = state_ppe["min_price"]
            STATE["profit_lock_activated"] = state_ppe["profit_lock_activated"]
            STATE["trail_tightened"] = state_ppe["trail_tightened"]
            TRADE_STATE["trail_on"] = STATE["trail_activated"]
            TRADE_STATE["tp1_hit"] = STATE["tp1_hit"]
            if action == "EXIT":
                # استخدام Pipeline لإغلاق الصفقة
                result = self._close_pipeline.request_close(symbol, "PPE_EXIT")
                self.event_bus.emit("lifecycle_change", TradeLifecycleState.CLOSED)
                DASHBOARD_STATE["live_trade_mode"] = False
                return

        # Final stop check
        if (side == "BUY" and mark_price <= STATE.get("synthetic_sl", 0)) or (side == "SELL" and mark_price >= STATE.get("synthetic_sl", 0)):
            # استخدام Pipeline لإغلاق الصفقة
            result = self._close_pipeline.request_close(symbol, "FINAL_STOP")
            self.event_bus.emit("lifecycle_change", TradeLifecycleState.CLOSED)
            DASHBOARD_STATE["live_trade_mode"] = False
            return

_event_bus = EventBus()
_exchange_sync = ExchangeSyncService(_event_bus)
_recovery_guard = RecoveryGuard(_event_bus, _exchange_sync)
_live_manager = LiveTradeManager(_event_bus, _exchange_sync, _recovery_guard)

def sync_position_state(symbol=None):
    if PAPER_MODE:
        if STATE.get("open"):
            price = get_ticker_safe(STATE["current_symbol"])
            if price:
                raw_pnl = (price - STATE["entry"])/STATE["entry"]*100 if STATE["side"]=="BUY" else (STATE["entry"]-price)/STATE["entry"]*100
                roe_pct = raw_pnl * LEVERAGE
                STATE["roe_pct"] = roe_pct
                STATE["mark_price"] = price
                STATE["unrealized_pnl_usdt"] = (price - STATE["entry"]) * STATE["qty"] if STATE["side"]=="BUY" else (STATE["entry"] - price) * STATE["qty"]
                return price, 0.0, 0.0, roe_pct
        return None, None, None, None

    if not symbol and STATE.get("open"):
        symbol = STATE["current_symbol"]
    if not symbol:
        return None, None, None, None

    snap = _exchange_sync.fetch_live_snapshot(symbol)
    if snap is None:
        if STATE.get("open"):
            log_execution(f"[POS_SYNC] Position closed externally on {symbol}, cleaning state", "WARN")
            with _TRADE_LOCK:
                STATE["open"] = False
                TRADE_STATE["in_position"] = False
                _live_manager.lifecycle_state = TradeLifecycleState.CLOSED
                DASHBOARD_STATE["live_trade_mode"] = False
        return None, None, None, None

    with _TRADE_LOCK:
        if not STATE.get("open"):
            # External position detected - mark as not bot-opened
            STATE["open"] = True
            STATE["bot_opened"] = False  # External manual position
            STATE["side"] = snap.side
            STATE["entry"] = snap.entry_price
            STATE["qty"] = snap.qty
            STATE["remaining_qty"] = snap.qty
            STATE["current_symbol"] = symbol
            STATE["entry_time"] = time.time()
            TRADE_STATE.update({
                "in_position": True,
                "symbol": symbol,
                "side": snap.side,
                "entry": snap.entry_price,
                "qty": snap.qty,
                "last_update_ts": time.time()
            })
            _live_manager.start_trade(symbol, snap.side, snap.entry_price, snap.qty, 0.0, 0.0, 0.0)
        else:
            STATE["entry"] = snap.entry_price
            STATE["qty"] = snap.qty
            STATE["remaining_qty"] = snap.qty
            STATE["side"] = snap.side
            TRADE_STATE.update({
                "entry": snap.entry_price,
                "qty": snap.qty,
                "side": snap.side
            })

        STATE["margin"] = snap.margin
        STATE["unrealized_pnl_usdt"] = snap.unrealized_pnl
        STATE["roe_pct"] = snap.roe_pct
        STATE["leverage"] = snap.leverage
        STATE["mark_price"] = snap.mark_price
        STATE["liquidation_price"] = snap.liquidation_price

    return snap.mark_price, snap.unrealized_pnl, snap.margin, snap.roe_pct

def get_realized_pnl_for_symbol(symbol, lookback_seconds=30):
    if PAPER_MODE:
        return 0.0, 0.0
    try:
        sym = normalize_symbol(symbol)
        since = int((time.time() - lookback_seconds) * 1000)
        trades = safe_api_call(ex.fetch_my_trades, sym, limit=100, params={'since': since})
        if not trades:
            return 0.0, 0.0
        pnl_usdt = 0.0
        for trade in trades:
            side = trade['side'].lower()
            qty = trade['amount']
            price = trade['price']
            cost = qty * price
            if side == 'buy':
                pnl_usdt -= cost
            else:
                pnl_usdt += cost
        balance = get_balance_safe()
        pnl_pct = (pnl_usdt / balance * 100) if balance > 0 else 0.0
        return pnl_usdt, pnl_pct
    except Exception as e:
        log_execution(f"[REALIZED_PNL] Error: {e}", "WARN")
        return 0.0, 0.0

# ========== INDICATORS ==========
def rma(series, period):
    return series.ewm(alpha=1/period, adjust=False).mean()

def ema(series, period):
    return series.ewm(span=period, adjust=False).mean()

def compute_atr(df, period=14):
    if df is None or len(df) < period+1:
        return pd.Series([0.0]*len(df))
    high = df['high']
    low = df['low']
    close = df['close']
    tr1 = high - low
    tr2 = (high - close.shift(1)).abs()
    tr3 = (low - close.shift(1)).abs()
    tr = pd.concat([tr1, tr2, tr3], axis=1).max(axis=1)
    atr = rma(tr, period)
    atr = atr.bfill().ffill().fillna(tr.mean())
    atr = atr.clip(lower=1e-8)
    return atr

def compute_adx(df, period=14):
    if df is None or len(df) < period*2:
        return pd.Series([0.0]*len(df))
    high = df['high']
    low = df['low']
    close = df['close']
    tr1 = high - low
    tr2 = (high - close.shift(1)).abs()
    tr3 = (low - close.shift(1)).abs()
    tr = pd.concat([tr1, tr2, tr3], axis=1).max(axis=1)
    atr = rma(tr, period) + 1e-9
    up_move = high.diff()
    down_move = -low.diff()
    plus_dm = np.where((up_move > down_move) & (up_move > 0), up_move, 0.0)
    minus_dm = np.where((down_move > up_move) & (down_move > 0), down_move, 0.0)
    plus_dm = pd.Series(plus_dm, index=df.index)
    minus_dm = pd.Series(minus_dm, index=df.index)
    plus_di = 100 * rma(plus_dm, period) / (atr + 1e-9)
    minus_di = 100 * rma(minus_dm, period) / (atr + 1e-9)
    dx = (abs(plus_di - minus_di) / (plus_di + minus_di + 1e-9)) * 100
    adx = rma(dx, period)
    adx = adx.bfill().ffill().fillna(0).clip(0, 100)
    return adx

def compute_rsi(df, period=14):
    if df is None or len(df) < period+1:
        return pd.Series([50.0]*len(df))
    close = df['close']
    delta = close.diff()
    gain = delta.clip(lower=0)
    loss = -delta.clip(upper=0)
    avg_gain = rma(gain, period) + 1e-9
    avg_loss = rma(loss, period) + 1e-9
    rs = avg_gain / (avg_loss + 1e-9)
    rsi = 100 - (100 / (1 + rs))
    rsi = rsi.bfill().ffill().fillna(50).clip(0, 100)
    return rsi

def compute_macd(df, fast=12, slow=26, signal=9):
    ema_fast = df['close'].ewm(span=fast, adjust=False).mean()
    ema_slow = df['close'].ewm(span=slow, adjust=False).mean()
    macd_line = ema_fast - ema_slow
    signal_line = macd_line.ewm(span=signal, adjust=False).mean()
    histogram = macd_line - signal_line
    return macd_line, signal_line, histogram

def macd_first_flip(hist):
    if len(hist) < 2:
        return False
    return hist.iloc[-2] < 0 and hist.iloc[-1] > 0

def volume_pressure_real(df, window=20, threshold=1.2):
    if len(df) < window + 1:
        return False
    vol = df['volume']
    mean = vol.rolling(window).mean().iloc[-1]
    std = vol.rolling(window).std().iloc[-1]
    if std == 0:
        return False
    z = (vol.iloc[-1] - mean) / std
    return z > threshold

def flow_engine(df):
    if len(df) < 2:
        return "neutral"
    last = df.iloc[-1]
    body = last['close'] - last['open']
    vol = last['volume']
    avg_vol = df['volume'].rolling(20).mean().iloc[-1] if len(df) >= 20 else vol
    if vol > avg_vol * 1.5:
        if body > 0:
            return "aggressive_buy"
        else:
            return "aggressive_sell"
    if vol > avg_vol and abs(body) < (last['high'] - last['low']) * 0.3:
        return "absorption"
    return "neutral"

def orderbook_imbalance(ob, depth=10):
    if not ob or 'bids' not in ob or 'asks' not in ob:
        return 0.0
    bids_sum = sum([b[1] for b in ob['bids'][:depth]]) if ob['bids'] else 0
    asks_sum = sum([a[1] for a in ob['asks'][:depth]]) if ob['asks'] else 0
    total = bids_sum + asks_sum
    if total == 0:
        return 0.0
    return (bids_sum - asks_sum) / total

def detect_walls(ob, depth=10, threshold=3.0):
    if not ob or 'bids' not in ob or 'asks' not in ob:
        return False, False
    bid_sizes = [b[1] for b in ob['bids'][:depth]]
    ask_sizes = [a[1] for a in ob['asks'][:depth]]
    if bid_sizes:
        avg_bid = sum(bid_sizes) / len(bid_sizes)
        bid_wall = any(s > avg_bid * threshold for s in bid_sizes)
    else:
        bid_wall = False
    if ask_sizes:
        avg_ask = sum(ask_sizes) / len(ask_sizes)
        ask_wall = any(s > avg_ask * threshold for s in ask_sizes)
    else:
        ask_wall = False
    return bid_wall, ask_wall

def is_late_move(df, atr, multiplier=1.5):
    if len(df) < 1 or atr <= 0:
        return False
    last = df.iloc[-1]
    candle_range = last['high'] - last['low']
    return candle_range > multiplier * atr

def early_score(df, ob, atr, side):
    score = 0
    reasons = []
    macd, signal, hist = compute_macd(df)
    if macd_first_flip(hist):
        score += 2
        reasons.append("macd_flip")
    if volume_pressure_real(df):
        score += 2
        reasons.append("volume_pressure")
    flow = flow_engine(df)
    if side == "BUY" and flow == "aggressive_buy":
        score += 2
        reasons.append("flow_buy")
    elif side == "SELL" and flow == "aggressive_sell":
        score += 2
        reasons.append("flow_sell")
    elif flow == "absorption":
        reasons.append("absorption")
    obi = orderbook_imbalance(ob, depth=10)
    if side == "BUY" and obi > 0.2:
        score += 2
        reasons.append(f"obi_bullish_{obi:.2f}")
    elif side == "SELL" and obi < -0.2:
        score += 2
        reasons.append(f"obi_bearish_{obi:.2f}")
    bid_wall, ask_wall = detect_walls(ob, depth=10, threshold=3.0)
    if side == "BUY" and bid_wall:
        score += 1
        reasons.append("bid_wall")
    elif side == "SELL" and ask_wall:
        score += 1
        reasons.append("ask_wall")
    if is_late_move(df, atr, multiplier=1.5):
        score -= 3
        reasons.append("late_move_penalty")
    return score, reasons

# ========== RF ENGINE ==========
class RFEngine:
    def __init__(self, period=20, multiplier=3.5):
        self.period = period
        self.multiplier = multiplier

    def ema(self, s, length):
        return s.ewm(span=length, adjust=False).mean()

    def rng_size(self, x):
        n = self.period
        qty = self.multiplier
        wper = (n * 2) - 1
        avrng = self.ema((x - x.shift(1)).abs(), n)
        return self.ema(avrng, wper) * qty

    def rng_filt(self, x, rng):
        filt = np.zeros(len(x))
        hi = np.zeros(len(x))
        lo = np.zeros(len(x))
        for i in range(len(x)):
            if i == 0:
                filt[i] = x.iloc[i]
            else:
                prev = filt[i - 1]
                r = rng.iloc[i]
                if x.iloc[i] - r > prev:
                    filt[i] = x.iloc[i] - r
                elif x.iloc[i] + r < prev:
                    filt[i] = x.iloc[i] + r
                else:
                    filt[i] = prev
            hi[i] = filt[i] + rng.iloc[i]
            lo[i] = filt[i] - rng.iloc[i]
        return pd.Series(hi, index=x.index), pd.Series(lo, index=x.index), pd.Series(filt, index=x.index)

    def compute(self, df, src="close"):
        x = df[src]
        rng = self.rng_size(x)
        h, l, filt = self.rng_filt(x, rng)
        fdir = np.zeros(len(filt))
        for i in range(1, len(filt)):
            if filt.iloc[i] > filt.iloc[i - 1]:
                fdir[i] = 1
            elif filt.iloc[i] < filt.iloc[i - 1]:
                fdir[i] = -1
            else:
                fdir[i] = fdir[i - 1]
        longCond = (x > filt) & (pd.Series(fdir) == 1)
        shortCond = (x < filt) & (pd.Series(fdir) == -1)
        CondIni = np.zeros(len(x))
        for i in range(1, len(x)):
            if longCond.iloc[i]:
                CondIni[i] = 1
            elif shortCond.iloc[i]:
                CondIni[i] = -1
            else:
                CondIni[i] = CondIni[i - 1]
        longSignal = longCond & (pd.Series(CondIni).shift(1) == -1)
        shortSignal = shortCond & (pd.Series(CondIni).shift(1) == 1)
        signal = None
        if longSignal.iloc[-1]:
            signal = "BUY"
        elif shortSignal.iloc[-1]:
            signal = "SELL"
        triggered = bool(longSignal.iloc[-1] or shortSignal.iloc[-1])
        distance = (x.iloc[-1] - filt.iloc[-1]) / x.iloc[-1] if x.iloc[-1] != 0 else 0
        return {
            "signal": signal,
            "triggered": triggered,
            "filt": filt.iloc[-1],
            "h_band": h.iloc[-1],
            "l_band": l.iloc[-1],
            "distance": distance
        }

# ========== ADVANCED CANDLE INTELLIGENCE ==========
def candle_metrics(candle):
    body = abs(candle['close'] - candle['open'])
    range_ = candle['high'] - candle['low']
    upper_wick = candle['high'] - max(candle['open'], candle['close'])
    lower_wick = min(candle['open'], candle['close']) - candle['low']
    return body, range_, upper_wick, lower_wick

def is_pinbar(candle, atr, side, body_atr_min=0.5, wick_body_ratio=2.5, wick_range_ratio=0.6):
    body, range_, upper_wick, lower_wick = candle_metrics(candle)
    if range_ == 0 or atr <= 0:
        return False
    if side == "BUY":
        return (lower_wick >= wick_body_ratio * body and
                lower_wick / range_ >= wick_range_ratio and
                body / atr >= body_atr_min)
    else:
        return (upper_wick >= wick_body_ratio * body and
                upper_wick / range_ >= wick_range_ratio and
                body / atr >= body_atr_min)

def classify_volume(df, period=20, expansion_threshold=1.8, normal_threshold=1.3, exhaustion_threshold=0.7):
    if len(df) < period + 1:
        return "neutral"
    vol = df['volume']
    avg_vol = vol.rolling(period).mean().iloc[-1]
    if avg_vol == 0:
        return "neutral"
    ratio = vol.iloc[-1] / avg_vol
    if ratio > expansion_threshold:
        return "expansion"
    elif ratio > normal_threshold:
        return "normal"
    elif ratio < exhaustion_threshold:
        return "exhaustion"
    else:
        return "neutral"

def detect_displacement(df, side, atr, volume_state, body_atr_threshold=0.8, volume_expansion_required=False):
    if len(df) < 2:
        return False
    last = df.iloc[-1]
    body, range_, _, _ = candle_metrics(last)
    if body / atr < body_atr_threshold:
        return False
    if side == "BUY" and last['close'] <= last['open']:
        return False
    if side == "SELL" and last['close'] >= last['open']:
        return False
    if volume_expansion_required and volume_state != "expansion":
        return False
    return True

def detect_location(df, price, supports, resistances, threshold=0.003):
    near_support = False
    near_resistance = False
    if supports:
        min_dist_sup = min(abs(price - s) / price for s in supports)
        if min_dist_sup < threshold:
            near_support = True
    if resistances:
        min_dist_res = min(abs(price - r) / price for r in resistances)
        if min_dist_res < threshold:
            near_resistance = True
    if near_support and not near_resistance:
        return "LOW"
    elif near_resistance and not near_support:
        return "HIGH"
    else:
        return "MID"

def get_liquidity_sweep_for_side(df, side, lookback=5):
    ctx = detect_liquidity_context(df, lookback=lookback)
    if side == "BUY" and ctx == "sell_side_taken":
        return True
    if side == "SELL" and ctx == "buy_side_taken":
        return True
    return False

def get_rejection_pinbar(df, side, atr):
    if len(df) < 1:
        return False
    candle = df.iloc[-1]
    return is_pinbar(candle, atr, side)

def advanced_detect_scenario(df, side, atr, volume_state):
    if len(df) < 3:
        return "NONE"
    sweep = get_liquidity_sweep_for_side(df, side)
    rejection = get_rejection_pinbar(df, side, atr)
    displacement = detect_displacement(df, side, atr, volume_state, body_atr_threshold=0.8, volume_expansion_required=False)
    if sweep and rejection:
        return "TRAP_REVERSAL"
    elif displacement and not rejection:
        return "TREND_CONTINUATION"
    else:
        return "NONE"

def advanced_decision_engine(scenario, adx, volume_state, location,
                              smart_money=None, momentum=None, events=None, zone_score=0,
                              readiness_score=0):
    """
    Advanced decision engine with institutional override support.
    
    ADX Override Rules:
    - If ADX < 18 but institutional context is strong, allow entry
    - Requires multiple institutional factors (>= 4 of 5)
    - Records override usage for analysis
    """
    if scenario == "NONE":
        return "SKIP", None, False
    if volume_state == "exhaustion":
        log_execution(f"[ADV_DECISION] Volume exhaustion -> SKIP", "INFO", debounce_key=f"adv_vol_exhaustion", debounce_sec=120)
        return "SKIP", None, False
    adx = float(adx) if adx is not None else 20.0
    
    # Check for institutional override when ADX is low
    # Uses Institutional Readiness as primary threshold
    adx_override_used = False
    if adx < 18 and smart_money and momentum:
        # Primary: Institutional Readiness must be STRONG (>= 85)
        if readiness_score >= 85:
            strong_factors = 0

            # Factor 1: Strong zone
            if zone_score >= 85:
                strong_factors += 1

            # Factor 2: Smart money alignment
            if smart_money.get("smart_money_dominant"):
                strong_factors += 1

            # Factor 3: Momentum alignment
            if momentum.get("direction") in ["BULLISH", "BEARISH"]:
                strong_factors += 1

            # Factor 4: Banker pressure
            if smart_money.get("banker_pressure", 50) > 60:
                strong_factors += 1

            # Factor 5: Strong signal event
            if events:
                has_signal = any(e.get("type") in ["strong_rejection", "liquidity_sweep", "failed_retest"] for e in events)
                if has_signal:
                    strong_factors += 1

            # Require at least 4/5 factors for override
            if strong_factors >= 4:
                adx_override_used = True
                log_execution(f"[ADV_DECISION] ADX {adx:.1f} < 18 but INSTITUTIONAL OVERRIDE (Readiness={readiness_score:.0f}, {strong_factors}/5 factors)", "INFO")

    # Standard ADX check (skipped if override)
    if adx < 18 and not adx_override_used:
        log_execution(f"[ADV_DECISION] ADX too low ({adx:.1f}) -> SKIP", "INFO", debounce_key=f"adv_adx_low", debounce_sec=120)
        return "SKIP", None, False
    
    if scenario == "TRAP_REVERSAL":
        if adx < 35 or adx_override_used:
            override_flag = " [OVERRIDE]" if adx_override_used else ""
            return "ENTER", f"STRONG{override_flag}", adx_override_used
        else:
            log_execution(f"[ADV_DECISION] TRAP_REVERSAL but ADX >=35 ({adx:.1f}) -> SKIP", "INFO", debounce_key=f"adv_trap_adx_high", debounce_sec=120)
            return "SKIP", None, False
    elif scenario == "TREND_CONTINUATION":
        if (20 < adx < 45) or adx_override_used:
            override_flag = " [OVERRIDE]" if adx_override_used else ""
            return "ENTER", f"MEDIUM{override_flag}", adx_override_used
        else:
            log_execution(f"[ADV_DECISION] TREND_CONTINUATION but ADX out of range (20-45) -> {adx:.1f} SKIP", "INFO", debounce_key=f"adv_trend_adx_range", debounce_sec=120)
            return "SKIP", None, False
    return "SKIP", None, False

# ========== LEGACY SMC FUNCTIONS ==========
def detect_bos(df, lookback=5):
    if len(df) < lookback+2:
        return False, False
    recent_high = df['high'].iloc[-lookback-1:-1].max()
    recent_low = df['low'].iloc[-lookback-1:-1].min()
    current_close = df['close'].iloc[-1]
    bos_up = current_close > recent_high
    bos_down = current_close < recent_low
    return bos_up, bos_down

def detect_scenario(df):
    if len(df) < 30:
        return "NONE"
    row = df.iloc[-1]
    liquidity_ctx = detect_liquidity_context(df, lookback=10)
    sweep_up = (liquidity_ctx == "buy_side_taken")
    sweep_down = (liquidity_ctx == "sell_side_taken")
    bos_up, bos_down = detect_bos(df)
    vol_spike_flag = volume_spike(df)
    vol_sma = df['volume'].iloc[-21:-1].mean() if len(df) >= 21 else df['volume'].mean()
    volume_ok = row['volume'] > 1.5 * vol_sma if vol_sma > 0 else False
    range_ = row['high'] - row['low']
    if range_ == 0:
        rejection_buy = False
        rejection_sell = False
    else:
        body = abs(row['close'] - row['open'])
        lower_wick = min(row['open'], row['close']) - row['low']
        upper_wick = row['high'] - max(row['open'], row['close'])
        rejection_buy = (lower_wick > 2 * body + 1e-9) or (row['close'] > row['open'] and body/range_ > 0.5)
        rejection_sell = (upper_wick > 2 * body + 1e-9) or (row['close'] < row['open'] and body/range_ > 0.5)
    if sweep_down and rejection_buy:
        return "REVERSAL_BUY"
    if sweep_up and rejection_sell:
        return "REVERSAL_SELL"
    if bos_up and volume_ok:
        return "TREND_BUY"
    if bos_down and volume_ok:
        return "TREND_SELL"
    if sweep_down and not rejection_buy:
        return "TRAP_SELL"
    if sweep_up and not rejection_sell:
        return "TRAP_BUY"
    return "NONE"

def decision_engine(scenario, rf_signal, adx):
    if scenario == "NONE":
        return "SKIP"
    if scenario == "REVERSAL_BUY" and rf_signal == "BUY":
        if adx < 35:
            return "STRONG"
        else:
            return "SKIP"
    if scenario == "REVERSAL_SELL" and rf_signal == "SELL":
        if adx < 35:
            return "STRONG"
        else:
            return "SKIP"
    if scenario == "TREND_BUY" and rf_signal == "BUY":
        if 20 < adx < 45:
            return "MEDIUM"
        else:
            return "SKIP"
    if scenario == "TREND_SELL" and rf_signal == "SELL":
        if 20 < adx < 45:
            return "MEDIUM"
        else:
            return "SKIP"
    if "TRAP" in scenario:
        return "STRONG"
    return "SKIP"

def apply_profit_engine(symbol, current_price, df, idx, position_state):
    if not position_state["open"]:
        return "HOLD"
    side = position_state["side"]
    entry = position_state["entry"]
    remaining = position_state["remaining_qty"]
    pnl_pct = (current_price - entry) / entry * 100 if side == "BUY" else (entry - current_price) / entry * 100
    if not position_state.get("tp1_hit", False) and pnl_pct >= 0.5:
        close_ratio = 0.3
        close_qty = remaining * close_ratio
        if close_qty > 0:
            if PAPER_MODE:
                position_state["remaining_qty"] -= close_qty
                TRADE_STATE["qty"] = position_state["remaining_qty"]
            else:
                close_partial(close_ratio)
            log_execution(f"TP1 hit at {pnl_pct:.2f}% - closed {close_ratio*100:.0f}%", "SUCCESS")
            tg_tp_hit(symbol, 1, pnl_pct)
        position_state["tp1_hit"] = True
        position_state["sl"] = entry
        position_state["trail_activated"] = True
        atr_val = compute_atr(df).iloc[-1] if len(df) > 14 else current_price * 0.01
        if side == "BUY":
            position_state["trail_stop"] = current_price - TRAIL_ATR_MULT * atr_val
        else:
            position_state["trail_stop"] = current_price + TRAIL_ATR_MULT * atr_val
        return "TP1"
    if position_state.get("tp1_hit", False) and not position_state.get("tp2_hit", False) and pnl_pct >= 1.2:
        close_ratio = 0.3
        close_qty = position_state["remaining_qty"] * close_ratio
        if close_qty > 0:
            if PAPER_MODE:
                position_state["remaining_qty"] -= close_qty
                TRADE_STATE["qty"] = position_state["remaining_qty"]
            else:
                close_partial(close_ratio)
            log_execution(f"TP2 hit at {pnl_pct:.2f}% - closed {close_ratio*100:.0f}%", "SUCCESS")
            tg_tp_hit(symbol, 2, pnl_pct)
        position_state["tp2_hit"] = True
        return "TP2"
    if len(df) >= 2 and idx >= 1:
        adx_series = compute_adx(df)
        if adx_series is not None and len(adx_series) > idx:
            adx_now = adx_series.iloc[idx]
            adx_prev = adx_series.iloc[idx-1]
            if adx_now < adx_prev:
                candle_close = df['close'].iloc[idx]
                candle_open = df['open'].iloc[idx]
                if side == "BUY" and candle_close < candle_open:
                    log_execution(f"Exhaustion exit: ADX weakening and bearish candle", "WARN")
                    CloseVerificationPipeline().request_close(symbol, "EXHAUSTION_EXIT")
                    return "EXIT"
                if side == "SELL" and candle_close > candle_open:
                    log_execution(f"Exhaustion exit: ADX weakening and bullish candle", "WARN")
                    CloseVerificationPipeline().request_close(symbol, "EXHAUSTION_EXIT")
                    return "EXIT"
    if position_state.get("trail_activated", False) and position_state.get("trail_stop", 0) > 0:
        if side == "BUY" and current_price <= position_state["trail_stop"]:
            log_execution(f"Trailing stop hit at {current_price:.4f}", "WARN")
            CloseVerificationPipeline().request_close(symbol, "TRAILING_STOP")
            return "EXIT"
        if side == "SELL" and current_price >= position_state["trail_stop"]:
            log_execution(f"Trailing stop hit at {current_price:.4f}", "WARN")
            CloseVerificationPipeline().request_close(symbol, "TRAILING_STOP")
            return "EXIT"
        atr_val = compute_atr(df).iloc[-1] if len(df) > 14 else current_price * 0.01
        if side == "BUY":
            new_stop = current_price - TRAIL_ATR_MULT * atr_val
            if new_stop > position_state["trail_stop"]:
                position_state["trail_stop"] = new_stop
        else:
            new_stop = current_price + TRAIL_ATR_MULT * atr_val
            if new_stop < position_state["trail_stop"]:
                position_state["trail_stop"] = new_stop
    return "HOLD"

def detect_institutional_liquidity(df, lookback=20, atr_multiplier=0.5, min_wick_pct=0.001,
                           smart_money=None, momentum=None, zone_context=None):
    """
    Institutional-Grade Liquidity Sweep Detection.
    
    Detects:
    - Swing High/Low sweeps (actual pivots, not previous candle)
    - Equal High/Low (EQH/EQL) pools  
    - Session High/Low sweeps
    - Internal/External structure liquidity
    
    STRENGTH EQUATION:
    ┌─────────────────────────────────────────────────────────────────────┐
    │ Strength = (Wick_Quality × 30) + (Body_Factor × 15) +             │
    │            (Institutional_Context × 35) + (Freshness × 20)          │
    │                                                                     │
    │ Where:                                                              │
    │ • Wick_Quality = min(wick/ATR, 1.0) - ATR-relative wick strength   │
    │ • Body_Factor = 1.0 if body_ratio < 0.3 else 0.5 - rejection quality│
    │ • Institutional_Context = sum of aligned factors / max_possible     │
    │ • Freshness = max(0, 1 - age/lookback) - recency bonus             │
    └─────────────────────────────────────────────────────────────────────┘
    
    CONFIRMATION REQUIREMENTS:
    ┌─────────────────────────────────────────────────────────────────────┐
    │ Sweep requires MINIMUM 3 of 4 confirmation factors:                 │
    │ 1. Wick_Quality >= 0.5 (wick must be ATR-significant)               │
    │ 2. Institutional_Context >= 0.4 (aligned with institutional flow)  │
    │ 3. Body_Factor = 1.0 (strong rejection candle)                      │
    │ 4. Zone_Alignment = True (sweep at fresh zone)                     │
    └─────────────────────────────────────────────────────────────────────┘
    
    CANDIDATE SELECTION (Best Sweep):
    ┌─────────────────────────────────────────────────────────────────────┐
    │ Priority:                                                          │
    │ 1. Confirmed (confirmed=True) - only confirmed sweeps qualify       │
    │ 2. Context_Alignment - institutional flow alignment                 │
    │ 3. Strength - higher score wins                                     │
    │ 4. Age - fresher sweeps win for same strength                       │
    └─────────────────────────────────────────────────────────────────────┘
    
    Context Integration:
    - smart_money: Used for institutional_bias and smart_money_dominant
    - momentum: Used for direction and trend_expansion
    - zone_context: Used for zone_state and zone_score
    """
    import time as time_module
    
    # === CONTEXT INTEGRATION (from existing engines) ===
    inst_bias = "NEUTRAL"
    inst_zone_state = "UNKNOWN"
    zone_score = 50
    
    if smart_money:
        inst_bias = smart_money.get("institutional_bias", "NEUTRAL")
    if momentum:
        mom_dir = momentum.get("direction", "NEUTRAL")
    if zone_context:
        inst_zone_state = zone_context.get("zone_state", "UNKNOWN")
        zone_score = zone_context.get("zone_score", 50)
    
    if df is None or len(df) < 10:
        return None
    
    # ATR computation for relative measurements
    atr = compute_atr(df).iloc[-1] if len(df) >= 14 else df['close'].iloc[-1] * 0.01
    price = df['close'].iloc[-1]
    min_wick_abs = atr * atr_multiplier  # Minimum wick in ATR units
    
    # === STRUCTURE DETECTION ===
    swing_highs = []
    swing_lows = []
    highs = df['high'].values
    lows = df['low'].values
    closes = df['close'].values
    opens = df['open'].values
    
    swing_lookback = 5
    for i in range(swing_lookback, len(highs) - swing_lookback):
        if highs[i] == max(highs[i-swing_lookback:i+swing_lookback+1]):
            swing_highs.append((i, highs[i]))
    for i in range(swing_lookback, len(lows) - swing_lookback):
        if lows[i] == min(lows[i-swing_lookback:i+swing_lookback+1]):
            swing_lows.append((i, lows[i]))
    
    # === EQUAL HIGHS/LOWS (Liquidity Pools) ===
    eqh_pools = []
    eqk_pools = []
    pool_tolerance = atr * 0.003  # 0.3% tolerance
    
    for i, (idx1, h1) in enumerate(swing_highs):
        touches = [(idx1, h1)]
        for j, (idx2, h2) in enumerate(swing_highs[i+1:], i+1):
            if abs(h1 - h2) < pool_tolerance:
                touches.append((idx2, h2))
        if len(touches) >= 2:
            eqh_pools.append({"level": h1, "touches": len(touches)})
    
    for i, (idx1, l1) in enumerate(swing_lows):
        touches = [(idx1, l1)]
        for j, (idx2, l2) in enumerate(swing_lows[i+1:], i+1):
            if abs(l1 - l2) < pool_tolerance:
                touches.append((idx2, l2))
        if len(touches) >= 2:
            eqk_pools.append({"level": l1, "touches": len(touches)})
    
    # === SESSION LEVELS ===
    session_high = max(highs[-20:])
    session_low = min(lows[-20:])
    
    # Recent swings
    recent_sh = sorted(swing_highs[-5:], key=lambda x: x[0], reverse=True)
    recent_sl = sorted(swing_lows[-5:], key=lambda x: x[0], reverse=True)
    
    candidates = []
    
    for i in range(-lookback, -1):
        idx = len(df) + i
        if idx < swing_lookback:
            continue
        
        o, h, l, c = opens[i], highs[i], lows[i], closes[i]
        body_high = max(o, c)
        body_low = min(o, c)
        body_size = abs(c - o)
        candle_range = h - l
        body_ratio = body_size / candle_range if candle_range > 0 else 1.0
        is_bullish = c > o
        
        # === SELL-SIDE SWEEP ===
        for swing_idx, swing_low in recent_sl:
            if swing_idx < idx - lookback:
                continue
            
            if l < swing_low:
                wick = body_low - l
                
                # Quality gates
                if wick < min_wick_abs:
                    continue
                if wick / price < min_wick_pct:
                    continue
                if c < body_low:
                    continue
                
                # === STRENGTH CALCULATION ===
                # 1. Wick Quality (0-1) × 30
                wick_quality = min(wick / (atr * 1.5), 1.0)
                
                # 2. Body Factor (0 or 1) × 15
                body_factor = 1.0 if body_ratio < 0.3 else 0.5 if body_ratio < 0.5 else 0.0
                
                # 3. Institutional Context (0-1) × 35
                inst_aligned = 0
                max_inst = 4
                if is_bullish: inst_aligned += 1
                if inst_bias in ("BUY", "STRONG_BUY"): inst_aligned += 1
                if momentum and momentum.get("direction") == "BULLISH": inst_aligned += 1
                if inst_zone_state in ("FRESH", "TOUCHED", "RETEST"): inst_aligned += 1
                inst_context = inst_aligned / max_inst
                
                # 4. Freshness (0-1) × 20
                age = abs(i)
                freshness = max(0, 1 - age / lookback)
                
                # Final Strength (0-100)
                strength = (
                    wick_quality * 30 +
                    body_factor * 15 +
                    inst_context * 35 +
                    freshness * 20
                )
                
                is_eqk = any(abs(swing_low - eqk["level"]) < pool_tolerance for eqk in eqk_pools)
                is_session_low = abs(swing_low - session_low) < pool_tolerance
                zone_aligned = inst_zone_state in ("FRESH", "TOUCHED", "RETEST")
                
                # === CONFIRMATION (3 of 4 factors) ===
                confirm_factors = [
                    wick_quality >= 0.5,
                    inst_context >= 0.4,
                    body_factor == 1.0,
                    zone_aligned
                ]
                confirmed = sum(confirm_factors) >= 3
                
                candidates.append({
                    "type": "sell_side_taken",
                    "sweep_index": i,
                    "level": swing_low,
                    "wick": wick,
                    "wick_quality": wick_quality,
                    "body_factor": body_factor,
                    "inst_context": inst_context,
                    "strength": strength,
                    "confirmed": confirmed,
                    "is_eqk": is_eqk,
                    "is_session_low": is_session_low,
                    "zone_aligned": zone_aligned,
                    "bullish_close": is_bullish,
                    "body_ratio": body_ratio,
                    "age": age,
                    "confirm_factors": confirm_factors
                })
        
        # === BUY-SIDE SWEEP ===
        for swing_idx, swing_high in recent_sh:
            if swing_idx < idx - lookback:
                continue
            
            if h > swing_high:
                wick = h - body_high
                
                if wick < min_wick_abs:
                    continue
                if wick / price < min_wick_pct:
                    continue
                if c > body_high:
                    continue
                
                # === STRENGTH CALCULATION ===
                wick_quality = min(wick / (atr * 1.5), 1.0)
                body_factor = 1.0 if body_ratio < 0.3 else 0.5 if body_ratio < 0.5 else 0.0
                
                inst_aligned = 0
                max_inst = 4
                if not is_bullish: inst_aligned += 1
                if inst_bias in ("SELL", "STRONG_SELL"): inst_aligned += 1
                if momentum and momentum.get("direction") == "BEARISH": inst_aligned += 1
                if inst_zone_state in ("FRESH", "TOUCHED", "RETEST"): inst_aligned += 1
                inst_context = inst_aligned / max_inst
                
                age = abs(i)
                freshness = max(0, 1 - age / lookback)
                
                strength = (
                    wick_quality * 30 +
                    body_factor * 15 +
                    inst_context * 35 +
                    freshness * 20
                )
                
                is_eqh = any(abs(swing_high - eqh["level"]) < pool_tolerance for eqh in eqh_pools)
                is_session_high = abs(swing_high - session_high) < pool_tolerance
                zone_aligned = inst_zone_state in ("FRESH", "TOUCHED", "RETEST")
                
                confirm_factors = [
                    wick_quality >= 0.5,
                    inst_context >= 0.4,
                    body_factor == 1.0,
                    zone_aligned
                ]
                confirmed = sum(confirm_factors) >= 3
                
                candidates.append({
                    "type": "buy_side_taken",
                    "sweep_index": i,
                    "level": swing_high,
                    "wick": wick,
                    "wick_quality": wick_quality,
                    "body_factor": body_factor,
                    "inst_context": inst_context,
                    "strength": strength,
                    "confirmed": confirmed,
                    "is_eqh": is_eqh,
                    "is_session_high": is_session_high,
                    "zone_aligned": zone_aligned,
                    "bearish_close": not is_bullish,
                    "body_ratio": body_ratio,
                    "age": age,
                    "confirm_factors": confirm_factors
                })
    
    if not candidates:
        return None
    
    # === BEST CANDIDATE SELECTION ===
    def candidate_priority(c):
        return (
            10000 if c["confirmed"] else 0,
            1000 * c["inst_context"],
            100 * c["strength"],
            -c["age"]
        )
    
    candidates.sort(key=candidate_priority, reverse=True)
    best = candidates[0]
    
    result = {
        "type": best["type"],
        "strength": round(best["strength"], 1),
        "level": round(best["level"], 6),
        "wick": round(best["wick"], 6),
        "wick_quality": round(best["wick_quality"], 2),
        "body_factor": best["body_factor"],
        "inst_context": round(best["inst_context"], 2),
        "confirmed": best["confirmed"],
        "age": best["age"],
        "is_institutional": best.get("is_eqk", False) or best.get("is_eqh", False),
        "is_session": best.get("is_session_low", False) or best.get("is_session_high", False),
        "zone_alignment": best["zone_aligned"],
        "quality": "HIGH" if best["strength"] >= 60 else "MEDIUM" if best["strength"] >= 40 else "LOW",
        "confirm_factors": {
            "wick_significant": best["confirm_factors"][0],
            "inst_aligned": best["confirm_factors"][1],
            "strong_rejection": best["confirm_factors"][2],
            "zone_nearby": best["confirm_factors"][3]
        },
        "sweep_candle": {
            "index": best["sweep_index"],
            "open": round(opens[best["sweep_index"]], 6),
            "high": round(highs[best["sweep_index"]], 6),
            "low": round(lows[best["sweep_index"]], 6),
            "close": round(closes[best["sweep_index"]], 6)
        }
    }
    
    return result


def _legacy_return(legacy_value):
    """Backward compatibility wrapper - returns old format for legacy callers."""
    return legacy_value


def detect_liquidity_context(df, lookback=20):
    """
    Backward-compatible wrapper for detect_institutional_liquidity.
    Returns string format for existing code, but uses new algorithm.
    """
    result = detect_institutional_liquidity(df, lookback=lookback)
    
    # Legacy callers expect string or None
    if result is None:
        return None
    
    # Return the type string for backward compatibility
    return result["type"]


def get_liquidity_context_advanced(df, lookback=20):
    """
    Returns full structured object for advanced consumers.
    Use this instead of detect_liquidity_context when you need:
    - strength score
    - confirmation status
    - zone alignment
    - sweep details
    """
    return detect_institutional_liquidity(df, lookback=lookback)

def detect_zone_context(price, supports, resistances, threshold=0.003):
    near_support = min([abs(price - s)/price for s in supports]) < threshold if supports else False
    near_resistance = min([abs(price - r)/price for r in resistances]) < threshold if resistances else False
    return {"near_support": near_support, "near_resistance": near_resistance}

def detect_structure_shift(df):
    if len(df) < 10:
        return None
    last_high = df['high'].iloc[-3]
    prev_high = df['high'].iloc[-6]
    last_low = df['low'].iloc[-3]
    prev_low = df['low'].iloc[-6]
    if last_high > prev_high and last_low > prev_low:
        return "bullish_shift"
    elif last_high < prev_high and last_low < prev_low:
        return "bearish_shift"
    return None

def get_clustered_zones(df, lookback=120, cluster_pct=0.002):
    highs = df['high'].values[-lookback:]
    lows = df['low'].values[-lookback:]
    swing_highs = []
    for i in range(2, len(highs)-2):
        if highs[i] == max(highs[i-2:i+3]):
            swing_highs.append(highs[i])
    swing_lows = []
    for i in range(2, len(lows)-2):
        if lows[i] == min(lows[i-2:i+3]):
            swing_lows.append(lows[i])
    def cluster(points, pct):
        if not points:
            return []
        points = sorted(points)
        clusters = []
        current = [points[0]]
        for p in points[1:]:
            if abs(p - current[-1]) / p < pct:
                current.append(p)
            else:
                clusters.append(sum(current)/len(current))
                current = [p]
        clusters.append(sum(current)/len(current))
        return clusters
    res_levels = cluster(swing_highs, cluster_pct)
    sup_levels = cluster(swing_lows, cluster_pct)
    return sup_levels, res_levels

def detect_liquidity_cluster(df, lb=20, tol=0.001):
    highs = df['high'].iloc[-lb:]
    lows  = df['low'].iloc[-lb:]
    if highs.max() == highs.min() or lows.max() == lows.min():
        return False, False
    eqh = (highs.max() - highs.min()) / highs.mean() < tol
    eql = (lows.max() - lows.min()) / lows.mean() < tol
    return eqh, eql

def detect_sweep_v2(df, side):
    if len(df) < 22:
        return False, False
    last = df.iloc[-1]
    prev = df.iloc[-2]
    eqh, eql = detect_liquidity_cluster(df, lb=20, tol=0.001)
    range_ = last['high'] - last['low']
    if range_ == 0:
        return False, False
    if side == "BUY":
        lower_wick = min(last['open'], last['close']) - last['low']
        wick_ratio = lower_wick / range_
        low_cluster_min = df['low'].iloc[-21:-1].min()
        sweep_broke = eql and (last['low'] < low_cluster_min)
        reclaim = last['close'] > last['low']
        valid = (wick_ratio > 0.6 and reclaim)
        return sweep_broke, valid
    else:
        upper_wick = last['high'] - max(last['open'], last['close'])
        wick_ratio = upper_wick / range_
        high_cluster_max = df['high'].iloc[-21:-1].max()
        sweep_broke = eqh and (last['high'] > high_cluster_max)
        reclaim = last['close'] < last['high']
        valid = (wick_ratio > 0.6 and reclaim)
        return sweep_broke, valid

def candle_rejection(df, side):
    if len(df) < 1:
        return False
    last = df.iloc[-1]
    range_ = last['high'] - last['low']
    if range_ == 0:
        return False
    body = abs(last['close'] - last['open'])
    if side == "BUY":
        lower_wick = min(last['open'], last['close']) - last['low']
        return (lower_wick > 1.5 * body) or (last['close'] > last['open'] and body/range_ > 0.5)
    else:
        upper_wick = last['high'] - max(last['open'], last['close'])
        return (upper_wick > 1.5 * body) or (last['close'] < last['open'] and body/range_ > 0.5)

def volume_spike(df):
    if len(df) < 21:
        return False
    avg_vol = df['volume'].iloc[-21:-1].mean()
    last_vol = df['volume'].iloc[-1]
    return last_vol >= 1.5 * avg_vol

def is_late_entry(df, side):
    if len(df) < 6:
        return False
    last5_move = abs(df['close'].iloc[-1] - df['close'].iloc[-6]) / df['close'].iloc[-6]
    if last5_move > 0.008:
        if side == "BUY":
            recent_high = df['high'].iloc[-5:].max()
            pullback = (recent_high - df['close'].iloc[-1]) / (recent_high - df['close'].iloc[-6]) if (recent_high - df['close'].iloc[-6]) != 0 else 0
            if pullback < 0.3:
                return True
        else:
            recent_low = df['low'].iloc[-5:].min()
            pullback = (df['close'].iloc[-1] - recent_low) / (df['close'].iloc[-6] - recent_low) if (df['close'].iloc[-6] - recent_low) != 0 else 0
            if pullback < 0.3:
                return True
    return False

def compute_location(df, price, side):
    low50 = df['low'].iloc[-50:].min()
    high50 = df['high'].iloc[-50:].max()
    if high50 == low50:
        return "mid"
    relative = (price - low50) / (high50 - low50)
    if side == "BUY":
        if relative <= 0.3:
            return "discount"
        elif relative >= 0.7:
            return "premium"
        else:
            return "mid"
    else:
        if relative >= 0.7:
            return "premium"
        elif relative <= 0.3:
            return "discount"
        else:
            return "mid"

def swing_points(df, lb=5):
    highs = df['high'].values
    lows = df['low'].values
    swing_highs = []
    swing_lows = []
    for i in range(lb, len(df)-lb):
        if highs[i] == max(highs[i-lb:i+lb+1]):
            swing_highs.append((i, highs[i]))
        if lows[i] == min(lows[i-lb:i+lb+1]):
            swing_lows.append((i, lows[i]))
    return swing_highs, swing_lows

def equal_levels(points, tolerance=0.0015):
    if len(points) < 2:
        return False
    avg = sum(points)/len(points)
    return all(abs(p - avg) / avg < tolerance for p in points)

def build_liquidity_pools(df):
    sh, sl = swing_points(df, lb=5)
    recent_highs = [p[1] for p in sh[-3:]] if len(sh) >= 3 else [sh[-1][1]] if sh else []
    if len(recent_highs) >= 2 and equal_levels(recent_highs):
        pools_high = recent_highs
    else:
        pools_high = [sh[-1][1]] if sh else []
    recent_lows = [p[1] for p in sl[-3:]] if len(sl) >= 3 else [sl[-1][1]] if sl else []
    if len(recent_lows) >= 2 and equal_levels(recent_lows):
        pools_low = recent_lows
    else:
        pools_low = [sl[-1][1]] if sl else []
    return {"high_pools": pools_high, "low_pools": pools_low}

def detect_sweep(df, pools):
    if len(df) < 2:
        return False, False
    last = df.iloc[-1]
    prev = df.iloc[-2]
    swept_high = False
    swept_low = False
    for h in pools["high_pools"]:
        if last['high'] > h and prev['high'] <= h and last['close'] < last['high']:
            swept_high = True
            break
    for l in pools["low_pools"]:
        if last['low'] < l and prev['low'] >= l and last['close'] > last['low']:
            swept_low = True
            break
    return swept_high, swept_low

def classify_sweep(df, side):
    if len(df) < 2:
        return "fake", -2
    last = df.iloc[-1]
    range_ = last['high'] - last['low']
    if range_ == 0:
        return "weak", 1
    if side == "BUY":
        lower_wick = min(last['open'], last['close']) - last['low']
        wick_ratio = lower_wick / range_
        reclaimed = last['close'] > last['low']
        if wick_ratio > 0.6 and reclaimed:
            return "strong", 3
        elif wick_ratio > 0.3:
            return "weak", 1.5
        else:
            return "fake", -2
    else:
        upper_wick = last['high'] - max(last['open'], last['close'])
        wick_ratio = upper_wick / range_
        reclaimed = last['close'] < last['high']
        if wick_ratio > 0.6 and reclaimed:
            return "strong", 3
        elif wick_ratio > 0.3:
            return "weak", 1.5
        else:
            return "fake", -2

def volume_engine(df):
    avg_vol = df['volume'].iloc[-20:].mean() if len(df) >= 20 else df['volume'].mean()
    last_vol = df['volume'].iloc[-1]
    if last_vol >= 1.5 * avg_vol:
        return "spike", 2
    elif last_vol < 0.7 * avg_vol:
        return "exhaustion", -1
    else:
        last = df.iloc[-1]
        body = abs(last['close'] - last['open'])
        range_ = last['high'] - last['low']
        if range_ > 0 and body / range_ < 0.4 and last_vol > avg_vol:
            return "absorption", 1
        else:
            return "normal", 0

def structure_engine(df):
    sh, sl = swing_points(df, lb=5)
    last_close = df['close'].iloc[-1]
    bos = False
    choch = False
    if len(sh) >= 2:
        if last_close > sh[-2][1]:
            bos = True
    if len(sl) >= 2:
        if last_close < sl[-2][1]:
            bos = True
    if len(sh) >= 2 and len(sl) >= 2:
        if sh[-1][1] > sh[-2][1] and sl[-1][1] > sl[-2][1]:
            choch = True
        elif sh[-1][1] < sh[-2][1] and sl[-1][1] < sl[-2][1]:
            choch = True
    return bos, choch

def pre_rf_context_boost(df, side):
    if len(df) < 3:
        return 0, []
    last2 = df.iloc[-3:-1]
    boost = 0
    reasons = []
    if side == "BUY":
        if last2['close'].iloc[-2] < last2['close'].iloc[-1] and last2['close'].iloc[-1] < df['close'].iloc[-1]:
            boost += 1
            reasons.append("consecutive_bullish")
        if (last2['close'].iloc[-1] - last2['low'].iloc[-1]) / (last2['high'].iloc[-1] - last2['low'].iloc[-1] + 1e-9) > 0.7:
            boost += 1
            reasons.append("strong_bullish_candle")
    else:
        if last2['close'].iloc[-2] > last2['close'].iloc[-1] and last2['close'].iloc[-1] > df['close'].iloc[-1]:
            boost += 1
            reasons.append("consecutive_bearish")
        if (last2['high'].iloc[-1] - last2['close'].iloc[-1]) / (last2['high'].iloc[-1] - last2['low'].iloc[-1] + 1e-9) > 0.7:
            boost += 1
            reasons.append("strong_bearish_candle")
    return min(boost, 2), reasons

def market_intent(df):
    if len(df) < 20:
        return None, 0
    recent_range = df['high'].iloc[-10:].max() - df['low'].iloc[-10:].min()
    avg_range = (df['high'].rolling(20).max() - df['low'].rolling(20).min()).iloc[-1]
    absorption = (recent_range / avg_range) < 0.5 if avg_range > 0 else False
    vol_state, _ = volume_engine(df)
    if absorption and vol_state == "absorption":
        return "accumulation", 1
    last = df.iloc[-1]
    prev = df.iloc[-2]
    if vol_state == "spike" and last['close'] < prev['high'] and last['high'] > prev['high']:
        return "distribution", 1
    if len(df) >= 3:
        c1 = df.iloc[-3]
        c2 = df.iloc[-2]
        c3 = df.iloc[-1]
        if c2['high'] > c1['high'] and c3['close'] < c2['high'] and c3['close'] < c3['open']:
            return "trap", 2
        if c2['low'] < c1['low'] and c3['close'] > c2['low'] and c3['close'] > c3['open']:
            return "trap", 2
    return None, 0

def council_decision(context):
    score = 0
    reasons = []
    if context["location"] == "discount" and context["side"] == "BUY":
        score += 3
        reasons.append("discount_location")
    elif context["location"] == "premium" and context["side"] == "SELL":
        score += 3
        reasons.append("premium_location")
    else:
        score -= 4
        reasons.append("bad_location")
    if context["sweep"] == "strong":
        score += 3
        reasons.append("strong_sweep")
    elif context["sweep"] == "weak":
        score += 1
        reasons.append("weak_sweep")
    elif context["sweep"] == "fake":
        score -= 2
        reasons.append("fake_sweep")
    if context["in_zone"]:
        score += 2.5
        reasons.append("zone_hit")
    if context["volume"] == "spike":
        score += 2
        reasons.append("volume_spike")
    elif context["volume"] == "absorption":
        score += 1
        reasons.append("absorption")
    elif context["volume"] == "exhaustion":
        score -= 1
        reasons.append("exhaustion")
    if context["bos"] or context["choch"]:
        score += 2
        reasons.append("structure_shift")
    intent = context.get("intent")
    if intent == "trap":
        score += 2
        reasons.append("trap_intent")
    elif intent == "accumulation":
        score += 1
        reasons.append("accumulation")
    elif intent == "distribution":
        score += 1
        reasons.append("distribution")
    score += context.get("pre_rf_boost", 0)
    if context.get("pre_rf_reasons"):
        reasons.extend(context["pre_rf_reasons"])
    if context.get("distance_penalty", 0) == -100:
        return -100, ["far_from_zone_skip"]
    score += context.get("distance_penalty", 0)
    if context.get("distance_reasons"):
        reasons.extend(context["distance_reasons"])
    adx = context["adx"]
    if adx < 18:
        score -= 1
        reasons.append("weak_trend")
    elif 20 <= adx <= 30:
        score += 2
        reasons.append("ideal_trend_phase")
    elif 30 < adx <= 35:
        score += 0.5
        reasons.append("mid_trend")
    elif adx > 40:
        score -= 2
        reasons.append("late_trend_no_entry")
    final_score = max(0, min(12, score))
    return final_score, reasons

def compute_sl_tp(entry_price, side, classification, atr, df):
    if classification == "REVERSAL":
        pools = build_liquidity_pools(df)
        if side == "BUY":
            sl = min(pools["low_pools"]) - 0.5 * atr if pools["low_pools"] else entry_price - atr * 1.2
        else:
            sl = max(pools["high_pools"]) + 0.5 * atr if pools["high_pools"] else entry_price + atr * 1.2
        min_sl_dist = 1.2 * atr
        if abs(entry_price - sl) < min_sl_dist:
            sl = entry_price - min_sl_dist if side == "BUY" else entry_price + min_sl_dist
        tp1 = entry_price * (1 + 0.005) if side == "BUY" else entry_price * (1 - 0.005)
        tp2 = entry_price * (1 + 0.01) if side == "BUY" else entry_price * (1 - 0.01)
    elif classification == "EARLY_TREND":
        ema50 = ema(df['close'], 50).iloc[-1]
        sl = ema50 - atr * 1.2 if side == "BUY" else ema50 + atr * 1.2
        tp1 = entry_price * (1 + 0.008) if side == "BUY" else entry_price * (1 - 0.008)
        tp2 = entry_price * (1 + 0.02) if side == "BUY" else entry_price * (1 - 0.02)
    else:
        sl = entry_price - atr * 1.6 if side == "BUY" else entry_price + atr * 1.6
        tp1 = entry_price * (1 + 0.008) if side == "BUY" else entry_price * (1 - 0.008)
        tp2 = entry_price * (1 + 0.02) if side == "BUY" else entry_price * (1 - 0.02)
    sl, tp1 = PrecisionSafety.adjust_sl_tp(df.symbol if hasattr(df, 'symbol') else DEFAULT_SYMBOL, entry_price, sl, tp1, side, atr)
    return sl, tp1, tp2

