def close_position(amount, symbol, max_retries=3):
    """
    إغلاق صفقة مع retry logic محسّن.
    
    المميزات من البوت القديم:
    - Retry logic (3 محاولات)
    - التحقق من إغلاق المركز بعد كل محاولة
    - معالجة positions الصغيرة (dust)
    - دعم hedge mode
    """
    global _ACTIVE_TRADE
    sym = normalize_symbol(symbol)
    side = STATE.get("side", "BUY")
    close_side = "sell" if side == "BUY" else "buy"
    
    for attempt in range(max_retries):
        try:
            # التحقق من حجم المركز
            pos = sync_position_with_exchange(sym)
            if pos is None:
                log_execution(f"Position already closed (attempt {attempt+1})", "INFO")
                with _TRADE_LOCK:
                    _ACTIVE_TRADE = False
                return True
            
            # التحقق من dust position
            size = abs(float(pos.get('contracts', 0)))
            if size < 1e-6:
                log_execution(f"Dust position detected ({size}), treating as closed", "INFO")
                with _TRADE_LOCK:
                    _ACTIVE_TRADE = False
                return True
            
            amount = float(ex.amount_to_precision(sym, size))
            
            # تحديد position side للمركز الحالي
            position_side = "LONG" if side == "BUY" else "SHORT"
            
            # بناء params مع reduceOnly
            params = {"reduceOnly": True}
            
            # دعم hedge mode
            if _get_position_mode(sym) == "hedge":
                params["positionSide"] = position_side
            
            # تنفيذ أمر الإغلاق
            order = safe_api_call(ex.create_order, sym, "market", close_side, amount, params=params)
            
            if order:
                log_execution(f"Close order executed: {side} {amount} {sym} (attempt {attempt+1})", "SUCCESS")
                
                # التحقق من الإغلاق
                time.sleep(0.5)
                verify_pos = sync_position_with_exchange(sym)
                if verify_pos is None:
                    with _TRADE_LOCK:
                        _ACTIVE_TRADE = False
                    return True
                else:
                    log_execution(f"Position still open after attempt {attempt+1}, retrying...", "WARN")
            else:
                log_execution(f"Close order returned None (attempt {attempt+1})", "WARN")
                
        except Exception as e:
            log_execution(f"Close position error (attempt {attempt+1}): {e}", "ERROR")
        
        # انتظار قبل إعادة المحاولة
        if attempt < max_retries - 1:
            time.sleep(1)
    
    # فشل الإغلاق بعد كل المحاولات
    log_execution(f"Failed to close position after {max_retries} attempts", "ERROR")
    with _TRADE_LOCK:
        _ACTIVE_TRADE = False
    return False

def close_position_full():
    """
    إغلاق الصفقة بشكل كامل مع fallback لـ force_close.
    
    المميزات من البوت القديم:
    - محاولة close_position أولاً
    - إذا فشلت، استخدم force_close
    - التحقق من إغلاق المركز على المنصة
    """
    if PAPER_MODE:
        paper["position"] = None
        STATE["open"] = False
        TRADE_STATE["in_position"] = False
        DASHBOARD_STATE["live_trade_mode"] = False
        return True
    
    if not STATE.get("open", False):
        # التحقق من وجود مركز على المنصة
        pos = sync_position_with_exchange(STATE.get("current_symbol", DEFAULT_SYMBOL))
        if pos is None:
            log_execution("No open position found", "INFO")
            return True
    
    symbol = STATE.get("current_symbol", DEFAULT_SYMBOL)
    remaining = STATE.get("remaining_qty", 0)
    
    # محاولة الإغلاق العادي
    order = close_position(remaining, symbol)
    if order:
        _cleanup_after_close(symbol)
        log_execution("Position fully closed", "SUCCESS")
        return True
    
    # الإغلاق الإجباري
    log_execution("Normal close failed, attempting force_close", "WARN")
    return force_close(symbol)


def force_close(symbol):
    """
    إغلاق إجباري لأي مركز مفتوح على الرمز.
    
    المميزات من البوت القديم:
    - يجد جميع المراكز المفتوحة للرمز
    - يغلقها واحدة تلو الأخرى
    - يستخدم close_position كـ fallback
    """
    sym = normalize_symbol(symbol)
    
    try:
        # جلب جميع المراكز المفتوحة
        if hasattr(ex, 'fetch_positions'):
            positions = safe_api_call(ex.fetch_positions, [sym])
        elif hasattr(ex, 'fetch_open_positions'):
            positions = safe_api_call(ex.fetch_open_positions, [sym])
        else:
            log_execution("No position fetch method available", "ERROR")
            return False
        
        if not positions:
            log_execution(f"No open positions for {sym}", "INFO")
            return True
        
        closed_any = False
        for pos in positions:
            pos_sym = pos.get('symbol', pos.get('info', {}).get('symbol', ''))
            if normalize_symbol(symbol) not in pos_sym:
                continue
            
            size = abs(float(pos.get('contracts', pos.get('positionAmt', 0))))
            if size < 1e-6:
                continue  # dust position
            
            pos_side = pos.get('side', pos.get('positionSide', '')).upper()
            side = "long" if pos_side == "LONG" else "short"
            
            log_execution(f"Force closing: {sym} {side} {size}", "WARN")
            
            # استخدام close_position لإغلاق المركز
            close_side = "sell" if side == "long" else "buy"
            params = {"reduceOnly": True, "positionSide": pos_side}
            
            amount = float(ex.amount_to_precision(sym, size))
            order = safe_api_call(ex.create_order, sym, "market", close_side, amount, params=params)
            
            if order:
                log_execution(f"Force close succeeded for {side}", "SUCCESS")
                closed_any = True
            else:
                log_execution(f"Force close failed for {side}", "ERROR")
        
        if closed_any:
            _cleanup_after_close(symbol)
        
        # التحقق النهائي
        verify = sync_position_with_exchange(sym)
        if verify is None:
            log_execution(f"All positions closed for {sym}", "SUCCESS")
            return True
        else:
            log_execution(f"Some positions may remain for {sym}", "WARN")
            return False
            
    except Exception as e:
        log_execution(f"Force close error: {e}", "ERROR")
        return False


def _cleanup_after_close(symbol):
    """تنظيف الحالة بعد الإغلاق."""
    with _TRADE_LOCK:
        STATE["open"] = False
        STATE["side"] = None
        STATE["current_symbol"] = None
        STATE["remaining_qty"] = 0
        STATE["entry"] = 0.0
        STATE["roe_pct"] = 0.0
        
        TRADE_STATE["in_position"] = False
        TRADE_STATE["symbol"] = None
        TRADE_STATE["qty"] = 0
        
        DASHBOARD_STATE["live_trade_mode"] = False

def close_partial(ratio):
    if PAPER_MODE:
        if paper["position"]:
            paper["position"]["remaining_qty"] *= (1-ratio)
            STATE["remaining_qty"] *= (1-ratio)
            TRADE_STATE["qty"] = STATE["remaining_qty"]
        return
    qty = STATE["remaining_qty"] * ratio
    side = "sell" if STATE["side"] == "BUY" else "buy"
    try:
        sym = normalize_symbol(STATE["current_symbol"])
        qty = float(ex.amount_to_precision(sym, qty))
        safe_api_call(ex.create_order, sym, "market", side, qty, params={"reduceOnly": True})
        STATE["remaining_qty"] -= qty
        STATE["partial_closed"] = True
        TRADE_STATE["qty"] = STATE["remaining_qty"]
        log_execution(f"Partial close {ratio*100:.0f}%", "SUCCESS")
        _exchange_sync.reconcile(STATE["current_symbol"], STATE)
    except Exception as e:
        log_execution(f"Partial close error: {e}", "ERROR")

