def get_timestamp_ms():
    """Get current timestamp with milliseconds."""
    now = datetime.now()
    return now.strftime("%H:%M:%S.%f")[:-3]

def generate_lifecycle_id(symbol):
    """
    Generate unique Lifecycle ID for a candidate.
    Format: SYMBOL_YYYYMMDD_HHMMSS_NNN
    """
    global _LIFECYCLE_COUNTER
    _LIFECYCLE_COUNTER += 1
    now = datetime.now()
    timestamp = now.strftime("%Y%m%d_%H%M%S")
    return f"{symbol.upper().replace('/', '')}_{timestamp}_{_LIFECYCLE_COUNTER:04d}"

def log_pipeline_stage(lifecycle_id, stage, passed, details=None, contribution=None, 
                       expected=None, actual=None, reason=None, sub_reasons=None,
                       engine_votes=None):
    """
    Log a pipeline stage with full details.
    
    Args:
        lifecycle_id: Unique identifier
        stage: Current pipeline stage
        passed: True/False
        details: Additional details
        contribution: Score contribution
        expected: Expected value
        actual: Actual value
        reason: Main failure reason
        sub_reasons: List of specific reasons (NEW)
        engine_votes: Dict of BUY/SELL votes from each engine (NEW)
    """
    timestamp = time.time()
    timestamp_ms = get_timestamp_ms()
    
    entry = {
        "lifecycle_id": lifecycle_id,
        "stage": stage,
        "timestamp": timestamp,
        "timestamp_ms": timestamp_ms,
        "passed": passed,
        "details": details or {},
        "contribution": contribution,
        "expected": expected,
        "actual": actual,
        "reason": reason,
        "sub_reasons": sub_reasons or [],  # NEW: Detailed reasons
        "engine_votes": engine_votes or {},  # NEW: Conflict matrix
        "stage_index": PIPELINE_STAGES.index(stage) if stage in PIPELINE_STAGES else -1,
    }
    
    _FORENSIC_LOG.append(entry)
    if len(_FORENSIC_LOG) > _MAX_FORENSIC_LOG:
        _FORENSIC_LOG.pop(0)
    
    # Update active lifecycle record
    if lifecycle_id in _ACTIVE_LIFECYCLES:
        rec = _ACTIVE_LIFECYCLES[lifecycle_id]
        rec["current_stage"] = stage
        rec[f"{stage.lower()}_time"] = timestamp
        rec[f"{stage.lower()}_time_ms"] = timestamp_ms
        
        # Store detailed info
        if sub_reasons:
            rec["stage_details"] = rec.get("stage_details", {})
            rec["stage_details"][stage] = {"sub_reasons": sub_reasons, "passed": passed}
        
        # Store engine votes for conflict matrix
        if engine_votes:
            rec["engine_votes"] = engine_votes
    
    # Print stage status with millisecond precision
    status = "✅ PASS" if passed else "❌ FAIL"
    stage_str = stage.ljust(16)
    
    log_execution(f"[FORENSIC] {timestamp_ms} | {lifecycle_id} | {stage_str} | {status}", "INFO")
    
    # Print sub-reasons for engines
    if sub_reasons:
        for sr in sub_reasons:
            log_execution(f"[FORENSIC]   └─ {sr}", "INFO")
    
    # Print engine votes
    if engine_votes:
        for engine, vote in engine_votes.items():
            icon = "🟢" if vote == "BUY" else "🔴" if vote == "SELL" else "⚪"
            log_execution(f"[FORENSIC]   {icon} {engine}: {vote}", "INFO")
    
    if not passed and reason:
        log_execution(f"[FORENSIC]   Reason: {reason}", "WARN")

