def get_forensic_summary():
    """
    Get summary of forensic tracking.
    """
    total = len(_FORENSIC_LOG)
    passed = sum(1 for e in _FORENSIC_LOG if e.get('passed', False))
    failed = total - passed
    
    # Count by stage
    stage_stats = {}
    for entry in _FORENSIC_LOG:
        stage = entry.get('stage', 'UNKNOWN')
        if stage not in stage_stats:
            stage_stats[stage] = {'passed': 0, 'failed': 0}
        if entry.get('passed', False):
            stage_stats[stage]['passed'] += 1
        else:
            stage_stats[stage]['failed'] += 1
    
    return {
        "total_entries": total,
        "passed": passed,
        "failed": failed,
        "pass_rate": passed / total if total > 0 else 0,
        "stage_stats": stage_stats,
        "lifecycle_counter": _LIFECYCLE_COUNTER,
    }

def print_forensic_dashboard():
    """
    Print forensic dashboard summary.
    """
    summary = get_forensic_summary()
    
    print("\n" + "="*70)
    print("FORENSIC LIFECYCLE DASHBOARD")
    print("="*70)
    print(f"Total Entries:    {summary['total_entries']}")
    print(f"Passed:           {summary['passed']}")
    print(f"Failed:          {summary['failed']}")
    print(f"Pass Rate:       {summary['pass_rate']*100:.1f}%")
    print(f"Lifecycle Count: {summary['lifecycle_counter']}")
    print("-"*70)
    print("STAGE BREAKDOWN")
    print("-"*70)
    print(f"{'Stage':<20} {'PASS':<8} {'FAIL':<8} {'Rate':<8}")
    print("-"*70)
    for stage in PIPELINE_STAGES[:15]:  # Show first 15 stages
        stats = summary['stage_stats'].get(stage, {'passed': 0, 'failed': 0})
        total_s = stats['passed'] + stats['failed']
        rate = stats['passed'] / total_s * 100 if total_s > 0 else 0
        print(f"{stage:<20} {stats['passed']:<8} {stats['failed']:<8} {rate:>6.1f}%")
    print("="*70 + "\n")

def get_last_rejected_entries(limit=10):
    """
    Get last N rejected entries with full details.
    """
    rejected = [r for r in _REJECTION_LOG if r.get('final_decision') == 'REJECTED']
    return sorted(rejected, key=lambda x: x.get('timestamp', 0), reverse=True)[:limit]

def print_last_rejected_entries(limit=10):
    """
    Print expanded last rejected entries section.
    """
    rejected = get_last_rejected_entries(limit)
    
    print("\n" + "="*70)
    print("LAST REJECTED ENTRIES")
    print("="*70)
    
    if not rejected:
        print("No rejected entries in log.")
    else:
        for i, entry in enumerate(rejected, 1):
            print(f"\n[{i}] {entry.get('lifecycle_id', 'N/A')}")
            print("-"*50)
            print(f"  Symbol:      {entry.get('symbol', 'N/A')}")
            print(f"  Side:        {entry.get('side', 'N/A')}")
            print(f"  Stage:       {entry.get('current_stage', 'N/A')}")
            print(f"  Score:       {entry.get('composite_score', 'N/A')}")
            print(f"  Confidence:  {entry.get('composite_confidence', 'N/A')}")
            print(f"  Time Alive:  {entry.get('time_alive_formatted', 'N/A')}")
            
            # Primary/Secondary failures
            reasons = entry.get('rejection_reasons', [])
            if reasons:
                print(f"  Primary Failure:   {reasons[0].get('stage', 'Unknown') if isinstance(reasons[0], dict) else reasons[0]}")
                if len(reasons) > 1:
                    print(f"  Secondary Failure: {reasons[1].get('stage', 'Unknown') if isinstance(reasons[1], dict) else reasons[1]}")
            
            # Evidence breakdown summary
            breakdown = entry.get('evidence_breakdown', {})
            if breakdown:
                failed_components = [k for k, v in breakdown.items() if not v.get('passed', True)]
                if failed_components:
                    print(f"  Failed Components: {', '.join(failed_components)}")
    
    print("="*70 + "\n")

def log_watchlist_cleanup(lifecycle_id, symbol, reason, details=None):
    """
    Log when a symbol is removed from watchlist.
    """
    entry = {
        "lifecycle_id": lifecycle_id,
        "symbol": symbol,
        "timestamp": time.time(),
        "event": "CLEANUP",
        "reason": reason,
        "details": details or {},
    }
    
    _FORENSIC_LOG.append(entry)
    
    reason_display = reason.upper().ljust(15)
    log_execution(f"[WATCHLIST CLEANUP] {lifecycle_id} | {symbol} | {reason_display}", "WARN")
    if details:
        for key, val in details.items():
            log_execution(f"  {key}: {val}", "INFO")

def log_execution_queue_audit(lifecycle_id, symbol, position, waiting_time, 
                               execute_called, blocking_reason=None):
    """
    Log execution queue audit for READY but not executed trades.
    """
    print("\n" + "="*70)
    print("EXECUTION QUEUE AUDIT")
    print("="*70)
    print(f"Lifecycle ID:       {lifecycle_id}")
    print(f"Symbol:            {symbol}")
    print(f"Queue Position:    {position}")
    print(f"Waiting Time:     {waiting_time:.1f}s")
    print(f"execute_entry() called: {'YES' if execute_called else 'NO'}")
    if not execute_called and blocking_reason:
        print(f"Blocking Reason:   {blocking_reason}")
    print("="*70 + "\n")

