# FORENSIC INVESTIGATION SYSTEM - Engine Vote Recording
# ============================================================================

def record_investigation_vote(lifecycle_id, engine_name, vote, score=None, 
                              confidence=None, reason=None, details=None):
    """
    Record a complete vote from an engine for forensic investigation.
    
    Args:
        lifecycle_id: The lifecycle ID
        engine_name: Name of the engine (SmartMoney, Banker, etc.)
        vote: "BUY", "SELL", or "NEUTRAL"
        score: Numerical score (0-100)
        confidence: Confidence level (0-100)
        reason: Textual reason for the vote
        details: Additional details dict
    """
    if lifecycle_id not in _ENGINE_VOTES:
        _ENGINE_VOTES[lifecycle_id] = {}
    
    _ENGINE_VOTES[lifecycle_id][engine_name] = {
        "vote": vote,
        "score": score,
        "confidence": confidence,
        "reason": reason,
        "details": details or {},
        "timestamp": time.time(),
        "timestamp_ms": get_timestamp_ms(),
    }
    
    # Also update active lifecycle
    if lifecycle_id in _ACTIVE_LIFECYCLES:
        rec = _ACTIVE_LIFECYCLES[lifecycle_id]
        if "engine_votes" not in rec:
            rec["engine_votes"] = {}
        rec["engine_votes"][engine_name] = _ENGINE_VOTES[lifecycle_id][engine_name]

def record_strategy_diagnostic(lifecycle_id, strategy_type, scenarios, 
                             selected_scenario, final_score):
    """
    Record strategy selection diagnostic for investigation.
    """
    if lifecycle_id not in _ENGINE_VOTES:
        _ENGINE_VOTES[lifecycle_id] = {}
    
    _ENGINE_VOTES[lifecycle_id]["DYNAMIC_STRATEGY"] = {
        "vote": "BUY" if final_score >= 50 else "NEUTRAL",
        "score": final_score,
        "strategy_type": strategy_type,
        "scenarios": scenarios,
        "selected_scenario": selected_scenario,
        "final_score": final_score,
        "timestamp": time.time(),
        "timestamp_ms": get_timestamp_ms(),
    }
    
    # Detect default/fallback values
    if strategy_type == 0 or strategy_type == "UNKNOWN":
        _PIPELINE_HEALTH["default_values_detected"].append({
            "lifecycle_id": lifecycle_id,
            "field": "strategy_type",
            "value": strategy_type,
            "reason": "No strategy scenario matched criteria"
        })
        log_execution(f"[FORENSIC WARNING] {lifecycle_id} | Strategy = 0/UNKNOWN - No scenario matched", "WARN")

def record_confidence_breakdown(lifecycle_id, components, final_confidence):
    """
    Record confidence calculation breakdown for investigation.
    """
    if lifecycle_id not in _ENGINE_VOTES:
        _ENGINE_VOTES[lifecycle_id] = {}
    
    _ENGINE_VOTES[lifecycle_id]["CONFIDENCE"] = {
        "components": components,
        "final_confidence": final_confidence,
        "formula": "Average of all component confidences",
        "timestamp": time.time(),
        "timestamp_ms": get_timestamp_ms(),
    }
    
    # Detect suspicious default values
    if final_confidence == 45 or final_confidence == 50 or final_confidence == 0:
        _PIPELINE_HEALTH["default_values_detected"].append({
            "lifecycle_id": lifecycle_id,
            "field": "confidence",
            "value": final_confidence,
            "reason": "Suspicious default confidence value"
        })
        log_execution(f"[FORENSIC WARNING] {lifecycle_id} | Confidence = {final_confidence}% - Possible default", "WARN")

def record_contribution_breakdown(lifecycle_id, contributions):
    """
    Record engine contribution to composite score.
    """
    if lifecycle_id not in _ENGINE_VOTES:
        _ENGINE_VOTES[lifecycle_id] = {}
    
    _ENGINE_VOTES[lifecycle_id]["COMPOSITE"] = {
        "contributions": contributions,
        "total_score": sum(c.get("contribution", 0) for c in contributions.values()) if isinstance(contributions, dict) else 0,
        "timestamp": time.time(),
        "timestamp_ms": get_timestamp_ms(),
    }

def get_lifecycle_timeline(lifecycle_id):
    """
    Get complete timeline for a lifecycle ID.
    """
    entries = [e for e in _FORENSIC_LOG if e.get('lifecycle_id') == lifecycle_id]
    return sorted(entries, key=lambda x: x.get('timestamp', 0))

