def print_complete_forensic_report(symbol, watchlist_entry, decision, rejection_stage, rejection_reason):
    """
    ═══════════════════════════════════════════════════════════════════════════════════
    COMPLETE FORENSIC REPORT - Every WATCH and SKIP Decision
    ═══════════════════════════════════════════════════════════════════════════════════
    
    OBSERVER ONLY - This function NEVER modifies any decision, threshold, weight, or strategy.
    It only records and reports.
    """
    print("\n" + "█"*100)
    print("█" + " "*98 + "█")
    print("█" + "🔍 COMPLETE CANDIDATE FORENSIC REPORT".center(98) + "█")
    print("█" + " "*98 + "█")
    print("█"*100)
    
    lifecycle_id = watchlist_entry.get("lifecycle_id", f"{symbol}_{int(time.time())}")
    
    # ===== SECTION 1: BASIC INFO =====
    print("\n" + "="*100)
    print("📋 CANDIDATE IDENTIFICATION")
    print("="*100)
    print(f"  Symbol:              {symbol}")
    print(f"  Side:                {watchlist_entry.get('side', 'UNKNOWN')}")
    print(f"  Trade Type:          {watchlist_entry.get('trade_type', 'UNKNOWN')}")
    print(f"  Lifecycle ID:        {lifecycle_id}")
    print(f"  Timestamp:           {datetime.now().strftime('%Y-%m-%d %H:%M:%S')}")
    
    # ===== SECTION 2: DECISION SUMMARY =====
    print("\n" + "="*100)
    print("📊 DECISION SUMMARY")
    print("="*100)
    
    action = decision.get("action", "UNKNOWN")
    readiness = decision.get("entry_readiness", "UNKNOWN")
    confidence = decision.get("confidence", 0)
    composite = decision.get("composite_evidence", confidence)
    
    # Color coding for action
    if action == "WATCH":
        action_icon = "👀"
        action_color = "YELLOW"
    elif action == "SKIP":
        action_icon = "❌"
        action_color = "RED"
    else:
        action_icon = "❓"
        action_color = "WHITE"
    
    print(f"  Action:              {action_icon} {action}")
    print(f"  Entry Readiness:     {readiness}")
    print(f"  Composite Evidence:  {composite:.1f}%")
    print(f"  Confidence:         {confidence:.1f}%")
    print(f"  Strategy Score:     {decision.get('strategy_score', 0):.1f}")
    print(f"  Strength:           {decision.get('strength', 'UNKNOWN')}")
    print(f"  Market Phase:       {watchlist_entry.get('market_phase', 'UNKNOWN')}")
    print(f"  Rejection Stage:    {rejection_stage}")
    print(f"  Rejection Reason:   {rejection_reason}")
    
    # ===== SECTION 3: COMPLETE EVIDENCE BREAKDOWN =====
    print("\n" + "="*100)
    print("📈 COMPLETE EVIDENCE BREAKDOWN")
    print("="*100)
    print(f"  {'Engine':<25} {'Raw':>6} {'Weight':>8} {'Contrib':>8} {'Maximum':>8} {'Lost':>8} {'Status':>8}")
    print(f"  {'-'*25} {'-'*6} {'-'*8} {'-'*8} {'-'*8} {'-'*8} {'-'*8}")
    
    components = decision.get("components", {})
    total_contribution = 0
    total_maximum = 0
    total_lost = 0
    pass_count = 0
    fail_count = 0
    
    # Define all evidence providers with their weights
    evidence_providers = [
        ("Smart Money", components.get("smart_money", {}), 0.10),
        ("Momentum", components.get("momentum", {}), 0.10),
        ("Structure", components.get("structure", {}), 0.10),
        ("Volume", components.get("volume", {}), 0.10),
        ("Liquidity", components.get("liquidity", {}), 0.10),
        ("Institutional SM", components.get("institutional_smart_money", {}), 0.12),
        ("Banker Flow", components.get("banker_flow", {}), 0.12),
        ("Hot Money", components.get("hot_money", {}), 0.08),
        ("Market Story", components.get("market_story", {}), 0.08),
    ]
    
    evidence_details = []
    
    for name, data, weight in evidence_providers:
        raw_score = data.get("score", 50) if isinstance(data, dict) else 50
        contribution = raw_score * weight
        maximum = 100 * weight
        lost = maximum - contribution
        passed = raw_score >= 50
        
        status = "✅ PASS" if passed else "❌ FAIL"
        if passed:
            pass_count += 1
        else:
            fail_count += 1
        
        total_contribution += contribution
        total_maximum += maximum
        total_lost += lost
        
        print(f"  {name:<25} {raw_score:>6.1f} {weight*100:>7.1f}% {contribution:>8.2f} {maximum:>8.2f} {lost:>8.2f} {status:>8}")
        
        evidence_details.append({
            "name": name,
            "raw": raw_score,
            "weight": weight,
            "contribution": contribution,
            "maximum": maximum,
            "lost": lost,
            "passed": passed
        })
    
    print(f"  {'-'*25} {'-'*6} {'-'*8} {'-'*8} {'-'*8} {'-'*8} {'-'*8}")
    print(f"  {'TOTAL':<25} {'':<6} {'':<8} {total_contribution:>8.2f} {total_maximum:>8.2f} {total_lost:>8.2f} {'✅' if total_contribution >= 60 else '❌':>8}")
    
    # ===== SECTION 4: SIGNAL CONTRIBUTION REPORT =====
    print("\n" + "="*100)
    print("🗳️ SIGNAL CONTRIBUTION REPORT")
    print("="*100)
    
    # Count signals from various sources
    signals = []
    
    # Smart Money signals
    sm = components.get("smart_money", {})
    if sm.get("dominant"):
        signals.append(("Smart Money Dominant", True, "Smart money controlling price"))
    if sm.get("bias") == watchlist_entry.get("side"):
        signals.append(("SM Bias Aligned", True, f"SM bias matches trade direction"))
    
    # Momentum signals
    mom = components.get("momentum", {})
    if mom.get("expansion"):
        signals.append(("Momentum Expansion", True, "Momentum strengthening"))
    if mom.get("strength", 0) >= 50:
        signals.append(("Momentum Strength", True, f"Strength: {mom.get('strength', 0):.0f}"))
    
    # Structure signals
    struct = components.get("structure", {})
    if struct.get("bos"):
        signals.append(("BOS Confirmed", True, "Break of Structure"))
    if struct.get("choch"):
        signals.append(("CHoCH Detected", True, "Change of Character"))
    if struct.get("mss"):
        signals.append(("MSS Confirmed", True, "Market Structure Shift"))
    
    # Volume signals
    vol = components.get("volume", {})
    if vol.get("expansion"):
        signals.append(("Volume Expansion", True, "Volume confirming move"))
    
    # Liquidity signals
    liq = components.get("liquidity", {})
    if liq.get("sweep"):
        signals.append(("Liquidity Sweep", True, "Liquidity grab detected"))
    if liq.get("retest"):
        signals.append(("Zone Retest", True, "Previous zone retested"))
    
    # Count positive and negative signals
    positive_count = len(signals)
    negative_count = 0
    neutral_count = 0
    
    # Check for negative signals
    if mom.get("decay"):
        signals.append(("Momentum Decay", False, "Momentum weakening"))
        negative_count += 1
    if sm.get("distribution_risk", 0) > 70:
        signals.append(("High Distribution Risk", False, f"Risk: {sm.get('distribution_risk', 0):.0f}%"))
        negative_count += 1
    
    # Requirements for READY
    required_for_normal = 3
    required_for_strong = 4
    
    print(f"\n  Signal Count Analysis:")
    print(f"    Total Signals:      {positive_count + negative_count + neutral_count}")
    print(f"    Positive:          {positive_count} ✅")
    print(f"    Negative:          {negative_count} ❌")
    print(f"    Neutral:           {neutral_count} ⚪")
    
    print(f"\n  Requirements for READY:")
    print(f"    NORMAL: Need ≥{required_for_normal} signals, Current: {positive_count} ({'✅' if positive_count >= required_for_normal else '❌'})")
    print(f"    STRONG: Need ≥{required_for_strong} signals, Current: {positive_count} ({'✅' if positive_count >= required_for_strong else '❌'})")
    
    print(f"\n  Detected Signals:")
    for signal_name, is_positive, reason in signals:
        icon = "✅" if is_positive else "❌"
        print(f"    {icon} {signal_name}: {reason}")
    
    # ===== SECTION 5: READY GAP ANALYSIS =====
    print("\n" + "="*100)
    print("📏 READY GAP ANALYSIS")
    print("="*100)
    
    normal_threshold = 60
    strong_threshold = 75
    normal_signals = 3
    strong_signals = 4
    
    evidence_gap_normal = normal_threshold - composite
    evidence_gap_strong = strong_threshold - composite
    signals_gap_normal = normal_signals - positive_count
    signals_gap_strong = strong_signals - positive_count
    
    print(f"\n  NORMAL READY Requirements:")
    print(f"    Evidence ≥ {normal_threshold}%")
    print(f"    Signals ≥ {normal_signals}")
    print(f"\n    Current Evidence:     {composite:.1f}%")
    print(f"    Gap to NORMAL:       {evidence_gap_normal:.1f}% {'✅ ACHIEVED' if evidence_gap_normal <= 0 else '❌ MISSING'}")
    print(f"\n    Current Signals:       {positive_count}")
    print(f"    Gap to NORMAL:        {signals_gap_normal} {'✅ ACHIEVED' if signals_gap_normal <= 0 else '❌ MISSING'}")
    
    print(f"\n  STRONG READY Requirements:")
    print(f"    Evidence ≥ {strong_threshold}%")
    print(f"    Signals ≥ {strong_signals}")
    print(f"\n    Current Evidence:     {composite:.1f}%")
    print(f"    Gap to STRONG:       {evidence_gap_strong:.1f}% {'✅ ACHIEVED' if evidence_gap_strong <= 0 else '❌ MISSING'}")
    print(f"\n    Current Signals:       {positive_count}")
    print(f"    Gap to STRONG:        {signals_gap_strong} {'✅ ACHIEVED' if signals_gap_strong <= 0 else '❌ MISSING'}")
    
    # ===== SECTION 6: ENGINE VOTE MATRIX =====
    print("\n" + "="*100)
    print("🔬 ENGINE VOTE MATRIX")
    print("="*100)
    print(f"  {'Engine':<20} {'Vote':<10} {'Score':>6} {'Conf':>6} {'Weight':>8} {'Contrib':>8} {'Reason'}")
    print(f"  {'-'*20} {'-'*10} {'-'*6} {'-'*6} {'-'*8} {'-'*8} {'-'*30}")
    
    engine_votes = []
    
    # Smart Money
    sm_data = components.get("smart_money", {})
    sm_vote = "BUY" if sm_data.get("bias") == watchlist_entry.get("side") else "NEUTRAL"
    sm_score = sm_data.get("score", 50)
    sm_contrib = sm_score * 0.10
    sm_reason = f"Dominant={sm_data.get('dominant')}, Bias={sm_data.get('bias')}"
    print(f"  {'Smart Money':<20} {sm_vote:<10} {sm_score:>6.0f} {sm_score:>6.0f} {10:>7.1f}% {sm_contrib:>8.2f} {sm_reason:<30}")
    engine_votes.append(("Smart Money", sm_vote, sm_score, sm_contrib))
    
    # Momentum
    mom_data = components.get("momentum", {})
    mom_vote = "BUY" if mom_data.get("expansion") else "NEUTRAL"
    mom_score = mom_data.get("strength", 50)
    mom_contrib = mom_score * 0.10
    mom_reason = f"Strength={mom_score:.0f}, Expansion={mom_data.get('expansion')}"
    print(f"  {'Momentum':<20} {mom_vote:<10} {mom_score:>6.0f} {mom_score:>6.0f} {10:>7.1f}% {mom_contrib:>8.2f} {mom_reason:<30}")
    engine_votes.append(("Momentum", mom_vote, mom_score, mom_contrib))
    
    # Structure
    struct_data = components.get("structure", {})
    struct_score = sum([struct_data.get("bos", False), struct_data.get("choch", False), struct_data.get("mss", False)]) * 33
    struct_vote = "BUY" if struct_score >= 50 else "NEUTRAL"
    struct_contrib = struct_score * 0.10
    struct_reason = f"BOS={struct_data.get('bos')}, CHoCH={struct_data.get('choch')}, MSS={struct_data.get('mss')}"
    print(f"  {'Structure':<20} {struct_vote:<10} {struct_score:>6.0f} {struct_score:>6.0f} {10:>7.1f}% {struct_contrib:>8.2f} {struct_reason:<30}")
    engine_votes.append(("Structure", struct_vote, struct_score, struct_contrib))
    
    # Volume
    vol_data = components.get("volume", {})
    vol_score = vol_data.get("score", 50)
    vol_vote = "BUY" if vol_data.get("expansion") else "NEUTRAL"
    vol_contrib = vol_score * 0.10
    vol_reason = f"Expansion={vol_data.get('expansion')}"
    print(f"  {'Volume':<20} {vol_vote:<10} {vol_score:>6.0f} {vol_score:>6.0f} {10:>7.1f}% {vol_contrib:>8.2f} {vol_reason:<30}")
    engine_votes.append(("Volume", vol_vote, vol_score, vol_contrib))
    
    # Liquidity
    liq_data = components.get("liquidity", {})
    liq_score = 50 + (30 if liq_data.get("sweep") else 0) + (15 if liq_data.get("retest") else 0)
    liq_vote = "BUY" if liq_data.get("sweep") else "NEUTRAL"
    liq_contrib = liq_score * 0.10
    liq_reason = f"Sweep={liq_data.get('sweep')}, Retest={liq_data.get('retest')}"
    print(f"  {'Liquidity':<20} {liq_vote:<10} {liq_score:>6.0f} {liq_score:>6.0f} {10:>7.1f}% {liq_contrib:>8.2f} {liq_reason:<30}")
    engine_votes.append(("Liquidity", liq_vote, liq_score, liq_contrib))
    
    # Banker Flow
    banker_data = components.get("banker_flow", {})
    banker_score = 50  # Default
    if banker_data.get("banker_entry") == "STRONG":
        banker_score = 80
    elif banker_data.get("banker_entry") == "WEAK":
        banker_score = 40
    banker_vote = "BUY" if banker_data.get("fund_trend") == "UP" else "NEUTRAL"
    banker_contrib = banker_score * 0.12
    banker_reason = f"Entry={banker_data.get('banker_entry')}, Zone={banker_data.get('zone')}"
    print(f"  {'Banker Flow':<20} {banker_vote:<10} {banker_score:>6.0f} {banker_score:>6.0f} {12:>7.1f}% {banker_contrib:>8.2f} {banker_reason:<30}")
    engine_votes.append(("Banker Flow", banker_vote, banker_score, banker_contrib))
    
    # Hot Money
    hot_data = components.get("hot_money", {})
    hot_score = hot_data.get("hot_money_pressure", 50)
    hot_vote = "NEUTRAL"
    if hot_data.get("fomo_detected") or hot_data.get("panic_detected"):
        hot_vote = "SELL"  # Against trade
    hot_contrib = hot_score * 0.08
    hot_reason = f"Pressure={hot_score:.0f}, FOMO={hot_data.get('fomo_detected')}"
    print(f"  {'Hot Money':<20} {hot_vote:<10} {hot_score:>6.0f} {hot_score:>6.0f} {8:>7.1f}% {hot_contrib:>8.2f} {hot_reason:<30}")
    engine_votes.append(("Hot Money", hot_vote, hot_score, hot_contrib))
    
    # Market Story
    story_data = components.get("market_story", {})
    story_score = 50
    if story_data.get("trade_recommended"):
        story_score = 80
    story_vote = "BUY" if story_data.get("trade_recommended") else "NEUTRAL"
    story_contrib = story_score * 0.08
    story_reason = f"Quality={story_data.get('quality')}, Recommended={story_data.get('trade_recommended')}"
    print(f"  {'Market Story':<20} {story_vote:<10} {story_score:>6.0f} {story_score:>6.0f} {8:>7.1f}% {story_contrib:>8.2f} {story_reason:<30}")
    engine_votes.append(("Market Story", story_vote, story_score, story_contrib))
    
    # ===== SECTION 7: FIRST FAILURE POINT =====
    print("\n" + "="*100)
    print("🎯 FIRST FAILURE POINT ANALYSIS")
    print("="*100)
    
    failures = []
    
    # Check each evidence provider
    if not sm_data.get("dominant") and sm_score < 50:
        failures.append((1, "SMART_MONEY", f"Smart money not dominant (score: {sm_score:.0f})"))
    
    if not mom_data.get("expansion") and mom_score < 50:
        failures.append((2, "MOMENTUM", f"Momentum not expanding (score: {mom_score:.0f})"))
    
    if struct_score < 50:
        failures.append((3, "STRUCTURE", f"No structure confirmation (score: {struct_score:.0f})"))
    
    if not vol_data.get("expansion"):
        failures.append((4, "VOLUME", "Volume not expanding"))
    
    if not liq_data.get("sweep") and not liq_data.get("retest"):
        failures.append((5, "LIQUIDITY", "No liquidity event detected"))
    
    if composite < 60:
        failures.append((6, "COMPOSITE", f"Evidence below NORMAL threshold (current: {composite:.1f}%)"))
    
    if positive_count < 3:
        failures.append((7, "SIGNALS", f"Insufficient signals (current: {positive_count}, need: 3)"))
    
    # Sort by importance and print
    failures.sort(key=lambda x: x[0])
    
    print("\n  FAILURE HIERARCHY (Ordered by Impact):")
    for i, (importance, stage, reason) in enumerate(failures, 1):
        print(f"    {i}. [{stage}] {reason}")
    
    if not failures:
        print("  ✅ No clear failures detected - candidate may be marginal")
    
    # ===== SECTION 8: DEFAULT VALUE DETECTION =====
    print("\n" + "="*100)
    print("⚠️ DEFAULT VALUE DETECTION")
    print("="*100)
    
    default_values = []
    suspicious_fields = [
        ("dynamic_strategy_type", watchlist_entry.get("dynamic_strategy_type")),
        ("dynamic_confidence", watchlist_entry.get("dynamic_confidence")),
        ("strategy_score", watchlist_entry.get("strategy_score")),
        ("confidence", watchlist_entry.get("confidence")),
        ("market_phase", watchlist_entry.get("market_phase")),
        ("smart_money_bias", watchlist_entry.get("smart_money_bias")),
        ("momentum_direction", watchlist_entry.get("momentum_direction")),
        ("institutional_state", watchlist_entry.get("institutional_state")),
        ("entry_signal_quality", watchlist_entry.get("entry_signal_quality")),
    ]
    
    for field, value in suspicious_fields:
        if value in [None, 0, 50, "UNKNOWN", "NEUTRAL", "Default", "Fallback", "N/A", "", None]:
            default_values.append((field, value, "Value is default/fallback"))
        elif isinstance(value, (int, float)) and value in [0, 50]:
            default_values.append((field, value, "Numeric default detected"))
    
    if default_values:
        print("\n  Suspicious Values Found:")
        for field, value, reason in default_values:
            print(f"    ⚠️ {field}: {value} ({reason})")
    else:
        print("\n  ✅ No default values detected - all fields have meaningful data")
    
    # ===== SECTION 9: MARKET PHASE ANALYSIS =====
    print("\n" + "="*100)
    print("📊 MARKET PHASE vs TRADE TYPE ALIGNMENT")
    print("="*100)
    
    trade_type = watchlist_entry.get("trade_type", "UNKNOWN")
    market_phase = watchlist_entry.get("market_phase", "UNKNOWN")
    
    phase_alignment = {
        ("TREND", "TREND"): ("✅", "Aligned - Trend trade in trending market"),
        ("TREND", "TREND_PULLBACK"): ("✅", "Aligned - Pullback in trend"),
        ("REVERSAL", "EXHAUSTION"): ("✅", "Aligned - Reversal at exhaustion"),
        ("REVERSAL", "RANGE"): ("✅", "Aligned - Mean reversion in range"),
        ("BREAKOUT", "RANGE"): ("✅", "Aligned - Breakout from consolidation"),
        ("TREND", "RANGE"): ("❌", "Misaligned - Trend trade in range market"),
        ("REVERSAL", "TREND"): ("⚠️", "Challenging - Reversal against trend"),
    }
    
    alignment = phase_alignment.get((trade_type, market_phase), ("❓", "Unknown combination"))
    print(f"\n  Trade Type:      {trade_type}")
    print(f"  Market Phase:    {market_phase}")
    print(f"  Alignment:      {alignment[0]} {alignment[1]}")
    
    # ===== SECTION 10: FINAL SUMMARY =====
    print("\n" + "="*100)
    print("📋 FINAL SUMMARY")
    print("="*100)
    
    print(f"""
  ┌────────────────────────────────────────────────────────────────────────────┐
  │  Candidate: {symbol:<50} │
  │  Decision:  {action:<50} │
  │  Readiness: {readiness:<50} │
  │  Evidence:  {composite:.1f}% (Gap to NORMAL: {max(0, 60-composite):.1f}%)                      │
  │  Signals:   {positive_count} positive, {negative_count} negative, {neutral_count} neutral              │
  │  Pass:      {pass_count}/{len(evidence_details)} evidence providers                                          │
  └────────────────────────────────────────────────────────────────────────────┘
    """)
    
    print("█"*100)
    print("█" + " "*98 + "█")
    print("█" + " END OF FORENSIC REPORT".center(98) + "█")
    print("█" + " Observer Mode - No Strategy Modification".center(98) + "█")
    print("█" + " "*98 + "█")
    print("█"*100 + "\n")
    
    # Return the report for storage
    return {
        "lifecycle_id": lifecycle_id,
        "symbol": symbol,
        "action": action,
        "readiness": readiness,
        "composite": composite,
        "evidence_details": evidence_details,
        "signals": signals,
        "positive_signals": positive_count,
        "negative_signals": negative_count,
        "failures": failures,
        "default_values": default_values,
        "total_contribution": total_contribution,
        "total_lost": total_lost,
    }


def print_investigation_report(lifecycle_id, symbol, side, current_stage, rejection_reasons=None):
    """
    Print COMPLETE forensic investigation report for a candidate.
    
    Includes:
    - Lifecycle ID and basic info
    - Complete engine votes with scores, confidences, reasons
    - Contribution breakdown
    - Conflict matrix
    - Detailed rejection reasons
    - Strategy diagnostic
    - Confidence breakdown
    - Timeline
    """
    # Get all investigation data
    votes = _ENGINE_VOTES.get(lifecycle_id, {})
    lifecycle = _ACTIVE_LIFECYCLES.get(lifecycle_id, {})
    
    # Count votes
    buy_votes = {k: v for k, v in votes.items() if v.get("vote") == "BUY"}
    sell_votes = {k: v for k, v in votes.items() if v.get("vote") == "SELL"}
    neutral_votes = {k: v for k, v in votes.items() if v.get("vote") == "NEUTRAL"}
    
    # Build timeline
    timeline = get_lifecycle_timeline(lifecycle_id)
    
    # Get creation time
    creation_time = lifecycle.get("creation_time", time.time())
    creation_time_ms = lifecycle.get("creation_time_ms", get_timestamp_ms())
    time_alive_ms = (time.time() - creation_time) * 1000
    
    print("\n" + "="*100)
    print("🔍 FORENSIC INVESTIGATION REPORT")
    print("="*100)
    print(f"Lifecycle ID:    {lifecycle_id}")
    print(f"Symbol:          {symbol}")
    print(f"Side:            {side}")
    print(f"Current Stage:   {current_stage}")
    print(f"Detection Time:  {creation_time_ms}")
    print(f"Time Alive:      {time_alive_ms/1000:.2f}s ({time_alive_ms:.0f}ms)")
    print("="*100)
    
    # ===== TIMELINE =====
    print("\n⏱️ TIMELINE (Millisecond Precision)")
    print("-"*100)
    prev_time = creation_time
    for entry in timeline[:20]:  # Show first 20 stages
        stage = entry.get("stage", "UNKNOWN")
        ts_ms = entry.get("timestamp_ms", get_timestamp_ms())
        passed = entry.get("passed", None)
        delta = (entry.get("timestamp", prev_time) - prev_time) * 1000
        
        status = "✅" if passed else "❌" if passed is False else "⏳"
        print(f"  {ts_ms} | {status} | {stage:<20} | +{delta:.1f}ms")
        prev_time = entry.get("timestamp", prev_time)
    
    # ===== ENGINE VOTES =====
    print("\n" + "="*100)
    print("🗳️ ENGINE VOTES (Complete Breakdown)")
    print("="*100)
    
    engine_order = [
        "SmartMoney", "Banker", "HotMoney", "MCDX", "MarketStory",
        "MarketPhase", "Structure", "Liquidity", "OrderBlock", "MultiTimeframe",
        "DYNAMIC_STRATEGY", "CONFIDENCE", "COMPOSITE"
    ]
    
    for engine in engine_order:
        if engine in votes:
            v = votes[engine]
            vote = v.get("vote", "NEUTRAL")
            icon = "🟢" if vote == "BUY" else "🔴" if vote == "SELL" else "⚪"
            
            print(f"\n  {icon} {engine}")
            print(f"     Vote: {vote}")
            
            if v.get("score") is not None:
                print(f"     Score: {v['score']}")
            if v.get("confidence") is not None:
                print(f"     Confidence: {v['confidence']}%")
            if v.get("reason"):
                print(f"     Reason: {v['reason']}")
            
            # Show details
            details = v.get("details", {})
            if details and engine not in ["CONFIDENCE", "COMPOSITE"]:
                for dk, dv in details.items():
                    if dv and str(dv) not in ["None", "{}", "[]"]:
                        print(f"     {dk}: {dv}")
            
            # Strategy-specific output
            if engine == "DYNAMIC_STRATEGY":
                print(f"     Strategy Type: {v.get('strategy_type', 'UNKNOWN')}")
                print(f"     Selected Scenario: {v.get('selected_scenario', 'N/A')}")
                scenarios = v.get("scenarios", {})
                if scenarios:
                    print(f"     Scenarios: {scenarios}")
            
            # Confidence breakdown
            if engine == "CONFIDENCE":
                comps = v.get("components", {})
                if comps:
                    print(f"     Components:")
                    for ck, cv in comps.items():
                        print(f"       - {ck}: {cv}")
            
            # Composite breakdown
            if engine == "COMPOSITE":
                contribs = v.get("contributions", {})
                if contribs:
                    print(f"     Contributions:")
                    for ck, cv in contribs.items():
                        weight = cv.get("weight", "N/A")
                        raw = cv.get("raw", "N/A")
                        contrib = cv.get("contribution", "N/A")
                        print(f"       - {ck}: Weight={weight}, Raw={raw}, Contrib={contrib}")
    
    # ===== CONFLICT MATRIX =====
    print("\n" + "="*100)
    print("⚖️ CONFLICT MATRIX")
    print("="*100)
    
    if buy_votes or sell_votes or neutral_votes:
        print("\n  🟢 BUY Votes:")
        for engine, v in buy_votes.items():
            if engine not in ["CONFIDENCE", "COMPOSITE"]:
                score = v.get("score", "N/A")
                reason = v.get("reason", "")[:50]
                print(f"     • {engine}: Score={score} | {reason}")
        
        print("\n  🔴 SELL Votes:")
        for engine, v in sell_votes.items():
            if engine not in ["CONFIDENCE", "COMPOSITE"]:
                score = v.get("score", "N/A")
                reason = v.get("reason", "")[:50]
                print(f"     • {engine}: Score={score} | {reason}")
        
        print("\n  ⚪ NEUTRAL Votes:")
        for engine, v in neutral_votes.items():
            if engine not in ["CONFIDENCE", "COMPOSITE"]:
                score = v.get("score", "N/A")
                print(f"     • {engine}: Score={score}")
        
        print(f"\n  📊 Vote Summary:")
        print(f"     BUY: {len(buy_votes)} | SELL: {len(sell_votes)} | NEUTRAL: {len(neutral_votes)}")
        
        if len(buy_votes) == len(sell_votes) and len(buy_votes) > 0:
            print(f"     ⚠️ CONFLICT DETECTED: Equal BUY/SELL votes")
            _PIPELINE_HEALTH["conflict_count"] += 1
    else:
        print("  No engine votes recorded")
    
    # ===== REJECTION REASONS =====
    if rejection_reasons:
        print("\n" + "="*100)
        print("❌ DETAILED REJECTION REASONS")
        print("="*100)
        for reason in rejection_reasons:
            if isinstance(reason, dict):
                stage = reason.get("stage", "UNKNOWN")
                reason_text = reason.get("reason", "N/A")
                expected = reason.get("expected", "")
                actual = reason.get("actual", "")
                print(f"\n  {stage}:")
                print(f"     Reason: {reason_text}")
                if expected:
                    print(f"     Expected: {expected}")
                if actual:
                    print(f"     Actual:   {actual}")
                
                # Track rejection
                if stage not in _PIPELINE_HEALTH["stage_failures"]:
                    _PIPELINE_HEALTH["stage_failures"][stage] = 0
                _PIPELINE_HEALTH["stage_failures"][stage] += 1
            else:
                print(f"  • {reason}")
    
    # ===== MARKET SNAPSHOT =====
    snapshot = lifecycle.get("market_snapshot", {})
    if snapshot:
        print("\n" + "="*100)
        print("📸 MARKET SNAPSHOT (At Time of Analysis)")
        print("="*100)
        
        print("\n  📈 PRICE & INDICATORS:")
        print(f"     Price: {snapshot.get('price', 'N/A')}")
        print(f"     ATR:   {snapshot.get('atr_14', 'N/A')}")
        print(f"     EMA20: {snapshot.get('ema_20', 'N/A')}")
        print(f"     EMA50: {snapshot.get('ema_50', 'N/A')}")
        print(f"     EMA200: {snapshot.get('ema_200', 'N/A')}")
        print(f"     Volume Ratio: {snapshot.get('volume_ratio', 'N/A')}")
        
        print("\n  🏦 INSTITUTIONAL:")
        print(f"     Banker Pressure: {snapshot.get('banker_pressure', 'N/A')}")
        print(f"     Retail Pressure:  {snapshot.get('retail_pressure', 'N/A')}")
        print(f"     Direction:       {snapshot.get('institutional_direction', 'N/A')}")
        print(f"     Strength:        {snapshot.get('institutional_strength', 'N/A')}")
        
        print("\n  📐 STRUCTURE:")
        print(f"     BOS:   {'✅' if snapshot.get('bos') else '❌'}")
        print(f"     MSS:   {'✅' if snapshot.get('mss') else '❌'}")
        print(f"     CHoCH: {'✅' if snapshot.get('choch') else '❌'}")
        
        print("\n  💧 LIQUIDITY:")
        print(f"     Sweep:    {'✅' if snapshot.get('liquidity_sweep') else '❌'}")
        print(f"     Retest:   {'✅' if snapshot.get('liquidity_retest') else '❌'}")
        print(f"     Rejection: {'✅' if snapshot.get('liquidity_rejection') else '❌'}")
        
        print("\n  🚀 MOMENTUM:")
        print(f"     Health:    {snapshot.get('momentum_health', 'N/A')}")
        print(f"     Direction: {snapshot.get('momentum_direction', 'N/A')}")
        
        print("\n  📊 SCORES:")
        print(f"     Composite Score:    {snapshot.get('score', 'N/A')}")
        print(f"     Dynamic Score:     {snapshot.get('dynamic_score', 'N/A')}")
        print(f"     Dynamic Confidence: {snapshot.get('dynamic_confidence', 'N/A')}")
        print(f"     Strategy Score:   {snapshot.get('strategy_score', 'N/A')}")
    
    print("\n" + "="*100 + "\n")
    
    # Add to investigation log
    report = {
        "lifecycle_id": lifecycle_id,
        "symbol": symbol,
        "side": side,
        "current_stage": current_stage,
        "buy_votes": list(buy_votes.keys()),
        "sell_votes": list(sell_votes.keys()),
        "neutral_votes": list(neutral_votes.keys()),
        "rejection_reasons": rejection_reasons,
        "timestamp": time.time(),
    }
    _INVESTIGATION_LOG.append(report)
    if len(_INVESTIGATION_LOG) > _MAX_INVESTIGATION_LOG:
        _INVESTIGATION_LOG.pop(0)

def print_pipeline_health_report():
    """
    Print end-of-cycle pipeline health report.
    """
    health = _PIPELINE_HEALTH
    
    print("\n" + "="*100)
    print("🏥 PIPELINE HEALTH REPORT")
    print("="*100)
    print(f"Cycle Count:             {health['cycle_count']}")
    print(f"Candidates Discovered:    {health['candidates_discovered']}")
    print(f"Candidates Added:        {health['candidates_added']}")
    print(f"Candidates Waiting:      {health['candidates_waiting']}")
    print(f"Candidates Removed:      {health['candidates_removed']}")
    
    if health["removal_reasons"]:
        print("\n📋 Removal Reasons:")
        for reason, count in health["removal_reasons"].items():
            print(f"   • {reason}: {count}")
    
    if health["stage_failures"]:
        print("\n❌ Stage Failures (Where Candidates Dropped):")
        for stage, count in sorted(health["stage_failures"].items(), key=lambda x: -x[1]):
            print(f"   • {stage}: {count}")
    
    if health["engine_rejections"]:
        print("\n🔴 Engines Causing Rejections:")
        for engine, count in sorted(health["engine_rejections"].items(), key=lambda x: -x[1]):
            print(f"   • {engine}: {count}")
    
    if health["default_values_detected"]:
        print("\n⚠️ DEFAULT VALUES DETECTED:")
        for dv in health["default_values_detected"][-10:]:  # Show last 10
            print(f"   • {dv['lifecycle_id']}: {dv['field']} = {dv['value']} | {dv['reason']}")
    
    if health["conflict_count"] > 0:
        print(f"\n⚖️ CONFLICTS DETECTED: {health['conflict_count']}")
    
    # Find first failure point
    stage_order = ["DISCOVERED", "SCANNER", "WATCHLIST", "EVIDENCE", "SMART_MONEY", 
                   "BANKER", "MCDX", "MARKET_STORY", "COMPOSITE", "RANKING", "READINESS"]
    
    first_failure = None
    for stage in stage_order:
        if stage in health["stage_failures"]:
            first_failure = stage
            break
    
    if first_failure:
        print(f"\n🎯 FIRST FAILURE POINT: {first_failure}")
        print(f"   Candidates drop here before reaching later stages.")
    
    print("="*100 + "\n")
    
    # Reset for next cycle
    health["cycle_count"] += 1

# ============================================================================
# EXECUTION QUEUE - Ready symbols waiting for execution
# ============================================================================
_EXECUTION_QUEUE = []  # List of symbols ready for execution
_EXECUTION_QUEUE_MAX = 10  # Max entries to keep in queue

def add_to_execution_queue(symbol, entry_data, decision):
    """
    Add a READY symbol to the execution queue.
    Called when aggregate_decision() produces action=READY.
    
    Status values: WAITING | EXECUTING | EXECUTED | REJECTED
    """
    # Check if already in queue with WAITING status
    for eq in _EXECUTION_QUEUE:
        if eq["symbol"] == symbol:
            if eq["status"] == "WAITING":
                # Already in queue, update data
                eq.update({
                    "entry_data": entry_data,
                    "decision": decision,
                    "updated_at": time.time(),
                })
                log_execution(
                    f"[EXECUTION QUEUE] UPDATED {symbol} | Status={eq['status']} | "
                    f"Confidence={decision.get('confidence', 0):.0f}%",
                    "INFO"
                )
                return eq
            elif eq["status"] in ("EXECUTING", "EXECUTED"):
                # Already being executed or executed, don't update
                log_execution(
                    f"[EXECUTION QUEUE] SKIPPED {symbol} | Status={eq['status']}",
                    "INFO"
                )
                return eq
    
    # Create new entry
    queue_entry = {
        "symbol": symbol,
        "side": entry_data.get("side", "BUY"),
        "score": entry_data.get("score", 0),
        "strategy_score": decision.get("strategy_score", 0),
        "confidence": decision.get("confidence", 0),
        "strategy_type": decision.get("trade_type", "UNKNOWN"),
        "entry_readiness": decision.get("entry_readiness", "NORMAL"),
        "action_reason": decision.get("action_reason", ""),
        "strength": decision.get("strength", "WEAK"),
        "market_phase": entry_data.get("market_phase", "UNKNOWN"),
        "smart_money_bias": entry_data.get("smart_money_bias", "NEUTRAL"),
        "smart_money_dominant": entry_data.get("smart_money_dominant", False),
        "momentum_expansion": entry_data.get("momentum_expansion", False),
        "continuation_strength": entry_data.get("continuation_strength", 0),
        "warnings": decision.get("warnings", []),
        "reasoning": decision.get("reasoning", []),
        "entry_data": entry_data,
        "decision": decision,
        "status": "WAITING",  # WAITING | EXECUTING | EXECUTED | REJECTED
        "added_at": time.time(),
        "updated_at": time.time(),
        "executed_at": None,
        "execution_result": None,
        "execution_error": None,
    }
    
    _EXECUTION_QUEUE.append(queue_entry)
    
    # Trim queue if too large
    while len(_EXECUTION_QUEUE) > _EXECUTION_QUEUE_MAX:
        # Remove oldest non-WAITING entry
        removed = False
        for i, eq in enumerate(_EXECUTION_QUEUE):
            if eq["status"] != "WAITING":
                _EXECUTION_QUEUE.pop(i)
                removed = True
                break
        if not removed:
            break
    
    log_execution(
        f"[EXECUTION QUEUE] ➕ ADDED {symbol} | Status=WAITING | "
        f"Side={queue_entry['side']} | Confidence={queue_entry['confidence']:.0f}% | "
        f"Type={queue_entry['strategy_type']} | Readiness={queue_entry['entry_readiness']}",
        "INFO"
    )
    
    return queue_entry

def get_execution_queue():
    """Get the execution queue for Dashboard display."""
    return _EXECUTION_QUEUE

def get_next_ready_entry():
    """
    Get the next WAITING entry from execution queue.
    Used by execute_entry() to select which symbol to execute.
    """
    for eq in _EXECUTION_QUEUE:
        if eq["status"] == "WAITING":
            return eq
    return None

def update_execution_status(symbol, status, execution_result=None, execution_error=None):
    """
    Update the status of an entry in the execution queue.
    
    Status values:
    - WAITING: Waiting for execution
    - EXECUTING: Currently being executed
    - EXECUTED: Successfully executed
    - REJECTED: Execution failed
    """
    for eq in _EXECUTION_QUEUE:
        if eq["symbol"] == symbol:
            old_status = eq["status"]
            eq["status"] = status
            eq["updated_at"] = time.time()
            
            if status == "EXECUTED":
                eq["executed_at"] = time.time()
                eq["execution_result"] = execution_result
            elif status == "REJECTED":
                eq["execution_error"] = execution_error
            
            log_execution(
                f"[EXECUTION QUEUE] 📋 {symbol} | Status: {old_status} → {status} | "
                f"Result: {execution_result or execution_error or 'N/A'}",
                "INFO"
            )
            return eq
    
    log_execution(
        f"[EXECUTION QUEUE] ⚠️ {symbol} not found in queue for status update",
        "WARN"
    )
    return None

def clear_executed_entries():
    """Remove EXECUTED and old REJECTED entries from queue."""
    before = len(_EXECUTION_QUEUE)
    _EXECUTION_QUEUE[:] = [
        eq for eq in _EXECUTION_QUEUE 
        if eq["status"] in ("WAITING", "EXECUTING")
    ]
    removed = before - len(_EXECUTION_QUEUE)
    if removed > 0:
        log_execution(f"[EXECUTION QUEUE] Cleared {removed} old entries", "INFO")
    return removed

def _add_decision_to_audit(symbol, decision_record):
    """
    Add decision to audit log with full timeline.
    Called at every decision point in the pipeline.
    """
    entry = {
        "timestamp": time.time(),
        "symbol": symbol,
        "decision": decision_record.copy(),
        "pipeline_stage": decision_record.get("pipeline_stage", "UNKNOWN"),
    }
    _DECISION_AUDIT_LOG.append(entry)
    if len(_DECISION_AUDIT_LOG) > _MAX_AUDIT_LOG:
        _DECISION_AUDIT_LOG.pop(0)
    return entry

def _log_rejection(symbol, rejection_data):
    """
    Log a rejected opportunity with EXACT subsystem responsible.
    Called whenever an opportunity is rejected at any stage.
    """
    entry = {
        "timestamp": time.time(),
        "symbol": symbol,
        "side": rejection_data.get("side", "UNKNOWN"),
        "strategy_type": rejection_data.get("strategy_type", "UNKNOWN"),
        "confidence": rejection_data.get("confidence", 0),
        "final_score": rejection_data.get("final_score", 0),
        "rejection_subsystem": rejection_data.get("rejection_subsystem", "UNKNOWN"),
        "rejection_reason": rejection_data.get("rejection_reason", "Unknown"),
        "rejection_details": rejection_data.get("rejection_details", ""),
        "lifecycle": rejection_data.get("lifecycle", "UNKNOWN"),
        "decision_snapshot": rejection_data.get("decision_snapshot", {}),
        "final_decision": "REJECTED",  # Required for get_last_rejected_entries() filter
    }
    _REJECTION_LOG.append(entry)
    if len(_REJECTION_LOG) > _MAX_REJECTION_LOG:
        _REJECTION_LOG.pop(0)
    
    # Log with subsystem tag
    log_execution(
        f"[REJECTED] {symbol} | Subsystem={entry['rejection_subsystem']} | "
        f"Reason={entry['rejection_reason']} | Confidence={entry['confidence']:.0f}% | "
        f"Score={entry['final_score']:.1f}",
        "WARN"
    )
    return entry

def get_rejected_opportunities(limit=10):
    """Get recent rejected opportunities for Dashboard display."""
    return _REJECTION_LOG[-limit:] if _REJECTION_LOG else []

def get_decision_audit_trail(symbol=None, limit=20):
    """Get decision audit trail, optionally filtered by symbol."""
    if symbol:
        return [e for e in _DECISION_AUDIT_LOG if e["symbol"] == symbol][-limit:]
    return _DECISION_AUDIT_LOG[-limit:] if _DECISION_AUDIT_LOG else []

def _build_complete_decision_record(symbol, watchlist_entry, stage="AGGREGATE"):
    """
    Build a complete decision record with all fields for audit.
    Used by both Dashboard and Pipeline for consistency.
    """
    # Read all available data
    return {
        # Basic Info
        "symbol": symbol,
        "side": watchlist_entry.get("side", "UNKNOWN"),
        "strategy_type": watchlist_entry.get("dynamic_strategy_type", 
                     watchlist_entry.get("strategy_type", "UNKNOWN")),
        
        # Readiness & Action
        "entry_readiness": watchlist_entry.get("entry_readiness", "NORMAL"),
        "action": watchlist_entry.get("action", "SKIP"),
        "action_reason": watchlist_entry.get("action_reason", "No decision made"),
        
        # Scores
        "confidence": watchlist_entry.get("dynamic_confidence",
                      watchlist_entry.get("confidence", 0)),
        "strategy_score": watchlist_entry.get("strategy_score", 0),
        "composite_score": watchlist_entry.get("composite_score", 0),
        
        # Strength
        "strength": watchlist_entry.get("strength", "WEAK"),
        "market_phase": watchlist_entry.get("market_phase", "UNKNOWN"),
        
        # Lifecycle
        "lifecycle": watchlist_entry.get("lifecycle", WatchlistLifecycle.DISCOVERED),
        "watchlist_state": watchlist_entry.get("watchlist_state", "UNKNOWN"),
        
        # Components
        "smart_money_dominant": watchlist_entry.get("smart_money_dominant", False),
        "smart_money_bias": watchlist_entry.get("smart_money_bias", "NEUTRAL"),
        "distribution_risk": watchlist_entry.get("distribution_risk", 0),
        "momentum_expansion": watchlist_entry.get("momentum_expansion", False),
        "continuation_strength": watchlist_entry.get("continuation_strength", 0),
        "bos": watchlist_entry.get("bos", False),
        "choch": watchlist_entry.get("choch", False),
        "mss": watchlist_entry.get("mss", False),
        
        # Warnings
        "warnings": watchlist_entry.get("warnings", []),
        "reasoning": watchlist_entry.get("reasoning", []),
        
        # Pipeline Stage
        "pipeline_stage": stage,
        "timestamp": time.time(),
    }

def _verify_decision_consistency(symbol, watchlist_entry, pipeline_decision):
    """
    Verify that Dashboard display and Pipeline decision are consistent.
    Call this whenever comparing Dashboard vs Pipeline states.
    
    If mismatch is detected, update MEMORY with the fresh pipeline decision.
    This ensures Dashboard shows the most current decision.
    """
    dashboard_readiness = watchlist_entry.get("entry_readiness", "NORMAL")
    dashboard_action = watchlist_entry.get("action", "SKIP")
    pipeline_action = pipeline_decision.get("action", "SKIP")
    pipeline_readiness = pipeline_decision.get("entry_readiness", "NORMAL")
    
    # Check for mismatches
    if dashboard_action != pipeline_action or dashboard_readiness != pipeline_readiness:
        log_execution(
            f"[⚠️ DECISION MISMATCH DETECTED] {symbol} | "
            f"Dashboard Action={dashboard_action} | Pipeline Action={pipeline_action} | "
            f"Dashboard Readiness={dashboard_readiness} | Pipeline Readiness={pipeline_readiness}",
            "ERROR"
        )
        log_execution(
            f"[MISMATCH] Dashboard Decision: {watchlist_entry.get('action_reason', 'N/A')} | "
            f"Pipeline Reason: {pipeline_decision.get('action_reason', 'N/A')}",
            "ERROR"
        )
        
        # Update MEMORY with fresh pipeline decision
        # This ensures Dashboard will show the current decision next refresh
        if "watchlist" in MEMORY and symbol in MEMORY["watchlist"]:
            MEMORY["watchlist"][symbol]["action"] = pipeline_action
            MEMORY["watchlist"][symbol]["entry_readiness"] = pipeline_readiness
            MEMORY["watchlist"][symbol]["action_reason"] = pipeline_decision.get("action_reason", "")
            MEMORY["watchlist"][symbol]["confidence"] = pipeline_decision.get("confidence", 0)
            MEMORY["watchlist"][symbol]["strategy_score"] = pipeline_decision.get("strategy_score", 0)
            MEMORY["watchlist"][symbol]["warnings"] = pipeline_decision.get("warnings", [])
            MEMORY["watchlist"][symbol]["reasoning"] = pipeline_decision.get("reasoning", [])
            MEMORY["watchlist"][symbol]["lifecycle"] = pipeline_decision.get("lifecycle", "")
            MEMORY["watchlist"][symbol]["decision_updated_by"] = "pipeline"
            log_execution(
                f"[MISMATCH FIX] {symbol} | Updated MEMORY with Pipeline decision | "
                f"Action={pipeline_action} | Readiness={pipeline_readiness}",
                "INFO"
            )
        
        return False
    
    return True


def _log_entry_decision(symbol, decision_data):
    """
    سجل قرار الدخول/الرفض للمراجعة.
    
    IMPORTANT: This function is OBSERVER ONLY.
    It must NEVER block trade execution.
    If any error occurs, log it and continue.
    """
    try:
        import datetime
        now = datetime.datetime.now()
        
        # Build complete entry with all fields
        entry = {
            "timestamp": now.strftime("%Y-%m-%d %H:%M:%S"),
            "symbol": symbol,
            "action": decision_data.get("action", "UNKNOWN"),
            "score": decision_data.get("score", 0),
            "confidence": decision_data.get("confidence", 0),
            "side": decision_data.get("side", "BUY"),
            "reasons": decision_data.get("reasons", []),
            "warnings": decision_data.get("warnings", []),
            "evaluation": decision_data.get("evaluation", {}),
            # Additional fields for rejection tracking
            "strength": decision_data.get("strength", "UNKNOWN"),
            "pipeline_stage": decision_data.get("pipeline_stage", "UNKNOWN"),
            "watchlist_validated": decision_data.get("watchlist_validated", False),
            "qty": decision_data.get("qty", 0),
            "error_type": decision_data.get("error_type", None),
            "bias": decision_data.get("bias", None),
        }
        
        _ENTRY_AUDIT_LOG.append(entry)
        
        # Keep only last _MAX_AUDIT_ENTRIES entries
        if len(_ENTRY_AUDIT_LOG) > _MAX_AUDIT_ENTRIES:
            _ENTRY_AUDIT_LOG.pop(0)
        
        # Also store in MEMORY for Dashboard
        if "entry_audit_log" not in MEMORY:
            MEMORY["entry_audit_log"] = []
        MEMORY["entry_audit_log"].append(entry)
        if len(MEMORY["entry_audit_log"]) > _MAX_AUDIT_ENTRIES:
            MEMORY["entry_audit_log"].pop(0)
        
        return entry
    except Exception as e:
        # NEVER block execution - log error and continue
        log_execution(f"[AUDIT ERROR] _log_entry_decision failed: {e}", "ERROR")
        return None

def get_rejected_entries(limit=10):
    """
    Get recent rejected opportunities for Dashboard.
    Uses the new _REJECTION_LOG which tracks exact rejection reasons.
    
    Returns list with:
    - Symbol
    - Side
    - Strategy Type
    - Confidence
    - Final Score
    - Exact Rejection Reason
    - Rejection Subsystem
    """
    # First, try the new _REJECTION_LOG
    if _REJECTION_LOG:
        return _REJECTION_LOG[-limit:]
    
    # Fallback to old method if no rejections logged yet
    rejected = []
    rejection_actions = (
        "SKIP", "WAIT", "REJECTED", 
        "EXCHANGE_ERROR", "ORDER_REJECTED", 
        "STRONG_REJECTED", "STRONG_NOT_EXECUTED",
        "NO_DATA", "INVALID_DATA", "NOT_STRONG",
        "POSITION_OPEN", "COOLDOWN", "INSUFFICIENT_BALANCE"
    )
    for entry in reversed(_ENTRY_AUDIT_LOG):
        if entry.get("action") in rejection_actions:
            # Convert to new format
            rejected.append({
                "symbol": entry.get("symbol"),
                "side": entry.get("side", "UNKNOWN"),
                "strategy_type": entry.get("strategy_type", "UNKNOWN"),
                "confidence": entry.get("confidence", 0),
                "final_score": entry.get("score", 0),
                "rejection_subsystem": entry.get("rejection_subsystem", "Unknown"),
                "rejection_reason": entry.get("reasons", ["Unknown"])[0] if entry.get("reasons") else "Unknown",
                "rejection_details": "",
                "lifecycle": entry.get("lifecycle", "UNKNOWN"),
                "timestamp": entry.get("timestamp", 0),
            })
            if len(rejected) >= limit:
                break
    return rejected


def execute_entry(side, symbol, price, sl, tp1, tp2, score, reason, atr_val, trade_type, entry_type, classification):
    """
    PHASE 4: execute_entry() - EXECUTION ONLY
    
    EXECUTION QUEUE is the Single Source of Truth for entry execution.
    
    If a symbol reached Execution Queue with status=WAITING,
    it means ALL strategy conditions have been validated by UnifiedDecisionEngine.
    
    This function ONLY handles:
    - Position Sizing (based on classification)
    - Execution Constraints (balance, qty, precision)
    - Order Execution
    - API error handling
    
    NO STRATEGY FILTERS HERE:
    - No ADX checks
    - No Smart Money checks
    - No Momentum checks
    - No Confidence calculations
    - No Thesis building
    
    All strategic decisions are made in the Watchlist by UnifiedDecisionEngine.
    """
    
    # Determine if this is a Watchlist-validated entry
    is_watchlist_validated = (entry_type == "CANDIDATE_AGGREGATION")
    
    # Update execution queue status to EXECUTING
    update_execution_status(symbol, "EXECUTING")
    
    # Enable API tracing for this entry attempt
    _enable_api_trace()
    _API_TRACE["current_source"] = "entry"
    _set_api_stage("INIT")
    
    # Log the entry attempt
    _log_entry_decision(symbol, {
        "action": "EXECUTING",
        "score": score,
        "side": side,
        "reasons": [reason],
        "trade_type": trade_type,
        "entry_type": entry_type,
        "classification": classification,
        "watchlist_validated": is_watchlist_validated,
    })
    
    # =================================================================
    # PHASE 4: EXECUTION ONLY - No Strategy Decisions
    # =================================================================
    
    log_execution(f"[EXECUTION TIMELINE] {symbol} Pipeline Start", "INFO")
    
    # BALANCE CHECK
    _set_api_stage("BALANCE_CHECK")
    log_execution(f"[EXECUTION] Stage 1/8: BALANCE_CHECK", "INFO")
    free_bal = get_free_balance_safe() if not PAPER_MODE else paper["balance"]
    usable_balance = free_bal * BALANCE_SAFETY_FACTOR
    if PAPER_MODE:
        balance = paper["balance"]
    else:
        balance = usable_balance

    # Position sizing based on classification (NOT strategy evaluation)
    if classification == "SNIPER" or classification == "INSTITUTIONAL_SNIPER":
        margin_percent = 0.40
        trade_type_label = "STRONG"
    elif classification == "TREND":
        margin_percent = 0.30
        trade_type_label = "NORMAL"
    elif classification == "LOW":
        margin_percent = 0.15
        trade_type_label = "LOW_CONF"
    else:
        margin_percent = 0.30
        trade_type_label = "NORMAL"

    margin = balance * margin_percent
    notional = margin * LEVERAGE
    qty = notional / price
    log_execution(f"[SIZING]\nFree USDT: {free_bal:.2f}\nUsable (x{BALANCE_SAFETY_FACTOR}): {balance:.2f}\nType: {trade_type_label}\nMargin: {margin:.2f}\nLeverage: {LEVERAGE}X\nNotional: {notional:.2f}\nFinal Qty: {qty:.6f}", "INFO")

    # =================================================================
    # EXECUTION CONSTRAINTS ONLY
    # =================================================================
    
    # Check 1: Balance availability
    log_execution(f"[EXECUTION] Stage 2/8: CHECKING BALANCE", "INFO")
    if balance <= 0 or free_bal <= 0:
        _log_entry_decision(symbol, {
            "action": "REJECTED",
            "score": score,
            "side": side,
            "reasons": ["Insufficient balance"],
            "watchlist_validated": is_watchlist_validated,
            "pipeline_stage": "EXECUTION",
        })
        # Log to rejection log with exact subsystem
        _log_rejection(symbol, {
            "side": side,
            "strategy_type": trade_type,
            "confidence": confidence,
            "final_score": score,
            "rejection_subsystem": "BalanceManager",
            "rejection_reason": "Insufficient balance",
            "rejection_details": f"Free balance={free_bal:.2f}, Required={margin:.2f}",
            "lifecycle": "EXECUTION",
        })
        log_execution(f"[ENTRY] ❌ REJECTED by BalanceManager: Insufficient balance {free_bal:.2f}", "WARN")
        log_execution(f"[EXECUTION TIMELINE] {symbol} → REJECTED: Balance insufficient", "WARN")
        _disable_api_trace()
        log_execution(_get_api_trace_report(), "INFO")
        return False
    
    # Check 2: Quantity threshold
    log_execution(f"[EXECUTION] Stage 3/8: CHECKING QUANTITY", "INFO")
    if qty <= 0:
        _log_entry_decision(symbol, {
            "action": "REJECTED",
            "score": score,
            "side": side,
            "reasons": ["Quantity calculation resulted in zero"],
            "watchlist_validated": is_watchlist_validated,
            "pipeline_stage": "EXECUTION",
        })
        _log_rejection(symbol, {
            "side": side,
            "strategy_type": trade_type,
            "confidence": confidence,
            "final_score": score,
            "rejection_subsystem": "PositionSizer",
            "rejection_reason": "Quantity calculation resulted in zero",
            "rejection_details": f"qty={qty}, notional={notional:.2f}",
            "lifecycle": "EXECUTION",
        })
        log_execution(f"[ENTRY] ❌ REJECTED by PositionSizer: Quantity is zero", "WARN")
        log_execution(f"[EXECUTION TIMELINE] {symbol} → REJECTED: Quantity invalid", "WARN")
        _disable_api_trace()
        log_execution(_get_api_trace_report(), "INFO")
        return False
    
    # Check 3: Active position check
    log_execution(f"[EXECUTION] Stage 4/8: CHECKING POSITION", "INFO")
    if STATE.get("open") or TRADE_STATE.get("in_position"):
        _log_entry_decision(symbol, {
            "action": "REJECTED",
            "score": score,
            "side": side,
            "reasons": ["Existing position already open"],
            "watchlist_validated": is_watchlist_validated,
            "pipeline_stage": "EXECUTION",
        })
        _log_rejection(symbol, {
            "side": side,
            "strategy_type": trade_type,
            "confidence": confidence,
            "final_score": score,
            "rejection_subsystem": "PositionManager",
            "rejection_reason": "Another trade is open",
            "rejection_details": f"STATE.open={STATE.get('open')}, TRADE_STATE.in_position={TRADE_STATE.get('in_position')}",
            "lifecycle": "EXECUTION",
        })
        log_execution(f"[ENTRY] ❌ REJECTED by PositionManager: Position already open", "WARN")
        log_execution(f"[EXECUTION TIMELINE] {symbol} → REJECTED: Another trade is open", "WARN")
        _disable_api_trace()
        log_execution(_get_api_trace_report(), "INFO")
        return False
    
    # Check 4: Cooldown check
    log_execution(f"[EXECUTION] Stage 5/8: CHECKING COOLDOWN", "INFO")
    if INSUFFICIENT_MARGIN_COOLDOWN_UNTIL and time.time() < INSUFFICIENT_MARGIN_COOLDOWN_UNTIL:
        remaining = INSUFFICIENT_MARGIN_COOLDOWN_UNTIL - time.time()
        _log_entry_decision(symbol, {
            "action": "REJECTED",
            "score": score,
            "side": side,
            "reasons": [f"Cooldown active, {remaining:.0f}s remaining"],
            "watchlist_validated": is_watchlist_validated,
            "pipeline_stage": "EXECUTION",
        })
        _log_rejection(symbol, {
            "side": side,
            "strategy_type": trade_type,
            "confidence": confidence,
            "final_score": score,
            "rejection_subsystem": "CooldownManager",
            "rejection_reason": f"Cooldown active, {remaining:.0f}s remaining",
            "rejection_details": "INSUFFICIENT_MARGIN_COOLDOWN_UNTIL triggered",
            "lifecycle": "EXECUTION",
        })
        log_execution(f"[ENTRY] ❌ REJECTED by CooldownManager: Cooldown active", "WARN")
        log_execution(f"[EXECUTION TIMELINE] {symbol} → REJECTED: Cooldown active", "WARN")
        _disable_api_trace()
        log_execution(_get_api_trace_report(), "INFO")
        return False

    # =================================================================
    # PHASE 4: NO STRATEGY CALCULATIONS HERE
    # All strategy decisions are made by UnifiedDecisionEngine in Watchlist
    # We just use the data from Watchlist for STATE tracking
    # =================================================================
    
    # Get confidence from Watchlist entry (already calculated)
    watchlist_entry = MEMORY.get("watchlist", {}).get(symbol, {})
    confidence = watchlist_entry.get("confidence", 75)  # Default if not in watchlist
    entry_readiness = watchlist_entry.get("entry_readiness", "NORMAL")
    warnings = watchlist_entry.get("warnings", [])
    
    # Update STATE with Watchlist data (NO recalculation)
    STATE["current_confidence"] = confidence
    STATE["entry_readiness"] = entry_readiness
    STATE["entry_readiness_class"] = entry_readiness
    STATE["watchlist_warnings"] = warnings
    
    # For backwards compatibility with existing trade management
    STATE["market_regime"] = "WATCHLIST_VALIDATED"
    STATE["adx_live"] = 25  # Neutral value - strategy decided in watchlist
    STATE["di_plus_live"] = 25
    STATE["di_minus_live"] = 25

    # PAPER MODE
    if PAPER_MODE:
        paper["position"] = {"side": side, "entry": price, "qty": qty, "remaining_qty": qty}
        STATE.update({
            "open": True, "bot_opened": True, "side": side, "entry": price, "qty": qty, "remaining_qty": qty,
            "sl": sl, "current_symbol": symbol, "tp1_done": False, "trail_activated": False,
            "peak": 0.0, "atr": atr_val, "entry_time": time.time(), "entry_reasons": [reason],
            "trade_score": score, "partial_closed": False, "tp1_price": tp1, "tp2_price": tp2,
            "trade_type": trade_type, "entry_type": entry_type, "be_done": False,
            "tp1_hit": False, "tp2_hit": False, "trail_stop": 0.0,
            "smart_tightened": False, "smart_partial_done": False, "smart_exit_triggered": False,
            "roe_pct": 0.0, "mark_price": price,
            "trade_personality": "WATCHLIST",
            "institutional_flow": "VALIDATED",
            "synthetic_sl": sl,
            "synthetic_tp1": tp1,
            "max_price": price,
            "min_price": price,
            # PHASE 4: Watchlist validated data
            "confidence": confidence,
            "entry_readiness": entry_readiness,
            "warnings": warnings,
        })
        TRADE_STATE.update({
            "in_position": True, "symbol": symbol, "side": side, "entry": price, "qty": qty,
            "tp1_hit": False, "trail_on": False, "last_update_ts": time.time()
        })
        _live_manager.start_trade(symbol, side, price, qty, sl, tp1, tp2)
        update_position_dashboard(symbol, side, price, qty)
        log_execution(f"PAPER {entry_type} {side} {qty:.6f} @ {price} | {trade_type_label} | {reason}", "SUCCESS")
        log_execution(f"[PHASE 4] Watchlist validated: Confidence={confidence:.0f}% | Readiness={entry_readiness}", "INFO")
        tg_entry(side, symbol, price, sl, tp1, score, reason, entry_type)
        
        # Update execution queue status to EXECUTED
        update_execution_status(symbol, "EXECUTED", execution_result=f"PAPER {side} {qty:.6f} @ {price}")
        
        return True

    # LIVE MODE
    sym = normalize_symbol(symbol)
    market = ex.market(sym)
    min_qty = market['limits']['amount']['min']
    if qty < min_qty:
        log_execution(f"SKIP: computed qty {qty:.6f} below minimum {min_qty}", "WARN")
        update_execution_status(symbol, "REJECTED", execution_error=f"Qty below min: {qty:.6f} < {min_qty}")
        _disable_api_trace()
        log_execution(_get_api_trace_report(), "INFO")
        return False
    precision = market['precision']['amount']
    qty = math.floor(qty / precision) * precision
    if qty <= 0:
        log_execution(f"SKIP: qty rounded to zero", "WARN")
        update_execution_status(symbol, "REJECTED", execution_error="Qty rounded to zero")
        _disable_api_trace()
        log_execution(_get_api_trace_report(), "INFO")
        return False
    
    # ENTRY ATTEMPT - Detailed logging
    log_execution(f"═══════════════════════════════════════════════════════════", "INFO")
    log_execution(f"📤 ENTRY ATTEMPT | {symbol} | {side} @ {price}", "INFO")
    log_execution(f"   Score: {score} | Type: {trade_type_label} | Reason: {reason}", "INFO")
    log_execution(f"   Qty: {qty:.6f} | SL: {sl} | TP1: {tp1} | TP2: {tp2}", "INFO")
    log_execution(f"   Balance: {free_bal:.2f} | Margin: {margin:.2f} | Notional: {notional:.2f}", "INFO")
    log_execution(f"[PHASE 4] Watchlist validated: Confidence={confidence:.0f}% | Readiness={entry_readiness}", "INFO")
    log_execution(f"═══════════════════════════════════════════════════════════", "INFO")
    
    try:
        result = open_position(side, qty, symbol)
    except Exception as e:
        error_msg = str(e)
        log_execution(f"❌ EXCHANGE ERROR | {symbol} | {error_msg}", "ERROR")
        
        _log_entry_decision(symbol, {
            "action": "EXCHANGE_ERROR",
            "score": score,
            "side": side,
            "reasons": [f"Exchange error: {error_msg}"],
            "pipeline_stage": "ORDER_EXECUTION",
            "watchlist_validated": is_watchlist_validated,
            "qty": qty,
            "error_type": "API_ERROR",
        })
        
        # Update execution queue status to REJECTED
        update_execution_status(symbol, "REJECTED", execution_error=f"Exchange API Error: {error_msg}")
        _log_rejection(symbol, {
            "side": side,
            "strategy_type": trade_type,
            "confidence": confidence,
            "final_score": score,
            "rejection_subsystem": "ExchangeAPI",
            "rejection_reason": f"Exchange API Error: {error_msg}",
            "rejection_details": error_msg,
            "lifecycle": "EXECUTION",
        })
        
        _disable_api_trace()
        log_execution(_get_api_trace_report(), "INFO")
        return False
    
    # Handle structured rejection from open_position
    if isinstance(result, dict) and result.get("rejected"):
        rejection_reason = result.get("reason", "UNKNOWN")
        rejection_details = result.get("details", "")
        
        log_execution(f"❌ ORDER REJECTED | {symbol} | {rejection_reason}: {rejection_details}", "WARN")
        
        _log_entry_decision(symbol, {
            "action": "ORDER_REJECTED",
            "score": score,
            "side": side,
            "reasons": [f"{rejection_reason}: {rejection_details}"],
            "pipeline_stage": "ORDER_EXECUTION",
            "watchlist_validated": is_watchlist_validated,
            "qty": qty,
            "error_type": rejection_reason,
        })

        update_execution_status(symbol, "REJECTED", execution_error=f"{rejection_reason}: {rejection_details}")
        _log_rejection(symbol, {
            "side": side,
            "strategy_type": trade_type,
            "confidence": confidence,
            "final_score": score,
            "rejection_subsystem": rejection_reason,
            "rejection_reason": rejection_reason,
            "rejection_details": rejection_details,
            "lifecycle": "EXECUTION",
        })

        _disable_api_trace()
        log_execution(_get_api_trace_report(), "INFO")
        return False

    order = result

    if order:
        STATE.update({
            "open": True, "bot_opened": True, "side": side, "entry": price, "qty": qty, "remaining_qty": qty,
            "sl": sl, "current_symbol": symbol, "tp1_done": False, "trail_activated": False,
            "peak": 0.0, "atr": atr_val, "entry_time": time.time(), "entry_reasons": [reason],
            "trade_score": score, "partial_closed": False, "tp1_price": tp1, "tp2_price": tp2,
            "trade_type": trade_type, "entry_type": entry_type, "be_done": False,
            "tp1_hit": False, "tp2_hit": False, "trail_stop": 0.0,
            "smart_tightened": False, "smart_partial_done": False, "smart_exit_triggered": False,
            "roe_pct": 0.0, "mark_price": price,
            "trade_personality": "WATCHLIST",
            "institutional_flow": "VALIDATED",
            "synthetic_sl": sl,
            "synthetic_tp1": tp1,
            "max_price": price,
            "min_price": price,
            # PHASE 4: Watchlist validated data
            "confidence": confidence,
            "entry_readiness": entry_readiness,
            "warnings": warnings,
        })
        TRADE_STATE.update({
            "in_position": True, "symbol": symbol, "side": side, "entry": price, "qty": qty,
            "tp1_hit": False, "trail_on": False, "last_update_ts": time.time()
        })
        _live_manager.start_trade(symbol, side, price, qty, sl, tp1, tp2)
        update_position_dashboard(symbol, side, price, qty)
        
        _set_api_stage("ORDER_VERIFICATION")
        
        _disable_api_trace()
        log_execution(f"✅ ORDER FILLED | {symbol} | {side} {qty:.6f} @ {price}", "SUCCESS")
        log_execution(_get_api_trace_report(), "INFO")
        tg_entry(side, symbol, price, sl, tp1, score, reason, entry_type)
        
        # Update execution queue status to EXECUTED
        update_execution_status(symbol, "EXECUTED", execution_result=f"ORDER FILLED {side} {qty:.6f} @ {price}")
        
        time.sleep(1)
        sync_position_state(symbol)
        return True
    else:
        log_execution(f"❌ ORDER REJECTED | {symbol} | Exchange returned None", "WARN")
        _log_entry_decision(symbol, {
            "action": "ORDER_REJECTED",
            "score": score,
            "side": side,
            "reasons": ["Exchange rejected order (returned None)"],
            "pipeline_stage": "ORDER_EXECUTION",
            "watchlist_validated": is_watchlist_validated,
            "qty": qty,
            "error_type": "EXCHANGE_REJECTION",
        })
        
        # Update execution queue status to REJECTED
        update_execution_status(symbol, "REJECTED", execution_error="Exchange rejected order (returned None)")
        _log_rejection(symbol, {
            "side": side,
            "strategy_type": trade_type,
            "confidence": confidence,
            "final_score": score,
            "rejection_subsystem": "ExchangeAPI",
            "rejection_reason": "Exchange rejected order",
            "rejection_details": "Order returned None",
            "lifecycle": "EXECUTION",
        })
        
        _disable_api_trace()
        log_execution(_get_api_trace_report(), "INFO")
        return False

def dynamic_spread_tolerance(symbol):
    df = get_ohlcv_safe(symbol, 50)
    if df is None:
        return MAX_SPREAD_PERCENT_DEFAULT
    atr = compute_atr(df).iloc[-1]
    price = df['close'].iloc[-1]
    atr_pct = (atr/price)*100 if price>0 else 0.5
    if atr_pct > 2.0:
        return MAX_SPREAD_PERCENT_VOLATILE
    return MAX_SPREAD_PERCENT_DEFAULT

# ========== DISCOVERY SCANNER ==========
# المرحلة الأولى: Discovery خفيف لجميع العملات
# يستخدم بيانات بسيطة فقط لاكتشاف أفضل الفرص
# لا يستخدم محركات مؤسسية أو تحليل عميق في هذه المرحلة

DISCOVERY_INTERVAL = 60 * 20  # 20 minutes
CONTINUOUS_ANALYSIS_INTERVAL = 15  # Analyze 6 symbols every 15 seconds
CONTINUOUS_BATCH_SIZE = 6  # Analyze 6 symbols per cycle

def run_discovery_scanner():
    """
    Discovery Scanner - المرحلة الأولى من نظام الفحص
    - فحص خفيف لجميع عقود USDT Futures
    - استخدام بيانات بسيطة فقط (price, volume, volatility)
    - لا يستخدم محركات مؤسسية أو تحليل عميق
    - يرتب السوق ويختار أفضل 60-80 عملة للمرحلة التالية
    """
    import time as time_module
    start_time = time_module.time()
    
    log_execution("[DISCOVERY] ========== DISCOVERY SCANNER START ==========", "INFO")
    
    try:
        # Phase 1: Market Discovery - بيانات خفيفة فقط
        log_execution("[DISCOVERY] Phase 1: Light Scan starting...", "INFO")
        discovery_data = _discovery_light_scan()
        
        if not discovery_data:
            log_execution("[DISCOVERY] ❌ No symbols discovered", "WARN")
            log_execution("[DISCOVERY] ========== DISCOVERY SCANNER END (FAILED) ==========", "INFO")
            return None
        
        log_execution(f"[DISCOVERY] ✅ Phase 1 Complete: {len(discovery_data)} symbols scanned", "INFO")
        
        # Phase 2: Light Ranking - ترتيب بسيط حسب السيولة والحركة
        log_execution("[DISCOVERY] Phase 2: Light Ranking starting...", "INFO")
        ranked = _discovery_light_ranking(discovery_data, top_n=80)
        
        if not ranked:
            log_execution("[DISCOVERY] ❌ No symbols passed ranking", "WARN")
            log_execution("[DISCOVERY] ========== DISCOVERY SCANNER END (FAILED) ==========", "INFO")
            return None
        
        log_execution(f"[DISCOVERY] ✅ Phase 2 Complete: {len(ranked)} symbols ranked", "INFO")
        
        # Phase 3: Build candidates queue for continuous analysis
        log_execution("[DISCOVERY] Phase 3: Building analysis queue...", "INFO")
        _add_to_discovery_queue(ranked)
        _build_analysis_queue(ranked, batch_size=CONTINUOUS_BATCH_SIZE)
        
        # Update MEMORY for Dashboard integration
        MEMORY["discovery_candidates"] = ranked[:80]
        MEMORY["discovery_last_scan"] = time_module.time()
        MEMORY["discovery_count"] = len(ranked)
        
        scan_time_ms = round((time_module.time() - start_time) * 1000, 1)
        log_execution(f"[DISCOVERY] ✅ Phase 3 Complete: Queue built with {len(ranked)} candidates", "INFO")
        log_execution(f"[DISCOVERY] ========== DISCOVERY SCANNER END ({len(ranked)} candidates) ==========", "INFO")
        
        return ranked
        
    except Exception as e:
        log_execution(f"[DISCOVERY] Error: {traceback.format_exc()}", "ERROR")
        return None


def _discovery_light_scan():
    """
    Phase 1: ULTRA-LIGHT scan - NO API calls
    - Gets symbol list only
    - No ticker calls (avoid rate limiting)
    - No OHLCV
    - Uses symbol name hashing for pseudo-random selection
    """
    debug = {
        "total_symbols": 0,
        "selected": 0,
    }
    
    try:
        symbols = get_usdt_perp_symbols()
        debug["total_symbols"] = len(symbols)
        log_execution(f"[DISCOVERY] Total Futures Loaded: {len(symbols)}", "INFO")
        
        # ULTRA-LIGHT: Just add all symbols with basic scoring
        # Heavy analysis happens in Continuous Analysis anyway
        # This avoids ALL API calls in Discovery
        
        import hashlib
        discovery_results = []
        
        for sym in symbols:
            try:
                # Create a pseudo-random but deterministic score based on symbol name
                # This ensures consistent ordering without API calls
                sym_hash = int(hashlib.md5(sym.encode()).hexdigest()[:8], 16)
                
                # Add all symbols - Continuous Analysis will filter
                discovery_results.append({
                    "symbol": sym,
                    "price": 0,  # No price data yet
                    "volume": 0,
                    "quote_volume": 0,
                    "rel_volume": 1.0,
                    "change_24h": 0,
                    "turnover": 0,
                    "_hash_score": sym_hash % 100,  # For consistent ordering
                })
                debug["selected"] += 1
                
            except Exception as e:
                continue
        
        log_execution(f"[DISCOVERY] ✅ Symbols Loaded: {debug['selected']} (no API calls)", "INFO")
        log_execution(f"[DISCOVERY] ✅ Discovery Results: {len(discovery_results)} symbols", "INFO")
        
        return discovery_results
        
    except Exception as e:
        log_execution(f"[DISCOVERY] Light scan error: {traceback.format_exc()}", "ERROR")
        return []


def _discovery_light_ranking(discovery_data, top_n=80):
    """
    Phase 2: Light ranking - symbol data ONLY
    Based on: symbol hash (for now), then let Continuous Analysis do real ranking
    """
    scored = []
    
    for item in discovery_data:
        try:
            sym = item["symbol"]
            
            # Since we have no real data yet, use symbol characteristics
            # This will be replaced by real data in Continuous Analysis
            
            # Symbol length factor (shorter = more established usually)
            len_score = 20 if len(sym) <= 5 else 15 if len(sym) <= 8 else 10
            
            # Hash-based score for consistent ordering
            hash_score = item.get("_hash_score", 50)
            
            # Base score
            base_score = len_score + hash_score
            
            scored.append({
                "symbol": sym,
                "discovery_score": base_score,
                "turnover": 0,
                "volume": 0,
                "change_24h": 0,
                "price": 0,
                "_len_score": len_score,
                "_hash_score": hash_score,
            })
            
        except Exception as e:
            continue
    
    # Sort by score
    scored.sort(key=lambda x: x["discovery_score"], reverse=True)
    
    # Log top 10
    if scored:
        top10 = scored[:10]
        log_execution(f"[DISCOVERY] Top 10 Initial Candidates:", "INFO")
        for i, s in enumerate(top10):
            log_execution(f"[DISCOVERY]   #{i+1}: {s['symbol']} score={s['discovery_score']:.0f}", "INFO")
    
    log_execution(f"[DISCOVERY] Selected top {min(top_n, len(scored))} symbols for analysis", "INFO")
    
    return scored[:top_n]


def run_continuous_analysis():
    """
    المرحلة الرابعة: التحليل المستمر
    - يحلل 6 عملات في كل دورة (كل 15 ثانية)
    - يستخدم المحركات الموجودة فقط (لا ينشئ محركات جديدة)
    - يدور على جميع المرشحين خلال 20 دقيقة (Round Robin حقيقي)
    - يرفع أولوية العملات القوية
    
    PIPELINE FLOW:
    1. Get candidates from analysis_queue
    2. Run SmartMoneyEngine, MomentumFlowEngine, MarketPhaseClassifier
    3. Run evaluate_liquidity_narrative
    4. Call record_watchlist_entry() -> StrategyEntryFilter
    5. Store in MEMORY["watchlist"]
    """
    import time as time_module
    analysis_id = uuid.uuid4().hex[:8]
    DIAG_CTX.set_analysis_id(analysis_id)
    start_time = time_module.time()
    
    try:
        # PIPELINE TRACE - Start of cycle
        log_execution("[PIPELINE] ========== CONTINUOUS ANALYSIS START ==========", "INFO")
        
        # CRITICAL: Track Watchlist state at start of cycle
        wl = MEMORY.get("watchlist", {})
        wl_start = len(wl)
        
        # Count by state for visibility
        state_counts = {}
        for v in wl.values():
            state = v.get("watchlist_state", "WATCHING")
            state_counts[state] = state_counts.get(state, 0) + 1
        
        log_execution(f"[PIPELINE] ═══════════════════════════════════════", "INFO")
        log_execution(f"[PIPELINE] CYCLE START | Watchlist: {wl_start} | States: {state_counts}", "INFO")
        
        # DYNAMIC ROTATION: Merge fresh Discovery candidates with Watchlist
        # This ensures the Watchlist is NEVER frozen - it continuously updates
        # with better candidates from Discovery even between 20-min cycles
        if wl_start > 0:
            rotation_result = _merge_discovery_with_watchlist()
            if rotation_result > 0:
                log_execution(f"[PIPELINE] DYNAMIC ROTATION: {rotation_result} changes applied", "INFO")
        
        try:
            # Get fresh candidates from queue or rebuild
            queue = _SCANNER_DATA_CACHE["analysis_queue"]
            idx = _SCANNER_DATA_CACHE["analysis_index"]
            queue_size = len(queue)
            remaining = max(0, queue_size - idx)
            
            log_execution(f"[PIPELINE] Queue: {idx}/{queue_size} | Remaining: {remaining}", "INFO")
            
            # If queue is empty or we've gone through all symbols, rebuild
            if not queue or idx >= len(queue):
                log_execution(f"[PIPELINE] ⚠️ Queue exhausted at {idx}/{queue_size} | Watchlist: {wl_start} entries", "WARN")
                
                # Try Discovery candidates first
                discovery_candidates = _get_discovery_candidates()
                if discovery_candidates:
                    _build_analysis_queue(discovery_candidates, batch_size=CONTINUOUS_BATCH_SIZE)
                    log_execution(f"[PIPELINE] 🔄 REBUILD from Discovery ({len(discovery_candidates)} candidates)", "INFO")
                else:
                    # NO DISCOVERY: Build queue from MEMORY["watchlist"] for continuous rotation
                    # This ensures Watchlist NEVER becomes empty during the 20-minute cycle
                    watchlist_queue = _build_watchlist_rotation_queue()
                    if watchlist_queue:
                        _SCANNER_DATA_CACHE["analysis_queue"] = watchlist_queue
                        _SCANNER_DATA_CACHE["analysis_index"] = 0
                        log_execution(f"[PIPELINE] 🔄 REBUILD from Watchlist ({len(watchlist_queue)} symbols) | Watchlist: {wl_start} entries", "INFO")
                    else:
                        # This is the critical issue - if both Discovery and Watchlist are empty
                        log_execution(f"[PIPELINE] ❌ CRITICAL: Both Discovery and Watchlist are empty!", "ERROR")
            
            # Get next batch to analyze
            batch = _get_next_analysis_batch(CONTINUOUS_BATCH_SIZE)
            
            if not batch:
                # No batch available - this is normal if:
                # 1. Watchlist is empty (before first Discovery)
                # 2. All symbols were recently analyzed
                # In this case, we continue monitoring the Watchlist state
                wl_size = len(MEMORY.get("watchlist", {}))
                log_execution(f"[PIPELINE] No batch available | Watchlist monitoring: {wl_size} entries", "INFO")
                
                # Update MEMORY for Dashboard
                MEMORY["watchlist_size"] = wl_size
                MEMORY["watchlist_strategy_valid_count"] = sum(1 for v in MEMORY.get("watchlist", {}).values() if v.get("strategy_valid") == True)
                return []
            
            # PIPELINE TRACE - Batch info
            log_execution(f"[PIPELINE] Batch size: {len(batch)} | Queue index: {idx}/{queue_size} | Symbols: {[b['symbol'] for b in batch]}", "INFO")
            
            analyzed = []
            
            # Watchlist size before this batch
            watchlist_before = len(MEMORY.get("watchlist", {}))
            log_execution(f"[PIPELINE] WATCHLIST before batch: {watchlist_before} entries", "INFO")
            
            for item in batch:
                sym = item["symbol"]
                
                # Skip if already recently analyzed
                if _get_heavy_analysis(sym):
                    # CRITICAL: Update last_update and refresh state for cached symbols
                    # This ensures the watchlist entry remains alive during the analysis cycle
                    if "watchlist" in MEMORY and sym in MEMORY["watchlist"]:
                        MEMORY["watchlist"][sym]["last_update"] = time.time()
                        # Refresh state to WATCHING if it was stale
                        current_state = MEMORY["watchlist"][sym].get("watchlist_state", "WATCHING")
                        if current_state in ("EXPIRED",):
                            MEMORY["watchlist"][sym]["watchlist_state"] = "WATCHING"
                        log_execution(f"[PIPELINE] CACHED: {sym} | State={MEMORY['watchlist'][sym].get('watchlist_state')} | last_update refreshed", "DEBUG")
                    analyzed.append({"symbol": sym, "status": "cached"})
                    continue
                
                try:
                    # Get OHLCV for analysis (100 candles for engines)
                    df = get_ohlcv_safe(sym, 100)
                    if df is None or len(df) < 80:
                        analyzed.append({"symbol": sym, "status": "no_data"})
                        continue
                    
                    # Run existing engines (NO NEW ENGINES)
                    smart_money = SmartMoneyEngine.analyze_smart_money(df)
                    momentum = MomentumFlowEngine.analyze_momentum_flow(df)
                    
                    if DEBUG_CONFIDENCE_TRACE:
                        prefix = f"[DIAG][{analysis_id}]"
                        log_execution(
                            f"{prefix} SmartMoneyEngine for {sym}: banker_pressure={smart_money.get('banker_pressure', 0):.1f}, "
                            f"dominant={smart_money.get('smart_money_dominant', False)}, bias={smart_money.get('institutional_bias', 'NEUTRAL')}",
                            "DEBUG"
                        )
                        log_execution(
                            f"{prefix} MomentumFlowEngine for {sym}: health={momentum.get('momentum_health', 0):.1f}, "
                            f"expansion={momentum.get('trend_expansion', False)}, decay={momentum.get('momentum_decay', False)}",
                            "DEBUG"
                        )
                    
                    # Get Market Phase from MarketPhaseClassifier
                    market_phase = MarketPhaseClassifier.classify(df, momentum, smart_money)
                    
                    # Determine side from smart money bias
                    inst_bias = smart_money.get("institutional_bias", "NEUTRAL")
                    if inst_bias not in ("BUY", "SELL"):
                        inst_bias = momentum.get("flow_bias", "BUY")
                    
                    # Get orderbook and ATR for evaluate_liquidity_narrative
                    ob = get_orderbook_cached(sym, limit=10)
                    atr = compute_atr(df).iloc[-1] if len(df) > 14 else df['close'].iloc[-1] * 0.01
                    
                    # Use evaluate_liquidity_narrative (same as reference bot)
                    narrative, nscore = evaluate_liquidity_narrative(df, ob, atr, inst_bias)
                    
                    # NOW extract structure data from narrative (AFTER narrative is defined)
                    # ========== FORENSIC FIX: Add tp_distance and sl_distance for RF validation ==========
                    # The StrategyEntryFilter._validate_rf() expects tp_distance and sl_distance
                    # to calculate proper RF ratio. Without these, RF validation always fails.
                    entry_price = df['close'].iloc[-1]
                    tp_distance = atr * 2  # Default
                    sl_distance = atr * 1.5  # Default
                    
                    # Try to get better TP/SL from RFEngine
                    try:
                        rf_data = RFEngine(20, 3.5).compute(df)
                        if rf_data.get("signal") == inst_bias or rf_data.get("triggered"):
                            if inst_bias == "BUY" and rf_data.get("l_band"):
                                tp_distance = max(tp_distance, rf_data.get("h_band", entry_price) - entry_price)
                                sl_distance = max(sl_distance, entry_price - rf_data.get("l_band", entry_price))
                            elif inst_bias == "SELL" and rf_data.get("h_band"):
                                tp_distance = max(tp_distance, entry_price - rf_data.get("l_band", entry_price))
                                sl_distance = max(sl_distance, rf_data.get("h_band", entry_price) - entry_price)
                    except Exception:
                        pass  # Keep defaults if RFEngine fails
                    
                    structure_data = {
                        "bos": narrative.get("bos", False),
                        "choch": narrative.get("choch_bos", False),
                        "mss": narrative.get("retest", False),  # Retest implies MSS
                        # Add TP/SL distances for RF validation
                        "tp_distance": tp_distance,
                        "sl_distance": sl_distance
                    }
                    
                    # Extract volume data from momentum
                    volume_data = {
                        "ratio": 1.0,  # Default
                        "expansion": momentum.get("trend_expansion", False)
                    }
                    
                    # Calculate priority based on engines
                    priority = 50  # Base priority
                    
                    # Boost for institutional dominance
                    if smart_money.get("smart_money_dominant", False):
                        priority += 20
                        if smart_money.get("institutional_bias") == "BUY":
                            priority += 10
                        elif smart_money.get("institutional_bias") == "SELL":
                            priority += 10
                    
                    # Boost for momentum expansion
                    if momentum.get("trend_expansion", False):
                        priority += 15
                    
                    # Boost for accumulation/distribution strength
                    accum = smart_money.get("accumulation_strength", 0)
                    dist = smart_money.get("distribution_risk", 0)
                    if accum > 60:
                        priority += 10
                    if dist > 70:
                        priority += 10
                    
                    # Calculate adjusted score (0-10 scale)
                    entry_score = min(10, max(1, nscore + priority / 20))
                    
                    # Cache heavy analysis (BEFORE watchlist for tracing)
                    _set_heavy_analysis(sym, {
                        "smart_money": smart_money,
                        "momentum": momentum,
                        "market_phase": market_phase,
                        "structure_data": structure_data,
                        "volume_data": volume_data,
                        "priority": priority,
                        "discovery_score": item.get("score", 0),
                        "narrative": narrative,
                        "entry_score": entry_score,
                        "timestamp": time_module.time()
                    })
                    
                    # PIPELINE TRACE LOG
                    log_execution(f"[PIPELINE TRACE] {sym} | SmartMoney={inst_bias} | Mom={momentum.get('direction','N/A')} | Phase={market_phase} | Narrative={narrative.get('classification','N/A')} | Score={entry_score:.1f}", "INFO")
                    
                    # FORENSIC: Create lifecycle ID for this candidate (with safety)
                    try:
                        lifecycle_id, _ = create_forensic_record(sym, inst_bias)
                        DIAG_CTX.set_lifecycle_id(lifecycle_id)
                    except Exception as forensic_err:
                        log_execution(f"[FORENSIC ERROR] Failed to create lifecycle for {sym}: {forensic_err}", "WARN")
                        lifecycle_id = f"{sym}_{int(time.time())}"  # Fallback
                    
                    # Record to watchlist WITH ALL ENGINE DATA
                    # StrategyEntryFilter will be run HERE using existing engine outputs
                    try:
                        record_watchlist_entry(
                            symbol=sym,
                            side=inst_bias,
                            narrative=narrative,
                            score=entry_score,
                            smart_money=smart_money,
                            momentum=momentum,
                            market_phase=market_phase,
                            structure_data=structure_data,
                            volume_data=volume_data,
                            df=df,  # <-- تمرير df الحالي
                            lifecycle_id=lifecycle_id
                        )
                    except Exception as entry_err:
                        import traceback
                        log_execution(f"[PIPELINE ERROR] {sym} failed to add to watchlist: {entry_err}", "ERROR")
                        log_execution(f"[PIPELINE ERROR] {sym} traceback: {traceback.format_exc()}", "ERROR")
                        continue  # Continue to next symbol, don't break pipeline
                    
                    log_execution(f"[PIPELINE TRACE] ✅ {sym} added to WATCHLIST | strategy_valid will be set by StrategyEntryFilter", "INFO")
                    
                    analyzed.append({
                        "symbol": sym,
                        "status": "analyzed",
                        "priority": priority,
                        "smart_money": inst_bias,
                        "momentum": momentum.get("flow_bias", "NEUTRAL")
                    })
                    
                except Exception as e:
                    analyzed.append({"symbol": sym, "status": "error", "error": str(e)})
                    log_execution(f"[PIPELINE ERROR] {sym} failed: {e}", "ERROR")
                    continue
            
            # PIPELINE TRACE - End of batch
            watchlist_after = len(MEMORY.get("watchlist", {}))
            watchlist_added = watchlist_after - watchlist_before
            
            # Count strategy_valid entries
            strategy_valid_count = sum(1 for v in MEMORY.get("watchlist", {}).values() if v.get("strategy_valid") == True)
            
            # Count actions in Watchlist
            action_counts = {"READY": 0, "WATCH": 0, "SKIP": 0}
            for v in MEMORY.get("watchlist", {}).values():
                action = v.get("action", "SKIP")
                action_counts[action] = action_counts.get(action, 0) + 1
            
            # Queue status
            queue_size = len(_SCANNER_DATA_CACHE["analysis_queue"])
            queue_idx = _SCANNER_DATA_CACHE["analysis_index"]
            queue_remaining = max(0, queue_size - queue_idx)
            
            log_execution(f"[PIPELINE] ========== CONTINUOUS ANALYSIS END ==========", "INFO")
            log_execution(f"[PIPELINE] Batch: Analyzed={len(analyzed)} | Watchlist Added={watchlist_added}", "INFO")
            log_execution(f"[PIPELINE] WATCHLIST: Before={watchlist_before} | After={watchlist_after} | StrategyValid={strategy_valid_count}", "INFO")
            log_execution(f"[PIPELINE] ACTION DISTRIBUTION: READY={action_counts['READY']} | WATCH={action_counts['WATCH']} | SKIP={action_counts['SKIP']}", "INFO")
            log_execution(f"[PIPELINE] QUEUE: {queue_idx}/{queue_size} | Remaining={queue_remaining}", "INFO")
            
            # CRITICAL: Verify watchlist integrity after batch
            final_wl = MEMORY.get("watchlist", {})
            final_watchlist_size = len(final_wl)
            
            # Count final states
            final_state_counts = {}
            for v in final_wl.values():
                state = v.get("watchlist_state", "WATCHING")
                final_state_counts[state] = final_state_counts.get(state, 0) + 1
            
            if final_watchlist_size == 0 and watchlist_before > 0:
                log_execution(f"[PIPELINE] ❌ CRITICAL: Watchlist was cleared! Before={watchlist_before} | After={final_watchlist_size}", "ERROR")
            else:
                log_execution(f"[PIPELINE] CYCLE END | Watchlist: {final_watchlist_size} entries | States: {final_state_counts}", "INFO")
            
            # Update MEMORY with analyzed count
            MEMORY["continuous_analyzed"] = analyzed
            MEMORY["continuous_analysis_index"] = _SCANNER_DATA_CACHE["analysis_index"]
            MEMORY["continuous_queue_size"] = len(_SCANNER_DATA_CACHE["analysis_queue"])
            MEMORY["watchlist_size"] = final_watchlist_size
            MEMORY["watchlist_strategy_valid_count"] = strategy_valid_count
            
            scan_time_ms = round((time_module.time() - start_time) * 1000, 1)
            log_execution(f"[CONTINUOUS] Batch done in {scan_time_ms}ms", "INFO")
            
            # ========== FORENSIC: Print Pipeline Health Report ==========
            # NEVER let forensic break the pipeline!
            try:
                # Update health metrics
                _PIPELINE_HEALTH["candidates_discovered"] += len(analyzed)
                _PIPELINE_HEALTH["candidates_added"] += len([a for a in analyzed if a.get("status") == "analyzed"])
                _PIPELINE_HEALTH["candidates_waiting"] = len(MEMORY.get("watchlist", {}))
                
                # Print pipeline health report every 3 cycles
                if _PIPELINE_HEALTH["cycle_count"] % 3 == 0:
                    print_pipeline_health_report()
            except Exception as forensic_err:
                log_execution(f"[FORENSIC ERROR] Health report failed: {forensic_err}", "WARN")
            
            return analyzed
            
        except Exception as e:
            log_execution(f"[CONTINUOUS] Analysis error: {traceback.format_exc()}", "ERROR")
            return []
    finally:
        DIAG_CTX.clear()


# ========== RF SCANNER ==========
def get_usdt_perp_symbols():
    try:
        ex.load_markets()
        markets = ex.markets
        symbols = []
        for s in markets:
            if "USDT" in s and markets[s].get('swap') and markets[s].get('active'):
                clean = s.replace(":USDT", "")
                symbols.append(clean)
        # FIX: Return ALL supported USDT futures contracts (no limit)
        return symbols
    except Exception as e:
        log_execution(f"Failed to load markets: {e}", "ERROR")
        return [DEFAULT_SYMBOL]

def rf_proximity_score(rf, adx_val, vol_ok, rsi_val, atr_pct):
    dist = abs(rf["distance"]) if rf["distance"] else 1.0
    proximity = max(0.0, 1.0 - (dist / 0.015))
    if adx_val < 18:
        trend = 0.2
    elif 18 <= adx_val <= 30:
        trend = 1.0
    elif 30 < adx_val <= 40:
        trend = 0.6
    else:
        trend = 0.2
    if 30 <= rsi_val <= 70:
        rsi_score = 0.5
    elif 20 <= rsi_val < 30 or 70 < rsi_val <= 80:
        rsi_score = 0.3
    else:
        rsi_score = 0.0
    vol_score = 1.0 if vol_ok else 0.0
    vol_boost = 0.3 if 0.5 <= atr_pct <= 2.0 else 0.0
    trigger_boost = 1.2 if rf["triggered"] else 0.0
    score = (proximity * 0.35) + (trend * 0.25) + (vol_score * 0.15) + (rsi_score * 0.1) + (vol_boost * 0.05) + trigger_boost
    return float(score)

def scan_market_rf(top_n=40):
    symbols = get_usdt_perp_symbols()
    if not symbols:
        return []
    rf_engine = RFEngine(period=20, multiplier=3.5)
    results = []
    for sym in symbols[:150]:
        try:
            df = get_ohlcv_safe(sym, 120, htf=False)
            if df is None or not validate_dataframe(df, 100):
                continue
            try:
                atr_series = compute_atr(df, 14)
                adx_series = compute_adx(df, 14)
                rsi_series = compute_rsi(df, 14)
                atr_val = float(atr_series.iloc[-1])
                adx_val = float(adx_series.iloc[-1])
                rsi_val = float(rsi_series.iloc[-1])
                if rsi_val == 0 or rsi_val is None or math.isnan(rsi_val):
                    continue
                if atr_val == 0 or atr_val is None or math.isnan(atr_val):
                    continue
                if adx_val is None or math.isnan(adx_val):
                    adx_val = 20.0
                atr_pct = (atr_val / df['close'].iloc[-1]) * 100 if df['close'].iloc[-1] > 0 else 0
            except Exception:
                continue
            rf = rf_engine.compute(df)
            if rf["signal"] is None and abs(rf.get("distance", 1.0)) > 0.015:
                continue
            avg_vol = df['volume'].iloc[-20:].mean()
            vol_ok = df['volume'].iloc[-1] >= avg_vol * 0.7
            atr_pct = (atr_val / df['close'].iloc[-1]) * 100 if df['close'].iloc[-1] > 0 else 0
            score = rf_proximity_score(rf, adx_val, vol_ok, rsi_val, atr_pct)
            if score < 0.3:
                continue
            if rf["triggered"]:
                status = "TRIGGERED"
            elif score >= 0.6:
                status = "READY"
            else:
                status = "PROXIMITY"
            results.append({
                "symbol": sym,
                "score": round(score, 3),
                "rf_signal": rf["signal"],
                "rf_triggered": rf["triggered"],
                "rf_distance": round(rf.get("distance", 0), 4),
                "adx": round(adx_val, 1),
                "rsi": round(rsi_val, 1),
                "atrp": round(atr_pct, 2),
                "status": status
            })
        except Exception:
            continue
    results = sorted(results, key=lambda x: x["score"], reverse=True)
    return results[:top_n]

# ========== SMART SCANNER v2 ==========
def smart_scanner_v2():
    symbols = get_usdt_perp_symbols()[:150]
    buy_candidates = []
    sell_candidates = []
    for sym in symbols:
        try:
            df = get_ohlcv_safe(sym, 150)
            if df is None or len(df) < 100:
                continue
            price = df['close'].iloc[-1]
            rf_engine = RFEngine(period=20, multiplier=3.5)
            rf = rf_engine.compute(df)
            if rf["distance"] is None:
                continue
            rf_prox = abs(rf["distance"])
            vol_ma = df['volume'].iloc[-21:-1].mean()
            if df['volume'].iloc[-1] < 0.5 * vol_ma:
                continue
            atr_val = compute_atr(df).iloc[-1]
            atr_pct = (atr_val / price) * 100 if price > 0 else 0
            if atr_pct < 0.2:
                continue
            liquidity_ctx = detect_liquidity_context(df, lookback=10)
            supports, resistances = get_clustered_zones(df, lookback=120, cluster_pct=0.002)
            zone_ctx = detect_zone_context(price, supports, resistances, threshold=0.003)
            structure_ctx = detect_structure_shift(df)
            rejection_buy = candle_rejection(df, "BUY")
            rejection_sell = candle_rejection(df, "SELL")
            vol_spike_flag = volume_spike(df)
            location = compute_location(df, price, "BUY")

            smart_money = SmartMoneyEngine.analyze_smart_money(df)
            momentum = MomentumFlowEngine.analyze_momentum_flow(df)

            score_mod_buy = 0
            score_mod_sell = 0

            if smart_money["smart_money_dominant"]:
                if smart_money["institutional_bias"] == "BUY":
                    score_mod_buy += 2.5
                elif smart_money["institutional_bias"] == "SELL":
                    score_mod_sell += 2.5
            if smart_money["distribution_risk"] > 70:
                score_mod_sell += 1.5
                score_mod_buy -= 2.0
            if smart_money["accumulation_strength"] > 60:
                score_mod_buy += 1.5
                score_mod_sell -= 2.0
            if smart_money["retail_euphoria"]:
                score_mod_buy -= 1.5
                score_mod_sell -= 1.5

            if momentum["trend_expansion"]:
                if momentum["flow_bias"] == "BUY":
                    score_mod_buy += 2.0
                elif momentum["flow_bias"] == "SELL":
                    score_mod_sell += 2.0
            if momentum["momentum_decay"]:
                score_mod_buy -= 1.5
                score_mod_sell -= 1.5
            if momentum["exhaustion_risk"] > 70:
                score_mod_buy -= 2.0
                score_mod_sell -= 2.0
            if momentum["climax_risk"] > 70:
                score_mod_buy -= 1.5
                score_mod_sell -= 1.5
            if momentum["greed_state"]:
                score_mod_buy -= 1.0
                score_mod_sell -= 1.0

            base_score_buy = 0
            if liquidity_ctx == "sell_side_taken":
                base_score_buy += 2
            if zone_ctx["near_support"]:
                base_score_buy += 2
            if structure_ctx == "bullish_shift":
                base_score_buy += 1.5
            if rf_prox < 0.0015:
                base_score_buy += 2
            elif rf_prox < 0.003:
                base_score_buy += 1
            if rejection_buy:
                base_score_buy += 1.5
            if vol_spike_flag:
                base_score_buy += 1

            base_score_sell = 0
            if liquidity_ctx == "buy_side_taken":
                base_score_sell += 2
            if zone_ctx["near_resistance"]:
                base_score_sell += 2
            if structure_ctx == "bearish_shift":
                base_score_sell += 1.5
            if rf_prox < 0.0015:
                base_score_sell += 2
            elif rf_prox < 0.003:
                base_score_sell += 1
            if rejection_sell:
                base_score_sell += 1.5
            if vol_spike_flag:
                base_score_sell += 1

            final_score_buy = base_score_buy + score_mod_buy
            final_score_sell = base_score_sell + score_mod_sell

            if final_score_buy >= 5:
                buy_candidates.append({
                    "symbol": sym,
                    "score": round(final_score_buy, 2),
                    "rf_prox": round(rf_prox*100, 3),
                    "liquidity": liquidity_ctx,
                    "zone": zone_ctx,
                    "structure": structure_ctx,
                    "rejection": rejection_buy,
                    "volume_spike": vol_spike_flag,
                    "location": location,
                    "smart_money": {
                        "bias": smart_money["institutional_bias"],
                        "bias_detailed": smart_money.get("institutional_bias_detailed", "NEUTRAL"),
                        "dominant": smart_money["smart_money_dominant"],
                        "distribution_risk": round(smart_money["distribution_risk"], 1),
                        "accumulation": round(smart_money["accumulation_strength"], 1)
                    },
                    "momentum": {
                        "expansion": momentum["trend_expansion"],
                        "decay": momentum["momentum_decay"],
                        "exhaustion_risk": round(momentum["exhaustion_risk"], 1),
                        "greed": momentum["greed_state"]
                    }
                })
            if final_score_sell >= 5:
                sell_candidates.append({
                    "symbol": sym,
                    "score": round(final_score_sell, 2),
                    "rf_prox": round(rf_prox*100, 3),
                    "liquidity": liquidity_ctx,
                    "zone": zone_ctx,
                    "structure": structure_ctx,
                    "rejection": rejection_sell,
                    "volume_spike": vol_spike_flag,
                    "location": compute_location(df, price, "SELL"),
                    "smart_money": {
                        "bias": smart_money["institutional_bias"],
                        "bias_detailed": smart_money.get("institutional_bias_detailed", "NEUTRAL"),
                        "dominant": smart_money["smart_money_dominant"],
                        "distribution_risk": round(smart_money["distribution_risk"], 1),
                        "accumulation": round(smart_money["accumulation_strength"], 1)
                    },
                    "momentum": {
                        "expansion": momentum["trend_expansion"],
                        "decay": momentum["momentum_decay"],
                        "exhaustion_risk": round(momentum["exhaustion_risk"], 1),
                        "greed": momentum["greed_state"]
                    }
                })
        except Exception as e:
            continue
    buy_sorted = sorted(buy_candidates, key=lambda x: x["score"], reverse=True)[:10]
    sell_sorted = sorted(sell_candidates, key=lambda x: x["score"], reverse=True)[:10]
    return buy_sorted, sell_sorted

# ========== INSTITUTIONAL LIQUIDITY NARRATIVE ENGINE ==========
# ========== INSTITUTIONAL MARKET SCANNER ==========
# Scanner Principles:
# 1. INCREMENTAL - reuses previous state, only re-analyzes changed symbols
# 2. NO DUPLICATE - uses existing engine results, doesn't recalculate
# 3. CONTEXT-AWARE - Opportunity Score uses multipliers for signal combinations
# 4. PRODUCTION-READY - stateless on restart, aging, decay, dynamic replacement

# Module-level state (cleared on bot restart via reset)
_INSTITUTIONAL_SCANNER_STATE = {
    "last_discovery": 0,
    "last_full_scan": 0,
    "discovery_data": {},
    "liquidity_ranked": [],
    "symbol_metadata": {},
    "watchlist": {"BUY": [], "SELL": []},
    "dirty_symbols": set(),
    "metrics": {
        "discovery_symbols": 0,
        "dirty_symbols": 0,
        "deep_analysis": 0,
        "buy_candidates": 0,
        "sell_candidates": 0,
        "avg_opportunity_score": 0,
        "scan_time_ms": 0,
        "api_calls": 0,
        "cache_hit_ratio": 0
    }
}

def _reset_scanner_state():
    """Reset scanner state for clean startup - called on bot restart"""
    global _INSTITUTIONAL_SCANNER_STATE
    _INSTITUTIONAL_SCANNER_STATE = {
        "last_discovery": 0,
        "last_full_scan": 0,
        "discovery_data": {},
        "liquidity_ranked": [],
        "symbol_metadata": {},
        "watchlist": {"BUY": [], "SELL": []},
        "dirty_symbols": set(),
        "metrics": {
            "discovery_symbols": 0,
            "dirty_symbols": 0,
            "deep_analysis": 0,
            "buy_candidates": 0,
            "sell_candidates": 0,
            "avg_opportunity_score": 0,
            "scan_time_ms": 0,
            "api_calls": 0,
            "cache_hit_ratio": 0
        }
    }
    log_execution("[INST_SCANNER] State reset for clean startup", "INFO")

def _detect_changes(prev_data, curr_data):
    """Detect which symbols have significant changes - returns dirty set"""
    dirty = set()
    for sym, curr in curr_data.items():
        prev = prev_data.get(sym, {})
        # Volume change > 30%
        prev_vol = prev.get("rel_volume", 1)
        curr_vol = curr.get("rel_volume", 1)
        if abs(curr_vol - prev_vol) / max(prev_vol, 0.1) > 0.3:
            dirty.add(sym)
        # Velocity change > 50%
        prev_vel = prev.get("velocity", 0)
        curr_vel = curr.get("velocity", 0)
        if abs(curr_vel - prev_vel) > 0.5:
            dirty.add(sym)
        # New symbol (not in previous)
        if sym not in prev_data:
            dirty.add(sym)
    # Removed symbols
    for sym in prev_data:
        if sym not in curr_data:
            dirty.add(sym)  # Mark as dirty to remove from watchlist
    return dirty


def _phase1_market_discovery():
    """Phase 1: Market Discovery - Lightweight scan of ALL futures symbols"""
    import time
    now = time.time()
    
    if now - _INSTITUTIONAL_SCANNER_STATE["last_discovery"] < 300:
        return _INSTITUTIONAL_SCANNER_STATE["discovery_data"]
    
    try:
        symbols = get_usdt_perp_symbols()
        discovery_data = []
        
        for sym in symbols:
            try:
                ticker = get_ticker_safe(sym)
                if not ticker or ticker <= 0:
                    continue
                
                df = get_ohlcv_safe(sym, 20, htf=False)
                if df is None or len(df) < 15:
                    continue
                
                price = df['close'].iloc[-1]
                atr = compute_atr(df).iloc[-1] if len(df) >= 14 else 0
                atr_pct = (atr / price * 100) if price > 0 else 0
                
                vol_now = df['volume'].iloc[-1]
                vol_avg = df['volume'].iloc[-20:].mean() if len(df) >= 20 else vol_now
                rel_vol = vol_now / vol_avg if vol_avg > 0 else 1
                
                change_24h = 0
                if len(df) >= 96:
                    change_24h = ((df['close'].iloc[-1] - df['open'].iloc[-96]) / df['open'].iloc[-96] * 100) if df['open'].iloc[-96] > 0 else 0
                
                velocity = 0
                if len(df) >= 5:
                    price_change = df['close'].iloc[-1] - df['close'].iloc[-5]
                    velocity = (price_change / df['close'].iloc[-5] * 100) if df['close'].iloc[-5] > 0 else 0
                
                discovery_data.append({
                    "symbol": sym,
                    "price": price,
                    "atr": atr,
                    "atr_pct": atr_pct,
                    "volume": vol_now,
                    "avg_volume": vol_avg,
                    "rel_volume": rel_vol,
                    "change_24h": change_24h,
                    "velocity": velocity
                })
            except:
                continue
        
        _INSTITUTIONAL_SCANNER_STATE["last_discovery"] = now
        _INSTITUTIONAL_SCANNER_STATE["discovery_data"] = discovery_data
        log_execution(f"[INST_SCANNER] Discovery: {len(discovery_data)} symbols", "INFO")
        return discovery_data
        
    except Exception as e:
        log_execution(f"[INST_SCANNER] Discovery error: {e}", "ERROR")
        return []


def _phase2_liquidity_ranking(discovery_data, top_n=80):
    """
    Phase 2: Liquidity Ranking
    - INCREMENTAL: Only re-scores dirty/changed symbols
    - Returns full ranking but only deeply analyzes dirty ones in Phase 3
    """
    if not discovery_data:
        return []
    
    # Convert discovery list to dict for easy access
    curr_data = {d["symbol"]: d for d in discovery_data}
    prev_data = {d["symbol"]: d for d in _INSTITUTIONAL_SCANNER_STATE.get("discovery_data", [])}
    
    # Detect changed symbols
    dirty = _detect_changes(prev_data, curr_data)
    _INSTITUTIONAL_SCANNER_STATE["dirty_symbols"] = dirty
    
    # Keep previous rankings but update dirty ones
    prev_ranked = {r["symbol"]: r for r in _INSTITUTIONAL_SCANNER_STATE.get("liquidity_ranked", [])}
    
    scored = []
    for sym, item in curr_data.items():
        try:
            rel_vol = item.get("rel_volume", 1)
            vol_pts = 30 if rel_vol >= 2.0 else 25 if rel_vol >= 1.5 else 20 if rel_vol >= 1.2 else 15 if rel_vol >= 1.0 else 5
            
            vol_now = item.get("volume", 0)
            vol_avg = item.get("avg_volume", 1)
            vol_exp = vol_now / vol_avg if vol_avg > 0 else 1
            exp_pts = 15 if vol_exp >= 2.0 else 12 if vol_exp >= 1.5 else 8 if vol_exp >= 1.2 else 3
            
            atr_pct = item.get("atr_pct", 0)
            atr_pts = 15 if atr_pct >= 3.0 else 12 if atr_pct >= 2.0 else 8 if atr_pct >= 1.0 else 3
            
            velocity = abs(item.get("velocity", 0))
            vel_pts = 20 if velocity >= 2.0 else 15 if velocity >= 1.0 else 10 if velocity >= 0.5 else 5
            
            change = abs(item.get("change_24h", 0))
            brk_pts = 10 if change >= 10 else 7 if change >= 5 else 4 if change >= 2 else 1
            
            fresh_pts = 10 if rel_vol >= 3.0 else 7 if rel_vol >= 2.0 else 4 if rel_vol >= 1.5 else 0
            
            total_score = vol_pts + exp_pts + atr_pts + vel_pts + brk_pts + fresh_pts
            
            scored.append({
                "symbol": sym,
                "liquidity_score": total_score,
                "rel_volume": rel_vol,
                "velocity": velocity,
                "atr_pct": atr_pct,
                "dirty": sym in dirty  # Mark dirty for Phase 3
            })
        except:
            continue
    
    scored.sort(key=lambda x: x["liquidity_score"], reverse=True)
    _INSTITUTIONAL_SCANNER_STATE["liquidity_ranked"] = scored[:top_n]
    _INSTITUTIONAL_SCANNER_STATE["discovery_data"] = discovery_data
    log_execution(f"[INST_SCANNER] Ranked {len(scored[:top_n])} symbols, {len(dirty)} dirty", "INFO")
    return scored[:top_n]


def _phase3_institutional_filtering(liquidity_ranked):
    """
    Phase 3: Institutional Filtering
    - INCREMENTAL: Only deeply analyzes DIRTY symbols (changed since last scan)
    - CLEAN symbols: reuse cached data from symbol_metadata
    - Sources: SmartMoneyEngine, MomentumFlowEngine ONLY (no recalculation)
    """
    if not liquidity_ranked:
        return []

    dirty = _INSTITUTIONAL_SCANNER_STATE.get("dirty_symbols", set())
    prev_metadata = _INSTITUTIONAL_SCANNER_STATE.get("symbol_metadata", {})
    filtered = []
    
    for item in liquidity_ranked:
        try:
            sym = item["symbol"]
            is_dirty = sym in dirty
            
            # Check if already in watchlist (prefer to keep if stable)
            was_in_watchlist = sym in [w["symbol"] for w in _INSTITUTIONAL_SCANNER_STATE["watchlist"]["BUY"] + 
                                       _INSTITUTIONAL_SCANNER_STATE["watchlist"]["SELL"]]
            
            # Only analyze deeply if dirty OR new AND in top 30
            rank = liquidity_ranked.index(item)
            needs_analysis = is_dirty or rank < 30
            
            if needs_analysis and is_dirty:
                # Deep analysis - call existing engines
                df = get_ohlcv_safe(sym, 150)
                if df is None or len(df) < 100:
                    continue
                
                price = df['close'].iloc[-1]
                
                # Use EXISTING engines only - NO recalculation
                smart_money = SmartMoneyEngine.analyze_smart_money(df)
                momentum = MomentumFlowEngine.analyze_momentum_flow(df)
                
                # Get zones
                supports, _ = get_clustered_zones(df, lookback=120, cluster_pct=0.002)
                zone_price = supports[-1]["level"] if supports else 0
                zone_score = 85 if zone_price and abs(price - zone_price) / price < 0.003 else 50
                
                # Get structure from momentum (MSS is already calculated)
                structure = momentum.get("structure_shift", None)
                mss_signal = momentum.get("mss_signal", None)
                
                # Get liquidity from momentum
                liq_ctx = momentum.get("liquidity_context", "neutral")
                
                # Get momentum direction (already calculated)
                mom_direction = momentum.get("direction", "NEUTRAL")
                
                # Build signals from engine results (ONLY using what exists in engines)
                signals = {
                    # From MomentumFlowEngine
                    "MOMENTUM_DIRECTION": momentum.get("direction", "NEUTRAL"),
                    "MOMENTUM_EXPANSION": momentum.get("trend_expansion", False),
                    "MOMENTUM_DECAY": momentum.get("momentum_decay", False),
                    "CONTINUATION_STRENGTH": momentum.get("continuation_strength", 50),
                    "FLOW_BIAS": momentum.get("flow_bias", "NEUTRAL"),
                    
                    # From SmartMoneyEngine
                    "SMART_MONEY_DOMINANT": smart_money.get("smart_money_dominant", False),
                    "SMART_MONEY_BIAS": smart_money.get("institutional_bias", "NEUTRAL"),
                    "ACCUMULATION": smart_money.get("accumulation_strength", 0),
                    "DISTRIBUTION_RISK": smart_money.get("distribution_risk", 0),
                    "BANKER_PRESSURE": smart_money.get("banker_pressure", 50),
                    
                    # Derived signals
                    "FRESH_DEMAND": zone_score >= 85 and zone_price < price,
                    "FRESH_SUPPLY": zone_score >= 85 and zone_price > price,
                    "VOLUME_ZONE_BUY": smart_money.get("accumulation_strength", 0) > 60,
                    "VOLUME_ZONE_SELL": smart_money.get("distribution_risk", 0) > 70,
                }
                
                # Cache metadata for next iteration
                _INSTITUTIONAL_SCANNER_STATE["symbol_metadata"][sym] = {
                    "signals": signals,
                    "smart_money": {"dominant": smart_money.get("smart_money_dominant", False), 
                                   "bias": smart_money.get("institutional_bias", "NEUTRAL"),
                                   "accumulation": smart_money.get("accumulation_strength", 0),
                                   "distribution_risk": smart_money.get("distribution_risk", 0),
                                   "banker_pressure": smart_money.get("banker_pressure", 50)},
                    "momentum": {"direction": mom_direction,
                                 "expansion": momentum.get("trend_expansion", False),
                                 "decay": momentum.get("momentum_decay", False),
                                 "strength": momentum.get("continuation_strength", 50)},
                    "zone_score": zone_score,
                    "structure": structure,
                    "liquidity_context": liq_ctx
                }
            else:
                # Reuse cached data
                cached = prev_metadata.get(sym, {})
                signals = cached.get("signals", {})
                smart_money = cached.get("smart_money", {})
                momentum = cached.get("momentum", {})
                zone_score = cached.get("zone_score", 50)
                structure = cached.get("structure", None)
                liq_ctx = cached.get("liquidity_context", "neutral")
            
            # Count institutional signals (using engine data)
            # BUY signals: Momentum expansion + Smart money dominant + Fresh demand
            buy_sig_count = sum([
                signals.get("MOMENTUM_EXPANSION") and signals.get("FLOW_BIAS") in ("BUY", "STRONG_BUY"),
                signals.get("SMART_MONEY_DOMINANT") and signals.get("SMART_MONEY_BIAS") in ("BUY", "STRONG_BUY"),
                signals.get("FRESH_DEMAND"),
                signals.get("VOLUME_ZONE_BUY"),
                signals.get("MOMENTUM_DECAY") == False,  # No decay is positive
            ])
            
            # SELL signals: Momentum expansion + Smart money dominant + Fresh supply
            sell_sig_count = sum([
                signals.get("MOMENTUM_EXPANSION") and signals.get("FLOW_BIAS") in ("SELL", "STRONG_SELL"),
                signals.get("SMART_MONEY_DOMINANT") and signals.get("SMART_MONEY_BIAS") in ("SELL", "STRONG_SELL"),
                signals.get("FRESH_SUPPLY"),
                signals.get("VOLUME_ZONE_SELL"),
                signals.get("MOMENTUM_DECAY") == False,
            ])
            
            if buy_sig_count >= 2 or sell_sig_count >= 2:
                filtered.append({
                    "symbol": sym,
                    "side": "BUY" if buy_sig_count > sell_sig_count else "SELL",
                    "signals": signals,
                    "buy_signal_count": buy_sig_count,
                    "sell_signal_count": sell_sig_count,
                    "smart_money": _INSTITUTIONAL_SCANNER_STATE["symbol_metadata"].get(sym, {}).get("smart_money", {}),
                    "momentum": _INSTITUTIONAL_SCANNER_STATE["symbol_metadata"].get(sym, {}).get("momentum", {}),
                    "zone_score": zone_score,
                    "structure": structure,
                    "liquidity_context": liq_ctx,
                    "liquidity_score": item["liquidity_score"],
                    "rel_volume": item["rel_volume"]
                })
        except:
            continue

    log_execution(f"[INST_SCANNER] Filtered: {len(filtered)} symbols", "INFO")
    return filtered


def _phase4_institutional_opportunity_score(filtered_symbols):
    """
    Phase 4: Context-Aware Opportunity Score
    - NOT simple addition: uses multipliers for signal combinations
    - Institutional movement requires MULTIPLE aligned signals, not just sum
    """
    scored = []
    for item in filtered_symbols:
        try:
            base_score = 0
            multipliers = []
            
            signals = item.get("signals", {})
            smart_money = item.get("smart_money", {})
            momentum = item.get("momentum", {})
            side = item.get("side", "BUY")
            
            # === ZONE QUALITY (Base 0-25, Multiplier 1.0-1.5) ===
            zone_score = item.get("zone_score", 50)
            zone_base = min(25, zone_score * 0.25)
            zone_mult = 1.3 if zone_score >= 85 else 1.1 if zone_score >= 70 else 1.0
            
            # === STRUCTURE (Base 0-30, triggers multiplier) ===
            # Structure is inferred from momentum + smart money alignment
            sm_bias = smart_money.get("bias", "NEUTRAL")
            mom_bias = momentum.get("flow_bias", "NEUTRAL")
            structure_base = 0
            if (sm_bias == side or sm_bias == "STRONG_" + side) and (mom_bias == side or mom_bias == "STRONG_" + side):
                structure_base = 30
                multipliers.append(("structure_aligned", 1.4))
            
            # === SMART MONEY (Base 0-30, major multiplier) ===
            sm_base = 0
            if smart_money.get("smart_money_dominant"):
                sm_base += 15
                multipliers.append(("smart_money_dominant", 1.3))
            if sm_bias == side or sm_bias == "STRONG_" + side:
                sm_base += 15
                multipliers.append(("bias_aligned", 1.2))
            
            # === MOMENTUM (Base 0-20, combination multiplier) ===
            mom_base = 0
            mom_dir = momentum.get("direction", "NEUTRAL")
            if mom_dir == side.upper()[:4] or (side == "BUY" and mom_dir == "BULLISH") or (side == "SELL" and mom_dir == "BEARISH"):
                mom_base = 20
                multipliers.append(("momentum_aligned", 1.2))
            elif momentum.get("trend_expansion", False):
                mom_base = 10
            
            # === LIQUIDITY (Base 0-15, validates signal) ===
            # Liquidity sweep detected via accumulation/distribution strength
            liq_base = 0
            accum = smart_money.get("accumulation", 0)
            dist = smart_money.get("distribution_risk", 0)
            if (side == "BUY" and accum > 70) or (side == "SELL" and dist > 70):
                liq_base = 15
                multipliers.append(("liquidity_strength", 1.15))
            
            # === VOLUME (Base 0-10) ===
            rel_vol = item.get("rel_volume", 1)
            vol_base = 10 if rel_vol >= 2.0 else 7 if rel_vol >= 1.5 else 4 if rel_vol >= 1.2 else 0
            
            # === SIGNAL COUNT (Base + Bonus) ===
            sig_key = "buy_signal_count" if side == "BUY" else "sell_signal_count"
            sig_count = item.get(sig_key, 0)
            sig_base = min(15, sig_count * 4)
            
            # Add signal combination bonus (exponential for more signals)
            if sig_count >= 5:
                multipliers.append(("many_signals", 1.3))
            elif sig_count >= 3:
                multipliers.append(("multiple_signals", 1.15))
            
            # === CALCULATE FINAL SCORE ===
            base_score = zone_base + structure_base + sm_base + mom_base + liq_base + vol_base + sig_base
            
            # Apply multipliers (context-aware)
            final_mult = 1.0
            for _, mult in multipliers:
                final_mult *= mult
            
            # Cap multiplier at 3.0 to prevent runaway scores
            final_mult = min(3.0, final_mult)
            final_score = base_score * final_mult
            
            scored.append({
                "symbol": item["symbol"],
                "side": side,
                "institutional_score": round(final_score, 1),
                "base_score": round(base_score, 1),
                "multiplier": round(final_mult, 2),
                "multipliers": [m[0] for m in multipliers],
                "signals": signals,
                "smart_money": smart_money,
                "momentum": momentum,
                "zone_score": zone_score,
                "liquidity_score": item.get("liquidity_score", 0)
            })
        except:
            continue

    scored.sort(key=lambda x: x["institutional_score"], reverse=True)
    return scored


def _phase5_build_watchlist(scored_symbols, max_per_side=8):
    """
    Phase 5: Dynamic Watchlist Builder with Aging + Decay
    - Removes stale items (age > MAX_WATCHLIST_AGE minutes)
    - Applies score decay for items without updates
    - Dynamic replacement: weakest item replaced by stronger candidate
    """
    import time
    MAX_WATCHLIST_AGE = 60  # minutes before forced removal
    DECAY_RATE = 0.02  # 2% decay per minute without update
    MIN_SCORE_THRESHOLD = 30  # minimum score to stay in watchlist
    
    now = time.time()
    buy_list, sell_list = [], []
    
    # Get previous watchlist for aging check
    prev_watchlist = _INSTITUTIONAL_SCANNER_STATE.get("watchlist", {"BUY": [], "SELL": []})
    prev_buy = {w["symbol"]: w for w in prev_watchlist["BUY"]}
    prev_sell = {w["symbol"]: w for w in prev_watchlist["SELL"]}
    
    def apply_decay(item, now_ts):
        """Apply score decay based on time since last update"""
        last_updated = item.get("last_updated", item.get("first_seen", now_ts))
        age_minutes = (now_ts - last_updated) / 60
        original_score = item.get("original_score", item["score"])
        # Apply decay
        decayed_score = original_score * (1 - DECAY_RATE * age_minutes)
        return max(0, decayed_score)
    
    def should_remove(item, now_ts):
        """Check if item should be removed due to age or low score"""
        first_seen = item.get("first_seen", now_ts)
        last_updated = item.get("last_updated", first_seen)
        age_minutes = (now_ts - first_seen) / 60
        decayed = apply_decay(item, now_ts)
        # Remove if too old or score too low
        return age_minutes > MAX_WATCHLIST_AGE or decayed < MIN_SCORE_THRESHOLD
    
    # Process BUY side
    for item in scored_symbols:
        if item["side"] != "BUY":
            continue
        
        sym = item["symbol"]
        # Check if already in watchlist
        existing = prev_buy.get(sym)
        
        if existing:
            # Update existing item with decay
            decayed_score = apply_decay(existing, now)
            if not should_remove(existing, now):
                buy_list.append({
                    "symbol": sym,
                    "score": decayed_score,
                    "original_score": existing.get("original_score", existing["score"]),
                    "first_seen": existing["first_seen"],
                    "last_updated": now,
                    "signals": item["signals"],
                    "zone_score": item["zone_score"],
                    "smart_money": item["smart_money"],
                    "momentum": item["momentum"]
                })
        elif len(buy_list) < max_per_side:
            # New candidate
            buy_list.append({
                "symbol": sym,
                "score": item["institutional_score"],
                "original_score": item["institutional_score"],
                "first_seen": now,
                "last_updated": now,
                "signals": item["signals"],
                "zone_score": item["zone_score"],
                "smart_money": item["smart_money"],
                "momentum": item["momentum"]
            })
    
    # Dynamic replacement: if new candidate stronger than weakest
    for item in scored_symbols:
        if item["side"] != "BUY":
            continue
        sym = item["symbol"]
        if sym not in prev_buy and len(buy_list) >= max_per_side:
            # Find weakest in current list
            weakest_idx = min(range(len(buy_list)), key=lambda i: buy_list[i]["score"])
            if item["institutional_score"] > buy_list[weakest_idx]["score"] * 1.2:
                buy_list[weakest_idx] = {
                    "symbol": sym,
                    "score": item["institutional_score"],
                    "original_score": item["institutional_score"],
                    "first_seen": now,
                    "last_updated": now,
                    "signals": item["signals"],
                    "zone_score": item["zone_score"],
                    "smart_money": item["smart_money"],
                    "momentum": item["momentum"]
                }
    
    # Same for SELL side
    for item in scored_symbols:
        if item["side"] != "SELL":
            continue
        
        sym = item["symbol"]
        existing = prev_sell.get(sym)
        
        if existing:
            decayed_score = apply_decay(existing, now)
            if not should_remove(existing, now):
                sell_list.append({
                    "symbol": sym,
                    "score": decayed_score,
                    "original_score": existing.get("original_score", existing["score"]),
                    "first_seen": existing["first_seen"],
                    "last_updated": now,
                    "signals": item["signals"],
                    "zone_score": item["zone_score"],
                    "smart_money": item["smart_money"],
                    "momentum": item["momentum"]
                })
        elif len(sell_list) < max_per_side:
            sell_list.append({
                "symbol": sym,
                "score": item["institutional_score"],
                "original_score": item["institutional_score"],
                "first_seen": now,
                "last_updated": now,
                "signals": item["signals"],
                "zone_score": item["zone_score"],
                "smart_money": item["smart_money"],
                "momentum": item["momentum"]
            })
    
    for item in scored_symbols:
        if item["side"] != "SELL":
            continue
        sym = item["symbol"]
        if sym not in prev_sell and len(sell_list) >= max_per_side:
            weakest_idx = min(range(len(sell_list)), key=lambda i: sell_list[i]["score"])
            if item["institutional_score"] > sell_list[weakest_idx]["score"] * 1.2:
                sell_list[weakest_idx] = {
                    "symbol": sym,
                    "score": item["institutional_score"],
                    "original_score": item["institutional_score"],
                    "first_seen": now,
                    "last_updated": now,
                    "signals": item["signals"],
                    "zone_score": item["zone_score"],
                    "smart_money": item["smart_money"],
                    "momentum": item["momentum"]
                }
    
    return {"BUY": buy_list, "SELL": sell_list}


def run_institutional_scanner():
    """Main entry point for Institutional Market Scanner"""
    import time as time_module
    start_time = time_module.time()
    
    # Initialize metrics
    metrics = {
        "discovery_symbols": 0,
        "dirty_symbols": 0,
        "deep_analysis": 0,
        "buy_candidates": 0,
        "sell_candidates": 0,
        "avg_opportunity_score": 0,
        "scan_time_ms": 0,
        "api_calls": 0,
        "cache_hit_ratio": 0
    }
    
    try:
        # Phase 1: Discovery
        discovery_data = _phase1_market_discovery()
        if not discovery_data:
            return
        metrics["discovery_symbols"] = len(discovery_data)
        metrics["api_calls"] += len(discovery_data)
        
        # Phase 2: Liquidity Ranking
        liquidity_ranked = _phase2_liquidity_ranking(discovery_data, top_n=80)
        if not liquidity_ranked:
            return
        metrics["dirty_symbols"] = len(_INSTITUTIONAL_SCANNER_STATE.get("dirty_symbols", set()))
        
        # Phase 3: Institutional Filtering
        filtered = _phase3_institutional_filtering(liquidity_ranked)
        metrics["deep_analysis"] = len([d for d in liquidity_ranked if d.get("dirty", False)])
        metrics["api_calls"] += metrics["deep_analysis"]
        
        # Phase 4: Opportunity Score
        scored = _phase4_institutional_opportunity_score(filtered)
        
        # Phase 5: Build Watchlist
        watchlist = _phase5_build_watchlist(scored, max_per_side=8)
        
        # Calculate metrics
        metrics["buy_candidates"] = len(watchlist["BUY"])
        metrics["sell_candidates"] = len(watchlist["SELL"])
        
        if scored:
            metrics["avg_opportunity_score"] = round(sum(s["institutional_score"] for s in scored) / len(scored), 1)
        
        metrics["scan_time_ms"] = round((time_module.time() - start_time) * 1000, 1)
        
        total_ranked = len(liquidity_ranked)
        dirty = len(_INSTITUTIONAL_SCANNER_STATE.get("dirty_symbols", set()))
        if total_ranked > 0:
            metrics["cache_hit_ratio"] = round((total_ranked - dirty) / total_ranked * 100, 1)
        
        # Store metrics
        _INSTITUTIONAL_SCANNER_STATE["metrics"] = metrics
        
        # Update MEMORY
        buy_candidates = [{"symbol": i["symbol"], "score": i["score"], "source": "INST_SCANNER",
                          "zone_score": i["zone_score"], "signals": i["signals"],
                          "first_seen": i.get("first_seen", 0), "last_updated": i.get("last_updated", 0)} 
                         for i in watchlist["BUY"]]
        sell_candidates = [{"symbol": i["symbol"], "score": i["score"], "source": "INST_SCANNER",
                           "zone_score": i["zone_score"], "signals": i["signals"],
                           "first_seen": i.get("first_seen", 0), "last_updated": i.get("last_updated", 0)}
                          for i in watchlist["SELL"]]
        
        MEMORY["institutional_buy"] = buy_candidates
        MEMORY["institutional_sell"] = sell_candidates
        MEMORY["institutional_watchlist"] = watchlist
        MEMORY["institutional_last_scan"] = time_module.time()
        MEMORY["institutional_metrics"] = metrics
        
        # Log metrics
        log_execution(f"[INST_SCANNER] Metrics: D={metrics['discovery_symbols']} "
                     f"Dr={metrics['dirty_symbols']} "
                     f"DA={metrics['deep_analysis']} "
                     f"B={metrics['buy_candidates']} "
                     f"S={metrics['sell_candidates']} "
                     f"Score={metrics['avg_opportunity_score']} "
                     f"ms={metrics['scan_time_ms']} "
                     f"API={metrics['api_calls']} "
                     f"Cache={metrics['cache_hit_ratio']}%", "INFO")
        
    except Exception as e:
        log_execution(f"[INST_SCANNER] Error: {e}", "ERROR")


def equal_levels_points(highs, lows, tolerance=0.002):
    eq_highs = []
    eq_lows = []
    def cluster(points, tol):
        if not points:
            return []
        points = sorted(points)
        clusters = []
        current = [points[0]]
        for p in points[1:]:
            if abs(p - current[-1]) / current[-1] < tol:
                current.append(p)
            else:
                clusters.append(current)
                current = [p]
        clusters.append(current)
        return clusters
    high_clusters = cluster(highs, tolerance)
    low_clusters = cluster(lows, tolerance)
    for cl in high_clusters:
        if len(cl) >= 2:
            eq_highs.extend([sum(cl)/len(cl)])
    for cl in low_clusters:
        if len(cl) >= 2:
            eq_lows.extend([sum(cl)/len(cl)])
    return eq_highs, eq_lows

def find_swing_points(df, window=3):
    highs = df['high'].values
    lows = df['low'].values
    swing_highs = []
    swing_lows = []
    for i in range(window, len(df)-window):
        if highs[i] == max(highs[i-window:i+window+1]):
            swing_highs.append(highs[i])
        if lows[i] == min(lows[i-window:i+window+1]):
            swing_lows.append(lows[i])
    return swing_highs, swing_lows

def detect_equal_highs_lows(df, lookback=50):
    sub = df.iloc[-lookback:]
    sh, sl = find_swing_points(sub, window=2)
    return equal_levels_points(sh, sl)

def detect_order_block(df, side, lookback=4):
    if len(df) < lookback+2:
        return None
    atr = compute_atr(df).iloc[-1]
    move = abs(df['close'].iloc[-1] - df['close'].iloc[-2])
    if move < atr * 1.2:
        return None
    for i in range(2, lookback+2):
        if i >= len(df):
            break
        candle = df.iloc[-i]
        if side == "BUY" and candle['close'] < candle['open']:
            return {"low": candle['low'], "high": candle['high'], "idx": -i}
        elif side == "SELL" and candle['close'] > candle['open']:
            return {"low": candle['low'], "high": candle['high'], "idx": -i}
    return None

def detect_fvg(df, threshold=0.001):
    if len(df) < 2:
        return None
    prev = df.iloc[-2]
    curr = df.iloc[-1]
    if curr['low'] > prev['high'] * (1+threshold):
        return ("bullish", prev['high'], curr['low'])
    elif curr['high'] < prev['low'] * (1-threshold):
        return ("bearish", curr['high'], prev['low'])
    return None

def evaluate_liquidity_narrative(df, ob, atr, side):
    narrative = {"sweep": False, "choch_bos": False, "retest": False, "rejection": False,
                 "displacement": False, "rf_alignment": False, "volume_confirmation": False}
    price = df['close'].iloc[-1]
    pools = build_liquidity_pools(df)
    swept_h, swept_l = detect_sweep(df, pools)
    if side == "BUY" and swept_l:
        narrative["sweep"] = True
    elif side == "SELL" and swept_h:
        narrative["sweep"] = True
    bos_up, bos_down = detect_bos(df)
    struct_shift = detect_structure_shift(df)
    choch = struct_shift is not None
    if side == "BUY" and (bos_up or (choch and struct_shift == "bullish_shift")):
        narrative["choch_bos"] = True
    elif side == "SELL" and (bos_down or (choch and struct_shift == "bearish_shift")):
        narrative["choch_bos"] = True
    zones = get_smart_zones(df.symbol if hasattr(df, 'symbol') else "unknown", df, ob)
    required_zone = None
    if zones:
        if side == "BUY" and zones["buy_zones"]:
            required_zone = zones["buy_zones"][0]
        elif side == "SELL" and zones["sell_zones"]:
            required_zone = zones["sell_zones"][0]
    if required_zone:
        dist = abs(price - required_zone["price"]) / price
        if dist < 0.003:
            narrative["retest"] = True
    if candle_rejection(df, side):
        narrative["rejection"] = True
    vol_state = classify_volume(df)
    if detect_displacement(df, side, atr, vol_state):
        narrative["displacement"] = True
    if vol_state in ("expansion", "spike"):
        narrative["volume_confirmation"] = True
    rf = RFEngine(20, 3.5).compute(df)
    if rf["signal"] == side and abs(rf["distance"]) < 0.003:
        narrative["rf_alignment"] = True
    score = 0
    if narrative["sweep"]: score += 2
    if narrative["choch_bos"]: score += 2
    if narrative["retest"]: score += 2
    if narrative["rejection"]: score += 1.5
    if narrative["displacement"]: score += 1.5
    if narrative["volume_confirmation"]: score += 1
    if narrative["rf_alignment"]: score += 2
    return narrative, score


# ========== CANDIDATE AGGREGATION LAYER ==========
# طبقة تجميع المرشحين من جميع المصادر
# - تزيل التكرار (نفس الرمز من مصادر متعددة)
# - تدمج الدرجات بطريقة ذكية (weighted average)
# - تحافظ على الأولوية الديناميكية
# - ترسل قائمة موحدة لـ smart_opportunity_selection()

_CANDIDATE_AGGREGATOR_STATE = {
    "unified_candidates": {},  # {symbol: {score, sides, sources, priority_boost, last_update}}
    "last_aggregation": 0,
    "aggregation_ttl": 60,  # 1 minute TTL for aggregated list
}

# وزن كل مصدر (المصادر الأكثر دقة تحصل على وزن أعلى)
_SOURCE_WEIGHTS = {
    "discovery": 1.2,    # Continuous analysis with engines (highest priority)
    "v2": 1.0,          # Smart Scanner v2
    "rf": 0.8,          # RF Scanner
    "institutional": 1.1, # Institutional Scanner
    "radar": 0.7,       # Radar Scanner
}

# Threshold لرفع الأولوية ديناميكياً
_HIGH_PRIORITY_THRESHOLD = 75
_PROMOTION_BOOST = 20  # نقاط إضافية للعملات القوية جداً

def aggregate_candidates():
    """
    Candidate Aggregation Layer
    - يجمع المرشحين من جميع المصادر
    - يزيل التكرار (symbol appearing in multiple sources)
    - يدمج الدرجات (weighted average)
    - يرفع أولوية العملات القوية
    """
    import time as time_module
    now = time_module.time()
    
    # Skip if aggregated recently (within TTL)
    if now - _CANDIDATE_AGGREGATOR_STATE["last_aggregation"] < _CANDIDATE_AGGREGATOR_STATE["aggregation_ttl"]:
        return _CANDIDATE_AGGREGATOR_STATE["unified_candidates"]
    
    unified = {}  # {symbol: {score, sides, sources, priority, last_update}}
    
    # Log current watchlist state for debugging
    watchlist_count = len(MEMORY.get("watchlist", {}))
    log_execution(f"[AGGREGATOR] MEMORY[watchlist]: {watchlist_count} entries", "INFO")
    
    # Source 1: Scanner v2 (same as reference bot)
    v2_buy = len(MEMORY.get("scanner_v2_buy", []))
    v2_sell = len(MEMORY.get("scanner_v2_sell", []))
    for c in MEMORY.get("scanner_v2_buy", [])[:5]:
        _add_candidate(unified, c["symbol"], "BUY", c.get("score", 50), "v2", _SOURCE_WEIGHTS["v2"])
    for c in MEMORY.get("scanner_v2_sell", [])[:5]:
        _add_candidate(unified, c["symbol"], "SELL", c.get("score", 50), "v2", _SOURCE_WEIGHTS["v2"])
    log_execution(f"[AGGREGATOR] Scanner v2: BUY={v2_buy} SELL={v2_sell}", "INFO")
    
    # Source 2: RF Watchlist (same as reference bot)
    rf_count = len(MEMORY.get("rf_watchlist", []))
    for c in MEMORY.get("rf_watchlist", [])[:10]:
        side = c.get("rf_signal") or c.get("side")
        if side in ("BUY", "SELL"):
            _add_candidate(unified, c["symbol"], side, c.get("score", 50), "rf", _SOURCE_WEIGHTS["rf"])
    log_execution(f"[AGGREGATOR] RF Watchlist: {rf_count}", "INFO")
    
    # Source 3: Discovery candidates (from Continuous Analysis)
    # These are stored in discovery_candidates
    discovery_candidates = MEMORY.get("discovery_candidates", [])
    for c in discovery_candidates[:10]:
        base_score = c.get("discovery_score", 50)
        # Determine side from hash-based score (just for distribution)
        _add_candidate(unified, c["symbol"], "BUY", base_score, "discovery", _SOURCE_WEIGHTS["discovery"])
    log_execution(f"[AGGREGATOR] Discovery: {len(discovery_candidates)} candidates", "INFO")
    
    log_execution(f"[AGGREGATOR] Total unified candidates: {len(unified)}", "INFO")
    
    # Calculate final score for each candidate (weighted average)
    for sym, data in unified.items():
        if data["source_count"] > 1:
            # Weighted average for multi-source candidates
            total_weighted_score = sum(
                score * _SOURCE_WEIGHTS.get(source, 1.0) 
                for score, source in zip(data["raw_scores"], data["sources"])
            )
            total_weight = sum(_SOURCE_WEIGHTS.get(source, 1.0) for source in data["sources"])
            data["final_score"] = total_weighted_score / total_weight
        else:
            data["final_score"] = data["raw_scores"][0] if data["raw_scores"] else 50
        
        # Dynamic priority boost for high-scoring candidates
        if data["final_score"] >= _HIGH_PRIORITY_THRESHOLD:
            data["priority_boost"] = _PROMOTION_BOOST
            data["is_hot"] = True
        else:
            data["is_hot"] = False
    
    # Sort by final score (with priority boost)
    sorted_candidates = sorted(
        unified.items(),
        key=lambda x: x[1]["final_score"] + x[1].get("priority_boost", 0),
        reverse=True
    )
    
    # Update state
    _CANDIDATE_AGGREGATOR_STATE["unified_candidates"] = unified
    _CANDIDATE_AGGREGATOR_STATE["last_aggregation"] = now
    
    log_execution(f"[AGGREGATOR] Unified {len(unified)} candidates from {sum(len(v['sources']) for v in unified.values())} raw entries", "INFO")
    
    return unified


def _add_candidate(unified, symbol, side, score, source, weight):
    """Helper to add candidate to unified list"""
    if symbol not in unified:
        unified[symbol] = {
            "symbol": symbol,
            "raw_scores": [],
            "sources": [],
            "sides": set(),
            "source_count": 0,
            "final_score": score,
            "priority_boost": 0,
            "is_hot": False,
            "last_update": time.time()
        }
    
    unified[symbol]["raw_scores"].append(score)
    unified[symbol]["sources"].append(source)
    unified[symbol]["sides"].add(side)
    unified[symbol]["source_count"] = len(unified[symbol]["sources"])


def get_aggregated_candidates(side=None, limit=20, min_score=50):
    """
    Get unified candidates sorted by final score
    - side: filter by BUY/SELL or None for all
    - limit: max number of candidates
    - min_score: minimum final score threshold
    """
    unified = aggregate_candidates()
    
    # Sort by score (with boost)
    sorted_list = sorted(
        unified.items(),
        key=lambda x: x[1]["final_score"] + x[1].get("priority_boost", 0),
        reverse=True
    )
    
    result = []
    for sym, data in sorted_list:
        # Filter by side if specified
        if side and side not in data["sides"]:
            continue
        # Filter by minimum score
        effective_score = data["final_score"] + data.get("priority_boost", 0)
        if effective_score < min_score:
            continue
        result.append({
            "symbol": sym,
            "side": list(data["sides"])[0] if len(data["sides"]) == 1 else "BOTH",
            "score": effective_score,
            "sources": data["sources"],
            "is_hot": data["is_hot"],
            "source_count": data["source_count"]
        })
        if len(result) >= limit:
            break
    
    return result


def boost_symbol_priority(symbol, boost_amount=20):
    """
    Boost a symbol's priority dynamically
    - Called when a symbol shows strong signals during analysis
    - Symbol moves to top of priority queue
    """
    unified = _CANDIDATE_AGGREGATOR_STATE["unified_candidates"]
    if symbol in unified:
        unified[symbol]["priority_boost"] += boost_amount
        unified[symbol]["is_hot"] = True
        log_execution(f"[AGGREGATOR] Boosted {symbol} priority by {boost_amount} (total: {unified[symbol]['priority_boost']})", "INFO")


# ========== SMART OPPORTUNITY SELECTION (UPDATED) ==========

def smart_opportunity_selection():
    """
    PHASE 4 v2: Entry Selection - WATCHLIST is Single Source of Truth
    
    This is the SINGLE ENTRY POINT for all trades.
    All strategic decisions are made by UnifiedDecisionEngine in the Watchlist.
    
    Pipeline stages:
    1. READ_WATCHLIST - Read candidates from watchlist
    2. GET_READY_OPPORTUNITIES - Use UnifiedDecisionEngine to get READY opportunities
    3. SELECT_BEST - Select best using COMPOSITE RANKING (multi-factor)
    4. UPDATE_LIFECYCLE - Mark selected as SELECTED
    5. FETCH_DATA - Get OHLCV data for execution
    6. PASS_TO_ENTRY - Call execute_entry() (EXECUTION ONLY)
    7. EXECUTE - Execute the order
    8. UPDATE_LIFECYCLE - Mark as ENTRY_SENT
    
    NO strategic decisions are made here - Watchlist decided.
    Lifecycle tracking: DISCOVERED → ANALYZING → WATCHING → READY → SELECTED → ENTRY_SENT → IN_POSITION
    """
    # Set diagnostic context
    analysis_id = uuid.uuid4().hex[:8]
    DIAG_CTX.set_analysis_id(analysis_id)
    
    # FORENSIC: Log pipeline stage header
    log_execution("[FORENSIC] =======================================", "INFO")
    log_execution("[FORENSIC] PIPELINE STAGES:", "INFO")
    log_execution("[FORENSIC] DISCOVERED → SCANNER → WATCHLIST → EVIDENCE →", "INFO")
    log_execution("[FORENSIC] SMART_MONEY → INSTITUTIONAL → BANKER_FLOW →", "INFO")
    log_execution("[FORENSIC] MCDX → MARKET_STORY → WEIGHT_AGG →", "INFO")
    log_execution("[FORENSIC] COMPOSITE → RANKING → READINESS → EXECUTE_ENTRY()", "INFO")
    log_execution("[FORENSIC] =======================================", "INFO")
    
    try:
        if DEBUG_CONFIDENCE_TRACE:
            log_execution(f"[DIAG][{analysis_id}] ========== OPPORTUNITY SELECTION START ==========", "INFO")
        
        # STAGE 1: READ_WATCHLIST
        watchlist = MEMORY.get("watchlist", {})
        watchlist_count = len(watchlist)
        
        # Count by lifecycle
        lifecycle_counts = {}
        for d in watchlist.values():
            lc = d.get("lifecycle", WatchlistLifecycle.WATCHING)
            lifecycle_counts[lc] = lifecycle_counts.get(lc, 0) + 1
        
        ready_count = sum(1 for d in watchlist.values() if d.get("action") == "READY")
        strategy_valid_count = sum(1 for d in watchlist.values() if d.get("strategy_valid") == True)
        
        log_execution(
            f"[PIPELINE] Stage 1: READ_WATCHLIST | Total: {watchlist_count} | "
            f"StrategyValid: {strategy_valid_count} | READY: {ready_count} | "
            f"Lifecycle: {lifecycle_counts}",
            "INFO"
        )
        
        if not watchlist:
            log_execution("[PIPELINE] WATCHLIST_EMPTY - No candidates to evaluate", "WARN")
            return False
        
        # STAGE 2: GET_READY_OPPORTUNITIES (with COMPOSITE RANKING)
        ready_opportunities = UnifiedDecisionEngine.get_ready_opportunities(watchlist)
        
        log_execution(f"[PIPELINE] Stage 2: COMPOSITE_RANKING | READY: {len(ready_opportunities)}", "INFO")
        
        # Log ranking factors for top 3
        for i, opp in enumerate(ready_opportunities[:3]):
            sym = opp['symbol']
            decision = opp['decision']
            factors = decision.get('ranking_factors', {})
            log_execution(
                f"[PIPELINE] #{i+1} {sym} | Composite={opp['composite_score']:.1f} | "
                f"Confidence={factors.get('confidence', 0):.0f} | "
                f"SM_Align={factors.get('smart_money', 0):.0f} | "
                f"Phase={factors.get('phase_alignment', 0):.0f}",
                "INFO"
            )
        
        if not ready_opportunities:
            # Log why no opportunities are ready
            log_execution("[PIPELINE] No READY opportunities - all setups pending", "WARN")
            
            # Show top candidates that are not ready
            top_candidates = sorted(
                [(sym, data) for sym, data in watchlist.items()],
                key=lambda x: x[1].get("strategy_score", 0) + x[1].get("score", 0),
                reverse=True
            )[:3]
            
            for sym, data in top_candidates:
                action = data.get("action", "UNKNOWN")
                readiness = data.get("entry_readiness", "N/A")
                confidence = data.get("confidence", 0)
                lifecycle = data.get("lifecycle", "N/A")
                log_execution(
                    f"[PIPELINE] TOP_CANDIDATE: {sym} | Lifecycle={lifecycle} | "
                    f"Action={action} | Readiness={readiness} | Confidence={confidence:.0f}%",
                    "INFO"
                )
            
            return False
        
        # STAGE 3: SELECT_BEST (already sorted by composite ranking)
        best = ready_opportunities[0]
        best_symbol = best["symbol"]
        best_entry = best["entry"]
        best_decision = best["decision"]
        
        # STAGE 4: UPDATE_LIFECYCLE to SELECTED
        best_entry["lifecycle"] = WatchlistLifecycle.SELECTED
        MEMORY["watchlist"][best_symbol] = best_entry
        
        log_execution(
            f"[PIPELINE] Stage 3: SELECT_BEST | {best_symbol} | "
            f"Readiness={best_decision['entry_readiness']} | "
            f"Composite={best['composite_score']:.1f} | "
            f"Type={best_entry.get('trade_type', 'UNKNOWN')}",
            "INFO"
        )
        
        # Extract data from watchlist entry
        side = best_entry.get("side", "BUY")
        if side == "BOTH":
            side = "BUY"
        
        watchlist_score = best_entry.get("score", 0)
        strategy_score = best_decision["strategy_score"]
        confidence = best_decision["confidence"]
        trade_type = best_entry.get("trade_type", "TREND")
        entry_readiness = best_decision["entry_readiness"]
        
        # STAGE 5: FETCH_DATA
        log_execution(f"[PIPELINE] Stage 5: FETCH_DATA | {best_symbol}", "INFO")
        
        df = get_ohlcv_safe(best_symbol, 100)
        if df is None:
            # Reset lifecycle
            best_entry["lifecycle"] = WatchlistLifecycle.WATCHING
            MEMORY["watchlist"][best_symbol] = best_entry
            log_execution(f"[PIPELINE] {best_symbol}: FAILED - No OHLCV data", "WARN")
            _log_entry_decision(best_symbol, {
                "action": "NO_DATA",
                "score": watchlist_score,
                "side": side,
                "confidence": confidence,
                "entry_readiness": entry_readiness,
                "lifecycle": "WATCHING",
                "reasons": ["No OHLCV data available"],
                "watchlist_validated": True,
                "pipeline_stage": "FETCH_DATA",
            })
            return False
            
        if not validate_dataframe(df, 80):
            best_entry["lifecycle"] = WatchlistLifecycle.WATCHING
            MEMORY["watchlist"][best_symbol] = best_entry
            log_execution(f"[PIPELINE] {best_symbol}: FAILED - DataFrame validation failed", "WARN")
            _log_entry_decision(best_symbol, {
                "action": "INVALID_DATA",
                "score": watchlist_score,
                "side": side,
                "confidence": confidence,
                "entry_readiness": entry_readiness,
                "lifecycle": "WATCHING",
                "reasons": ["DataFrame validation failed"],
                "watchlist_validated": True,
                "pipeline_stage": "FETCH_DATA",
            })
            return False
        
        df.symbol = best_symbol
        atr = compute_atr(df).iloc[-1] if len(df) > 14 else df['close'].iloc[-1] * 0.01
        
        # Calculate entry parameters
        price = df['close'].iloc[-1]
        sl, tp1, tp2 = compute_sl_tp(price, side, trade_type, atr, df)
        
        # Build reason string from watchlist decision
        reasons_str = best_decision.get("action_reason", "")
        if best_decision.get("reasoning"):
            reasons_str = f"WATCHLIST {entry_readiness} | " + " | ".join(best_decision["reasoning"][:3])
        
        log_execution(f"[PIPELINE] Stage 6: PASS_TO_ENTRY | {best_symbol} @ {price} | SL={sl} | TP={tp1}", "INFO")
        log_execution(f"[WATCHLIST DECISION] {reasons_str}", "INFO")
        
        # STAGE 7: EXECUTE
        # Update lifecycle to ENTRY_SENT
        best_entry["lifecycle"] = WatchlistLifecycle.ENTRY_SENT
        MEMORY["watchlist"][best_symbol] = best_entry
        
        ok = execute_entry(
            side, best_symbol, price, sl, tp1, tp2, 
            watchlist_score, reasons_str, atr,
            trade_type=trade_type, 
            entry_type="CANDIDATE_AGGREGATION", 
            classification="SNIPER"
        )
        
        if ok:
            log_execution(
                f"[PIPELINE] ✅ {best_symbol}: EXECUTED | Confidence={confidence:.0f}% | "
                f"Composite={best['composite_score']:.1f}",
                "SUCCESS"
            )
            return True
        else:
            # Reset lifecycle to WATCHING
            best_entry["lifecycle"] = WatchlistLifecycle.WATCHING
            MEMORY["watchlist"][best_symbol] = best_entry
            log_execution(f"[PIPELINE] ❌ {best_symbol}: REJECTED (execute_entry returned False)", "WARN")
            _log_entry_decision(best_symbol, {
                "action": "EXECUTION_REJECTED",
                "score": watchlist_score,
                "strategy_score": strategy_score,
                "confidence": confidence,
                "side": side,
                "entry_readiness": entry_readiness,
                "lifecycle": "WATCHING",
                "composite_score": best['composite_score'],
                "reasons": ["execute_entry returned False"],
                "watchlist_validated": True,
                "pipeline_stage": "EXECUTE_ENTRY",
            })
            return False
    finally:
        DIAG_CTX.clear()


def record_watchlist_entry(symbol, side, narrative, score, smart_money=None, momentum=None,
                            market_phase=None, structure_data=None, volume_data=None,
                            df=None, lifecycle_id=None):
    """
    PHASE 4 v2: Watchlist as Single Strategy Engine
    
    Record entry in watchlist with complete strategy information.
    This function is called from run_continuous_analysis after all engines
    have analyzed the symbol.
    
    Pipeline:
    1. All engines calculate their scores (SmartMoney, Momentum, etc.)
    2. StrategyEntryFilter validates
    3. DynamicStrategyEngine determines type
    4. UnifiedDecisionEngine produces final decision (READ-ONLY AGGREGATOR)
    
    Lifecycle states:
    - DISCOVERED: New coin discovered
    - ANALYZING: Being analyzed
    - WATCHING: Analyzed, waiting
    - READY: Ready for entry
    - SELECTED: Selected for execution
    - ENTRY_SENT: Order sent
    - IN_POSITION: Trade open
    - FINISHED: Trade completed
    
    IMPORTANT: Forensic calls are wrapped in try/except to NEVER break the pipeline.
    """
    # ========== COMPREHENSIVE NULL SAFETY ==========
    # Ensure all optional parameters are never None
    if narrative is None:
        narrative = {}
    if smart_money is None:
        smart_money = {}
    if momentum is None:
        momentum = {}
    if market_phase is None:
        market_phase = "UNKNOWN"
    if structure_data is None:
        structure_data = {}
    if volume_data is None:
        volume_data = {}
    # df can be None (will be fetched later if needed)
    if score is None:
        score = 0
    # =============================================

    # FORENSIC: Create lifecycle ID if not provided (with safety)
    try:
        if lifecycle_id is None:
            lifecycle_id, _ = create_forensic_record(symbol, side)
        
        # Set DIAG_CTX lifecycle_id for downstream forensic tracking
        DIAG_CTX.set_lifecycle_id(lifecycle_id)
    except Exception as forensic_err:
        log_execution(f"[FORENSIC ERROR] Failed to create lifecycle: {forensic_err}", "WARN")
        lifecycle_id = f"{symbol}_{int(time.time())}"  # Fallback ID
    
    # PIPELINE TRACE
    log_execution(f"[WATCHLIST TRACE] record_watchlist_entry() CALLED for {symbol} | Score={score:.1f} | LID={lifecycle_id}", "INFO")
    
    now = time.time()
    
    # FORENSIC: Log pipeline stages (with safety)
    try:
        log_pipeline_stage(lifecycle_id, "SCANNER", True, 
                          details={"score": score, "narrative_keys": list(narrative.keys()) if narrative else []})
        log_pipeline_stage(lifecycle_id, "WATCHLIST", True, details={"state": "ADDED"})
    except Exception as forensic_err:
        log_execution(f"[FORENSIC ERROR] Failed to log pipeline stage: {forensic_err}", "WARN")
    
    # Determine state based on narrative (with null safety)
    state = "DETECTED"
    if narrative and narrative.get("retest"):
        state = "RETEST"
    if narrative and narrative.get("rejection"):
        state = "REJECTION"
    if narrative and narrative.get("displacement"):
        state = "DISPLACEMENT"
    if narrative and narrative.get("sweep") and narrative.get("choch_bos") and narrative.get("retest") and narrative.get("rejection"):
        state = "CONFIRMED"
    
    # Build reasons list (with null safety)
    reasons_list = []
    if narrative and narrative.get("sweep"): reasons_list.append("Sweep")
    if narrative and narrative.get("choch_bos"): reasons_list.append("CHoCH/BOS")
    if narrative and narrative.get("retest"): reasons_list.append("ZONE_RETEST")
    if narrative and narrative.get("rejection"): reasons_list.append("OB")
    if narrative and narrative.get("displacement"): reasons_list.append("Displacement")
    if narrative and narrative.get("volume_confirmation"): reasons_list.append("Volume")
    if narrative and narrative.get("rf_alignment"): reasons_list.append("RF")
    
    # ========== DYNAMIC STRATEGY ENGINE ==========
    # Use df if provided, otherwise fetch
    if df is None:
        df_for_analysis = get_ohlcv_safe(symbol, 100)
    else:
        df_for_analysis = df
    
    # Use DynamicStrategyEngine to determine best strategy based on all elements
    dynamic_result = DynamicStrategyEngine.analyze(
        df=df_for_analysis,
        smart_money=smart_money,
        momentum=momentum,
        market_phase=market_phase,
        narrative=narrative,
        structure_data=structure_data,
        volume_data=volume_data
    )
    
    # Log dynamic strategy analysis results (with null safety)
    confidence = dynamic_result.get("confidence", 0) if dynamic_result else 0
    best_score = dynamic_result.get("best_score", 0) if dynamic_result else 0
    strategy_type_str = dynamic_result.get("strategy_type", "UNKNOWN") if dynamic_result else "UNKNOWN"
    element_scores = dynamic_result.get("element_scores", {}) if dynamic_result else {}
    failure_reason = dynamic_result.get("failure_reason") if dynamic_result else None
    
    # ========== INSTITUTIONAL STRATEGY ENGINES ==========
    # Run new institutional engines if df is available
    # These enhance the existing engines with institutional intelligence
    
    # Institutional Smart Money (enhanced)
    institutional_sm = InstitutionalSmartMoneyEngine.analyze_institutional_smart_money(df_for_analysis)
    
    # Banker Fund Flow (Original)
    banker_flow = BankerFundFlowEngine.analyze_banker_fund_flow(df_for_analysis)
    
