        # PIPELINE TRACE - Dashboard read
        log_execution(f"[DASHBOARD TRACE] Reading MEMORY['watchlist'] | Entries: {len(watchlist_data)}", "INFO")
        
        no_entry_feed = MEMORY.get("no_entry_feed", [])[-5:]
        live_data = {}
